export interface HivemindError {
  message: string;
  code?: string;
  statusCode?: number;
  originalError?: Error;
  context?: Record<string, any>;
}

export const ErrorClassification = {
  USER_ERROR: 'user_error',
  SYSTEM_ERROR: 'system_error',
  NETWORK_ERROR: 'network_error',
  VALIDATION_ERROR: 'validation_error',
  UNKNOWN_ERROR: 'unknown_error',
} as const;

export type ErrorClassification = (typeof ErrorClassification)[keyof typeof ErrorClassification];

class ErrorUtils {
  /**
   * Converts an unknown error to a standardized HivemindError format.
   *
   * @param error - The error to convert.
   * @param context - Additional context information.
   * @returns A standardized HivemindError object.
   */
  public static toHivemindError(error: unknown, context?: Record<string, any>): HivemindError {
    if (error instanceof Error) {
      return {
        message: error.message,
        code: (error as any).code,
        originalError: error,
        context,
      };
    }

    if (typeof error === 'string') {
      return {
        message: error,
        context,
      };
    }

    return {
      message: 'An unknown error occurred',
      context: { ...context, originalError: error },
    };
  }

  /**
   * Classifies an error based on its properties and context.
   *
   * @param error - The HivemindError to classify.
   * @returns An object containing the classification and suggested log level.
   */
  public static classifyError(error: HivemindError): {
    classification: ErrorClassification;
    logLevel: 'error' | 'warn' | 'info';
  } {
    // Check for specific error codes or messages
    if (error.code === 'VALIDATION_ERROR' || error.message.toLowerCase().includes('validation')) {
      return { classification: ErrorClassification.VALIDATION_ERROR, logLevel: 'warn' };
    }

    if (
      error.code === 'ECONNREFUSED' ||
      error.code === 'ENOTFOUND' ||
      error.message.toLowerCase().includes('network')
    ) {
      return { classification: ErrorClassification.NETWORK_ERROR, logLevel: 'error' };
    }

    if (error.statusCode && error.statusCode >= 400 && error.statusCode < 500) {
      return { classification: ErrorClassification.USER_ERROR, logLevel: 'warn' };
    }

    if (error.statusCode && error.statusCode >= 500) {
      return { classification: ErrorClassification.SYSTEM_ERROR, logLevel: 'error' };
    }

    // Default classification
    return { classification: ErrorClassification.UNKNOWN_ERROR, logLevel: 'error' };
  }

  /**
   * Extracts a user-friendly message from a HivemindError.
   *
   * @param error - The HivemindError to extract the message from.
   * @returns A user-friendly error message.
   */
  public static getMessage(error: HivemindError): string {
    // For user errors, return the original message
    const classification = this.classifyError(error);
    if (
      classification.classification === ErrorClassification.USER_ERROR ||
      classification.classification === ErrorClassification.VALIDATION_ERROR
    ) {
      return error.message;
    }

    // For system errors, return a generic message to avoid exposing internal details
    return 'An internal error occurred. Please try again later.';
  }

  /**
   * Handles an error by logging it appropriately.
   * This is a legacy method for backward compatibility.
   *
   * @param error - The error to handle.
   */
  public static handleError(error: Error): void {
    const hivemindError = this.toHivemindError(error);
    const classification = this.classifyError(hivemindError);

    if (classification.logLevel === 'error') {
      console.error('Application error:', hivemindError);
    } else if (classification.logLevel === 'warn') {
      console.warn('Application warning:', hivemindError);
    } else {
      console.info('Application info:', hivemindError);
    }
  }
}

/**
 * Structured Logger with correlation IDs for request tracing
 *
 * This module provides JSON-formatted logging with support for:
 * - Correlation IDs (traceId, spanId) for distributed tracing
 * - Structured context data
 * - Integration with the 'debug' package for development
 * - Sensitive data redaction via sanitizeForLogging
 *
 * @module StructuredLogger
 */

import Debug from 'debug';
import { sanitizeForLogging } from './logger';

/**
 * Log levels supported by the StructuredLogger
 */
type LogLevel = 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Error categories for classification
 */
type ErrorCategory = 'database' | 'network' | 'validation' | 'configuration' | 'system';

/**
 * Structured log entry format
 */
interface LogEntry {
  timestamp: string;
  level: LogLevel;
  message: string;
  context?: Record<string, unknown>;
  traceId?: string;
  spanId?: string;
  service: string;
}

/**
 * Options for creating a StructuredLogger
 */
interface StructuredLoggerOptions {
  /** Service name for log entries */
  service: string;
  /** Optional trace ID for request correlation */
  traceId?: string;
  /** Optional span ID for operation tracking */
  spanId?: string;
}

/**
 * Error information for structured error logging
 */
interface ErrorInfo {
  name: string;
  message: string;
  stack?: string;
  code?: string;
  category?: ErrorCategory;
}

/**
 * Extract error information from an Error object
 */
function extractErrorInfo(error: Error): ErrorInfo {
  const info: ErrorInfo = {
    name: error.name,
    message: error.message,
    stack: error.stack,
  };

  // Check for HivemindError properties
  const anyError = error as unknown as Record<string, unknown>;
  if (anyError.code && typeof anyError.code === 'string') {
    info.code = anyError.code;
  }
  if (anyError.category && typeof anyError.category === 'string') {
    info.category = anyError.category as ErrorCategory;
  }

  return info;
}

/**
 * Sanitize context data for safe logging
 */
function sanitizeContext(context: Record<string, unknown>): Record<string, unknown> {
  const sanitized: Record<string, unknown> = {};
  for (const [key, value] of Object.entries(context)) {
    sanitized[key] = sanitizeForLogging(value, key);
  }
  return sanitized;
}

/**
 * StructuredLogger provides JSON-formatted logging with correlation IDs
 *
 * @example
 * ```typescript
 * const logger = createLogger('messageHandler');
 * logger.info('Processing message', { messageId: '123', channel: 'general' });
 *
 * // With trace ID for request correlation
 * const tracedLogger = logger.withTraceId('abc-123-def');
 * tracedLogger.error('Failed to process', new Error('Connection timeout'));
 * ```
 */
export class StructuredLogger {
  private readonly debugLogger: Debug.Debugger;
  private readonly service: string;
  private readonly traceId?: string;
  private readonly spanId?: string;

  constructor(options: StructuredLoggerOptions) {
    this.service = options.service;
    this.traceId = options.traceId;
    this.spanId = options.spanId;
    this.debugLogger = Debug(`app:${options.service}`);
  }

  /**
   * Format a log entry with consistent structure
   */
  private formatEntry(
    level: LogLevel,
    message: string,
    context?: Record<string, unknown>
  ): LogEntry {
    const entry: LogEntry = {
      timestamp: new Date().toISOString(),
      level,
      message,
      service: this.service,
    };

    if (context && Object.keys(context).length > 0) {
      entry.context = sanitizeContext(context);
    }

    if (this.traceId) {
      entry.traceId = this.traceId;
    }

    if (this.spanId) {
      entry.spanId = this.spanId;
    }

    return entry;
  }

  /**
   * Log a debug message (only visible when DEBUG=app:* is set)
   */
  debug(message: string, context?: Record<string, unknown>): void {
    const entry = this.formatEntry('debug', message, context);
    this.debugLogger(JSON.stringify(entry));
  }

  /**
   * Log an informational message
   */
  info(message: string, context?: Record<string, unknown>): void {
    const entry = this.formatEntry('info', message, context);
    console.info(JSON.stringify(entry));
  }

  /**
   * Log a warning message
   */
  warn(message: string, context?: Record<string, unknown>): void {
    const entry = this.formatEntry('warn', message, context);
    console.warn(JSON.stringify(entry));
  }

  /**
   * Log an error message with optional Error object
   */
  error(message: string, error?: Error, context?: Record<string, unknown>): void {
    const errorContext = error
      ? {
          ...context,
          error: extractErrorInfo(error),
        }
      : context;

    const entry = this.formatEntry('error', message, errorContext);
    console.error(JSON.stringify(entry));
  }

  /**
   * Log a fatal error message (application cannot continue)
   */
  fatal(message: string, error?: Error, context?: Record<string, unknown>): void {
    const errorContext = error
      ? {
          ...context,
          error: extractErrorInfo(error),
        }
      : context;

    const entry = this.formatEntry('fatal', message, errorContext);
    console.error(JSON.stringify(entry));
  }

  /**
   * Create a new logger instance with a trace ID for request correlation
   */
  withTraceId(traceId: string): StructuredLogger {
    return new StructuredLogger({
      service: this.service,
      traceId,
      spanId: this.spanId,
    });
  }

  /**
   * Create a new logger instance with a span ID for operation tracking
   */
  withSpanId(spanId: string): StructuredLogger {
    return new StructuredLogger({
      service: this.service,
      traceId: this.traceId,
      spanId,
    });
  }

  /**
   * Create a child logger with additional context that will be included in all log entries
   *
   * @deprecated Use withTraceId or withSpanId instead for correlation
   */
  child(options: Partial<StructuredLoggerOptions>): StructuredLogger {
    return new StructuredLogger({
      service: options.service ?? this.service,
      traceId: options.traceId ?? this.traceId,
      spanId: options.spanId ?? this.spanId,
    });
  }
}

/**
 * Factory function to create a StructuredLogger instance
 *
 * @param service - The service name for log entries
 * @returns A new StructuredLogger instance
 *
 * @example
 * ```typescript
 * const logger = createLogger('messageHandler');
 * logger.info('Message received', { from: 'user123' });
 * ```
 */
export function createLogger(service: string): StructuredLogger {
  return new StructuredLogger({ service });
}

export default StructuredLogger;

import fs, { promises as fsPromises } from 'fs';
import path from 'path';
import readline from 'readline';
import Debug from 'debug';

const debug = Debug('app:auditLogger');

interface AuditEvent {
  id: string;
  timestamp: string;
  user: string;
  action: string;
  resource: string;
  result: 'success' | 'failure';
  details: string;
  ipAddress?: string;
  userAgent?: string;
  oldValue?: any;
  newValue?: any;
  metadata?: Record<string, any>;
}

export class AuditLogger {
  private static instance: AuditLogger;
  private logFilePath: string;
  private maxLogSize: number = 10 * 1024 * 1024; // 10MB
  private maxLogFiles = 5;
  private logQueue: string[] = [];
  private isProcessing: boolean = false;

  private constructor() {
    const configDir = process.env.NODE_CONFIG_DIR || path.join(__dirname, '../../config');
    this.logFilePath = path.join(configDir, 'audit.log');
    this.ensureLogDirectory();
  }

  public static getInstance(): AuditLogger {
    if (!AuditLogger.instance) {
      AuditLogger.instance = new AuditLogger();
    }
    return AuditLogger.instance;
  }

  private ensureLogDirectory(): void {
    const dir = path.dirname(this.logFilePath);
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true });
    }
  }

  private async rotateLogIfNeeded(): Promise<void> {
    try {
      // Check if file exists
      try {
        await fsPromises.access(this.logFilePath);
      } catch {
        return; // File does not exist
      }

      const stats = await fsPromises.stat(this.logFilePath);
      if (stats.size > this.maxLogSize) {
        // Rotate log files
        for (let i = this.maxLogFiles - 1; i >= 1; i--) {
          const oldFile = `${this.logFilePath}.${i}`;
          const newFile = `${this.logFilePath}.${i + 1}`;

          try {
            await fsPromises.access(oldFile);
            // File exists
            if (i === this.maxLogFiles - 1) {
              await fsPromises.unlink(oldFile); // Remove oldest
            } else {
              await fsPromises.rename(oldFile, newFile);
            }
          } catch {
            // File does not exist, skip
          }
        }
        // Move current log to .1
        await fsPromises.rename(this.logFilePath, `${this.logFilePath}.1`);
      }
    } catch (error) {
      debug('Failed to rotate audit log:', error);
    }
  }

  private async processQueue(): Promise<void> {
    if (this.isProcessing) return;
    this.isProcessing = true;

    try {
      while (this.logQueue.length > 0) {
        await this.rotateLogIfNeeded();

        // Process all currently queued items
        const batch = this.logQueue.splice(0, this.logQueue.length);
        if (batch.length === 0) break;

        const data = batch.join('');

        try {
          await fsPromises.appendFile(this.logFilePath, data);
        } catch (error) {
          debug('Failed to write to audit log:', error);
          console.error('AUDIT LOG WRITE ERROR:', error);
          // In case of write error, we lose these logs.
          // In a robust system we might retry or write to a fallback,
          // but for now we just log the error to stderr.
        }
      }
    } catch (error) {
      debug('Error in processQueue:', error);
    } finally {
      this.isProcessing = false;
      // Check if new items arrived while we were finishing
      if (this.logQueue.length > 0) {
        this.processQueue();
      }
    }
  }

  public async waitForQueueDrain(timeoutMs = 5000): Promise<void> {
    const start = Date.now();
    while (this.isProcessing || this.logQueue.length > 0) {
      if (Date.now() - start > timeoutMs) {
        debug('Timeout waiting for queue drain');
        break;
      }
      await new Promise((resolve) => setTimeout(resolve, 50));
    }
  }

  public log(event: Omit<AuditEvent, 'id' | 'timestamp'>): void {
    try {
      const auditEvent: AuditEvent = {
        id: this.generateId(),
        timestamp: new Date().toISOString(),
        ...event,
      };

      const logEntry = JSON.stringify(auditEvent) + '\n';
      this.logQueue.push(logEntry);

      debug('Audit event queued:', {
        id: auditEvent.id,
        action: auditEvent.action,
        user: auditEvent.user,
        result: auditEvent.result,
      });

      this.processQueue();
    } catch (error) {
      debug('Failed to queue audit event:', error);
      console.error('AUDIT LOG ERROR:', event, error);
    }
  }

  public logConfigChange(
    user: string,
    action: 'CREATE' | 'UPDATE' | 'DELETE' | 'RELOAD',
    resource: string,
    result: 'success' | 'failure',
    details: string,
    options: {
      ipAddress?: string;
      userAgent?: string;
      oldValue?: any;
      newValue?: any;
      metadata?: Record<string, any>;
    } = {}
  ): void {
    this.log({
      user,
      action: `CONFIG_${action}`,
      resource,
      result,
      details,
      ...options,
    });
  }

  public logBotAction(
    user: string,
    action: 'CREATE' | 'UPDATE' | 'DELETE' | 'START' | 'STOP' | 'CLONE',
    botName: string,
    result: 'success' | 'failure',
    details: string,
    options: {
      ipAddress?: string;
      userAgent?: string;
      oldValue?: any;
      newValue?: any;
      metadata?: Record<string, any>;
    } = {}
  ): void {
    this.log({
