      resource: `bots/${botName}`,
      result,
      details,
      ...options,
    });
  }

  public logAdminAction(
    user: string,
    action: string,
    resource: string,
    result: 'success' | 'failure',
    details: string,
    options: {
      ipAddress?: string;
      userAgent?: string;
      metadata?: Record<string, any>;
    } = {}
  ): void {
