import Debug from 'debug';

const logger = Debug('app:ErrorHandler');

/**
 * Centralized error handling utility for the Open Hivemind bot
 *
 * Provides consistent error logging, recovery strategies, and monitoring
 * across all bot operations and integrations.
 */
export class ErrorHandler {
  /**
   * Handle and log errors with context information
   *
   * @param error - The error that occurred
   * @param context - Context information about where the error occurred
   * @param severity - Error severity level (default: 'error')
   */
  static handle(
    error: Error | unknown,
    context: string,
    severity: 'error' | 'warn' | 'info' = 'error'
  ): void {
    const errorMessage = error instanceof Error ? error.message : String(error);
    const logMessage = `[${context}] ${errorMessage}`;

    switch (severity) {
      case 'warn':
        logger(logMessage);
        console.warn(logMessage);
        break;
      case 'info':
        logger(logMessage);
        console.info(logMessage);
        break;
      default:
        logger(logMessage);
        console.error(logMessage);
        break;
    }

    // Here you could add:
    // - Error reporting to external services
    // - Metrics collection
    // - Alert notifications
    // - Error recovery strategies
  }

  /**
   * Wrap async operations with error handling
   *
   * @param operation - The async operation to wrap
   * @param context - Context for error reporting
   * @param fallback - Optional fallback value to return on error
   * @returns Promise<T | null> - Result of operation or fallback
   */
  static async withErrorHandling<T>(
    operation: () => Promise<T>,
    context: string,
    fallback: T | null = null
  ): Promise<T | null> {
    try {
      return await operation();
    } catch (error) {
      this.handle(error, context);
      return fallback;
    }
  }

  /**
   * Create a safe wrapper for functions that might throw
   *
   * @param fn - Function to wrap
   * @param context - Context for error reporting
   * @returns Wrapped function that catches errors
   */
  static createSafeWrapper<T extends any[], R>(
    fn: (...args: T) => R | Promise<R>,
    context: string
  ): (...args: T) => Promise<R | null> {
    return async (...args: T): Promise<R | null> => {
      try {
        const result = fn(...args);
        if (result instanceof Promise) {
          return await result.catch((error) => {
            this.handle(error, context);
            return null;
          });
        }
        return result;
      } catch (error) {
        this.handle(error, context);
        return null;
      }
    };
  }
}

/**
 * Base error class for all Open-Hivemind errors.
 *
 * Provides structured error information with:
 * - Error codes for programmatic handling
 * - Categories for error classification
 * - Context data for debugging
 * - Cause chain for error wrapping
 * - JSON serialization for logging
 *
 * @example
 * ```typescript
 * throw new DatabaseNotInitializedError('Database not initialized', {
 *   attemptedOperation: 'getUser'
 * });
 * ```
 */

import { randomUUID } from 'crypto';

/**
 * Error categories for classification
 */
type ErrorCategory = 'database' | 'network' | 'validation' | 'configuration' | 'system';

/**
 * Context information for errors
 */
type ErrorContext = Record<string, unknown>;

/**
 * JSON representation of an error for logging
 */
interface ErrorJSON {
  name: string;
  code: string;
  category: ErrorCategory;
  message: string;
  context: ErrorContext;
  timestamp: string;
  traceId?: string;
  cause?: ErrorJSON;
  stack?: string;
}

/**
 * Abstract base class for all Open-Hivemind errors.
 *
 * Extend this class to create domain-specific errors with
 * consistent structure and serialization.
 */
abstract class HivemindError extends Error {
  /**
   * Unique error code for programmatic handling
   */
  abstract readonly code: string;

  /**
   * Category for error classification
   */
  abstract readonly category: ErrorCategory;

  /**
   * Additional context for debugging
   */
  readonly context: ErrorContext;

  /**
   * ISO timestamp when error was created
   */
  readonly timestamp: string;

  /**
   * Optional trace ID for request tracing
   */
  traceId?: string;

  /**
   * Original error that caused this error
   */
  cause?: Error;

  constructor(message: string, context: ErrorContext = {}, cause?: Error) {
    super(message);
    this.name = this.constructor.name;
    this.context = context;
    this.timestamp = new Date().toISOString();

    if (cause) {
      this.cause = cause;
    }

    // Maintain proper stack trace in V8 environments
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, this.constructor);
    }
  }

  /**
   * Set the trace ID for request tracing
   */
  withTraceId(traceId: string): this {
    this.traceId = traceId;
    return this;
  }

  /**
   * Convert error to JSON for logging
   */
  toJSON(): ErrorJSON {
    const json: ErrorJSON = {
      name: this.name,
      code: this.code,
      category: this.category,
      message: this.message,
      context: this.context,
      timestamp: this.timestamp,
    };

    if (this.traceId) {
      json.traceId = this.traceId;
    }

    if (this.cause instanceof HivemindError) {
      json.cause = this.cause.toJSON();
    } else if (this.cause) {
      json.cause = {
        name: this.cause.name,
        code: 'UNKNOWN',
        category: 'system',
        message: this.cause.message,
        context: {},
        timestamp: this.timestamp,
      };
    }

    if (process.env.NODE_ENV !== 'production') {
      json.stack = this.stack;
    }

    return json;
  }

  /**
   * Get a formatted string representation for logging
   */
  toString(): string {
    const parts = [`[${this.code}] ${this.message}`];

    if (this.traceId) {
      parts.push(`traceId=${this.traceId}`);
    }

    if (Object.keys(this.context).length > 0) {
      parts.push(`context=${JSON.stringify(this.context)}`);
    }

    return parts.join(' ');
  }
}

/**
 * Database-related errors
 */
abstract class DatabaseError extends HivemindError {
  readonly category: ErrorCategory = 'database';
}

/**
 * Thrown when database is not initialized before use
 */
class DatabaseNotInitializedError extends DatabaseError {
  readonly code = 'DB_NOT_INITIALIZED';

  constructor(message = 'Database not initialized', context: ErrorContext = {}) {
    super(message, context);
  }
}

/**
 * Thrown when a database connection fails
 */
class DatabaseConnectionError extends DatabaseError {
  readonly code = 'DB_CONNECTION_FAILED';

  constructor(
    message = 'Failed to connect to database',
    context: ErrorContext = {},
    cause?: Error
  ) {
    super(message, context, cause);
  }
}

/**
 * Thrown when a database query fails
 */
class DatabaseQueryError extends DatabaseError {
  readonly code = 'DB_QUERY_FAILED';

  constructor(message = 'Database query failed', context: ErrorContext = {}, cause?: Error) {
    super(message, context, cause);
  }
}

/**
 * Network-related errors
 */
abstract class NetworkError extends HivemindError {
  readonly category: ErrorCategory = 'network';
}

/**
 * Thrown when a bot is not found
 */
class BotNotFoundError extends NetworkError {
  readonly code = 'BOT_NOT_FOUND';
  readonly botName: string;

  constructor(botName: string, context: ErrorContext = {}) {
    super(`Bot '${botName}' not found`, { ...context, botName });
    this.botName = botName;
