import Debug from 'debug';
import { getRandomErrorMessage } from './getRandomErrorMessage';

const debug = Debug('app:handleError');

/**
 * Interface for message channel objects that can send messages
 */
interface MessageChannel {
  send(message: string): Promise<any> | any;
}

/**
 * Type guard to check if an object is an Error instance
 */
function isError(obj: any): obj is Error {
  return (
    obj instanceof Error || (obj && typeof obj === 'object' && typeof obj.message === 'string')
  );
}

/**
 * Type guard to check if an object has a valid send method
 */
function isValidMessageChannel(obj: any): obj is MessageChannel {
  return obj && typeof obj.send === 'function';
}

/**
 * Handles errors by logging them and optionally sending a random error message to a message channel.
 *
 * @param error - The error object to be handled.
 * @param messageChannel - The message channel to send the error message to.
 */
function handleError(error: unknown, messageChannel: any = null): void {
  // Validate error parameter
  if (!isError(error)) {
    debug('Invalid error parameter provided to handleError:', typeof error);
    // Create a fallback error for logging
    const fallbackError = new Error(`Invalid error type: ${typeof error}`);
    debug(`Error Message: ${fallbackError.message}`);
    debug(`Error Stack Trace: ${fallbackError.stack}`);

    if (isValidMessageChannel(messageChannel)) {
      const errorMsg = getRandomErrorMessage();
      try {
        messageChannel.send(errorMsg);
      } catch (sendError) {
        debug('Failed to send error message to channel:', sendError);
      }
    }
    return;
  }

  // Log the validated error
  debug(`Error Message: ${error.message || 'No message available'}`);
  debug(`Error Stack Trace: ${error.stack || 'No stack trace available'}`);

  // Send message to channel if valid
  if (isValidMessageChannel(messageChannel)) {
    const errorMsg = getRandomErrorMessage();
    try {
      messageChannel.send(errorMsg);
      debug('Error message sent to channel successfully');
    } catch (sendError) {
      debug('Failed to send error message to channel:', sendError);
    }
  } else if (messageChannel !== null) {
    debug('Invalid messageChannel provided - missing or invalid send method');
  }
}

import { redactSensitiveInfo } from './redactSensitiveInfo';

type LogLevel = 'trace' | 'debug' | 'info' | 'warn' | 'error';

const LOG_LEVEL_PRIORITY: Record<LogLevel, number> = {
  trace: 10,
  debug: 20,
  info: 30,
  warn: 40,
  error: 50,
};

const KEY_VALUE_REGEX =
  /\b([A-Za-z0-9_.-]*(?:password|token|secret|key)[A-Za-z0-9_.-]*)\b\s*[:=]\s*([^\s,"']+)/gi;
const BEARER_TOKEN_REGEX = /\bBearer\s+([A-Za-z0-9\-._~+/]+=*)/gi;
const GENERIC_TOKEN_REGEX = /\b(?:sk|pk|rk|ak)_[A-Za-z0-9]{8,}\b/gi;
const DEFAULT_LEVEL: LogLevel =
  (process.env.LOG_LEVEL && parseLogLevel(process.env.LOG_LEVEL)) ||
  (process.env.NODE_ENV === 'production' ? 'info' : 'debug');

let activeLevel: LogLevel = DEFAULT_LEVEL;

function parseLogLevel(level?: string | null): LogLevel | undefined {
  if (!level) {
    return undefined;
  }
  const normalized = level.toLowerCase();
  if (Object.prototype.hasOwnProperty.call(LOG_LEVEL_PRIORITY, normalized)) {
    return normalized as LogLevel;
  }
  return undefined;
}

function resolveLogLevel(level: string | LogLevel): LogLevel {
  if (typeof level === 'string') {
    const parsed = parseLogLevel(level);
    if (parsed) {
      return parsed;
    }
    logInternal('warn', `Invalid log level "${level}" provided, retaining "${activeLevel}".`);
    return activeLevel;
  }
  return level;
}

/**
 * Determines whether a log of straight level should be printed
 * based on the active log level priority.
 */
function shouldLog(level: LogLevel): boolean {
  return LOG_LEVEL_PRIORITY[level] >= LOG_LEVEL_PRIORITY[activeLevel];
}

function sanitizeLooseString(value: string): string {
  let sanitized = value.replace(KEY_VALUE_REGEX, (_, key: string) => `${key}=********`);
  sanitized = sanitized.replace(BEARER_TOKEN_REGEX, 'Bearer ********');
  sanitized = sanitized.replace(GENERIC_TOKEN_REGEX, '********');
  return sanitized;
}

function sanitizeError(error: Error, seen: WeakSet<object>): Record<string, unknown> {
  const base: Record<string, unknown> = {
    name: error.name,
    message: sanitizeLooseString(error.message ?? ''),
  };

  if (error.stack) {
    base.stack = sanitizeLooseString(error.stack);
  }

  const errorAsObject = error as unknown as Record<string, unknown>;
  for (const [key, value] of Object.entries(errorAsObject)) {
    if (key === 'name' || key === 'message' || key === 'stack') {
      continue;
    }
    base[key] = sanitizeValue(key, value, seen);
  }

  return base;
}

function sanitizeMap(map: Map<unknown, unknown>, seen: WeakSet<object>): Record<string, unknown> {
  const result: Record<string, unknown> = {};
  let index = 0;
  for (const [key, value] of map.entries()) {
    const mapKey = typeof key === 'string' ? key : `entry_${index}`;
    result[mapKey] = sanitizeValue(mapKey, value, seen);
    index += 1;
  }
  return result;
}

function sanitizeSet(set: Set<unknown>, seen: WeakSet<object>): unknown[] {
  const result: unknown[] = [];
  let index = 0;
  for (const value of set.values()) {
    result.push(sanitizeValue(`set[${index}]`, value, seen));
    index += 1;
  }
  return result;
}

function sanitizeValue(key: string | undefined, value: unknown, seen: WeakSet<object>): unknown {
  if (value === null || value === undefined) {
    return value;
  }

  if (typeof value === 'string') {
    return key ? redactSensitiveInfo(key, value) : sanitizeLooseString(value);
  }

  if (typeof value === 'number' || typeof value === 'boolean' || typeof value === 'bigint') {
    return value;
  }

  if (value instanceof Date) {
    return value.toISOString();
  }

  if (typeof Buffer !== 'undefined' && Buffer.isBuffer(value)) {
    return `<Buffer length=${value.length}>`;
  }

  if (value instanceof Error) {
    return sanitizeError(value, seen);
  }

  if (Array.isArray(value)) {
    return value.map((item, index) => sanitizeValue(`${key ?? 'item'}[${index}]`, item, seen));
  }

  if (value instanceof Map) {
    return sanitizeMap(value, seen);
  }

  if (value instanceof Set) {
    return sanitizeSet(value, seen);
  }

  if (typeof value === 'object') {
    const objectValue = value as Record<string, unknown>;
    if (seen.has(objectValue)) {
      return '[Circular]';
    }
    seen.add(objectValue);

    const sanitized: Record<string, unknown> = {};
    for (const [childKey, childValue] of Object.entries(objectValue)) {
      sanitized[childKey] = sanitizeValue(childKey, childValue, seen);
    }

    seen.delete(objectValue);
    return sanitized;
  }

  return value;
}

function sanitizeArgs(args: unknown[]): unknown[] {
  const seen = new WeakSet<object>();
  return args.map((arg) => sanitizeValue(undefined, arg, seen));
}

function getConsoleMethod(level: LogLevel): (...args: unknown[]) => void {
  switch (level) {
    case 'trace':
      return console.trace.bind(console);
    case 'debug':
      return (console.debug || console.log).bind(console);
    case 'info':
      return (console.info || console.log).bind(console);
    case 'warn':
      return (console.warn || console.log).bind(console);
    case 'error':
      return (console.error || console.log).bind(console);
    default:
      return console.log.bind(console);
  }
}

function logInternal(level: LogLevel, ...args: unknown[]): void {
  if (!shouldLog(level)) {
    return;
  }
  const consoleMethod = getConsoleMethod(level);
  consoleMethod(...sanitizeArgs(args));
}

export function sanitizeForLogging<T>(value: T, key?: string): unknown {
  return sanitizeValue(key, value, new WeakSet<object>());
}

interface LoggerInstance {
  trace: (...args: unknown[]) => void;
  debug: (...args: unknown[]) => void;
  info: (...args: unknown[]) => void;
  warn: (...args: unknown[]) => void;
  error: (...args: unknown[]) => void;
}

export type LoggerApi = LoggerInstance & {
  setLevel: (level: string | LogLevel) => void;
  getLevel: () => LogLevel;
  withContext: (context: string) => LoggerInstance;
};

export const Logger: LoggerApi = {
  trace: (...args: unknown[]) => logInternal('trace', ...args),
  debug: (...args: unknown[]) => logInternal('debug', ...args),
  info: (...args: unknown[]) => logInternal('info', ...args),
  warn: (...args: unknown[]) => logInternal('warn', ...args),
  error: (...args: unknown[]) => logInternal('error', ...args),
  setLevel: (level: string | LogLevel) => {
    activeLevel = resolveLogLevel(level);
  },
  getLevel: () => activeLevel,
  withContext: (context: string): LoggerInstance => {
    const prefix = `[${context}]`;
    return {
      trace: (...args: unknown[]) => logInternal('trace', prefix, ...args),
      debug: (...args: unknown[]) => logInternal('debug', prefix, ...args),
      info: (...args: unknown[]) => logInternal('info', prefix, ...args),
      warn: (...args: unknown[]) => logInternal('warn', prefix, ...args),
      error: (...args: unknown[]) => logInternal('error', prefix, ...args),
    };
  },
};

export default Logger;

import debug from 'debug';

const redactDebug = debug('app:redactSensitiveInfo');

/**
 * Redacts sensitive information from values based on key patterns
 * @param key - The key name to check for sensitivity
 * @param value - The value to potentially redact
 * @returns Original value if non-sensitive, redacted string '********' if sensitive
 * @example
 * // Returns '********'
 * redactSensitiveInfo('password', 'mySecret123')
 * @example
 * // Returns 'publicValue'
 * redactSensitiveInfo('username', 'admin')
 */
export function redactSensitiveInfo(key: string, value: any): string {
  const sensitivePatterns = [
    'password',
    'apikey',
    'api_key',
    'auth_token',
    'secret',
    'token',
    'key',
  ];
  try {
    const lowerKey = key.toLowerCase();
    const isSensitive = sensitivePatterns.some((pattern) => lowerKey.includes(pattern));

    if (!isSensitive) {
      return value === undefined || value === null ? '' : String(value);
    }

    const stringValue = value === undefined || value === null ? '' : String(value);
    if (stringValue.length === 0) {
      return '********';
    }

    if (stringValue.length <= 8) {
      const visible = stringValue.slice(-4);
      const redactionLength = Math.max(stringValue.length - visible.length, 4);
      return `${'*'.repeat(redactionLength)}${visible}`;
    }

    const start = stringValue.slice(0, 4);
    const end = stringValue.slice(-4);
    const middleLength = Math.max(stringValue.length - 8, 4);
    return `${start}${'*'.repeat(middleLength)}${end}`;
  } catch (error: unknown) {
    redactDebug(`Error processing value: ${(error as Error).message}`);
    return '********';
  }
}

import Debug from 'debug';

const debug = Debug('app:inputSanitizer');

/**
 * Configuration for sanitization options
 */
interface SanitizationOptions {
  maxLength?: number;
  allowHtml?: boolean;
  allowMarkdown?: boolean;
  stripScripts?: boolean;
  normalizeWhitespace?: boolean;
}

/**
 * Default sanitization options
 */
const DEFAULT_OPTIONS: SanitizationOptions = {
  maxLength: 10000,
  allowHtml: false,
  allowMarkdown: true,
  stripScripts: true,
  normalizeWhitespace: true,
};

/**
 * Input sanitizer utility class for preventing XSS and injection attacks
 */
export class InputSanitizer {
  /**
   * Sanitizes user-provided text content
   * @param input - The input string to sanitize
   * @param options - Sanitization options
   * @returns Sanitized string
   */
  public static sanitizeText(
    input: string | null | undefined,
    options: SanitizationOptions = {}
  ): string {
    if (!input || typeof input !== 'string') {
      debug('Invalid input provided to sanitizeText:', typeof input);
      return '';
    }

    const opts = { ...DEFAULT_OPTIONS, ...options };
    let sanitized = input;

    // Truncate if exceeds max length
    if (opts.maxLength && sanitized.length > opts.maxLength) {
      sanitized = sanitized.substring(0, opts.maxLength);
      debug(`Input truncated to ${opts.maxLength} characters`);
    }

    // Strip script tags and javascript: URLs
    if (opts.stripScripts) {
      sanitized = sanitized
        .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
        .replace(/javascript:/gi, '')
        .replace(/on\w+\s*=/gi, '') // Remove event handlers like onclick=
        .replace(/data:text\/html/gi, '') // Remove data URLs with HTML
        .replace(/vbscript:/gi, '');
    }

    // Remove HTML tags if not allowed, but preserve Slack mentions
    if (!opts.allowHtml) {
      sanitized = sanitized
        .replace(/<(?!@[UW][A-Z0-9]+>)[^>]*>/g, '') // Remove HTML tags except Slack mentions
        .replace(/&lt;(?!@[UW][A-Z0-9]+&gt;)[^&gt;]*&gt;/g, ''); // Remove encoded HTML tags except Slack mentions
    }

    // Normalize whitespace
    if (opts.normalizeWhitespace) {
      sanitized = sanitized
        .replace(/\s+/g, ' ') // Replace multiple whitespace with single space
        .trim();
    }

    // Escape remaining special characters for safety
    sanitized = sanitized
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#x27;');

    debug(`Sanitized input: ${input.substring(0, 50)}... -> ${sanitized.substring(0, 50)}...`);
    return sanitized;
  }

  /**
   * Sanitizes user names and display names
   * @param name - The name to sanitize
   * @returns Sanitized name
   */
  public static sanitizeName(name: string | null | undefined): string {
    if (!name || typeof name !== 'string') {
      return 'Unknown User';
    }

    return this.sanitizeText(name, {
      maxLength: 100,
      allowHtml: false,
      allowMarkdown: false,
      stripScripts: true,
      normalizeWhitespace: true,
    });
  }

  /**
   * Sanitizes email addresses
   * @param email - The email to sanitize
   * @returns Sanitized email or null if invalid
   */
  public static sanitizeEmail(email: string | null | undefined): string | null {
    if (!email || typeof email !== 'string') {
      return null;
    }

    // Basic email validation and sanitization
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    const sanitized = this.sanitizeText(email, {
      maxLength: 254, // RFC 5321 limit
      allowHtml: false,
      allowMarkdown: false,
      stripScripts: true,
      normalizeWhitespace: true,
    });

    return emailRegex.test(sanitized) ? sanitized : null;
  }

  /**
   * Sanitizes channel content that may contain user-generated data
   * @param content - The content to sanitize
   * @returns Sanitized content
   */
  public static sanitizeChannelContent(content: string | null | undefined): string {
    if (!content || typeof content !== 'string') {
      return '';
    }

    return this.sanitizeText(content, {
      maxLength: 50000, // Larger limit for channel content
      allowHtml: false,
      allowMarkdown: true, // Allow markdown for formatting
      stripScripts: true,
      normalizeWhitespace: false, // Preserve formatting in content
    });
  }

  /**
   * Sanitizes file names and attachment metadata
   * @param fileName - The file name to sanitize
   * @returns Sanitized file name
   */
  public static sanitizeFileName(fileName: string | null | undefined): string {
    if (!fileName || typeof fileName !== 'string') {
      return 'unknown_file';
    }

    // Remove path traversal attempts and dangerous characters
    let sanitized = fileName
      .replace(/\.\./g, '') // Remove path traversal
      .replace(/[\/\\:*?"<>|]/g, '_') // Replace dangerous file system characters
      .replace(/^[\s\.]+|[\s\.]+$/g, ''); // Remove leading/trailing spaces and dots

    sanitized = this.sanitizeText(sanitized, {
      maxLength: 255, // File system limit
      allowHtml: false,
      allowMarkdown: false,
      stripScripts: true,
      normalizeWhitespace: true,
    });

    return sanitized || 'sanitized_file';
  }

  /**
   * Validates and sanitizes user IDs
   * @param userId - The user ID to validate
   * @returns Sanitized user ID or 'unknown'
   */
  public static sanitizeUserId(userId: string | null | undefined): string {
    if (!userId || typeof userId !== 'string') {
      return 'unknown';
    }

    const sanitized = userId.trim();

    // Allow empty strings for backward compatibility
    if (sanitized === '') {
      return 'unknown';
    }

    // Slack user IDs should start with U or W and contain alphanumeric characters
    // More flexible pattern to accommodate test cases like U123ABC
    const userIdRegex = /^[UW][A-Z0-9]{3,}$/;

    if (!userIdRegex.test(sanitized)) {
      debug(`Invalid user ID format: ${sanitized}, returning 'unknown'`);
      return 'unknown';
    }

    return sanitized;
  }

  /**
   * Validates and sanitizes channel IDs
   * @param channelId - The channel ID to validate
   * @returns Sanitized channel ID or empty string if not provided
   */
  public static sanitizeChannelId(channelId: string | null | undefined): string {
    if (!channelId || typeof channelId !== 'string') {
      return '';
    }

    const sanitized = channelId.trim();

    // Allow empty strings for backward compatibility
    if (sanitized === '') {
      return '';
    }

    // Slack channel IDs should start with C, D, or G and be alphanumeric
    const channelIdRegex = /^[CDG][A-Z0-9]{8,}$/;

    if (!channelIdRegex.test(sanitized)) {
      debug(`Invalid channel ID format: ${sanitized}, returning empty string`);
      return '';
    }

    return sanitized;
  }
}

/**
 * Convenience function for sanitizing message text
 */
export function sanitizeMessageText(text: string | null | undefined): string {
  return InputSanitizer.sanitizeText(text, {
    maxLength: 4000, // Slack message limit
    allowHtml: false,
    allowMarkdown: true,
    stripScripts: true,
    normalizeWhitespace: false, // Preserve user formatting
  });
}

/**
 * Convenience function for sanitizing user input in interactive actions
 */
function sanitizeUserInput(input: string | null | undefined): string {
  return InputSanitizer.sanitizeText(input, {
    maxLength: 1000,
    allowHtml: false,
    allowMarkdown: false,
    stripScripts: true,
    normalizeWhitespace: true,
  });
}

/**
 * Builds a URL by joining a base URL with path parts.
 * Handles trailing and leading slashes appropriately.
 * Filters out empty or undefined parts.
 *
 * @param baseUrl - The base URL (e.g., 'https://example.com/api')
 * @param pathParts - Variable number of path parts
 * @returns The constructed URL
 */
export function buildUrl(baseUrl: string, ...pathParts: (string | undefined)[]): string {
  const parts = pathParts
    .filter((part): part is string => part != null && part.trim() !== '')
    .map((part) => part.replace(/^\/+|\/+$/g, ''));

  if (parts.length === 0) {
    return baseUrl.replace(/\/$/, '');
  }

  const base = baseUrl.replace(/\/$/, '');
  const path = parts.join('/');
  return `${base}/${path}`;
}

/**
 * Normalizes a URL by removing trailing slash unless it's the root URL.
 *
 * @param url - The URL to normalize
 * @returns Normalized URL
 */
export function normalizeUrl(url: string): string {
  const trimmed = url.trim();
  if (trimmed === '/') {
    return '/';
  }
  return trimmed.replace(/\/$/, '');
}

/**
 * Ensures a URL has a trailing slash.
 *
 * @param url - The URL
 * @returns URL with trailing slash
 */
export function ensureTrailingSlash(url: string): string {
  const normalized = normalizeUrl(url);
  return normalized === '/' ? '/' : `${normalized}/`;
}

/**
 * Removes trailing slash from URL.
 *
 * @param url - The URL
 * @returns URL without trailing slash
 */
export function removeTrailingSlash(url: string): string {
  return normalizeUrl(url);
}

/**
 * Validates if a given string is a valid URL.
 *
 * @param url - The string to validate
 * @returns True if the URL is valid, false otherwise
 */
export function isValidUrl(url: string): boolean {
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
}

