import { watch } from 'fs';
import { EventEmitter } from 'events';

export class ConfigWatcher extends EventEmitter {
  private watchers = new Map<string, any>();

  watchConfig(configPath: string) {
    if (this.watchers.has(configPath)) {return;}

    const watcher = watch(configPath, (eventType) => {
      if (eventType === 'change') {
        this.emit('configChanged', configPath);
      }
    });

    this.watchers.set(configPath, watcher);
  }

  stopWatching(configPath?: string) {
    if (configPath) {
      const watcher = this.watchers.get(configPath);
      if (watcher) {
        watcher.close();
        this.watchers.delete(configPath);
      }
    } else {
      this.watchers.forEach(watcher => watcher.close());
      this.watchers.clear();
    }
  }
}

export const configWatcher = new ConfigWatcher();

import 'reflect-metadata';
import { injectable, singleton } from 'tsyringe';
import convict from 'convict';
import Debug from 'debug';
import { isValidUrl } from '../common/urlUtils';
import { SecureConfigManager } from './SecureConfigManager';
import { ValidationError } from '../types/errorClasses';
import { type IConfigurationManager } from '../di/interfaces';
const debug = Debug('app:ConfigurationManager');

/**
 * Base convict schema for environment configuration
 * @typedef {Object} BaseSchema
 * @property {Object} NODE_ENV - Node environment configuration
 */
const schema = convict({
  NODE_ENV: {
    doc: 'The application environment.',
    format: ['production', 'development', 'test'],
    default: 'development',
    env: 'NODE_ENV',
  },
  VITE_API_BASE_URL: {
    doc: 'API base URL for Vite frontend',
    format: (val: any) => {
      if (typeof val !== 'string') {
        throw new ValidationError(
          'Value must be a string',
          'VITE_API_BASE_URL',
          val,
          'string',
          ['Must be a valid string'],
        );
      }
      if (!isValidUrl(val)) {
        throw new ValidationError(
          'Value must be a valid URL',
          'VITE_API_BASE_URL',
          val,
          'valid URL',
          ['Must be a properly formatted URL'],
        );
      }
    },
    default: 'http://localhost:3000/api',
    env: 'VITE_API_BASE_URL',
  },
  PLAYWRIGHT_BASE_URL: {
    doc: 'Base URL for Playwright E2E tests',
    format: (val: any) => {
      if (typeof val !== 'string') {
        throw new ValidationError(
          'Value must be a string',
          'PLAYWRIGHT_BASE_URL',
          val,
          'string',
          ['Must be a valid string'],
        );
      }
      if (!isValidUrl(val)) {
        throw new ValidationError(
          'Value must be a valid URL',
          'PLAYWRIGHT_BASE_URL',
          val,
          'valid URL',
          ['Must be a properly formatted URL'],
        );
      }
    },
    default: 'http://localhost:3000',
    env: 'PLAYWRIGHT_BASE_URL',
  },
});

/**
 * ConfigurationManager Class - Singleton configuration manager
 *
 * Now supports dependency injection via tsyringe while maintaining
 * backward compatibility with the singleton pattern.
 *
 * @class
 * @implements {IConfigurationManager}
 * @description Centralized configuration management system that handles:
 * - Environment configuration validation
 * - Runtime configuration storage
 * - Session ID management across integrations
 *
 * @example
 * // Using singleton pattern (backward compatible)
 * const configManager = ConfigurationManager.getInstance();
 * const envConfig = configManager.getConfig('environment');
 *
 * @example
 * // Using dependency injection (recommended for new code)
 * import { container, TOKENS } from '../di';
 * const configManager = container.resolve<IConfigurationManager>(TOKENS.ConfigurationManager);
 */
@singleton()
@injectable()
export class ConfigurationManager implements IConfigurationManager {
  private static instance: ConfigurationManager | null = null;
  private configs: Record<string, convict.Config<any>> = {};
  private sessionStore: Record<string, Record<string, string>> = {};

  /**
     * Constructor for ConfigurationManager
     * @throws {Error} If schema validation fails
     */
  constructor() {
    // Validate schema before loading files - use 'warn' to allow extra params from config files
    schema.validate({ allowed: 'warn' });

    const secureManager = SecureConfigManager.getInstance();
    const env = process.env.NODE_ENV || 'default';
    const fileConfig = secureManager.getDecryptedMainConfig(env);
    if (fileConfig) {
      schema.load(fileConfig);
      // Use 'warn' to allow extra config params that aren't in the minimal schema
      schema.validate({ allowed: 'warn' });
    }

    // Final validation with warnings for undeclared params
    schema.validate({ allowed: 'warn' });

    // Access all configuration values to trigger env var loading
    schema.getProperties();

    this.configs['environment'] = schema;
    debug('ConfigurationManager initialized in development environment');
  }

  /**
     * Gets the singleton instance (backward compatible)
     * @static
     * @returns {ConfigurationManager} The singleton instance
     * @deprecated Prefer using dependency injection via container.resolve()
     * @example
     * const configManager = ConfigurationManager.getInstance();
     */
  public static getInstance(): ConfigurationManager {
    if (!ConfigurationManager.instance) {
      ConfigurationManager.instance = new ConfigurationManager();
      debug('ConfigurationManager instance created');
    }
    return ConfigurationManager.instance!;
  }

  /**
     * Retrieves a configuration object by name
     * @param {string} configName - Name of the configuration to retrieve
     * @returns {convict.Config<any>|null} Requested configuration or null if not found
     * @throws {TypeError} If configName is not a string
     * @example
     * const dbConfig = configManager.getConfig('database');
     */
  public getConfig(configName: string): convict.Config<any> | null {
    if (typeof configName !== 'string') {
      throw new ValidationError(
        'configName must be a string',
        'configName',
        configName,
        'string',
        ['Must be a valid string'],
      );
    }
    const config = this.configs[configName];
    if (config) {
      debug(`Configuration '${configName}' retrieved successfully`);
    } else {
      debug(`Configuration '${configName}' not found`);
    }
    return config || null;
  }

  /**
     * Stores a unique session ID for an integration/channel combination
     * @param {string} integration - Integration name (e.g., 'slack', 'discord')
     * @param {string} channelId - Channel/conversation identifier
     * @param {string} sessionId - Session identifier to store
     * @returns {void}
     * @throws {TypeError} If any argument is missing or invalid
     * @example
     * configManager.setSession('slack', 'C123456', 'session_789');
     */
  public setSession(integration: string, channelId: string, sessionId: string) {
    if (typeof integration !== 'string') {
      throw new ValidationError(
        'integration must be a string',
        'integration',
        integration,
        'string',
        ['Must be a valid string'],
      );
    }
    if (typeof channelId !== 'string') {
      throw new ValidationError(
        'channelId must be a string',
        'channelId',
        channelId,
        'string',
        ['Must be a valid string'],
      );
    }
    if (typeof sessionId !== 'string') {
      throw new ValidationError(
        'sessionId must be a string',
        'sessionId',
        sessionId,
        'string',
        ['Must be a valid string'],
      );
    }
    if (!this.sessionStore[integration]) {
      this.sessionStore[integration] = {};
    }
    const uniqueSessionId = `${integration}-${channelId}-${sessionId}`;
    this.sessionStore[integration][channelId] = uniqueSessionId;
    debug(`Session set for integration ${integration}, channel ${channelId}, session ${uniqueSessionId}`);
  }

  /**
     * Retrieves a stored session ID
     * @param {string} integration - Integration name
     * @param {string} channelId - Channel/conversation identifier
     * @returns {string|undefined} Session ID if exists, undefined otherwise
     * @throws {TypeError} If arguments are invalid
     * @example
     * const session = configManager.getSession('slack', 'C123456');
     */
  public getSession(integration: string, channelId: string): string | undefined {
    return this.sessionStore[integration]?.[channelId];
  }

  /**
     * Retrieves all sessions for an integration
     * @param {string} integration - Integration name
     * @returns {Record<string, string>|undefined} All channel-session mappings or undefined
     * @throws {TypeError} If integration name is invalid
     * @example
     * const allSessions = configManager.getAllSessions('slack');
     */
  public getAllSessions(integration: string): Record<string, string> | undefined {
    return this.sessionStore[integration];
  }
}

import { BotConfigurationManager } from './BotConfigurationManager';
import { UserConfigStore } from './UserConfigStore';
import { WebSocketService } from '@src/server/services/WebSocketService';
import { ErrorUtils } from '@src/types/errors';
import type { BotOverride } from '@src/types/config';
import Debug from 'debug';
import fs from 'fs';
import path from 'path';

const debug = Debug('app:HotReloadManager');

export interface ConfigurationChange {
  id: string;
  timestamp: string;
  type: 'create' | 'update' | 'delete';
  botName?: string;
  changes: Record<string, any>;
  previousConfig?: Record<string, any>;
  userId?: string;
  validated: boolean;
  applied: boolean;
  rollbackAvailable: boolean;
}

export interface HotReloadResult {
  success: boolean;
  message: string;
  affectedBots: string[];
  warnings: string[];
  errors: string[];
  rollbackId?: string;
}

export class HotReloadManager {
  private static instance: HotReloadManager;
  private changeHistory: ConfigurationChange[] = [];
  private rollbackSnapshots = new Map<string, Record<string, any>>();
  private isReloading = false;
  private configWatchers = new Map<string, fs.FSWatcher>();
  private userConfigStore = UserConfigStore.getInstance();

  private constructor() {
    this.initializeFileWatchers();
  }

  public static getInstance(): HotReloadManager {
    if (!HotReloadManager.instance) {
      HotReloadManager.instance = new HotReloadManager();
    }
    return HotReloadManager.instance;
  }

  private initializeFileWatchers(): void {
    // Watch configuration files for changes
    const configPaths = [
      path.join(process.cwd(), 'config'),
      path.join(process.cwd(), 'config', 'user'),
    ];

    configPaths.forEach(configPath => {
      if (fs.existsSync(configPath)) {
        try {
          const watcher = fs.watch(configPath, { recursive: true }, (eventType, filename) => {
            if (filename && (filename.endsWith('.json') || filename.endsWith('.js'))) {
              debug(`Configuration file changed: ${filename}`);
              this.handleFileChange(eventType, filename);
            }
          });
          this.configWatchers.set(configPath, watcher);
        } catch (error: unknown) {
          const hivemindError = ErrorUtils.toHivemindError(error) as any;
          const errorInfo = ErrorUtils.classifyError(hivemindError);
          debug(`Failed to watch config path ${configPath}:`, {
            error: hivemindError.message,
            errorCode: (hivemindError as any).code,
            errorType: errorInfo.type,
            severity: errorInfo.severity,
            configPath,
          });
        }
      }
    });
  }

  private handleFileChange(eventType: string, filename: string): void {
    // Debounce file changes to avoid multiple reloads
    setTimeout(() => {
      this.detectConfigurationChanges();
    }, 1000);
  }

  private detectConfigurationChanges(): void {
    try {
      const manager = BotConfigurationManager.getInstance();
      const currentBots = manager.getAllBots();

      // Compare with previous state and detect changes
      // This is a simplified implementation - in production you'd want more sophisticated diffing

      debug('Configuration changes detected, triggering hot reload check');
      // For now, just log the detection - full auto-reload would be implemented here

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Error detecting configuration changes:', {
        error: hivemindError.message,
        errorCode: (hivemindError as any).code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
    }
  }

  public async applyConfigurationChange(
    change: Omit<ConfigurationChange, 'id' | 'timestamp' | 'validated' | 'applied' | 'rollbackAvailable'>,
  ): Promise<HotReloadResult> {
    if (this.isReloading) {
      return {
        success: false,
        message: 'Hot reload already in progress',
        affectedBots: [],
        warnings: [],
        errors: ['Another reload is in progress'],
      };
    }

    this.isReloading = true;

    try {
      const changeId = `change_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      const fullChange: ConfigurationChange = {
        ...change,
        id: changeId,
        timestamp: new Date().toISOString(),
        validated: false,
        applied: false,
        rollbackAvailable: false,
      };

      // Validate the change
      const validation = await this.validateChange(fullChange);
      if (!validation.valid) {
        return {
          success: false,
          message: 'Configuration change validation failed',
          affectedBots: validation.affectedBots,
          warnings: validation.warnings,
          errors: validation.errors,
        };
      }

      fullChange.validated = true;

      // Create rollback snapshot
      const rollbackId = await this.createRollbackSnapshot(fullChange);
      fullChange.rollbackAvailable = !!rollbackId;

      // Apply the change
      const result = await this.applyChange(fullChange);

      if (result.success) {
        fullChange.applied = true;
        this.changeHistory.push(fullChange);

        // Notify via WebSocket
        const wsService = WebSocketService.getInstance();
        wsService.recordAlert({
          level: 'info',
          title: 'Configuration Updated',
          message: 'Configuration change applied successfully',
          botName: change.botName,
          metadata: { changeId, affectedBots: result.affectedBots },
        });

        return {
          ...result,
          rollbackId: rollbackId || undefined,
        };
      } else {
        // Attempt rollback if application failed
        if (rollbackId) {
          await this.rollbackToSnapshot(rollbackId);
        }
        return result;
      }

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Error applying configuration change:', {
        error: hivemindError.message,
        errorCode: (hivemindError as any).code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      return {
        success: false,
        message: 'Unexpected error during configuration change',
        affectedBots: [],
        warnings: [],
        errors: [hivemindError.message],
      };
    } finally {
      this.isReloading = false;
    }
  }

  private async validateChange(change: ConfigurationChange): Promise<{
    valid: boolean;
    affectedBots: string[];
    warnings: string[];
    errors: string[];
  }> {
    const warnings: string[] = [];
    const errors: string[] = [];
    const affectedBots: string[] = [];

    try {
      const manager = BotConfigurationManager.getInstance();

      if (change.botName) {
        // Single bot change
        const bot = manager.getBot(change.botName);
        if (!bot) {
          errors.push(`Bot '${change.botName}' not found`);
          return { valid: false, affectedBots, warnings, errors };
        }
        affectedBots.push(change.botName);

        // Validate specific changes
        if (change.changes.messageProvider) {
          warnings.push('Changing message provider may require bot restart');
        }
        if (change.changes.llmProvider) {
          warnings.push('Changing LLM provider may affect response quality');
        }

      } else {
        // Global change affecting all bots
        const allBots = manager.getAllBots();
        affectedBots.push(...allBots.map(b => b.name));
        warnings.push('Global configuration change affects all bots');
      }

      // Additional validation logic would go here
      // - Check for invalid values
      // - Validate provider-specific configurations
      // - Check for circular dependencies
      // - Validate rate limits and quotas

      return {
        valid: errors.length === 0,
        affectedBots,
        warnings,
        errors,
      };

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Validation error:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      errors.push(`Validation error: ${hivemindError.message}`);
      return { valid: false, affectedBots, warnings, errors };
    }
  }

  private async createRollbackSnapshot(change: ConfigurationChange): Promise<string | null> {
    try {
      const manager = BotConfigurationManager.getInstance();
      const snapshotId = `rollback_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;

      if (change.botName) {
        // Single bot snapshot
        const bot = manager.getBot(change.botName);
        if (bot) {
          this.rollbackSnapshots.set(snapshotId, { [change.botName]: { ...bot } });
        }
      } else {
        // Full system snapshot
        const allBots = manager.getAllBots();
        const snapshot: Record<string, any> = {};
        allBots.forEach(bot => {
          snapshot[bot.name] = { ...bot };
        });
        this.rollbackSnapshots.set(snapshotId, snapshot);
      }

      return snapshotId;
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Error creating rollback snapshot:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      return null;
    }
  }

  private async applyChange(change: ConfigurationChange): Promise<HotReloadResult> {
    try {
      const manager = BotConfigurationManager.getInstance();
      const affectedBots: string[] = [];
      const warnings: string[] = [];
      const errors: string[] = [];

      if (change.botName) {
        // Apply change to specific bot
        const success = await this.applyBotChange(change.botName, change.changes);
        if (success) {
          affectedBots.push(change.botName);
        } else {
          errors.push(`Failed to apply changes to bot '${change.botName}'`);
        }
      } else {
        // Apply global changes
        const allBots = manager.getAllBots();
        const results = await Promise.all(
          allBots.map(bot =>
            this.applyBotChange(bot.name, change.changes).then(success => ({
              botName: bot.name,
              success,
            }))
          )
        );

        for (const result of results) {
          if (result.success) {
            affectedBots.push(result.botName);
          } else {
            warnings.push(`Failed to apply changes to bot '${result.botName}'`);
          }
        }
      }

      return {
        success: errors.length === 0,
        message: errors.length === 0 ? 'Configuration changes applied successfully' : 'Some changes failed to apply',
        affectedBots,
        warnings,
        errors,
      };

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Error applying configuration changes:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      return {
        success: false,
        message: 'Failed to apply configuration changes',
        affectedBots: [],
        warnings: [],
        errors: [hivemindError.message],
      };
    }
  }

  private async applyBotChange(botName: string, changes: Record<string, any>): Promise<boolean> {
    try {
      debug(`Applying changes to bot '${botName}':`, changes);

      const allowedFields: (keyof BotOverride)[] = [
        'messageProvider',
        'llmProvider',
        'llmProfile',
        'responseProfile',
        'mcpGuardProfile',
        'persona',
        'systemInstruction',
        'mcpServers',
        'mcpGuard',
      ];

      const sanitizedChanges: Partial<BotOverride> = {};

      for (const [key, value] of Object.entries(changes)) {
        if (!allowedFields.includes(key as keyof BotOverride)) {
          continue;
        }

        if (key === 'mcpGuard' && value) {
          const guard = value as BotOverride['mcpGuard'];
          sanitizedChanges.mcpGuard = {
            enabled: Boolean(guard?.enabled),
            type: guard?.type === 'custom' ? 'custom' : 'owner',
            allowedUsers: Array.isArray(guard?.allowedUsers)
              ? guard?.allowedUsers.filter(Boolean)
              : typeof guard?.allowedUsers === 'string'
                ? (guard?.allowedUsers as string).split(',').map((id: string) => id.trim()).filter(Boolean)
                : undefined,
          };
          continue;
        }

        (sanitizedChanges as any)[key] = value;
      }

      if (Object.keys(sanitizedChanges).length > 0) {
        this.userConfigStore.setBotOverride(botName, sanitizedChanges);

        // Reload configuration so changes take effect immediately
        const manager = BotConfigurationManager.getInstance();
        manager.reload();
      }

      return true;
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug(`Error applying changes to bot '${botName}':`, {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
        botName,
      });
      return false;
    }
  }

  public async rollbackToSnapshot(snapshotId: string): Promise<boolean> {
    try {
      const snapshot = this.rollbackSnapshots.get(snapshotId);
      if (!snapshot) {
        debug(`Rollback snapshot '${snapshotId}' not found`);
        return false;
      }

      // Restore the snapshot concurrently and surface any partial failures
      const snapshotEntries = Object.entries(snapshot);
      const restoreResults = await Promise.all(
        snapshotEntries.map(([botName, botConfig]) =>
          this.applyBotChange(botName, botConfig as Record<string, any>)
        )
      );

      const failedBots = snapshotEntries
        .filter((_, i) => !restoreResults[i])
        .map(([botName]) => botName);

      if (failedBots.length > 0) {
        debug(`Rollback partially failed; could not restore bots: ${failedBots.join(', ')}`);
      }

      // Remove the snapshot after rollback attempt
      this.rollbackSnapshots.delete(snapshotId);

      debug(`Rolled back to snapshot '${snapshotId}'${failedBots.length > 0 ? ' (partial)' : ' (complete)'}`);
      return true;
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Error during rollback:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
        snapshotId,
      });
      return false;
    }
  }

  public getChangeHistory(limit = 50): ConfigurationChange[] {
    return this.changeHistory.slice(-limit);
  }

  public getAvailableRollbacks(): string[] {
    return Array.from(this.rollbackSnapshots.keys());
  }

  public shutdown(): void {
    // Clean up file watchers
    this.configWatchers.forEach((watcher, path) => {
      try {
        watcher.close();
        debug(`Closed file watcher for ${path}`);
      } catch (error: unknown) {
        const hivemindError = ErrorUtils.toHivemindError(error) as any;
        const errorInfo = ErrorUtils.classifyError(hivemindError);
        debug(`Error closing file watcher for ${path}:`, {
          error: hivemindError.message,
          errorCode: hivemindError.code,
          errorType: errorInfo.type,
          severity: errorInfo.severity,
          path,
        });
      }
    });
    this.configWatchers.clear();

    debug('HotReloadManager shut down');
  }
}

import Debug from 'debug';
import { EventEmitter } from 'events';
import type { ChildProcess } from 'child_process';
import { spawn } from 'child_process';
import { v4 as uuidv4 } from 'uuid';
import { ErrorUtils } from '@src/types/errors';
import type {
  MCPProviderConfig,
  MCPProviderStatus,
  MCPProviderTestResult,
  MCPProviderTemplate,
  MCPProviderValidationResult,
  MCPProviderManager as IMCPProviderManager,
  MCPProviderStats,
} from '../types/mcp';



const debug = Debug('app:MCPProviderManager');

/**
 * MCP Provider Manager
 *
 * Manages lifecycle, configuration, and testing of MCP (Model Context Protocol)
 * servers that provide external tool capabilities to bots.
 */
export class MCPProviderManager extends EventEmitter implements IMCPProviderManager {
  private providers = new Map<string, MCPProviderConfig>();
  private processes = new Map<string, ChildProcess>();
  private statuses = new Map<string, MCPProviderStatus>();
  private healthCheckIntervals = new Map<string, NodeJS.Timeout>();

  constructor() {
    super();
    debug('MCP Provider Manager initialized');
  }

  // Core provider management
  async addProvider(config: MCPProviderConfig): Promise<void> {
    debug(`Adding MCP provider: ${config.name}`);

    const validation = this.validateProviderConfig(config);
    if (!validation.isValid) {
      throw ErrorUtils.createError(
        `Invalid MCP provider configuration: ${validation.errors.join(', ')}`,
        'validation',
        'MCP_PROVIDER_CONFIG_INVALID',
        undefined,
        { validationErrors: validation.errors },
      );
    }

    // Ensure unique ID
    const providerId = config.id || uuidv4();
    const provider = { ...config, id: providerId };

    this.providers.set(providerId, provider);

    // Initialize status
    this.statuses.set(providerId, {
      id: providerId,
      status: 'stopped',
      lastCheck: new Date(),
    });

    this.emit('provider_added', { type: 'provider_added', providerId, timestamp: new Date() });
    debug(`MCP provider added: ${provider.name} (${providerId})`);
  }

  async removeProvider(id: string): Promise<void> {
    debug(`Removing MCP provider: ${id}`);

    const provider = this.providers.get(id);
    if (!provider) {
      throw new Error(`MCP provider not found: ${id}`);
    }

    // Stop provider if running
    if (this.processes.has(id)) {
      await this.stopProvider(id);
    }

    this.providers.delete(id);
    this.statuses.delete(id);

    this.emit('provider_removed', { type: 'provider_removed', providerId: id, timestamp: new Date() });
    debug(`MCP provider removed: ${provider.name} (${id})`);
  }

  async updateProvider(id: string, config: Partial<MCPProviderConfig>): Promise<void> {
    debug(`Updating MCP provider: ${id}`);

    const existingProvider = this.providers.get(id);
    if (!existingProvider) {
      throw new Error(`MCP provider not found: ${id}`);
    }

    const validation = this.validateProviderConfig({ ...existingProvider, ...config });
    if (!validation.isValid) {
      throw ErrorUtils.createError(
        `Invalid MCP provider configuration: ${validation.errors.join(', ')}`,
        'validation',
        'MCP_PROVIDER_CONFIG_INVALID',
        undefined,
        { validationErrors: validation.errors, providerId: id },
      );
    }

    const updatedProvider = { ...existingProvider, ...config };
    this.providers.set(id, updatedProvider);

    this.emit('provider_updated', {
      type: 'provider_updated',
      providerId: id,
      timestamp: new Date(),
      data: { oldProvider: existingProvider, newProvider: updatedProvider },
    });
    debug(`MCP provider updated: ${updatedProvider.name} (${id})`);
  }

  getProvider(id: string): MCPProviderConfig | null {
    return this.providers.get(id) || null;
  }

  getAllProviders(): MCPProviderConfig[] {
    return Array.from(this.providers.values());
  }

  // Status and testing
  getProviderStatus(id: string): MCPProviderStatus | null {
    return this.statuses.get(id) || null;
  }

  getAllProviderStatuses(): Record<string, MCPProviderStatus> {
    const result: Record<string, MCPProviderStatus> = {};
    this.statuses.forEach((status, id) => {
      result[id] = status;
    });
    return result;
  }

  async testProvider(id: string): Promise<MCPProviderTestResult> {
    debug(`Testing MCP provider: ${id}`);

    const provider = this.providers.get(id);
    if (!provider) {
      throw ErrorUtils.createError(
        `MCP provider not found: ${id}`,
        'configuration',
        'MCP_PROVIDER_NOT_FOUND',
        undefined,
        { providerId: id },
      );
    }

    const startTime = new Date();

    try {
      const result = await this.executeProviderTest(provider);
      const endTime = new Date();

      const testResult: MCPProviderTestResult = {
        success: result.success,
        startTime,
        endTime,
        duration: endTime.getTime() - startTime.getTime(),
        error: result.error,
        output: result.output,
        version: result.version,
        capabilities: result.capabilities,
      };

      this.emit('provider_test_completed', {
        type: 'provider_test_completed',
        providerId: id,
        timestamp: new Date(),
        data: testResult,
      });

      debug(`MCP provider test completed: ${provider.name} (${id}) - ${testResult.success ? 'SUCCESS' : 'FAILED'}`);
      return testResult;

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      const endTime = new Date();
      const testResult: MCPProviderTestResult = {
        success: false,
        startTime,
        endTime,
        duration: endTime.getTime() - startTime.getTime(),
        error: hivemindError.message,
      };

      debug(`MCP provider test failed: ${provider.name} (${id}) -`, {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
        providerId: id,
      });
      return testResult;
    }
  }

  // Lifecycle management
  async startProvider(id: string): Promise<void> {
    debug(`Starting MCP provider: ${id}`);

    const provider = this.providers.get(id);
    if (!provider) {
      throw ErrorUtils.createError(
        `MCP provider not found: ${id}`,
        'configuration',
        'MCP_PROVIDER_NOT_FOUND',
        undefined,
        { providerId: id },
      );
    }

    if (this.processes.has(id)) {
      debug(`MCP provider already running: ${provider.name} (${id})`);
      return;
    }

    try {
      const process = await this.startProviderProcess(provider);
      this.processes.set(id, process);

      // Update status
      this.statuses.set(id, {
        id,
        status: 'running',
        lastCheck: new Date(),
        uptime: 0,
        processId: process.pid,
      });

      // Start health check if enabled
      if (provider.healthCheck?.enabled) {
        this.startHealthCheck(id);
      }

      this.emit('provider_started', { type: 'provider_started', providerId: id, timestamp: new Date() });
      debug(`MCP provider started: ${provider.name} (${id})`);

    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      this.statuses.set(id, {
        id,
        status: 'error',
        lastCheck: new Date(),
        error: hivemindError.message,
      });

      debug(`Failed to start MCP provider: ${provider.name} (${id}) -`, {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
        providerId: id,
      });

      this.emit('provider_error', {
        type: 'provider_error',
        providerId: id,
        timestamp: new Date(),
        data: { error: hivemindError },
      });

      throw hivemindError;
    }
  }

  async stopProvider(id: string): Promise<void> {
    debug(`Stopping MCP provider: ${id}`);

    const provider = this.providers.get(id);
    if (!provider) {
      throw ErrorUtils.createError(
        `MCP provider not found: ${id}`,
        'configuration',
        'MCP_PROVIDER_NOT_FOUND',
        undefined,
        { providerId: id },
      );
    }

    const process = this.processes.get(id);
    if (!process) {
      debug(`MCP provider not running: ${provider.name} (${id})`);
      return;
    }

    // Stop health check
    this.stopHealthCheck(id);

    // Kill process
    process.kill('SIGTERM');

    // Wait a bit for graceful shutdown
    await new Promise(resolve => setTimeout(resolve, 2000));

    if (process && !process.killed) {
      process.kill('SIGKILL');
    }

    this.processes.delete(id);
    this.statuses.set(id, {
      id,
      status: 'stopped',
      lastCheck: new Date(),
    });

    this.emit('provider_stopped', { type: 'provider_stopped', providerId: id, timestamp: new Date() });
    debug(`MCP provider stopped: ${provider.name} (${id})`);
  }

  async restartProvider(id: string): Promise<void> {
    debug(`Restarting MCP provider: ${id}`);
    await this.stopProvider(id);
    await new Promise(resolve => setTimeout(resolve, 1000));
    await this.startProvider(id);
  }

  // Configuration
  validateProviderConfig(config: Partial<MCPProviderConfig>): MCPProviderValidationResult {
    const errors: string[] = [];
    const warnings: string[] = [];
    const suggestions: string[] = [];

    // Required fields
    if (!config.name || (config.name as string).trim().length < 2) {
      errors.push('Provider name is required and must be at least 2 characters');
    }

    if (!config.command || (config.command as string).trim().length === 0) {
      errors.push('Command is required');
    }

    if (!config.type || !['desktop', 'cloud'].includes(config.type)) {
      errors.push('Provider type must be either "desktop" or "cloud"');
    }

    // Command validation
    if (config.command) {
      const command = (config.command as string).trim();

      // Security validation: Block dangerous shell commands
      const blockedCommands = [
        'sh', 'bash', 'zsh', 'dash', 'csh', 'ksh', 'tcsh',
        'cmd', 'cmd.exe', 'powershell', 'powershell.exe', 'pwsh',
      ];

      const isBlocked = blockedCommands.some(blocked => {
        const lowerCommand = command.toLowerCase();
        // Check exact match
        if (lowerCommand === blocked) return true;
        // Check if it ends with the blocked command (e.g. /bin/sh)
        // using forward slash or backslash as separator
        // blocked commands are lowercase in the list
        const pattern = new RegExp(`[\\/\\\\]${blocked}$`);
        return pattern.test(lowerCommand);
      });

      if (isBlocked) {
        errors.push('Command is not allowed for security reasons');
      }

      const validCommandPatterns = [
        /^[a-zA-Z0-9\-_]+$/,
        /^\.\/[a-zA-Z0-9\-_\/.]+$/,
        /^\/[a-zA-Z0-9\-_\/.]+$/,
        /^[a-zA-Z]:\\[a-zA-Z0-9\-_\/.\\]+$/,
        /^npx [a-zA-Z0-9\-@/.]+$/,
        /^npm run [a-zA-Z0-9\-_]+$/,
      ];

      const isValidCommand = validCommandPatterns.some(pattern => pattern.test(command));
      if (!isValidCommand) {
        errors.push('Invalid command format');
      }
    }

    // Args validation
    if (config.args && typeof config.args === 'string') {
      try {
        // Try to parse as JSON array
        JSON.parse(config.args);
      } catch {
        // If not valid JSON, it's treated as space-separated
        if ((config.args as string).trim().length === 0) {
          warnings.push('Arguments field is empty');
        }
      }
    }

    // Cloud provider warnings
    if (config.type === 'cloud') {
      const envVars = config.env || {};
      const hasConnectionConfig = Object.keys(envVars).some(key =>
        key.toLowerCase().includes('url') ||
        key.toLowerCase().includes('endpoint') ||
        key.toLowerCase().includes('key') ||
        key.toLowerCase().includes('token'),
      );

      if (!hasConnectionConfig) {
        warnings.push('Cloud providers typically require connection configuration (URLs, API keys, etc.)');
      }
    }

    // Timeout validation
    if (config.timeout !== undefined) {
      if (typeof config.timeout !== 'number' || config.timeout < 5 || config.timeout > 300) {
        errors.push('Timeout must be a number between 5 and 300 seconds');
      }
    }

    // Suggestions
    if (config.type === 'desktop') {
      const hasArgs = Array.isArray(config.args)
        ? config.args.length > 0
        : !!config.args && (config.args as string).trim().length > 0;

      if (!hasArgs) {
        suggestions.push('Consider adding arguments like "--port 3000" for local MCP servers');
      }
    }

    if (!config.healthCheck?.enabled) {
      suggestions.push('Consider enabling health checks for better reliability');
    }

    return {
      isValid: errors.length === 0,
      errors,
      warnings,
      suggestions,
    };
  }

  exportProviders(): string {
    const providers = Array.from(this.providers.values());
    return JSON.stringify(providers, null, 2);
  }

  async importProviders(data: string): Promise<void> {
    try {
      const providers = JSON.parse(data);
      if (!Array.isArray(providers)) {
        throw new Error('Import data must be an array of providers');
      }

      for (const provider of providers) {
        await this.addProvider(provider);
      }

      debug(`Imported ${providers.length} MCP providers`);
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Failed to import MCP providers:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      throw ErrorUtils.createError(
        `Failed to import MCP providers: ${hivemindError.message}`,
        'configuration',
        'MCP_PROVIDERS_IMPORT_FAILED',
        undefined,
        { originalError: hivemindError },
      );
    }
  }

