  createFromTemplate(templateId: string, overrides: Partial<MCPProviderConfig>): MCPProviderConfig {
    const template = this.getTemplates().find(t => t.id === templateId);
    if (!template) {
      throw ErrorUtils.createError(
        `Template not found: ${templateId}`,
        'configuration',
        'MCP_TEMPLATE_NOT_FOUND',
        undefined,
        { templateId },
      );
    }

    const envVars: Record<string, string> = {};
    template.envVars.forEach(envVar => {
      envVars[envVar.name] = envVar.defaultValue || '';
    });

    const baseConfig: MCPProviderConfig = {
      id: uuidv4(),
      name: template.name,
      type: template.type,
      description: template.description,
      command: template.command,
      args: template.args,
      env: envVars,
      enabled: template.enabledByDefault,
      timeout: 30,
      autoRestart: true,
      healthCheck: {
        enabled: true,
        interval: 60,
        timeout: 10,
        retries: 3,
      },
    };

    return { ...baseConfig, ...overrides };
  }

  // Statistics
  getStats(): MCPProviderStats {
    const statuses = Array.from(this.statuses.values());
    const runningProviders = statuses.filter(s => s.status === 'running').length;
    const stoppedProviders = statuses.filter(s => s.status === 'stopped').length;
    const errorProviders = statuses.filter(s => s.status === 'error').length;

    return {
      totalProviders: this.providers.size,
      runningProviders,
      stoppedProviders,
      errorProviders,
      averageUptime: this.calculateAverageUptime(),
      totalMemoryUsage: this.calculateTotalMemoryUsage(),
      lastUpdated: new Date(),
    };
  }

  // Private methods
  private async executeProviderTest(provider: MCPProviderConfig): Promise<{
    success: boolean;
    error?: string;
    output?: string;
    version?: string;
    capabilities?: string[];
  }> {
    return new Promise((resolve) => {
      const timeout = provider.timeout || 30;
      const args = this.parseArgs(provider.args || '');

      const mcpProcess = spawn(provider.command, args, {
        env: { ...process.env, ...provider.env },
        stdio: ['pipe', 'pipe', 'pipe'],
        timeout: timeout * 1000,
      });

      let output = '';
      let errorOutput = '';

      mcpProcess.stdout?.on('data', (data: any) => {
        output += data.toString();
      });

      mcpProcess.stderr?.on('data', (data: any) => {
        errorOutput += data.toString();
      });

      mcpProcess.on('close', (code: any) => {
        if (code === 0) {
          // Try to extract version and capabilities from output
          const version = this.extractVersion(output);
          const capabilities = this.extractCapabilities(output);

          resolve({
            success: true,
            output: output.trim(),
            version,
            capabilities,
          });
        } else {
          resolve({
            success: false,
            error: `Process exited with code ${code}${errorOutput ? ': ' + errorOutput.trim() : ''}`,
          });
        }
      });

      mcpProcess.on('configuration', (error: any) => {
        resolve({
          success: false,
          error: error.message,
        });
      });

      // Kill process after timeout
      setTimeout(() => {
        if (mcpProcess && !mcpProcess.killed) {
          mcpProcess.kill();
          resolve({
            success: false,
            error: `Process timed out after ${timeout} seconds`,
          });
        }
      }, timeout * 1000);
    });
  }

  private async startProviderProcess(provider: MCPProviderConfig): Promise<ChildProcess> {
    const args = this.parseArgs(provider.args || '');

    const providerProcess = spawn(provider.command, args, {
      env: { ...process.env, ...provider.env },
      stdio: ['pipe', 'pipe', 'pipe'],
      detached: false,
    });

    return new Promise((resolve, reject) => {
      const timeout = provider.timeout || 30;

      providerProcess.on('spawn', () => {
        resolve(providerProcess);
      });

      providerProcess.on('configuration', (error: any) => {
        reject(error);
      });

      providerProcess.on('close', (code: any) => {
        if (code !== 0) {
          reject(new Error(`MCP process exited with code ${code}`));
        }
      });

      // Timeout handling
      setTimeout(() => {
        if (providerProcess && !providerProcess.killed) {
          providerProcess.kill();
          reject(new Error(`MCP process failed to start within ${timeout} seconds`));
        }
      }, timeout * 1000);
    });
  }

  private parseArgs(args: string | string[]): string[] {
    if (Array.isArray(args)) {
      return args;
    }

    if (!args || (args as string).trim().length === 0) {
      return [];
    }

    try {
      // Try to parse as JSON
      return JSON.parse(args);
    } catch {
      // Parse as space-separated arguments
      return (args as string).trim().split(/\s+/);
    }
  }

  private extractVersion(output: string): string | undefined {
    // Look for version patterns in output
    const versionPatterns = [
      /version[:\s]+(\d+\.\d+\.\d+)/i,
      /v(\d+\.\d+\.\d+)/,
      /(\d+\.\d+\.\d+)/,
    ];

    for (const pattern of versionPatterns) {
      const match = output.match(pattern);
      if (match) {
        return match[1];
      }
    }

    return undefined;
  }

  private extractCapabilities(output: string): string[] {
    // Look for capability patterns in MCP output
    const capabilities: string[] = [];

    // Common MCP capability indicators
    const capabilityPatterns = [
      /tools?:\s*([^\n]+)/i,
      /resources?:\s*([^\n]+)/i,
      /prompts?:\s*([^\n]+)/i,
    ];

    for (const pattern of capabilityPatterns) {
      const match = output.match(pattern);
      if (match) {
        capabilities.push(match[1].trim());
      }
    }

    return capabilities;
  }

  private startHealthCheck(providerId: string): void {
    const provider = this.providers.get(providerId);
    if (!provider?.healthCheck?.enabled) {
      return;
    }

    const interval = provider.healthCheck.interval * 1000; // Convert to milliseconds

    const healthInterval = setInterval(() => {
      this.performHealthCheck(providerId);
    }, interval);

    this.healthCheckIntervals.set(providerId, healthInterval);
  }

  private stopHealthCheck(providerId: string): void {
    const interval = this.healthCheckIntervals.get(providerId);
    if (interval) {
      clearInterval(interval);
      this.healthCheckIntervals.delete(providerId);
    }
  }

  private async performHealthCheck(providerId: string): Promise<void> {
    const process = this.processes.get(providerId);
    const status = this.statuses.get(providerId);
    const provider = this.providers.get(providerId);

    if (!process || !status || !provider) {
      return;
    }

    try {
      // Check if process is still running
      if (process.killed) {
        status.status = 'error';
        status.error = 'Process was killed';

        this.emit('provider_error', {
          type: 'provider_error',
          providerId,
          timestamp: new Date(),
          data: { error: 'Process was killed' },
        });

        // Auto-restart if enabled
        if (provider.autoRestart) {
          debug(`Auto-restarting MCP provider: ${provider.name} (${providerId})`);
          await this.restartProvider(providerId);
        }
      } else {
        // Update uptime
        if (status.uptime !== undefined && provider.healthCheck?.interval) {
          status.uptime += provider.healthCheck.interval;
        }
        status.lastCheck = new Date();
        status.error = undefined;
      }
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug(`Health check failed for MCP provider ${providerId}:`, {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
        providerId,
      });
      status.status = 'error';
      status.error = hivemindError.message;
    }
  }

  private calculateAverageUptime(): number {
    const runningStatuses = Array.from(this.statuses.values())
      .filter(s => s.status === 'running' && s.uptime !== undefined);

    if (runningStatuses.length === 0) {
      return 0;
    }

    const totalUptime = runningStatuses.reduce((sum, status) => sum + (status.uptime || 0), 0);
    return totalUptime / runningStatuses.length;
  }

  private calculateTotalMemoryUsage(): number {
    // This would require actual memory monitoring implementation
    // For now, return 0 as a placeholder
    return 0;
  }
}

// Export singleton instance
export default new MCPProviderManager();

import * as fs from 'fs';
import * as path from 'path';
import Debug from 'debug';
import { v4 as uuidv4 } from 'uuid';

const debug = Debug('app:providerConfigManager');

export interface ProviderInstance {
  id: string;
  type: string; // 'discord', 'slack', 'openai', etc.
  category: 'message' | 'llm';
  name: string;
  enabled: boolean;
  config: Record<string, any>; // Provider-specific config (token, model, etc.)
}

export interface ProviderStore {
  message: ProviderInstance[];
  llm: ProviderInstance[];
}

class ProviderConfigManager {
  private static instance: ProviderConfigManager;
  private configPath: string;
  private store: ProviderStore = { message: [], llm: [] };
  private initialized = false;

  private constructor() {
    const configDir = process.env.NODE_CONFIG_DIR || path.join(__dirname, '../../config');
    // Ensure providers directory exists
    const providersDir = path.join(configDir, 'providers');
    if (!fs.existsSync(providersDir)) {
      fs.mkdirSync(providersDir, { recursive: true });
    }
    this.configPath = path.join(providersDir, 'instances.json');
    this.loadConfig();

    // Migration: If empty, try to populate from legacy sources (one-time)
    if (this.store.message.length === 0 && this.store.llm.length === 0) {
      this.migrateLegacyConfigs();
    }
  }

  public static getInstance(): ProviderConfigManager {
    if (!ProviderConfigManager.instance) {
      ProviderConfigManager.instance = new ProviderConfigManager();
    }
    return ProviderConfigManager.instance;
  }

  /**
   * Interpolate ${ENV_VAR} patterns in config values with actual environment variables
   */
  private interpolateEnvVars(obj: any): any {
    if (typeof obj === 'string') {
      return obj.replace(/\$\{([^}]+)\}/g, (_, envVar) => {
        const value = process.env[envVar] || '';
        debug(`Interpolating \${${envVar}} -> "${value}" (env available: ${!!process.env[envVar]})`);
        return value;
      });
    }
    if (Array.isArray(obj)) {
      return obj.map(item => this.interpolateEnvVars(item));
    }
    if (typeof obj === 'object' && obj !== null) {
      const result: any = {};
      for (const key of Object.keys(obj)) {
        result[key] = this.interpolateEnvVars(obj[key]);
      }
      return result;
    }
    return obj;
  }

  private loadConfig(): void {
    try {
      if (fs.existsSync(this.configPath)) {
        const raw = fs.readFileSync(this.configPath, 'utf-8');
        const parsed = JSON.parse(raw);
        // Interpolate ${ENV_VAR} patterns with actual env values
        this.store = this.interpolateEnvVars(parsed);
        debug(`Loaded ${this.store.message.length} message and ${this.store.llm.length} llm providers`);
      } else {
        this.store = { message: [], llm: [] };
        this.saveConfig();
      }
      this.initialized = true;
    } catch (error) {
      debug('Error loading provider config:', error);
      this.store = { message: [], llm: [] };
    }
  }

  private saveConfig(): void {
    try {
      fs.writeFileSync(this.configPath, JSON.stringify(this.store, null, 2));
      debug('Saved provider config');
    } catch (error) {
      debug('Error saving provider config:', error);
    }
  }

  /**
   * One-time migration from environment variables/legacy configs to instances
   */
  private migrateLegacyConfigs(): void {
    debug('Migrating legacy configs...');
    let changed = false;

    // Discord
    const discordToken = process.env.DISCORD_BOT_TOKEN;
    if (discordToken) {
      const tokens = discordToken.split(',');
      tokens.forEach((token, idx) => {
        if (token.trim()) {
          this.store.message.push({
            id: `discord-${idx === 0 ? 'default' : uuidv4()}`,
            type: 'discord',
            category: 'message',
            name: idx === 0 ? 'Default Discord Bot' : `Discord Bot ${idx + 2}`,
            enabled: true,
            config: { token: token.trim() },
          });
          changed = true;
        }
      });
    }

    // OpenAI
    const openAiKey = process.env.OPENAI_API_KEY;
    if (openAiKey) {
      this.store.llm.push({
        id: 'openai-default',
        type: 'openai',
        category: 'llm',
        name: 'Default OpenAI',
        enabled: true,
        config: {
          apiKey: openAiKey,
          model: process.env.OPENAI_MODEL || 'gpt-4',
        },
      });
      changed = true;
    }

    // Ollama
    const ollamaUrl = process.env.OLLAMA_BASE_URL;
    if (ollamaUrl) {
      this.store.llm.push({
        id: 'ollama-default',
        type: 'ollama',
        category: 'llm',
        name: 'Local Ollama',
        enabled: true,
        config: {
          baseUrl: ollamaUrl,
          model: process.env.OLLAMA_MODEL || 'llama2',
        },
      });
      changed = true;
    }

    if (changed) {
      this.saveConfig();
      debug('Migration complete');
    }
  }

  // CRUD Operations

  public getAllProviders(category?: 'message' | 'llm'): ProviderInstance[] {
    if (category) {
      return this.store[category];
    }
    return [...this.store.message, ...this.store.llm];
  }

  public getProvider(id: string): ProviderInstance | undefined {
    return [...this.store.message, ...this.store.llm].find(p => p.id === id);
  }

  public createProvider(data: Omit<ProviderInstance, 'id'>): ProviderInstance {
    const newInstance: ProviderInstance = {
      ...data,
      id: uuidv4(), // Generate ID
    };

    if (newInstance.category === 'message') {
      this.store.message.push(newInstance);
    } else {
      this.store.llm.push(newInstance);
    }

    this.saveConfig();
    return newInstance;
  }

  public updateProvider(id: string, updates: Partial<ProviderInstance>): ProviderInstance | null {
    let target = this.store.message.find(p => p.id === id);

    if (!target) {
      target = this.store.llm.find(p => p.id === id);
    }

    if (!target) {return null;}

    // Merge updates
    Object.assign(target, updates);
    // Ensure category/id/type are immutable if needed? For now allow update except ID
    target.id = id;

    this.saveConfig();
    return target;
  }

  public deleteProvider(id: string): boolean {
    const msgIdx = this.store.message.findIndex(p => p.id === id);
    if (msgIdx !== -1) {
      this.store.message.splice(msgIdx, 1);
      this.saveConfig();
      return true;
    }

    const llmIdx = this.store.llm.findIndex(p => p.id === id);
    if (llmIdx !== -1) {
      this.store.llm.splice(llmIdx, 1);
      this.saveConfig();
      return true;
    }

    return false;
  }
}

export default ProviderConfigManager;

import fs from 'fs';
import path from 'path';
import crypto from 'crypto';
import Debug from 'debug';
import { ErrorUtils } from '../types/errors';

const debug = Debug('app:SecureConfigManager');

export interface SecureConfig {
  id: string;
  name: string;
  type?: string;
  data: any;
  updatedAt: string;
  checksum: string;
  createdAt?: string;
  rotationInterval?: number;
}

/**
 * SecureConfigManager handles the encryption and storage of sensitive configuration data.
 * It uses AES-256-GCM for authenticated encryption and stores data in the filesystem.
 */
export class SecureConfigManager {
  private static instance: SecureConfigManager;
  private readonly configDir: string;
  private readonly backupDir: string;
  private readonly encryptionKey: Buffer;
  private readonly algorithm = 'aes-256-gcm';
  private readonly keyPath: string;
  private readonly mainConfigDir: string;

  private constructor() {
    this.configDir = path.join(process.cwd(), 'config', 'secure');
    this.backupDir = path.join(process.cwd(), 'config', 'backups');
    this.keyPath = path.join(process.cwd(), 'config', '.key');

    this.ensureDirectories();

    // Generate or load encryption key
    this.encryptionKey = this.getOrCreateEncryptionKey();
    this.mainConfigDir = path.join(process.cwd(), 'config');
  }

  public static getInstance(): SecureConfigManager {
    if (!SecureConfigManager.instance) {
      SecureConfigManager.instance = new SecureConfigManager();
    }
    return SecureConfigManager.instance;
  }

  /**
   * Helper to safely resolve a file path and prevent directory traversal
   */
  private getSecureFilePath(id: string): string {
    // Additional input validation: only allow alphanumeric, hyphens, and underscores
    // This prevents path traversal characters like ../ and ./ from even being processed
    if (!/^[a-zA-Z0-9_-]+$/.test(id)) {
      throw ErrorUtils.createError(
        'Invalid configuration ID: ID must contain only alphanumeric characters, hyphens, and underscores',
        'validation',
        'SECURE_CONFIG_INVALID_ID',
        400,
      );
    }

    const targetPath = path.join(this.configDir, `${id}.enc`);

    // Resolve both paths to their absolute forms
    const resolvedConfigDir = path.resolve(this.configDir);
    const resolvedTargetPath = path.resolve(targetPath);

    // Ensure the resolved target path starts with the resolved config directory
    if (!resolvedTargetPath.startsWith(resolvedConfigDir + path.sep) && resolvedTargetPath !== resolvedConfigDir) {
      throw ErrorUtils.createError(
        'Invalid configuration ID: Path traversal detected',
        'validation',
        'SECURE_CONFIG_INVALID_ID',
        400,
      );
    }

    return targetPath;
  }

  /**
   * Store a configuration securely
   */
  public async storeConfig(config: Omit<SecureConfig, 'updatedAt' | 'checksum'>): Promise<void> {
    // Validate configuration
    if (!config.id || config.id.trim() === '') {
      throw ErrorUtils.createError(
        'Configuration ID is required',
        'validation',
        'SECURE_CONFIG_ID_REQUIRED',
        400,
      );
    }
    if (!config.name || config.name.trim() === '') {
      throw ErrorUtils.createError(
        'Configuration name is required',
        'validation',
        'SECURE_CONFIG_NAME_REQUIRED',
        400,
      );
    }

    try {
      debug(`Storing configuration ${config.id}`);
      const secureConfig: SecureConfig = {
        ...config,
        updatedAt: new Date().toISOString(),
        checksum: '',
      };

      // Calculate checksum before encryption (exclude checksum field itself)
      const { checksum, ...configForChecksum } = secureConfig;
      secureConfig.checksum = this.calculateChecksum(configForChecksum);

      const filePath = this.getSecureFilePath(config.id);
      const encryptedData = this.encrypt(JSON.stringify(secureConfig));

      await fs.promises.writeFile(filePath, encryptedData, 'utf8');
      debug(`Configuration ${config.id} stored successfully`);
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      debug(`Failed to store configuration ${config.id}:`, hivemindError.message);
      throw ErrorUtils.createError(
        `Failed to store secure configuration: ${hivemindError.message}`,
        'unknown',
        'SECURE_CONFIG_STORE_FAILED',
        500,
      );
    }
  }

  /**
   * Retrieve a configuration securely
   */
  public async getConfig(id: string): Promise<SecureConfig | null> {
    try {
      const filePath = this.getSecureFilePath(id);
      if (!fs.existsSync(filePath)) {
        return null;
      }

      const encryptedData = await fs.promises.readFile(filePath, 'utf8');
      const decryptedData = this.decrypt(encryptedData);
      const config: SecureConfig = JSON.parse(decryptedData);

      // Verify integrity
      const { checksum, ...configWithoutChecksum } = config;
      if (this.calculateChecksum(configWithoutChecksum) !== checksum) {
        throw ErrorUtils.createError(
          'Configuration integrity check failed',
          'IntegrityError' as any,
          'SECURE_CONFIG_INTEGRITY_FAILED',
          500,
        );
      }

      // Check if rotation is required based on rotationInterval
      // Ensure the config actually contains keys before warning about rotation
      const hasConfiguredKeys = config.data && Object.keys(config.data).length > 0;
      if (hasConfiguredKeys && config.rotationInterval && config.rotationInterval > 0) {
        const lastUpdated = new Date(config.updatedAt).getTime();
        const now = Date.now();
        const daysSinceUpdate = (now - lastUpdated) / (1000 * 60 * 60 * 24);

        if (daysSinceUpdate >= config.rotationInterval) {
          debug(`[WARNING] Secure configuration '${config.name}' (ID: ${config.id}) is due for credential rotation (Interval: ${config.rotationInterval} days, Days since update: ${Math.floor(daysSinceUpdate)} days).`);
          // In a fully automated system, this could trigger an event/webhook to automatically rotate secrets.
        }
      }

      return config;
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      debug(`Failed to retrieve configuration ${id}:`, hivemindError.message);
      return null;
    }
  }

  public getDecryptedMainConfig(env: string): any {
    try {
      const configPath = path.join(this.mainConfigDir, `${env}.json.enc`);
      if (fs.existsSync(configPath)) {
        const encryptedData = fs.readFileSync(configPath, 'utf8');
        const decryptedData = this.decrypt(encryptedData);
        return JSON.parse(decryptedData);
      }
      return null;
    } catch (error) {
      debug(`Failed to read decrypted main config for env ${env}:`, error);
      return null;
    }
  }

  /**
   * Delete a configuration
   */
  public async deleteConfig(id: string): Promise<void> {
    try {
      const filePath = this.getSecureFilePath(id);
      if (fs.existsSync(filePath)) {
        await fs.promises.unlink(filePath);
        debug(`Configuration ${id} deleted`);
      }
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      debug(`Failed to delete configuration ${id}:`, hivemindError.message);
      throw ErrorUtils.createError(
        `Failed to delete secure configuration: ${hivemindError.message}`,
        'unknown',
        'SECURE_CONFIG_DELETE_FAILED',
        500,
      );
    }
  }

  /**
   * List all stored configurations (metadata only)
   */
  public async listConfigs(): Promise<Omit<SecureConfig, 'data'>[]> {
    try {
      const files = await fs.promises.readdir(this.configDir);
      const configPromises = files
        .filter(file => file.endsWith('.enc'))
        .map(async (file) => {
          const id = file.replace('.enc', '');
          const config = await this.getConfig(id);
          if (config) {
            const { data, ...metadata } = config;
            return metadata;
          }
          return null;
        });

      // Use allSettled so a single corrupt file doesn't abort the entire listing
      const results = await Promise.allSettled(configPromises);
      return results
        .filter((r): r is PromiseFulfilledResult<Omit<SecureConfig, 'data'>> =>
          r.status === 'fulfilled' && r.value !== null
        )
        .map(r => r.value);
    } catch (error: unknown) {
      debug('Failed to list configurations:', error);
      return [];
    }
  }

  /**
   * Create a full backup of all secure configurations
   */
  public async listBackups(): Promise<any[]> {
    try {
      if (!fs.existsSync(this.backupDir)) return [];
      const files = await fs.promises.readdir(this.backupDir);
      return files.filter(f => f.endsWith('.enc'));
    } catch {
      return [];
    }
  }

  public async createBackup(): Promise<string> {
    try {
      const configs = await fs.promises.readdir(this.configDir);
      const backupId = `backup_${new Date().toISOString().replace(/[:.]/g, '-')}`;
      const backupPath = path.join(this.backupDir, `${backupId}.json`);

      const configPromises = configs
        .filter(file => file.endsWith('.enc'))
        .map(async (file) => {
          const id = file.replace('.enc', '');
          const config = await this.getConfig(id);
          if (config) {
            return { id, config };
          }
          return null;
        });

      // Use allSettled so a single corrupt file doesn't abort the entire backup
      const results = await Promise.allSettled(configPromises);
      const allConfigs: Record<string, SecureConfig> = {};
      for (const result of results) {
        if (result.status === 'fulfilled' && result.value) {
          allConfigs[result.value.id] = result.value.config;
        } else if (result.status === 'rejected') {
          debug('Skipping config during backup due to error:', result.reason);
        }
      }

      const fullBackupData = {
        metadata: {
          id: backupId,
          createdAt: new Date().toISOString(),
          configCount: Object.keys(allConfigs).length,
          checksum: '',
        },
        data: allConfigs,
      };

      // Calculate backup checksum on metadata
      const { checksum, ...metadataWithoutChecksum } = fullBackupData.metadata;
      fullBackupData.metadata.checksum = this.calculateChecksum(metadataWithoutChecksum);

      // Encrypt and store backup
      const encryptedBackup = this.encrypt(JSON.stringify(fullBackupData));
      await fs.promises.writeFile(backupPath, encryptedBackup, 'utf8');

      debug(`Backup ${backupId} created with ${Object.keys(allConfigs).length} configurations`);
      return backupId;
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug('Failed to create backup:', {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      throw ErrorUtils.createError(
        `Backup creation failed: ${hivemindError.message}`,
        errorInfo.type,
        'SECURE_CONFIG_BACKUP_CREATE_FAILED',
        500,
      );
    }
  }

  /**
   * Restore from a backup
   */
  public async restoreBackup(backupId: string): Promise<void> {
    try {
      const backupPath = path.join(this.backupDir, `${backupId}.json`);

      // Security check to prevent path traversal
      const resolvedBackupPath = path.resolve(backupPath);
      const resolvedBackupDir = path.resolve(this.backupDir);
      if (!resolvedBackupPath.startsWith(resolvedBackupDir + path.sep) && resolvedBackupPath !== resolvedBackupDir) {
        throw ErrorUtils.createError(
          'Invalid backup ID: Path traversal detected',
          'validation',
          'SECURE_CONFIG_INVALID_BACKUP_ID',
          400,
        );
      }

      if (!fs.existsSync(backupPath)) {
        throw ErrorUtils.createError(
          `Backup ${backupId} not found`,
          'validation',
          'SECURE_CONFIG_BACKUP_NOT_FOUND',
          404,
        );
      }

      const encryptedBackup = await fs.promises.readFile(backupPath, 'utf8');
      const decryptedBackup = this.decrypt(encryptedBackup);
      const fullBackupData = JSON.parse(decryptedBackup);

      // Verify backup integrity
      const { checksum, ...metadataWithoutChecksum } = fullBackupData.metadata;
      if (this.calculateChecksum(metadataWithoutChecksum) !== checksum) {
        throw ErrorUtils.createError(
          'Backup integrity check failed',
          'IntegrityError' as any,
          'SECURE_CONFIG_BACKUP_INTEGRITY_FAILED',
          500,
        );
      }

      const { data } = fullBackupData;

      // Restore configurations
      await Promise.all(
        Object.values(data).map(config => this.storeConfig(config as SecureConfig))
      );

      debug(`Backup ${backupId} restored successfully`);
    } catch (error: unknown) {
      const hivemindError = ErrorUtils.toHivemindError(error) as any;
      const errorInfo = ErrorUtils.classifyError(hivemindError);
      debug(`Failed to restore backup ${backupId}:`, {
        error: hivemindError.message,
        errorCode: hivemindError.code,
        errorType: errorInfo.type,
        severity: errorInfo.severity,
      });
      throw ErrorUtils.createError(
        `Backup restoration failed: ${hivemindError.message}`,
        errorInfo.type,
        'SECURE_CONFIG_BACKUP_RESTORE_FAILED',
        500,
      );
    }
  }

  private ensureDirectories(): void {
    [this.configDir, this.backupDir].forEach(dir => {
      if (!fs.existsSync(dir)) {
        fs.mkdirSync(dir, { recursive: true });
      }
    });
  }

  private getOrCreateEncryptionKey(): Buffer {
    if (fs.existsSync(this.keyPath)) {
      return fs.readFileSync(this.keyPath);
    }

    const key = crypto.randomBytes(32);
    fs.writeFileSync(this.keyPath, key);
    return key;
  }

  public encrypt(text: string): string {
    const iv = crypto.randomBytes(16);
    const cipher = crypto.createCipheriv(this.algorithm, this.encryptionKey, iv);

    let encrypted = cipher.update(text, 'utf8', 'hex');
    encrypted += cipher.final('hex');

    const authTag = cipher.getAuthTag().toString('hex');

    return `${iv.toString('hex')}:${authTag}:${encrypted}`;
  }

  public decrypt(text: string): string {
    const [ivHex, authTagHex, encryptedText] = text.split(':');

    const iv = Buffer.from(ivHex, 'hex');
    const authTag = Buffer.from(authTagHex, 'hex');
    const decipher = crypto.createDecipheriv(this.algorithm, this.encryptionKey, iv);

    decipher.setAuthTag(authTag);

    let decrypted = decipher.update(encryptedText, 'hex', 'utf8');
    decrypted += decipher.final('utf8');

    return decrypted;
  }

  private calculateChecksum(data: any): string {
    return crypto
      .createHash('sha256')
      .update(JSON.stringify(data))
      .digest('hex');
  }

  private verifyChecksum(config: SecureConfig | any): boolean {
    const { checksum, ...data } = config;
    return this.calculateChecksum(data) === checksum;
  }
}

