import { promises as fs } from 'fs';
import path from 'path';
import type { BotConfiguration } from '../database/DatabaseManager';
import type { BotOverride, MessageProvider, LlmProvider, McpServerConfig, McpGuardConfig } from '@src/types/config';

interface ToolConfig {
  guards?: {
    ownerOnly?: boolean;
    allowedUsers?: string[];
  };
}

interface BotDisabledState {
  disabled: boolean;
  disabledAt?: string;
}

type GeneralSettings = Record<string, any>;

export class UserConfigStore {
  private static instance: UserConfigStore;
  private config: {
    toolSettings?: Record<string, ToolConfig>;
    bots?: BotConfiguration[];
    botDisabledStates?: Record<string, BotDisabledState>;
    generalSettings?: GeneralSettings;
  } = {};
  private configPath: string;

  public constructor() {
    this.configPath = path.join(process.cwd(), 'config', 'user-config.json');
    // Load config synchronously for now to avoid async issues in constructor
    try {
      const data = require('fs').readFileSync(this.configPath, 'utf-8');
      this.config = JSON.parse(data);
    } catch (error) {
      // If config file doesn't exist, use default empty config
      this.config = {
        toolSettings: {},
        bots: [],
        botDisabledStates: {},
      };
    }
  }

  public static getInstance(): UserConfigStore {
    if (!UserConfigStore.instance) {
      UserConfigStore.instance = new UserConfigStore();
    }
    return UserConfigStore.instance;
  }

  private async loadConfig(): Promise<void> {
    try {
      const data = await fs.readFile(this.configPath, 'utf-8');
      this.config = JSON.parse(data);
    } catch (error) {
      // If config file doesn't exist, use default empty config
      this.config = {
        toolSettings: {},
        bots: [],
        botDisabledStates: {},
      };
    }
  }

  /**
   * Save the current configuration to disk.
   */
  public async saveConfig(): Promise<void> {
    try {
      const configDir = path.dirname(this.configPath);
      // Ensure directory exists
      await fs.mkdir(configDir, { recursive: true });
      await fs.writeFile(this.configPath, JSON.stringify(this.config, null, 2), 'utf-8');
    } catch (error) {
      console.error('Failed to save user config:', error);
      throw error;
    }
  }

  /**
   * Check if a bot is disabled.
   * @param botName The name of the bot.
   * @returns true if bot is disabled, false otherwise.
   */
  public isBotDisabled(botName: string): boolean {
    return this.config.botDisabledStates?.[botName]?.disabled ?? false;
  }

  /**
   * Set bot disabled state and persist to config file.
   * @param botName The name of the bot.
   * @param disabled Whether the bot should be disabled.
   */
  public async setBotDisabled(botName: string, disabled: boolean): Promise<void> {
    if (!this.config.botDisabledStates) {
      this.config.botDisabledStates = {};
    }

    this.config.botDisabledStates[botName] = {
      disabled,
      disabledAt: disabled ? new Date().toISOString() : undefined,
    };

    await this.saveConfig();
  }

  /**
   * Get all disabled bot names.
   * @returns Array of disabled bot names.
   */
  public getDisabledBots(): string[] {
    if (!this.config.botDisabledStates) {
      return [];
    }
    return Object.entries(this.config.botDisabledStates)
      .filter(([_, state]) => state.disabled)
      .map(([name]) => name);
  }

  public getToolConfig(toolName: string): ToolConfig | undefined {
    return this.config.toolSettings?.[toolName];
  }

  public setToolConfig(toolName: string, config: ToolConfig): void {
    if (!this.config.toolSettings) {
      this.config.toolSettings = {};
    }
    this.config.toolSettings[toolName] = config;
  }

  /**
   * Get user overrides for a specific bot.
   * @param botName The name of the bot.
   * @returns A BotOverride object if found, otherwise undefined.
   */
  public getBotOverride(botName: string): BotOverride | undefined {
    if (!this.config.bots) {
      return undefined;
    }
    const botConfig = this.config.bots.find(bot => bot.name === botName);
    if (!botConfig) {
      return undefined;
    }
    // Map BotConfiguration to BotOverride
    return {
      disabled: this.isBotDisabled(botName),
      messageProvider: botConfig.messageProvider as MessageProvider,
      llmProvider: botConfig.llmProvider as LlmProvider,
      llmProfile: (botConfig as any).llmProfile as string | undefined,
      responseProfile: botConfig.responseProfile as string | undefined,
      persona: botConfig.persona,
      systemInstruction: botConfig.systemInstruction,
      mcpServers: botConfig.mcpServers as McpServerConfig[],
      mcpGuard: botConfig.mcpGuard as McpGuardConfig,
      mcpGuardProfile: (botConfig as any).mcpGuardProfile as string | undefined,
    };
  }

  /**
   * Get all user overrides for bots in a Map for O(1) lookup.
   * @returns A Map of botName to BotOverride.
   */
  public getAllBotOverrides(): Map<string, BotOverride> {
    const overrides = new Map<string, BotOverride>();
    if (!this.config.bots) {
      return overrides;
    }

    // Pre-calculate disabled status for all bots to avoid O(N^2)
    const disabledBots = new Set(this.config.general?.disabledBots || []);

    for (const botConfig of this.config.bots) {
      if (!botConfig.name) continue;
      overrides.set(botConfig.name, {
        disabled: disabledBots.has(botConfig.name),
        messageProvider: botConfig.messageProvider as MessageProvider,
        llmProvider: botConfig.llmProvider as LlmProvider,
        llmProfile: (botConfig as any).llmProfile as string | undefined,
        responseProfile: botConfig.responseProfile as string | undefined,
        persona: botConfig.persona,
        systemInstruction: botConfig.systemInstruction,
        mcpServers: botConfig.mcpServers as McpServerConfig[],
        mcpGuard: botConfig.mcpGuard as McpGuardConfig,
        mcpGuardProfile: (botConfig as any).mcpGuardProfile as string | undefined,
      });
    }

    return overrides;
  }

  /**
   * Set user overrides for a specific bot.
   * @param botName The name of the bot.
   * @param overrides The overrides to apply.
   */
  public setBotOverride(botName: string, overrides: BotOverride): void {
    if (!this.config.bots) {
      this.config.bots = [];
    }
    const existingBotIndex = this.config.bots.findIndex(bot => bot.name === botName);
    const botConfig: BotConfiguration = {
      name: botName,
      messageProvider: overrides.messageProvider || 'discord' as MessageProvider,
      llmProvider: overrides.llmProvider || 'flowise' as LlmProvider,
      llmProfile: (overrides as any).llmProfile,
      responseProfile: overrides.responseProfile,
      persona: overrides.persona,
      systemInstruction: overrides.systemInstruction,
      mcpServers: overrides.mcpServers,
      mcpGuard: overrides.mcpGuard,
      mcpGuardProfile: (overrides as any).mcpGuardProfile,
      isActive: true,
      createdAt: new Date(),
      updatedAt: new Date(),
    };

    if (existingBotIndex >= 0) {
      this.config.bots[existingBotIndex] = botConfig;
    } else {
      this.config.bots.push(botConfig);
    }
  }

  /**
   * Get general settings.
   * @returns The general settings object.
   */
  public getGeneralSettings(): GeneralSettings {
    return this.config.generalSettings || {};
  }

  /**
   * Set general settings and persist to config file.
   * @param settings The settings to merge/save.
   */
  public async setGeneralSettings(settings: GeneralSettings): Promise<void> {
    if (!this.config.generalSettings) {
      this.config.generalSettings = {};
    }

    // Merge new settings with existing
    this.config.generalSettings = {
      ...this.config.generalSettings,
      ...settings,
    };

    await this.saveConfig();
  }
}

/**
 * @fileoverview Debug utility for logging and validating environment variables
 * @module config/debugEnvVars
 * @description Provides functionality to debug environment variables by logging them
 * in a secure manner (redacting sensitive information) and checking for required
 * variables based on configured providers.
 */

import { redactSensitiveInfo } from '../common/redactSensitiveInfo';
import Debug from 'debug';

const debug = Debug('app:debugEnvVars');

/**
 * Debug and validate environment variables for the application.
 *
 * @function debugEnvVars
 * @description This function performs two main tasks:
 * 1. Logs all environment variables while redacting sensitive information
 * 2. Checks for missing required environment variables based on configured providers
 *
 * @returns {void}
 *
 * @example
 * ```typescript
 * import { debugEnvVars } from './config/debugEnvVars';
 *
 * // Debug environment variables at startup
 * debugEnvVars();
 * ```
 *
 * @description
 * The function automatically detects which environment variables are required
 * based on the MESSAGE_PROVIDER and LLM_PROVIDER configuration:
 *
 * - Discord provider requires: DISCORD_BOT_TOKEN, DISCORD_CLIENT_ID, DISCORD_GUILD_ID
 * - Slack provider requires: SLACK_BOT_TOKEN, SLACK_APP_TOKEN, SLACK_SIGNING_SECRET
 * - OpenAI provider requires: OPENAI_API_KEY, OPENAI_BASE_URL, OPENAI_MODEL
 * - Flowise provider requires: FLOWISE_API_KEY, FLOWISE_API_ENDPOINT
 *
 * Sensitive information (variables containing KEY, TOKEN, SECRET, or PASSWORD)
 * is automatically redacted before logging.
 */
export function debugEnvVars() {
  debug('=== Environment Variables ===');

  // Iterate over all environment variables
  Object.keys(process.env).forEach(key => {
    if (key === 'BOT_DEBUG_MODE') {
      return; // Skip BOT_DEBUG_MODE
    }
    // Security: Skip any variables that might contain credentials
    if (key.includes('TOKEN') || key.includes('KEY') || key.includes('SECRET') || key.includes('PASSWORD')) {
      debug(`Skipping sensitive variable: ${key}`);
      return;
    }
    let value = process.env[key] || '';
    const upperKey = key.toUpperCase();
    // Redact variables containing KEY, TOKEN, or ending with SECRET
    if (upperKey.includes('KEY') || upperKey.includes('TOKEN') || upperKey.endsWith('SECRET') || upperKey.endsWith('PASSWORD')) {
      value = redactSensitiveInfo(key, value);
    }
    debug(`${key} = ${value}`);
  });

  // Check for required environment variables based on configured providers
  const requiredEnvVars = new Set<string>();
  const messageProvider = process.env['MESSAGE_PROVIDER'] || '';
  const llmProvider = process.env['LLM_PROVIDER'] || '';

  if (messageProvider.toLowerCase().includes('discord')) {
    requiredEnvVars.add('DISCORD_BOT_TOKEN');
    requiredEnvVars.add('DISCORD_CLIENT_ID');
    requiredEnvVars.add('DISCORD_GUILD_ID');
  }
  if (messageProvider.toLowerCase().includes('slack')) {
    requiredEnvVars.add('SLACK_BOT_TOKEN');
    requiredEnvVars.add('SLACK_APP_TOKEN');
    requiredEnvVars.add('SLACK_SIGNING_SECRET');
  }
  if (llmProvider.toLowerCase().includes('openai')) {
    requiredEnvVars.add('OPENAI_API_KEY');
    requiredEnvVars.add('OPENAI_BASE_URL');
    requiredEnvVars.add('OPENAI_MODEL');
  }
  if (llmProvider.toLowerCase().includes('flowise')) {
    requiredEnvVars.add('FLOWISE_API_KEY');
    requiredEnvVars.add('FLOWISE_API_ENDPOINT');
  }

  if (requiredEnvVars.size > 0) {
    debug('=== Checking for Missing Required Environment Variables ===');
    requiredEnvVars.forEach(varName => {
      if (!process.env[varName]) {
        debug(`WARNING: Required environment variable ${varName} is missing!`);
      }
    });
  }
}

