          anomaly.timestamp,
          anomaly.metric,
          anomaly.value,
          anomaly.expectedMean,
          anomaly.standardDeviation,
          anomaly.zScore,
          anomaly.threshold,
          anomaly.severity,
          anomaly.explanation,
          anomaly.resolved ? 1 : 0,
          anomaly.tenantId,
        ]
      );

      debug(`Anomaly stored: ${anomaly.id}`);
    } catch (error) {
      debug('Error storing anomaly:', error);
      throw error;
