          await db.exec('CREATE INDEX IF NOT EXISTS idx_job_queue_priority ON job_queue(priority)');
          await db.exec('CREATE INDEX IF NOT EXISTS idx_job_queue_tenant ON job_queue(tenantId)');
          await db.exec('CREATE INDEX IF NOT EXISTS idx_job_queue_created ON job_queue(createdAt)');
        },
      },
      {
        id: '010_add_event_streaming',
        name: 'Add event streaming support',
        version: 10,
        up: async (db: any) => {
          await db.exec(`
            CREATE TABLE IF NOT EXISTS event_stream (
              id TEXT PRIMARY KEY,
              eventType TEXT NOT NULL,
              eventData TEXT NOT NULL,
              source TEXT,
              tenantId TEXT,
              timestamp DATETIME DEFAULT CURRENT_TIMESTAMP,
              FOREIGN KEY (tenantId) REFERENCES tenants(id) ON DELETE CASCADE
            )
          `);

          await db.exec(
            'CREATE INDEX IF NOT EXISTS idx_event_stream_type ON event_stream(eventType)'
          );
          await db.exec(
            'CREATE INDEX IF NOT EXISTS idx_event_stream_tenant ON event_stream(tenantId)'
          );
          await db.exec(
            'CREATE INDEX IF NOT EXISTS idx_event_stream_timestamp ON event_stream(timestamp)'
          );
        },
      },
      {
        id: '011_add_cron_timezone_support',
        name: 'Add timezone support to cron scheduling tables',
        version: 11,
        up: async (db: any) => {
          await db.exec("ALTER TABLE bot_scheduling ADD COLUMN timezone TEXT DEFAULT 'UTC'");
          await db.exec("ALTER TABLE bot_backup_schedules ADD COLUMN timezone TEXT DEFAULT 'UTC'");
          await db.exec(
            "ALTER TABLE bot_data_purging_schedules ADD COLUMN timezone TEXT DEFAULT 'UTC'"
          );
        },
        down: async (db: any) => {
          // SQLite doesn't support DROP COLUMN cleanly in all versions. We omit down or leave empty for safety,
          // or ideally we would recreate the table without the column. For simplicity, we'll leave it as a no-op down.
        },
      },
    ];
  }

  async createMigrationsTable(): Promise<void> {
    await this.db.exec(`
      CREATE TABLE IF NOT EXISTS migrations (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        version INTEGER NOT NULL UNIQUE,
        executedAt DATETIME DEFAULT CURRENT_TIMESTAMP,
        checksum TEXT
      )
    `);
  }

  async getExecutedMigrations(): Promise<string[]> {
    const rows = await this.db.all('SELECT id FROM migrations ORDER BY version');
    return rows.map((row: any) => row.id);
  }

  async runMigrations(): Promise<void> {
    try {
      await this.createMigrationsTable();
      this.executedMigrations = new Set(await this.getExecutedMigrations());

      const pendingMigrations = this.migrations
        .filter((migration) => !this.executedMigrations.has(migration.id))
        .sort((a, b) => a.version - b.version);

      for (const migration of pendingMigrations) {
        await this.executeMigration(migration);
      }

      Logger.info(`Executed ${pendingMigrations.length} pending migrations`);
    } catch (error) {
      Logger.error('Error running migrations:', error);
      throw error;
    }
  }

  private async executeMigration(migration: Migration): Promise<void> {
    try {
      Logger.info(`Executing migration ${migration.id}: ${migration.name}`);

      // Start transaction
      await this.db.exec('BEGIN TRANSACTION');

      // Execute migration
      await migration.up(this.db);

      // Record migration in migrations table
      await this.db.run('INSERT INTO migrations (id, name, version) VALUES (?, ?, ?)', [
        migration.id,
        migration.name,
        migration.version,
      ]);

      // Commit transaction
      await this.db.exec('COMMIT');

      Logger.info(`Successfully executed migration ${migration.id}`);
    } catch (error) {
      // Rollback on error
      try {
        await this.db.exec('ROLLBACK');
      } catch (rollbackError) {
        Logger.error('Error rolling back migration:', rollbackError);
      }

      Logger.error(`Failed to execute migration ${migration.id}:`, error);
      throw error;
    }
  }

  async rollbackToVersion(version: number): Promise<void> {
    const migrationsToRollback = this.migrations
      .filter((m) => m.version > version)
      .sort((a, b) => b.version - a.version); // Reverse order

    // Validate that all migrations to be rolled back are reversible
    const irreversibleMigration = migrationsToRollback.find((m) => !m.down);
    if (irreversibleMigration) {
      throw new Error(
        `Cannot rollback: Migration ${irreversibleMigration.id} is irreversible (missing down method).`
      );
    }

    for (const migration of migrationsToRollback) {
      if (migration.down) {
        await this.rollbackMigration(migration);
      }
    }
  }

  private async rollbackMigration(migration: Migration): Promise<void> {
    try {
      Logger.info(`Rolling back migration ${migration.id}: ${migration.name}`);

      // Start transaction
      await this.db.exec('BEGIN TRANSACTION');

      // Execute rollback
      await migration.down!(this.db);

      // Remove from migrations table
      await this.db.run('DELETE FROM migrations WHERE id = ?', [migration.id]);

      // Commit transaction
      await this.db.exec('COMMIT');

      Logger.info(`Successfully rolled back migration ${migration.id}`);
    } catch (error) {
      // Rollback on error
      try {
        await this.db.exec('ROLLBACK');
      } catch (rollbackError) {
        Logger.error('Error rolling back migration:', rollbackError);
      }

      Logger.error(`Failed to roll back migration ${migration.id}:`, error);
      throw error;
    }
  }

  getMigrationsStatus(): { executed: Migration[]; pending: Migration[] } {
    const executed = this.migrations.filter((m) => this.executedMigrations.has(m.id));
    const pending = this.migrations.filter((m) => !this.executedMigrations.has(m.id));

    return { executed, pending };
  }
}

