import axios from 'axios';
import Debug from 'debug';
import { isSafeUrl } from '@src/utils/ssrfGuard';

const debug = Debug('app:flowiseCommand');

export class FlowiseCommand {
  name = 'flowise';
  description =
    'Interact with the Flowise API to retrieve information based on the provided endpoint ID.';

  /**
   * Executes the Flowise API command.
   * @param args The command arguments, including an optional endpointId.
   * @returns An object indicating the success of the operation, a message, and optionally any additional data.
   */
  async execute(args: {
    endpointId?: string;
  }): Promise<{ success: boolean; message: string; error?: string; data?: any }> {
    const { endpointId } = args;

    // Guard: Check if the API base URL is defined in the environment variables
    const apiUrl = process.env.FLOWISE_BASE_URL;
    if (!apiUrl) {
      const errorMessage = 'Flowise API base URL is not defined in the environment variables.';
      debug(errorMessage);
      return { success: false, message: errorMessage };
    }
    debug('Flowise API base URL: ' + apiUrl);

    // Guard: Ensure API key is provided
    const apiKey = process.env.FLOWISE_API_KEY;
    if (!apiKey) {
      const errorMessage = 'Flowise API key is missing.';
      debug(errorMessage);
      return { success: false, message: errorMessage };
    }
    debug('Flowise API Key: ' + apiKey);

    // Guard: Ensure endpointId is provided
    if (!endpointId) {
      const errorMessage = 'Endpoint ID is required but was not provided.';
      debug(errorMessage);
      return { success: false, message: errorMessage };
    }
    debug('Endpoint ID: ' + endpointId);

    // Construct the full API URL
    const url = apiUrl + endpointId;
    debug('Constructed Flowise API URL: ' + url);

    if (!(await isSafeUrl(url))) {
      const errorMessage = 'Flowise API URL is not safe to connect to.';
      debug(errorMessage);
      return { success: false, message: errorMessage };
    }

    try {
      // Log the request headers for better debugging
      const headers = { Authorization: 'Bearer ' + apiKey };
      debug('Request Headers:', headers);

      // Make a GET request to the Flowise API
      const response = await axios.get(url, { headers });
      debug('Flowise API response status: ' + response.status);

      // Return success response with data
      return { success: true, message: 'Request successful', data: response.data };
    } catch (error: any) {
      // Handle and log any errors that occur during the API request
      debug('Flowise API request failed: ' + error.message);
      return { success: false, message: 'Flowise API request failed', error: error.message };
    }
  }
}

import Debug from 'debug';
import flowiseConfig from '@config/flowiseConfig';
import { getFlowiseResponse } from '@integrations/flowise/flowiseRestClient';
import { getFlowiseSdkResponse } from '@integrations/flowise/flowiseSdkClient';
import type { ILlmProvider } from '@llm/interfaces/ILlmProvider';
import type { IMessage } from '@message/interfaces/IMessage';

const flowiseDebug = Debug('app:flowiseProvider');

export class FlowiseProvider implements ILlmProvider {
  name = 'flowise';
  private config: any;

  constructor(config?: any) {
    this.config = config || {};
  }

  supportsCompletion(): boolean {
    return false;
  }

  supportsChatCompletion(): boolean {
    return true;
  }

  supportsHistory(): boolean {
    return false;
  }

  async generateChatCompletion(
    userMessage: string,
    historyMessages: IMessage[],
    metadata?: Record<string, any>
  ): Promise<string> {
    const channelId = metadata?.channelId;
    if (!channelId) {
      flowiseDebug('Error: channelId is missing from metadata for Flowise request.');
      return 'Sorry, I am missing some context to respond. Please try again.';
    }

    try {
      flowiseDebug(`Sending request to Flowise for channel ${channelId}`);
      let response: string;

      const useRest =
        this.config.useRest !== undefined
          ? this.config.useRest
          : flowiseConfig.get('FLOWISE_USE_REST');

      if (useRest) {
        response = await getFlowiseResponse(channelId, userMessage);
      } else {
        const chatflowId =
          this.config.chatflowId || flowiseConfig.get('FLOWISE_CONVERSATION_CHATFLOW_ID');
        if (!chatflowId) {
          throw new Error('FLOWISE_CONVERSATION_CHATFLOW_ID is not set.');
        }
        response = await getFlowiseSdkResponse(userMessage, chatflowId);
      }
      return response;
    } catch (error) {
      flowiseDebug('Error getting response from Flowise:', error);
      return 'There was an error communicating with the AI service.';
    }
  }

  async generateCompletion(prompt: string): Promise<string> {
    flowiseDebug('generateCompletion is not supported, redirecting to generateChatCompletion.');
    return this.generateChatCompletion(prompt, [], { channelId: 'default-completion' });
  }
}

