import axios, { type AxiosInstance } from 'axios';
import Debug from 'debug';
import { isSafeUrl } from '@src/utils/ssrfGuard';

const debug = Debug('app:mattermost-client');

export interface MattermostConfig {
  serverUrl: string;
  token: string;
}

export default class MattermostClient {
  private axios: AxiosInstance;
  private connected: boolean = false;
  private me: any = null;

  constructor(config: MattermostConfig) {
    this.axios = axios.create({
      baseURL: `${config.serverUrl}/api/v4`,
      headers: {
        Authorization: `Bearer ${config.token}`,
        'Content-Type': 'application/json',
      },
    });
  }

  public async connect(): Promise<void> {
    try {
      if (!(await isSafeUrl(this.axios.defaults.baseURL!))) {
        throw new Error('Mattermost API URL is not safe to connect to.');
      }
      const response = await this.axios.get('/users/me');
      this.me = response.data;
      this.connected = true;
      debug('Connected to Mattermost as', this.me.username);
    } catch (error: any) {
      debug('Failed to connect to Mattermost:', error.message);
      this.connected = false;
      throw error;
    }
  }

  public isConnected(): boolean {
    return this.connected;
  }

  public getCurrentUserId(): string | undefined {
    return this.me?.id;
  }

  public getCurrentUsername(): string | undefined {
    return this.me?.username;
  }

  public async postMessage(post: {
    channel: string;
    text: string;
    root_id?: string;
  }): Promise<any> {
    const response = await this.axios.post('/posts', {
      channel_id: post.channel,
      message: post.text,
      root_id: post.root_id,
    });
    return response.data;
  }

  public async getChannelPosts(channelId: string, page = 0, perPage = 10): Promise<any[]> {
    const response = await this.axios.get(`/channels/${channelId}/posts`, {
      params: { page, per_page: perPage },
    });
    // Mattermost returns { order: [...ids], posts: { id: post } }
    const { order, posts } = response.data;
    if (!order || !posts) return [];
    return order.map((id: string) => posts[id]);
  }

  public async getUser(userId: string): Promise<any> {
    try {
      const response = await this.axios.get(`/users/${userId}`);
      return response.data;
    } catch {
      return null;
    }
  }

  public async getChannelInfo(channelId: string): Promise<any> {
    const response = await this.axios.get(`/channels/${channelId}`);
    return response.data;
  }

  public async sendTyping(channelId: string, parentId?: string): Promise<void> {
    // Fire and forget typing event
    this.axios.post(`/channels/${channelId}/typing`, { parent_id: parentId }).catch(() => {});
  }
}

import axios from 'axios';
import { isSafeUrl } from '@src/utils/ssrfGuard';
import type { ILlmProvider } from '@llm/interfaces/ILlmProvider';

export class OpenSwarmProvider implements ILlmProvider {
  name = 'openswarm';

  private baseUrl: string;
  private apiKey: string;

  constructor() {
    this.baseUrl = process.env.OPENSWARM_BASE_URL || 'http://localhost:8000/v1';
    this.apiKey = process.env.OPENSWARM_API_KEY || 'dummy-key';
  }

  supportsChatCompletion(): boolean {
    return true;
  }

  supportsCompletion(): boolean {
    return true;
  }

  async generateChatCompletion(
    userMessage: string,
    historyMessages: any[],
    metadata?: Record<string, any>
  ): Promise<string> {
    try {
      const teamName = metadata?.team || metadata?.model || 'default-team';
      const targetUrl = `${this.baseUrl}/chat/completions`;

      if (!(await isSafeUrl(targetUrl))) {
        throw new Error('OpenSwarm API URL is not safe to connect to.');
      }

      const response = await axios.post(
        targetUrl,
        {
          model: teamName,
          messages: [...historyMessages, { role: 'user', content: userMessage }],
        },
        {
          headers: {
            Authorization: `Bearer ${this.apiKey}`,
            'Content-Type': 'application/json',
          },
          timeout: 15000,
        }
      );

      return response.data.choices[0]?.message?.content || 'No response';
    } catch (error: any) {
      console.error('OpenSwarm API error:', error.message);
      return `Error: ${error.message}`;
    }
  }

  async generateCompletion(prompt: string): Promise<string> {
    const content = await this.generateChatCompletion(prompt, [], {});
    return content;
  }
}

import { exec, spawn } from 'child_process';
import path from 'path';
import { promisify } from 'util';
import { type IToolInstaller } from '../../types/IToolInstaller';

const execAsync = promisify(exec);

export class SwarmInstaller implements IToolInstaller {
  id = 'openswarm';
  label = 'OpenSwarm';

  private installPath: string;

  constructor() {
    this.installPath = path.join(process.cwd(), 'open-swarm');
  }

  // Interface implementations
  async checkPrerequisites(): Promise<boolean> {
    return this.checkPython();
  }

  async checkInstalled(): Promise<boolean> {
    return this.checkSwarmInstalled();
  }

  async install(): Promise<{ success: boolean; message: string }> {
    return this.installSwarm();
  }

  async start(config?: any): Promise<{ success: boolean; message: string }> {
    const port = config?.port || 8000;
    return this.startSwarm(port);
  }

  getWebUIUrl(): string {
    return this.getSwarmWebUIUrl();
  }

  // Original methods
  async checkPython(): Promise<boolean> {
    try {
      await execAsync('python3 --version');
      return true;
    } catch {
      try {
        await execAsync('python --version');
        return true;
      } catch {
        return false;
      }
    }
  }

  async checkSwarmInstalled(): Promise<boolean> {
    try {
      await execAsync('swarm-cli --version');
      return true;
    } catch {
      return false;
    }
  }

  async installSwarm(): Promise<{ success: boolean; message: string }> {
    try {
      if (!(await this.checkPython())) {
        return { success: false, message: 'Python not found. Please install Python 3.10+' };
      }

      if (await this.checkSwarmInstalled()) {
        return { success: true, message: 'OpenSwarm already installed' };
      }

      console.log('Installing OpenSwarm via pip...');
      await execAsync('pip install open-swarm');

      return { success: true, message: 'OpenSwarm installed successfully via pip' };
    } catch (error: any) {
      return { success: false, message: `Installation failed: ${error.message}` };
    }
  }

  async startSwarm(port = 8000): Promise<{ success: boolean; message: string }> {
    try {
      // Validate port
      const portNum = Number(port);
      if (isNaN(portNum) || portNum < 1 || portNum > 65535) {
        return {
          success: false,
          message: 'Invalid port number. Must be between 1 and 65535.',
        };
      }

      // Check if swarm-api command is available
      try {
        await execAsync('swarm-api --help');
      } catch {
        return {
          success: false,
          message: 'OpenSwarm not installed. Run pip install open-swarm first.',
        };
      }

      // Start swarm API server in background
      const child = spawn('swarm-api', ['--port', portNum.toString()], {
        detached: true,
        stdio: 'ignore',
      });
      child.unref();

      // Wait a moment for startup
      await new Promise((resolve) => setTimeout(resolve, 3000));

      return { success: true, message: `OpenSwarm API started on port ${portNum}` };
    } catch (error: any) {
      return { success: false, message: `Failed to start: ${error.message}` };
    }
  }

  getSwarmWebUIUrl(): string {
    return process.env.OPENSWARM_WEBUI_URL || 'http://localhost:8002';
  }
}

import axios from 'axios';
import Debug from 'debug';
import type { IMessage } from '@message/interfaces/IMessage';

const debug = Debug('app:openWebUI:direct');

interface OpenWebUIOverrides {
  apiUrl: string;
  authHeader?: string;
  model: string;
}

export async function generateChatCompletionDirect(
  overrides: OpenWebUIOverrides,
  userMessage: string,
  historyMessages: IMessage[] = [],
  systemPrompt?: string
): Promise<string> {
  if (!overrides?.apiUrl || !overrides?.model) {
    throw new Error('OpenWebUI overrides require apiUrl and model');
  }
  const baseURL = overrides.apiUrl.replace(/\/$/, '');
  const headers: Record<string, string> = { 'Content-Type': 'application/json' };
  if (overrides.authHeader) {
    headers['Authorization'] = overrides.authHeader;
  }
  const client = axios.create({ baseURL, headers, timeout: 15000 });

  const messages: { role: string; content: string }[] = [];
  if (systemPrompt && systemPrompt.trim()) {
    messages.push({ role: 'system', content: systemPrompt });
  }
  for (const h of historyMessages) {
    try {
      const role = (h as unknown as { role?: string }).role || 'user';
      const content = h.getText();
      messages.push({ role, content });
    } catch {
      // ignore malformed
    }
  }
  messages.push({ role: 'user', content: userMessage });

  try {
    const resp = await client.post('/chat/completions', {
      model: overrides.model,
      messages,
    });
    const text = resp?.data?.choices?.[0]?.message?.content;
    if (typeof text === 'string' && text.length > 0) {
      return text;
    }
    debug('No choices[0].message.content; returning empty');
    return '';
  } catch (e: any) {
    debug('OpenWebUI direct error', e?.message || e);
    throw new Error('OpenWebUI direct request failed');
  }
}

import axios from 'axios';
import Debug from 'debug';
import type { IMessage } from '@src/message/interfaces/IMessage';
import type { ILlmProvider } from '@llm/interfaces/ILlmProvider';
import openWebUIConfig from './openWebUIConfig';

const debug = Debug('app:openWebUIProvider');

// Create axios instance with API URL and headers
const openWebUIClient = axios.create({
  baseURL: openWebUIConfig.get('apiUrl'),
  headers: {
    'Content-Type': 'application/json',
    Authorization: 'Bearer ollama', // Adjust as needed
  },
  timeout: 15000,
});

const model = openWebUIConfig.get('model');

/**
 * Provides chat and non-chat completion functionality for OpenWebUI.
 */
export const openWebUIProvider: ILlmProvider = {
  name: 'openwebui',
  supportsChatCompletion: (): boolean => true,
  supportsCompletion: (): boolean => true,
  supportsHistory: (): boolean => false,

  async generateChatCompletion(
    userMessage: string,
    historyMessages: IMessage[] = []
  ): Promise<string> {
    debug('Generating chat completion with OpenWebUI:', { userMessage, historyMessages });

    const messages = [
      ...historyMessages.map((msg) => ({ role: 'user', content: msg.getText() })),
      { role: 'user', content: userMessage },
    ];

    try {
      const response = await openWebUIClient.post('/chat/completions', {
        model,
        messages,
      });

      return response.data.choices[0].message.content;
    } catch (error) {
      debug('Error generating chat completion:', formatError(error));
      throw new Error(`Chat completion failed: ${getErrorMessage(error)}`);
    }
  },

  async generateCompletion(prompt: string): Promise<string> {
    debug('Generating non-chat completion with OpenWebUI:', { prompt });

    try {
      const response = await openWebUIClient.post('/completions', {
        model,
        prompt,
        max_tokens: 100,
      });

      return response.data.choices[0].text;
    } catch (error) {
      debug('Error generating non-chat completion:', formatError(error));
      throw new Error(`Non-chat completion failed: ${getErrorMessage(error)}`);
    }
  },
};

/**
 * Safely extracts the error message.
 */
function getErrorMessage(error: unknown): string {
  if (error instanceof Error) {
    return error.message;
  }
  return String(error);
}

/**
 * Formats the error for debugging purposes.
 */
function formatError(error: unknown): any {
  if (axios.isAxiosError(error)) {
    return error.response?.data || error.message;
  }
  return getErrorMessage(error);
}

import axios from 'axios';
import Debug from 'debug';
import { isSafeUrl } from '@src/utils/ssrfGuard';
import type { IMessage } from '@message/interfaces/IMessage';
import openWebUIConfig from './openWebUIConfig';
import { getSessionKey } from './sessionManager';
import { getKnowledgeFileId } from './uploadKnowledgeFile';

const debug = Debug('app:runInference');

/**
 * Executes inference using Open WebUI with the provided user message, chat history, and metadata.
 *
 * @param userMessage - The input from the user.
 * @param historyMessages - The message history.
 * @param metadata - Optional metadata for additional context.
 * @returns A promise resolving to the inference result with a text property.
 */
export async function generateChatCompletion(
  userMessage: string,
  historyMessages: IMessage[],
  metadata?: Record<string, any>
): Promise<{ text: string }> {
  const { apiUrl } = openWebUIConfig.getProperties();

  if (!userMessage || userMessage.trim() === '') {
    debug('Invalid user message:', userMessage);
    throw new Error('User message cannot be empty.');
  }

  const knowledgeFileId = getKnowledgeFileId();

  debug('Running inference with user message:', userMessage);
  debug('Using knowledge file ID:', knowledgeFileId);
  debug('History Messages:', historyMessages);
  debug('Metadata:', metadata);

  try {
    const sessionKey = await getSessionKey();
    const headers = {
      Authorization: 'Bearer ' + sessionKey,
      'Content-Type': 'application/json',
    };

    const url = apiUrl + '/chat/completions';
    const payload: any = {
      prompt: userMessage,
      knowledgeFileId,
      history: historyMessages.map((msg) => msg.getText()), // Convert to plain text
      metadata: metadata || {}, // Include metadata in payload
    };
    // Optional model override (for task routing).
    if (metadata && (metadata.modelOverride || metadata.model)) {
      payload.model = metadata.modelOverride || metadata.model;
    }
    if (
      metadata &&
      typeof metadata.systemPrompt === 'string' &&
      metadata.systemPrompt.trim() !== ''
    ) {
      payload.systemPrompt = metadata.systemPrompt;
    }

    if (!(await isSafeUrl(url))) {
      throw new Error('OpenWebUI API URL is not safe to connect to.');
    }

    const response = await axios.post(url, payload, { headers, timeout: 15000 });

    debug('Inference result:', response.data);
    // Assume OpenWebUI returns a string or object with a text field; adjust as needed
    const responseText =
      typeof response.data === 'string' ? response.data : response.data.text || 'No response';
    return { text: responseText };
  } catch (error) {
    debug('Inference request failed:', error);
    throw new Error('Inference failed. Please try again.');
  }
}

import Debug from 'debug';
import ProviderConfigManager from '@src/config/ProviderConfigManager';
import { MetricsCollector } from '@src/monitoring/MetricsCollector';
import { instantiateLlmProvider, loadPlugin } from '@src/plugins/PluginLoader';
import type { IConfigAccessor } from '@src/types/configAccessor';
import llmConfig from '@config/llmConfig';
import type { ILlmProvider } from '@llm/interfaces/ILlmProvider';
import type { IMessage } from '@message/interfaces/IMessage';

const debug = Debug('app:getLlmProvider');

interface CachedProvider {
  instance: ILlmProvider;
  configHash: string;
}

const providerCache = new Map<string, CachedProvider>();

function withTokenCounting(provider: ILlmProvider, _instanceId: string): ILlmProvider {
  const metrics = MetricsCollector.getInstance();

  return {
    name: provider.name,
    supportsChatCompletion: provider.supportsChatCompletion,
    supportsCompletion: provider.supportsCompletion,
    supportsHistory: provider.supportsHistory,
    // Add instance ID to provider object if interface allows, to help tracking?
    // For now we map it.
    generateChatCompletion: async (
      userMessage: string,
      historyMessages: IMessage[],
      // eslint-disable-next-line @typescript-eslint/no-explicit-any
      metadata?: Record<string, any>
    ): Promise<string> => {
      const response = await provider.generateChatCompletion(
        userMessage,
        historyMessages,
        metadata
      );
      if (response) {
        metrics.recordLlmTokenUsage(response.length);
      }
      return response;
    },
    generateCompletion: async (userMessage: string): Promise<string> => {
      const response = await provider.generateCompletion(userMessage);
      if (response) {
        metrics.recordLlmTokenUsage(response.length);
      }
      return response;
    },
  };
}

export function getLlmProvider(): ILlmProvider[] {
  const providerManager = ProviderConfigManager.getInstance();
  const configuredProviders = providerManager.getAllProviders('llm').filter((p) => p.enabled);

  const activeProviderIds = new Set<string>();
  const llmProviders: ILlmProvider[] = [];

  if (configuredProviders.length > 0) {
    // New System: Use configured instances
    for (const config of configuredProviders) {
      try {
        const configHash = JSON.stringify(config.config || {});
        const cached = providerCache.get(config.id);

        if (cached && cached.configHash === configHash) {
          llmProviders.push(cached.instance);
          activeProviderIds.add(config.id);
          continue;
        }

        let instance: ILlmProvider | undefined;
        try {
          const mod = loadPlugin(`llm-${config.type.toLowerCase()}`);
          instance = instantiateLlmProvider(mod, config.config);
          debug(`Initialized LLM provider via plugin loader: ${config.type} (${config.name})`);
        } catch (err) {
          debug(`Failed to load LLM plugin 'llm-${config.type}': ${err}`);
        }

        if (instance) {
          // We could attach the instance ID to the provider object if we extend the interface
          // We wrap it to count tokens
          const wrappedInstance = withTokenCounting(instance, config.id);
          providerCache.set(config.id, { instance: wrappedInstance, configHash });
          llmProviders.push(wrappedInstance);
          activeProviderIds.add(config.id);
        }
      } catch (error) {
        debug(`Failed to initialize provider ${config.name}: ${error}`);
      }
    }
  }

  if (llmProviders.length === 0) {
    // Fallback: Check Legacy Env Var (LLM_PROVIDER)
    // This is necessary if no migration happened or it failed, or for quick development.
    const rawProvider: unknown = (llmConfig as unknown as IConfigAccessor).get('LLM_PROVIDER');
    const legacyTypes = (
      typeof rawProvider === 'string'
        ? rawProvider.split(',').map((v: string) => v.trim())
        : Array.isArray(rawProvider)
          ? rawProvider
          : []
    ) as string[];

    if (legacyTypes.length > 0 && legacyTypes[0] !== '') {
      debug(`Fallback to legacy LLM_PROVIDER env var: ${legacyTypes.join(',')}`);
      for (const type of legacyTypes) {
        const legacyId = `legacy-${type}`;
        const configHash = 'legacy-env';

        const cached = providerCache.get(legacyId);
        if (cached && cached.configHash === configHash) {
          llmProviders.push(cached.instance);
          activeProviderIds.add(legacyId);
          continue;
        }

        let instance: ILlmProvider | undefined;
        try {
          const mod = loadPlugin(`llm-${type.toLowerCase()}`);
          instance = instantiateLlmProvider(mod, {});
          debug(`Initialized legacy LLM provider via plugin loader: ${type}`);
        } catch (err) {
          debug(`Failed to load legacy LLM plugin 'llm-${type}': ${err}`);
        }
        if (instance) {
          const wrappedInstance = withTokenCounting(instance, 'legacy');
          providerCache.set(legacyId, { instance: wrappedInstance, configHash });
          llmProviders.push(wrappedInstance);
          activeProviderIds.add(legacyId);
        }
      }
    }
  }

  if (llmProviders.length === 0) {
    // If still empty, default to OpenAI (legacy default)
    debug('No providers configured, defaulting to OpenAI (Legacy default)');
    const defaultId = 'default-openai';
    const configHash = 'default';

    const cached = providerCache.get(defaultId);
    if (cached && cached.configHash === configHash) {
      llmProviders.push(cached.instance);
      activeProviderIds.add(defaultId);
    } else {
      const mod = loadPlugin('llm-openai');
      const instance = instantiateLlmProvider(mod, {});
      const wrappedInstance = withTokenCounting(instance, 'default');
      providerCache.set(defaultId, { instance: wrappedInstance, configHash });
      llmProviders.push(wrappedInstance);
      activeProviderIds.add(defaultId);
    }
  }

  // Prune cache
  for (const key of providerCache.keys()) {
    if (!activeProviderIds.has(key)) {
      providerCache.delete(key);
      debug(`Removed stale provider from cache: ${key}`);
    }
  }

  return llmProviders;
}

import Debug from 'debug';
import ProviderConfigManager, { type ProviderInstance } from '@src/config/ProviderConfigManager';
import { MetricsCollector } from '@src/monitoring/MetricsCollector';
import llmTaskConfig from '@config/llmTaskConfig';
import { FlowiseProvider } from '@integrations/flowise/flowiseProvider';
import { openWebUIProvider as openWebUI } from '@integrations/openwebui/openWebUIProvider';
import { getLlmProvider } from '@llm/getLlmProvider';
import type { ILlmProvider } from '@llm/interfaces/ILlmProvider';
import type { IMessage } from '@message/interfaces/IMessage';

const debug = Debug('app:taskLlmRouter');

export type LlmTask = 'semantic' | 'summary' | 'followup' | 'idle';

export interface TaskLlmSelection {
  provider: ILlmProvider;
  metadata: Record<string, any>;
  source: 'default' | 'override';
}

function normalizeRef(v: string): string {
  return String(v || '')
    .trim()
    .toLowerCase();
}

function readOverride(task: LlmTask): { providerRef: string; modelRef: string } {
  // Primary (new) env vars via convict
  const keyProvider = `LLM_TASK_${task.toUpperCase()}_PROVIDER` as const;
  const keyModel = `LLM_TASK_${task.toUpperCase()}_MODEL` as const;

  const providerRef = String((llmTaskConfig.get as any)(keyProvider) || '').trim();
  const modelRef = String((llmTaskConfig.get as any)(keyModel) || '').trim();

  // Back-compat aliases (if someone uses older naming conventions)
  const aliasProvider = String(process.env[`LLM_${task.toUpperCase()}_PROVIDER`] || '').trim();
  const aliasModel = String(process.env[`LLM_${task.toUpperCase()}_MODEL`] || '').trim();

  return {
    providerRef: providerRef || aliasProvider,
    modelRef: modelRef || aliasModel,
  };
}

function withTokenCounting(provider: ILlmProvider, instanceId: string): ILlmProvider {
  const metrics = MetricsCollector.getInstance();
  return {
    name: provider.name,
    supportsChatCompletion: provider.supportsChatCompletion,
    supportsCompletion: provider.supportsCompletion,
    supportsHistory: provider.supportsHistory,
    generateChatCompletion: async (
      userMessage: string,
      historyMessages: IMessage[],
      metadata?: Record<string, any>
    ) => {
      const response = await provider.generateChatCompletion(
        userMessage,
        historyMessages,
        metadata
      );
      if (response) {
        metrics.recordLlmTokenUsage(response.length);
      }
      return response;
    },
    generateCompletion: async (userMessage: string) => {
      const response = await provider.generateCompletion(userMessage);
      if (response) {
        metrics.recordLlmTokenUsage(response.length);
      }
      return response;
    },
  };
}

function createProviderFromInstance(
  instance: ProviderInstance,
  modelOverride?: string
): ILlmProvider | null {
  try {
    const type = String(instance.type || '').toLowerCase();
    const baseConfig = instance.config || {};
    const cfg = modelOverride ? { ...baseConfig, model: modelOverride } : baseConfig;

    let provider: ILlmProvider | undefined;
    switch (type) {
      case 'openai':
        const { OpenAiProvider } = require('@hivemind/llm-openai');
        provider = new OpenAiProvider(cfg);
        break;
      case 'flowise':
        provider = new FlowiseProvider(cfg);
        break;
      case 'openwebui':
        provider = openWebUI;
        break;
      default:
        return null;
    }

    return withTokenCounting(provider, instance.id);
  } catch (e) {
    debug(
      `Failed to create provider for instance ${instance.id}: ${e instanceof Error ? e.message : String(e)}`
    );
    return null;
  }
}

function pickProviderInstance(
  ref: string,
  candidates: ProviderInstance[]
): ProviderInstance | null {
  const wanted = normalizeRef(ref);
  if (!wanted) {
    return null;
  }

  // Prefer exact id match.
  const byId = candidates.find((p) => normalizeRef(p.id) === wanted);
  if (byId) {
    return byId;
  }

  // Then by name (case-insensitive).
  const byName = candidates.find((p) => normalizeRef(p.name) === wanted);
  if (byName) {
    return byName;
  }

  // Then by type (first enabled provider of that type).
  const byType = candidates.find((p) => normalizeRef(p.type) === wanted);
  if (byType) {
    return byType;
  }

  return null;
}

export function getTaskLlm(
  task: LlmTask,
  opts?: { fallbackProviders?: ILlmProvider[]; baseMetadata?: Record<string, any> }
): TaskLlmSelection {
  const overrides = readOverride(task);
  const providerRef = overrides.providerRef;
  const modelRef = overrides.modelRef;

  const baseMetadata = opts?.baseMetadata || {};
  const metadata: Record<string, any> = { ...baseMetadata };
  if (modelRef) {
    metadata.modelOverride = modelRef;
  }

  const fallbackProviders =
    opts?.fallbackProviders && opts.fallbackProviders.length > 0
      ? opts.fallbackProviders
      : getLlmProvider();

  if (!fallbackProviders || fallbackProviders.length === 0) {
    throw new Error('No LLM providers available for task routing');
  }

  if (!providerRef) {
    return {
      provider: fallbackProviders[0],
      metadata,
      source: modelRef ? 'override' : 'default',
    };
  }

  const providerManager = ProviderConfigManager.getInstance();
  const enabled = providerManager.getAllProviders('llm').filter((p) => p.enabled);
  const picked = pickProviderInstance(providerRef, enabled);

  if (!picked) {
    debug(
      `Task ${task}: provider override "${providerRef}" not found; falling back to default providers`
    );
    return { provider: fallbackProviders[0], metadata, source: 'default' };
  }

  const instanceProvider = createProviderFromInstance(picked, modelRef);
  if (!instanceProvider) {
    debug(
      `Task ${task}: provider instance "${picked.id}" failed to initialize; falling back to default providers`
    );
    return { provider: fallbackProviders[0], metadata, source: 'default' };
  }

  debug(
    `Task ${task}: using override provider=${picked.name} (type=${picked.type}, id=${picked.id}) model=${modelRef || '(default)'}`
  );
  return { provider: instanceProvider, metadata, source: 'override' };
}

import crypto from 'crypto';
import { EventEmitter } from 'events';
import fs from 'fs';
import path from 'path';
import Debug from 'debug';
import { BotConfigurationManager } from '@config/BotConfigurationManager';
import { SecureConfigManager } from '@config/SecureConfigManager';
import { UserConfigStore } from '@config/UserConfigStore';
import { getLlmDefaultStatus } from '../config/llmDefaultStatus';
import type { MCPGuardConfig } from '../mcp/MCPGuard';
import type { MCPConfig } from '../mcp/MCPService';
import { getMessengerServiceByProvider } from '../message/ProviderRegistry';
import { webUIStorage } from '../storage/webUIStorage';
import { ErrorUtils } from '../types/errors';
import { checkBotEnvOverrides } from '../utils/envUtils';

const debug = Debug('app:BotManager');

export interface BotInstance {
  id: string;
  name: string;
  messageProvider: string;
  llmProvider: string;
  isActive: boolean;
  createdAt: string;
  lastModified: string;
  config: Record<string, unknown>;
  persona?: string;
  systemInstruction?: string;
  mcpServers?: MCPConfig[];
  mcpGuard?: MCPGuardConfig;
  envOverrides?: Record<string, { isOverridden: boolean; redactedValue?: string }>;
}

export interface CreateBotRequest {
  name: string;
  messageProvider: 'discord' | 'slack' | 'mattermost';
  llmProvider?: 'openai' | 'flowise' | 'openwebui' | 'openswarm';
  config?: {
    discord?: {
      token: string;
      voiceChannelId?: string;
    };
    slack?: {
      botToken: string;
      signingSecret: string;
      appToken?: string;
    };
    mattermost?: {
      serverUrl: string;
      token: string;
    };
    openai?: {
      apiKey: string;
      model?: string;
    };
    flowise?: {
      apiKey: string;
      endpoint?: string;
    };
    openwebui?: {
      apiKey: string;
      endpoint?: string;
    };
  };
  persona?: string;
  systemInstruction?: string;
  mcpServers?: MCPConfig[];
  mcpGuard?: MCPGuardConfig;
}

export class BotManager extends EventEmitter {
  private static instance: BotManager;
  private botConfigManager: BotConfigurationManager;
  private secureConfigManager: SecureConfigManager;
  private customBots = new Map<string, BotInstance>();
  private botsFilePath: string;

  constructor() {
    super();
    this.botConfigManager = BotConfigurationManager.getInstance();
    this.secureConfigManager = SecureConfigManager.getInstance();
    this.botsFilePath = path.join(process.cwd(), 'config', 'user', 'custom-bots.json');
    this.loadCustomBots();
    debug('BotManager initialized');
  }

  public static getInstance(): BotManager {
    if (!BotManager.instance) {
      BotManager.instance = new BotManager();
    }
    return BotManager.instance;
  }

  /**
   * Generate a stable ID for configured bots based on name
   */
  private getStableId(name: string): string {
    return crypto.createHash('md5').update(name).digest('hex').substring(0, 8);
  }

  /**
   * Load custom bots from file

  /**
   * Load custom bots from file
   */
  private loadCustomBots(): void {
    try {
      if (fs.existsSync(this.botsFilePath)) {
        const data = fs.readFileSync(this.botsFilePath, 'utf8');
        const bots = JSON.parse(data);
        this.customBots.clear();
        Object.entries(bots).forEach(([id, bot]: [string, unknown]) => {
          // Type guard to ensure the unknown value matches BotInstance interface
          if (this.isValidBotInstance(bot)) {
            this.customBots.set(id, bot);
          } else {
            debug(`Invalid bot instance found for ID ${id}, skipping`);
          }
        });
        debug(`Loaded ${this.customBots.size} custom bots`);
      }
    } catch (error: unknown) {
      debug('Error loading custom bots:', ErrorUtils.getMessage(error));
    }
  }

  /**
   * Save custom bots to file
   */
  private saveCustomBots(): void {
    try {
      const botsDir = path.dirname(this.botsFilePath);
      if (!fs.existsSync(botsDir)) {
        fs.mkdirSync(botsDir, { recursive: true });
      }

      const bots = Object.fromEntries(this.customBots);
      fs.writeFileSync(this.botsFilePath, JSON.stringify(bots, null, 2));
      debug(`Saved ${this.customBots.size} custom bots`);
    } catch (error: unknown) {
      debug('Error saving custom bots:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError('Failed to save custom bots', 'configuration');
    }
  }

  /**
   * Get all bot instances (both configured and custom)
   */
  public async getAllBots(): Promise<BotInstance[]> {
    try {
      const configuredBots = this.botConfigManager.getAllBots();
      const botMap = new Map<string, BotInstance>();

      // Add configured bots first
      for (const bot of configuredBots) {
        const botInstance: BotInstance = {
          // Use bot name as stable ID - random UUIDs break getBot() lookups
          id: bot.name,
          name: bot.name,
          messageProvider: bot.messageProvider,
          llmProvider: bot.llmProvider,
          isActive: true, // Configured bots are considered active
          createdAt: new Date().toISOString(),
          lastModified: new Date().toISOString(),
          config: this.sanitizeConfig(bot),
          persona: bot.persona || 'default',
          systemInstruction: bot.systemInstruction,
          mcpServers: bot.mcpServers || [],
          mcpGuard: bot.mcpGuard || { enabled: false, type: 'owner' },
          envOverrides: checkBotEnvOverrides(bot.name),
        };
        botMap.set(botInstance.id, botInstance);
      }

      // Add custom bots from web UI storage (overwriting configured bots with same ID)
      const customBots = webUIStorage.getAgents();
      for (const bot of customBots) {
        botMap.set(bot.id, bot);
      }

      const botInstances = Array.from(botMap.values());
      debug(`Retrieved ${botInstances.length} bot instances`);
      return botInstances;
    } catch (error: unknown) {
      debug('Error getting all bots:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError('Failed to retrieve bot instances', 'configuration');
    }
  }

  /**
   * Get a specific bot by ID
   */
  public async getBot(botId: string): Promise<BotInstance | null> {
    try {
      // Check custom bots first
      if (this.customBots.has(botId)) {
        const bot = this.customBots.get(botId)!;
        debug(`Retrieved custom bot: ${bot.name} (${bot.id})`);
        return bot;
      }

      // Check configured bots
      const bots = await this.getAllBots();
      const bot = bots.find((b) => b.id === botId);

      if (bot) {
        debug(`Retrieved configured bot: ${bot.name} (${bot.id})`);
      } else {
        debug(`Bot not found: ${botId}`);
      }

      return bot || null;
    } catch (error: unknown) {
      debug('Error getting bot:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError('Failed to retrieve bot instance', 'configuration');
    }
  }

  /**
   * Create a new bot instance
   */
  public async createBot(request: CreateBotRequest): Promise<BotInstance> {
    try {
      // Validate the request
      this.validateCreateBotRequest(request);

      // Generate unique ID
      const botId = crypto.randomUUID();

      // Create bot instance
      const botInstance: BotInstance = {
        id: botId,
        name: request.name,
        messageProvider: request.messageProvider,
        llmProvider: request.llmProvider?.trim() || '',
        isActive: false, // New bots start inactive
        createdAt: new Date().toISOString(),
        lastModified: new Date().toISOString(),
        config: this.sanitizeConfig(request.config || {}),
        persona: request.persona,
        systemInstruction: request.systemInstruction,
        mcpServers: request.mcpServers,
        mcpGuard: request.mcpGuard,
      };

      // Store sensitive configuration securely
      await this.storeSecureConfig(botId, request.config || {});

      // Add to web UI storage
      webUIStorage.saveAgent(botInstance);

      debug(`Created new bot: ${request.name} (${botId})`);

      // Emit event for real-time updates
      this.emit('botCreated', botInstance);

      return botInstance;
    } catch (error: unknown) {
      debug('Error creating bot:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError(
        `Failed to create bot: ${ErrorUtils.getMessage(error)}`,
        'configuration'
      );
    }
  }

  /**
   * Type guard to validate BotInstance
   */
  private isValidBotInstance(obj: unknown): obj is BotInstance {
    if (!obj || typeof obj !== 'object') {
      return false;
    }

    const bot = obj as Record<string, unknown>;

    return (
      typeof bot.id === 'string' &&
      typeof bot.name === 'string' &&
      typeof bot.messageProvider === 'string' &&
      typeof bot.llmProvider === 'string' &&
      typeof bot.isActive === 'boolean' &&
      typeof bot.createdAt === 'string' &&
      typeof bot.lastModified === 'string' &&
      typeof bot.config === 'object' &&
      bot.config !== null
    );
  }

  /**
   * Clone an existing bot instance
   */
  public async cloneBot(botId: string, newName: string): Promise<BotInstance> {
    try {
      const sourceBot = await this.getBot(botId);
      if (!sourceBot) {
        throw new Error('Source bot not found');
      }

      // Check if it's a custom bot
      const customBots = webUIStorage.getAgents();
      const isCustom = customBots.some((b) => b.id === botId);

      if (isCustom) {
        // Clone as custom bot (existing logic)
        const cloneRequest: CreateBotRequest = {
          name: newName,
          messageProvider: sourceBot.messageProvider as 'discord' | 'slack' | 'mattermost',
          llmProvider: (sourceBot.llmProvider || undefined) as
            | 'openai'
            | 'flowise'
            | 'openwebui'
            | 'openswarm'
            | undefined,
          config: sourceBot.config as CreateBotRequest['config'],
          persona: sourceBot.persona,
          systemInstruction: sourceBot.systemInstruction,
          mcpServers: sourceBot.mcpServers,
          mcpGuard: sourceBot.mcpGuard,
        };

        const clonedBot = await this.createBot(cloneRequest);
        debug(`Cloned custom bot ${sourceBot.name} (${botId}) to ${newName} (${clonedBot.id})`);
        this.emit('botCloned', { sourceBot, clonedBot });
        return clonedBot;
      } else {
        // Clone as configured bot (file-based)
        await this.botConfigManager.cloneBot(botId, newName);

        // Retrieve the new configured bot instance
        const clonedBot = await this.getBot(newName);
        if (!clonedBot) {
          throw new Error(`Failed to retrieve cloned configured bot "${newName}"`);
        }

        debug(`Cloned configured bot ${sourceBot.name} (${botId}) to ${newName}`);
        this.emit('botCloned', { sourceBot, clonedBot });
        return clonedBot;
      }
    } catch (error: unknown) {
      debug('Error cloning bot:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError(
        `Failed to clone bot: ${ErrorUtils.getMessage(error)}`,
        'configuration'
      );
    }
  }

  /**
   * Update an existing bot instance
   */
  public async updateBot(botId: string, updates: Partial<CreateBotRequest>): Promise<BotInstance> {
    try {
      const existingBot = await this.getBot(botId);
      if (!existingBot) {
        throw new Error('Bot not found');
      }

      // Validate updates
      if (updates.config) {
        this.validateBotConfig(updates.config);
      }

      // Update bot instance
      const updatedBot: BotInstance = {
        ...existingBot,
        ...updates,
        lastModified: new Date().toISOString(),
        config: updates.config
          ? this.sanitizeConfig({ ...existingBot.config, ...updates.config })
          : existingBot.config,
        persona: updates.persona !== undefined ? updates.persona : existingBot.persona,
        systemInstruction:
          updates.systemInstruction !== undefined
            ? updates.systemInstruction
            : existingBot.systemInstruction,
        mcpServers: updates.mcpServers !== undefined ? updates.mcpServers : existingBot.mcpServers,
        mcpGuard: updates.mcpGuard !== undefined ? updates.mcpGuard : existingBot.mcpGuard,
      };

      // Store updated secure config if provided
      if (updates.config) {
        await this.storeSecureConfig(botId, updates.config);
      }

      // Update in web UI storage
      webUIStorage.saveAgent(updatedBot);

      debug(`Updated bot: ${updatedBot.name} (${botId})`);

      // Emit event for real-time updates
      this.emit('botUpdated', updatedBot);

      return updatedBot;
    } catch (error: unknown) {
      debug('Error updating bot:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError(
        `Failed to update bot: ${ErrorUtils.getMessage(error)}`,
        'configuration'
      );
    }
  }

  /**
   * Delete a bot instance
   */
  public async deleteBot(botId: string): Promise<void> {
    try {
      const bot = await this.getBot(botId);
      if (!bot) {
        throw new Error(`Bot not found: ${botId}`);
      }

      // Check if it's a custom bot
      const customBots = webUIStorage.getAgents();
      const isCustom = customBots.some((b) => b.id === botId);

      if (isCustom) {
        // Remove from web UI storage
        webUIStorage.deleteAgent(botId);
        // Remove secure configuration
        await this.secureConfigManager.deleteConfig(`bot_${botId}`);
      } else {
        // Assume it's a configured bot
        try {
          await this.botConfigManager.deleteBot(botId);
          // Also try to remove secure config if it exists
          await this.secureConfigManager.deleteConfig(`bot_${botId}`);
        } catch (err: any) {
          debug(`Failed to delete configured bot ${botId}: ${err.message}`);
          throw err;
        }
      }

      debug(`Deleted bot: ${bot.name} (${botId})`);

      // Emit event for real-time updates
      this.emit('botDeleted', bot);
    } catch (error: unknown) {
      debug('Error deleting bot:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError(
        `Failed to delete bot: ${ErrorUtils.getMessage(error)}`,
        'configuration'
      );
    }
  }

  /**
   * Start a bot instance
  /**
   * Start a bot instance
   */
  public async startBot(botId: string): Promise<boolean> {
    try {
      const bot = await this.getBot(botId);
      if (!bot) {
        throw new Error('Bot not found');
      }

      // Persist enabled state to user config file
      const userConfigStore = UserConfigStore.getInstance();
      await userConfigStore.setBotDisabled(bot.name, false);
      debug(`Persisted enabled state for bot: ${bot.name}`);

      // Update bot status in memory
      const updatedBot = { ...bot, isActive: true, lastModified: new Date().toISOString() };
      const isCustomBot = this.customBots.has(botId);
      if (isCustomBot) {
        this.customBots.set(botId, updatedBot);
        this.saveCustomBots();
      }

      await this.startBotById(botId);

      // Send Welcome Message when bot is enabled (if configured)
      const enableWelcome = process.env.ENABLE_WELCOME_MESSAGE === 'true';
      if (enableWelcome) {
        try {
          const service = await this.getMessengerService(bot.messageProvider);
          if (service) {
            const defaultChannel =
              (bot.config as any)?.slack?.defaultChannelId ||
              (bot.config as any)?.discord?.defaultChannelId ||
              service.getDefaultChannel?.();
            if (defaultChannel) {
              const welcomeText =
                process.env.WELCOME_MESSAGE_TEXT || '🤖 I am now online and ready to assist.';
              await service.sendMessageToChannel(defaultChannel, welcomeText);
              debug(`Sent welcome message for bot ${bot.name} to channel ${defaultChannel}`);
            }
          }
        } catch (welcomeErr: any) {
          debug(`Failed to send welcome message for ${bot.name}:`, welcomeErr?.message);
        }
      }

      debug(`Started bot: ${bot.name} (${botId})`);

      // Emit event for real-time updates
      this.emit('botStarted', updatedBot);

      return true;
    } catch (error: unknown) {
      debug('Error starting bot:', ErrorUtils.getMessage(error));
