export class PersonaManager extends EventEmitter {
  private static instance: PersonaManager;
  private personas = new Map<string, Persona>();
  private personasFilePath: string;

  private constructor() {
    super();
    this.personasFilePath = path.join(process.cwd(), 'config', 'user', 'custom-personas.json');
    this.loadPersonas();
    debug('PersonaManager initialized');
  }

  public static getInstance(): PersonaManager {
    if (!PersonaManager.instance) {
      PersonaManager.instance = new PersonaManager();
    }
    return PersonaManager.instance;
  }

  private loadPersonas(): void {
    try {
      // Clear existing personas (for reload functionality)
      this.personas.clear();

      // Load built-ins first
      BUILTIN_PERSONAS.forEach((p) => this.personas.set(p.id, { ...p }));

      if (fs.existsSync(this.personasFilePath)) {
        const data = fs.readFileSync(this.personasFilePath, 'utf8');
        const customPersonas = JSON.parse(data);

        Object.values(customPersonas).forEach((p: any) => {
          // Determine ID if not present (migration) or just use id
          if (p.id) {
            this.personas.set(p.id, p);
          }
        });
        debug(`Loaded ${Object.keys(customPersonas).length} custom personas`);
      }
    } catch (error: any) {
      debug('Error loading personas:', ErrorUtils.getMessage(error));
    }
  }

  /**
   * Reload personas from disk (useful for runtime refresh without restart)
   */
  public reloadPersonas(): void {
    debug('Reloading personas from disk');
    this.loadPersonas();
    this.emit('personasReloaded');
  }

  private savePersonas(): void {
    try {
      const personasDir = path.dirname(this.personasFilePath);
      if (!fs.existsSync(personasDir)) {
        fs.mkdirSync(personasDir, { recursive: true });
      }

      // Filter out built-ins before saving
      const customPersonas: Record<string, Persona> = {};
      for (const [id, persona] of this.personas.entries()) {
        if (!persona.isBuiltIn) {
          customPersonas[id] = persona;
        }
      }

      fs.writeFileSync(this.personasFilePath, JSON.stringify(customPersonas, null, 2));
      debug(`Saved ${Object.keys(customPersonas).length} custom personas`);
    } catch (error: any) {
      debug('Error saving personas:', ErrorUtils.getMessage(error));
      throw ErrorUtils.createError('Failed to save personas', 'configuration');
    }
  }

  public getAllPersonas(): Persona[] {
    return Array.from(this.personas.values());
  }

  public getPersona(id: string): Persona | undefined {
    return this.personas.get(id);
  }

  public createPersona(request: CreatePersonaRequest): Persona {
    const id = crypto.randomUUID();
    const newPersona: Persona = {
      id,
      ...request,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    this.personas.set(id, newPersona);
    this.savePersonas();
    this.emit('personaCreated', newPersona);
    return newPersona;
  }

  public updatePersona(id: string, updates: UpdatePersonaRequest): Persona {
    const existing = this.personas.get(id);
    if (!existing) {
      throw new Error(`Persona with ID ${id} not found`);
    }

    if (existing.isBuiltIn) {
      throw new Error('Cannot update built-in personas');
    }

    const updated: Persona = {
      ...existing,
      ...updates,
      updatedAt: new Date().toISOString(),
    };

    this.personas.set(id, updated);
    this.savePersonas();
    this.emit('personaUpdated', updated);
    return updated;
  }

  public clonePersona(id: string, overrides?: Partial<CreatePersonaRequest>): Persona {
    const existing = this.personas.get(id);
    if (!existing) {
      throw new Error(`Persona with ID ${id} not found`);
    }

    const newId = crypto.randomUUID();
    const clonedPersona: Persona = {
      ...existing,
      ...overrides,
      id: newId,
      isBuiltIn: false, // Cloned personas are always custom
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
    };

    this.personas.set(newId, clonedPersona);
    this.savePersonas();
    this.emit('personaCreated', clonedPersona);
    return clonedPersona;
  }

  public deletePersona(id: string): boolean {
    const existing = this.personas.get(id);
    if (!existing) {
      return false;
    }

    if (existing.isBuiltIn) {
      throw new Error('Cannot delete built-in personas');
    }

    this.personas.delete(id);
    this.savePersonas();
    this.emit('personaDeleted', id);
    return true;
  }
}

/**
 * TimingManager handles message timing delays.
 */
class TimingManager {
  config: { minDelay: number; maxDelay: number; decayRate: number };
  channelsTimingInfo: Record<string, { lastIncomingMessageTime: number }>;
  channelTimers: Record<string, NodeJS.Timeout>;

  constructor(
    config: { minDelay: number; maxDelay: number; decayRate: number } = {
      minDelay: 1000,
      maxDelay: 10000,
      decayRate: -0.5,
    }
  ) {
    if (config.minDelay > config.maxDelay) {
      throw new Error('minDelay cannot be greater than maxDelay');
    }
    this.config = config;
    this.channelsTimingInfo = {};
    this.channelTimers = {};
  }

  get minDelay(): number {
    return this.config.minDelay;
  }

  get maxDelay(): number {
    return this.config.maxDelay;
  }

  get decayRate(): number {
    return this.config.decayRate;
  }

  logIncomingMessage(channelId: string): void {
    this.channelsTimingInfo[channelId] = { lastIncomingMessageTime: Date.now() };
  }

  calculateDelay(channelId: string, processingTime: number): number {
    const channelInfo = this.channelsTimingInfo[channelId];
    if (!channelInfo || !channelInfo.lastIncomingMessageTime) {
      return this.config.maxDelay;
    }

    const timeSinceLastMessage = Date.now() - channelInfo.lastIncomingMessageTime;
    const baseDelay = this.config.minDelay + processingTime;

    // Adaptive delay based on time since last message
    let adaptiveDelay = baseDelay;
    if (timeSinceLastMessage < 1000) {
      // Very recent activity
      adaptiveDelay = this.config.minDelay;
    } else if (timeSinceLastMessage > 30000) {
      // Old activity
      adaptiveDelay = this.config.maxDelay;
    }

    // Ensure delay is within bounds
    if (adaptiveDelay < this.config.minDelay) {
      adaptiveDelay = this.config.minDelay;
    }
    if (adaptiveDelay > this.config.maxDelay) {
      adaptiveDelay = this.config.maxDelay;
    }

    return adaptiveDelay;
  }

  scheduleMessage(
    channelId: string,
    messageContent: string,
    processingTime: number,
    sendFunction: (text: string) => void
  ): void {
    // Clear any existing timer for this channel
    if (this.channelTimers[channelId]) {
      clearTimeout(this.channelTimers[channelId]);
    }

    const delay = this.calculateDelay(channelId, processingTime);
    this.channelTimers[channelId] = setTimeout(() => {
      try {
        sendFunction(messageContent);
      } catch (error) {
        // Log error but don't throw to prevent crashing
        console.error('Error in send function:', error);
      }
      // Clean up the timer reference
      delete this.channelTimers[channelId];
    }, delay);
  }
}

module.exports = TimingManager;

import Debug from 'debug';
import { SlackMessageProvider } from '@hivemind/message-slack';
import { BotConfigurationManager } from '@config/BotConfigurationManager';
import { MCPGuard, type MCPGuardConfig } from './MCPGuard';

// DiscordMessageProvider imported dynamically to avoid ESM require error

const debug = Debug('app:mcp');

export interface MCPConfig {
  serverUrl: string;
  apiKey?: string;
  name: string;
}

export interface MCPTool {
  name: string;
  description?: string;
  inputSchema?: any;
  serverName: string;
}

export class MCPService {
  private static instance: MCPService;
  private clients = new Map<string, any>();
  private tools = new Map<string, MCPTool[]>();

  private constructor() {}

  /**
   * Gets the singleton instance of MCPService.
   *
   * @returns {MCPService} The singleton instance
   * @example
   * ```typescript
   * const mcpService = MCPService.getInstance();
   * const tools = mcpService.getAllTools();
   * ```
   */

  public static getInstance(): MCPService {
    if (!MCPService.instance) {
      MCPService.instance = new MCPService();
    }
    return MCPService.instance;
  }

  /**
   * Test connection to an MCP server without storing the client
   */
  public async testConnection(config: MCPConfig): Promise<MCPTool[]> {
    try {
      debug(`Testing connection to MCP server: ${config.name} at ${config.serverUrl}`);

      // Dynamically require the MCP SDK
      const { Client } = require('@modelcontextprotocol/sdk');

      // Create a new client for this server
      const client = new Client({
        name: 'Open-Hivemind-Test',
        version: '1.0.0',
      });

      // Connect to the server
      await client.connect({
        url: config.serverUrl,
        apiKey: config.apiKey,
      });

      // Try to list tools to verify connection works
      const tools = await client.listTools();

      // Add server name to each tool for identification
      const mcpTools: MCPTool[] = tools.tools.map((tool: any) => ({
        ...tool,
        serverName: config.name,
      }));

      // If we got here, connection is successful
      // Since SDK doesn't have disconnect, we just let it go out of scope
      // Ideally we would close the transport if accessible

      return mcpTools;
    } catch (error) {
      debug(`Error testing connection to MCP server ${config.name}:`, error);
      throw new Error(
        `Failed to connect to MCP server ${config.name}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Connects to an MCP server and discovers available tools.
   *
   * @param {MCPConfig} config - The server configuration containing URL and API key
   * @returns {Promise<MCPTool[]>} Array of discovered tools from the server
   * @throws {Error} If connection fails or server is unreachable
   * @example
   * ```typescript
   * const tools = await mcpService.connectToServer({
   *   name: 'my-server',
   *   serverUrl: 'https://api.example.com/mcp',
   *   apiKey: 'secret-key'
   * });
   * ```
   */

  public async connectToServer(config: MCPConfig): Promise<MCPTool[]> {
    try {
      debug(`Connecting to MCP server: ${config.name} at ${config.serverUrl}`);

      // Dynamically require the MCP SDK
      const { Client } = require('@modelcontextprotocol/sdk');

      // Create a new client for this server
      const client = new Client({
        name: 'Open-Hivemind',
        version: '1.0.0',
      });

      // Connect to the server
      await client.connect({
        url: config.serverUrl,
        apiKey: config.apiKey,
      });

      // Store the client
      this.clients.set(config.name, client);

      // Discover tools
      const tools = await client.listTools();

      // Add server name to each tool for identification
      const mcpTools: MCPTool[] = tools.tools.map((tool: any) => ({
        ...tool,
        serverName: config.name,
      }));

      // Store tools
      this.tools.set(config.name, mcpTools);

      debug(`Discovered ${tools.tools.length} tools from ${config.name}`);

      return mcpTools;
    } catch (error) {
      debug(`Error connecting to MCP server ${config.name}:`, error);
      throw new Error(
        `Failed to connect to MCP server ${config.name}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Disconnect from an MCP server
   */
  public async disconnectFromServer(serverName: string): Promise<void> {
    try {
      const client = this.clients.get(serverName);
      if (client) {
        // MCP SDK doesn't have an explicit disconnect method, so we'll just remove it
        this.clients.delete(serverName);
        this.tools.delete(serverName);
        debug(`Disconnected from MCP server: ${serverName}`);
      }
    } catch (error) {
      debug(`Error disconnecting from MCP server ${serverName}:`, error);
      throw new Error(
        `Failed to disconnect from MCP server ${serverName}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  /**
   * Disconnect from all MCP servers - used for graceful shutdown
   */
  public async disconnectAll(): Promise<void> {
    debug('Disconnecting from all MCP servers...');

    const serverNames = Array.from(this.clients.keys());
    const disconnectPromises = serverNames.map((serverName) =>
      this.disconnectFromServer(serverName)
    );

    await Promise.allSettled(disconnectPromises);

    this.clients.clear();
    this.tools.clear();

    debug('All MCP connections closed');
  }

  /**
   * Get all tools from all connected servers
   */
  public getAllTools(): MCPTool[] {
    const allTools: MCPTool[] = [];
    for (const tools of this.tools.values()) {
      allTools.push(...tools);
    }
    return allTools;
  }

  /**
   * Get tools from a specific server
   */
  public getToolsFromServer(serverName: string): MCPTool[] | undefined {
    return this.tools.get(serverName);
  }

  /**
   * Get all connected server names
   */
  public getConnectedServers(): string[] {
    return Array.from(this.clients.keys());
  }

  /**
   * Executes a tool on a connected MCP server.
   *
   * @param {string} serverName - The name of the MCP server
   * @param {string} toolName - The name of the tool to execute
   * @param {any} arguments_ - The arguments to pass to the tool
   * @param {Object} [context] - Optional execution context for guard validation
   * @param {string} [context.botName] - The bot name for guard checks
   * @param {string} [context.messageProvider] - The message provider type
   * @param {string} [context.forumId] - The forum/channel ID
   * @param {string} [context.forumOwnerId] - The forum owner's user ID
   * @param {string} [context.userId] - The user ID executing the tool
   * @returns {Promise<any>} The result from the tool execution
   * @throws {Error} If not connected to server or tool execution fails
   * @example
   * ```typescript
   * const result = await mcpService.executeTool(
   *   'my-server',
   *   'search',
   *   { query: 'hello world' },
   *   { botName: 'assistant', userId: 'user123' }
   * );
   * ```
   */

  public async executeTool(
    serverName: string,
    toolName: string,
    arguments_: any,
    context?: {
      botName?: string;
      messageProvider?: string;
      forumId?: string;
      forumOwnerId?: string;
      userId?: string;
    }
  ): Promise<any> {
    try {
      if (context?.botName) {
        await this.assertGuardAllowsExecution(context);
      }

      const client = this.clients.get(serverName);
      if (!client) {
        throw new Error(`Not connected to MCP server: ${serverName}`);
      }

      debug(`Executing tool ${toolName} on server ${serverName}`);
      const result = await client.callTool({
        name: toolName,
        arguments: arguments_,
      });
      debug('Tool execution result:', result);

      return result;
    } catch (error) {
      debug(`Error executing tool ${toolName} on server ${serverName}:`, error);
      throw new Error(
        `Failed to execute tool ${toolName} on server ${serverName}: ${error instanceof Error ? error.message : String(error)}`
      );
    }
  }

  private async assertGuardAllowsExecution(context: {
    botName?: string;
    messageProvider?: string;
    forumId?: string;
    forumOwnerId?: string;
    userId?: string;
  }): Promise<void> {
    const { botName, messageProvider, forumId, forumOwnerId, userId } = context;

    if (!botName) {
      return;
    }

    const manager = BotConfigurationManager.getInstance();
    const botConfig = manager.getBot(botName);
    if (!botConfig?.mcpGuard) {
      return;
    }

    const guard: MCPGuardConfig = botConfig.mcpGuard;
    if (!guard.enabled) {
      return;
    }

    if (!userId) {
      throw new Error('MCP tool access denied: requesting user ID is required.');
    }

    let ownerId = forumOwnerId || null;
    if (!ownerId && forumId) {
      ownerId = await this.resolveForumOwner(messageProvider || botConfig.messageProvider, forumId);
    }

    if (guard.type === 'owner' && !ownerId) {
      throw new Error('MCP tool access denied: unable to determine forum owner.');
    }

    const allowed = MCPGuard.isUserAllowed(userId, ownerId || '', guard);
    if (!allowed) {
      throw new Error('MCP tool access denied by guard configuration.');
    }
  }

  private async resolveForumOwner(
    providerName: string | undefined,
    forumId: string
  ): Promise<string | null> {
    if (!providerName) {
      return null;
    }

    const normalized = providerName.toLowerCase();

    try {
      if (normalized === 'slack') {
        const provider = new SlackMessageProvider();
        return await provider.getForumOwner(forumId);
      }

      if (normalized === 'discord') {
        const { DiscordMessageProvider } = await import('@hivemind/message-discord');
        const provider = new DiscordMessageProvider();
        return await provider.getForumOwner(forumId);
      }
    } catch (error) {
      debug(`Unable to resolve forum owner via provider ${providerName}:`, error);
    }

    return null;
  }
}

/**
 * Dynamic Provider Registry for Messenger Service Loading
 *
 * Providers are discovered at runtime by scanning the integrations directory.
 * Convention: Each integration folder should export a service implementing IMessengerService
 * with a static getInstance() method.
 *
 * Discovery patterns:
 * - src/integrations/{name}/{Name}Service.ts (e.g., discord/DiscordService.ts)
 * - The exported class should have a static getInstance() method
 *
 * Type Guards ensure only valid IMessengerService implementations are loaded.
 */
import fs from 'fs';
import path from 'path';
import Debug from 'debug';
import type { IMessengerService } from './interfaces/IMessengerService';

const debug = Debug('app:ProviderRegistry');

// Cache of loaded providers
const loadedProviders = new Map<string, IMessengerService>();

// Discovered provider metadata
const discoveredProviders = new Map<string, { modulePath: string; serviceExport: string }>();

let initialized = false;

/**
 * Type guard to check if a module export is a valid IMessengerService factory.
 */
function isValidServiceFactory(obj: any): obj is { getInstance: () => IMessengerService } {
  return obj && typeof obj === 'function' && typeof obj.getInstance === 'function';
}

/**
 * Type guard to check if an instance implements IMessengerService.
 */
function isMessengerService(obj: any): obj is IMessengerService {
  return (
    obj &&
    typeof obj.initialize === 'function' &&
    typeof obj.sendMessageToChannel === 'function' &&
    typeof obj.getMessagesFromChannel === 'function' &&
    typeof obj.shutdown === 'function'
  );
}

/**
 * Discover available providers by scanning the integrations directory.
 * This is called lazily on first access.
 */
function discoverProviders(): void {
  if (initialized) return;
  initialized = true;

  const integrationsDir = path.join(__dirname, '..', 'integrations');

  if (!fs.existsSync(integrationsDir)) {
    debug('Integrations directory not found');
    return;
  }

  const entries = fs.readdirSync(integrationsDir, { withFileTypes: true });

  for (const entry of entries) {
    if (!entry.isDirectory()) continue;

    const providerName = entry.name.toLowerCase();
    const pascalName = providerName.charAt(0).toUpperCase() + providerName.slice(1);
    const serviceFileName = `${pascalName}Service`;
    const providerDir = path.join(integrationsDir, entry.name);

    // Look for {Name}Service.ts or {Name}Service.js
    const possiblePaths = [
      path.join(providerDir, `${serviceFileName}.ts`),
      path.join(providerDir, `${serviceFileName}.js`),
    ];

    for (const filePath of possiblePaths) {
      if (fs.existsSync(filePath)) {
        discoveredProviders.set(providerName, {
          modulePath: path.relative(__dirname, filePath).replace(/\.(ts|js)$/, ''),
          serviceExport: serviceFileName,
        });
        debug(`Discovered provider: ${providerName} -> ${serviceFileName}`);
        break;
      }
    }
  }

  debug(`Provider discovery complete: ${discoveredProviders.size} providers found`);
}

/**
 * Dynamically load and get a messenger service by provider name.
 * Returns null if not found, disabled, or fails validation.
 */
export async function getMessengerServiceByProvider(
  providerName: string
): Promise<IMessengerService | null> {
  discoverProviders();

  const normalizedName = providerName.toLowerCase();

  // Check cache first
  if (loadedProviders.has(normalizedName)) {
    return loadedProviders.get(normalizedName)!;
  }

  const providerMeta = discoveredProviders.get(normalizedName);
  if (!providerMeta) {
    debug(`Provider "${providerName}" was not discovered.`);
    return null;
  }

  try {
    debug(`Loading provider: ${providerName}`);

    // Dynamic import
    const module = await import(providerMeta.modulePath);
    const ServiceClass = module[providerMeta.serviceExport];

    // Validate factory pattern
    if (!isValidServiceFactory(ServiceClass)) {
      debug(`Provider "${providerName}" does not have a valid getInstance() factory`);
      return null;
    }

    const service = ServiceClass.getInstance();

    // Validate IMessengerService interface
    if (!isMessengerService(service)) {
      debug(`Provider "${providerName}" does not implement IMessengerService correctly`);
      return null;
    }

    loadedProviders.set(normalizedName, service);
    debug(`Successfully loaded provider: ${providerName}`);
    return service;
  } catch (error: any) {
    debug(`Failed to load provider "${providerName}": ${error.message}`);
    return null;
  }
}

/**
 * Get list of all discovered provider names.
 */
export function getRegisteredProviders(): string[] {
  discoverProviders();
  return Array.from(discoveredProviders.keys());
}

/**
 * Check if a provider is discovered.
 */
export function isProviderRegistered(providerName: string): boolean {
  discoverProviders();
  return discoveredProviders.has(providerName.toLowerCase());
}

/**
 * Get list of currently loaded (active) providers.
 */
export function getLoadedProviders(): string[] {
  return Array.from(loadedProviders.keys());
}

/**
 * Unload a provider from cache (e.g. when disabling).
 */
export function unloadProvider(providerName: string): void {
  const normalizedName = providerName.toLowerCase();
  if (loadedProviders.has(normalizedName)) {
    loadedProviders.delete(normalizedName);
    debug(`Unloaded provider: ${providerName}`);
  }
}

/**
 * Force re-discovery of providers (useful after adding new integrations).
 */
export function refreshProviders(): void {
  initialized = false;
  discoveredProviders.clear();
  discoverProviders();
}

// src/message/common/chatHistory.ts

import type { IMessage } from '@src/message/interfaces/IMessage';

/**
 * ChatHistory - Tracks messages sent by the bot for timing and activity purposes.
 *
 * This class allows the bot to store, query, and manage its own messages, providing features such as:
 * - Tracking recent messages with timestamps and channels.
 * - Querying messages within a specific timeframe.
 * - Clearing old messages to maintain memory efficiency.
 */
export class ChatHistory {
  private static instance: ChatHistory;
  private history: IMessage[] = [];

  /**
   * Singleton pattern: Ensures only one instance of ChatHistory is used across the bot.
   * @returns {ChatHistory} The single instance of ChatHistory.
   */
  public static getInstance(): ChatHistory {
    if (!ChatHistory.instance) {
      ChatHistory.instance = new ChatHistory();
    }
    return ChatHistory.instance;
  }

  /**
   * Adds a new message to the chat history.
   * @param {IMessage} message - The IMessage instance to add.
   */
  public addMessage(message: IMessage): void {
    this.history.push(message);
    console.debug('[ChatHistory] Message added:', message.getMessageId());
  }

  /**
   * Retrieves all messages sent within the specified timeframe.
   * @param {number} timeframe - The time in milliseconds to look back (e.g., last 60000 ms).
   * @returns {IMessage[]} An array of messages sent within the timeframe.
   */
  public getRecentMessages(timeframe: number): IMessage[] {
    if (timeframe <= 0) {
      console.error('[ChatHistory] Invalid timeframe provided:', timeframe);
      return [];
    }
    const currentTime = Date.now();
    const recentMessages = this.history.filter(
      (msg) => currentTime - msg.getTimestamp().getTime() <= timeframe
    );
    console.debug(
      '[ChatHistory] Recent messages retrieved:',
      recentMessages.map((m) => m.getMessageId())
    );
    return recentMessages;
  }

  /**
   * Clears messages older than the specified cutoff time.
   * @param {number} cutoffTime - The time in milliseconds (messages older than this will be removed).
   */
  public clearOldMessages(cutoffTime: number): void {
    const cutoffDate = new Date(Date.now() - cutoffTime);
    const initialLength = this.history.length;
    this.history = this.history.filter((msg) => msg.getTimestamp() > cutoffDate);
    const clearedMessages = initialLength - this.history.length;
    console.debug(
      `[ChatHistory] Cleared ${clearedMessages} old messages. Current history size: ${this.history.length}`
    );
  }
}

/**
 * Common UI elements and message types for cross-platform compatibility.
 *
 * This module provides standardized interfaces for UI elements and messages
 * that work across different messaging platforms (Discord, Slack, etc.).
 */

/**
 * Represents a UI element that can be displayed across different platforms.
 *
 * This interface provides a common structure for various UI elements like
 * text, buttons, images, and embeds that can be rendered appropriately
 * on different messaging platforms.
 *
 * @interface
 * @example
 * ```typescript
 * const button: ICommonUIElement = {
 *   type: 'button',
 *   text: 'Click me',
 *   url: 'https://example.com'
 * };
 * ```
 */
export interface ICommonUIElement {
  /**
   * The type of UI element to display.
   * @type {'text' | 'button' | 'image' | 'embed'}
   */
  type: 'text' | 'button' | 'image' | 'embed';

  /**
   * The text content for the UI element.
   * Used for text, button labels, or embed descriptions.
   * @type {string}
   * @optional
   */
  text?: string;

  /**
   * The URL for the UI element.
   * Used for button links, image sources, or embed URLs.
   * @type {string}
   * @optional
   */
  url?: string;

  /**
   * Additional properties can be added here as needed.
   * For example: action IDs for buttons, embed titles, etc.
   */
  [key: string]: any;
}

/**
 * Common message interface that standardizes messages across platforms.
 *
 * This interface provides a unified structure for messages from different
 * messaging platforms, ensuring consistent handling regardless of the source.
 *
 * @interface
 * @example
 * ```typescript
 * const message: ICommonMessage = {
 *   text: "Hello, world!",
 *   senderId: "user123",
 *   channelId: "general",
 *   timestamp: new Date(),
 *   uiElements: [
 *     { type: 'button', text: 'Learn More', url: 'https://example.com' }
 *   ]
 * };
 * ```
 */
export interface ICommonMessage {
  /**
   * The text content of the message.
   * @type {string}
   */
  text: string;

  /**
   * The unique identifier of the message sender.
   * @type {string}
   */
  senderId: string;

  /**
   * The unique identifier of the channel where the message was sent.
   * @type {string}
   */
  channelId: string;

  /**
   * The timestamp when the message was created.
   * @type {Date}
   */
  timestamp: Date;

  /**
   * Optional array of UI elements to display with the message.
   * @type {ICommonUIElement[]}
   * @optional
   */
  uiElements?: ICommonUIElement[];
}

