/**
 * Main message handler that processes incoming messages and generates responses.
 *
 * This function handles the complete message processing pipeline including:
 * - Input sanitization and validation
 * - Command processing
 * - Reply eligibility determination
 * - Delay and timing management
 * - LLM inference with retry logic
 * - Response sending with typing indicators
 *
 * @param {IMessage} message - The incoming message to process
 * @param {IMessage[]} [historyMessages=[]] - Previous messages for context
 * @param {any} botConfig - Bot configuration settings
 * @returns {Promise<string | null>} The generated response, or null if no response should be sent
 *
 * @example
 * ```typescript
 * const response = await handleMessage(
 *   message,
 *   historyMessages,
 *   botConfig
 * );
 * if (response) {
 *   console.log('Bot responded:', response);
 * }
 * ```
 */

export async function handleMessage(
  message: IMessage,
  historyMessages: IMessage[] = [],
  botConfig: any
): Promise<string | null> {
  return await PerformanceMonitor.measureAsync(
    async () => {
      const channelId = message.getChannelId();
      let resolvedBotId = botConfig.BOT_ID || botConfig.name || 'unknown-bot';
      let delayKey: string | null = null;
      let isLeaderInvocation = false;
      let didLock = false;
      const activeAgentName = botConfig.MESSAGE_USERNAME_OVERRIDE || botConfig.name || 'Bot';
      let providerSenderKey = activeAgentName;
      let typingInterval: NodeJS.Timeout | null = null;
      let typingTimeout: NodeJS.Timeout | null = null;
      let stopTyping = false;
      let historyTuneKey: string | null = null;
      let historyTuneRequestedLimit: number | null = null;

      // Use a per-bot debug namespace so logs are easily attributable in swarm mode.
      const logger = Debug(`app:messageHandler:${activeAgentName}`);

      // Helper for random integer (chaos)
      const randInt = (min: number, max: number): number =>
        Math.floor(Math.random() * (max - min + 1)) + min;

      // Log received message
      const userId = message.getAuthorId();
      const text = message.getText();
      if (text) {
        // Only log if text exists (check logic inside later handles empty text, but we need text for log)
        AuditLogger.getInstance().logBotAction(
          userId,
          'UPDATE',
          botConfig.name || botConfig.BOT_ID || 'unknown-bot',
          'success',
          `Received message: "${text.substring(0, 50)}${text.length > 50 ? '...' : ''}"`,
          {
            metadata: {
              type: 'MESSAGE_RECEIVED',
              channelId: channelId,
              botId: botConfig.BOT_ID || 'unknown-bot',
              content: text,
            },
          }
        );
      }

      try {
        const text = message.getText();
        if (!text) {
          logger('Empty message content, skipping processing.');
          return null;
        }

        // Sanitize input
        const sanitizedText = InputSanitizer.sanitizeMessage(text);
        const validation = InputSanitizer.validateMessage(sanitizedText);
        if (!validation.isValid) {
          logger(`Invalid message: ${validation.reason}`);
          return null;
        }

        // Get providers safely
        const messageProviders = await getMessengerProvider();
        const llmProviders = await getLlmProvider();

        if (messageProviders.length === 0) {
          console.error('No message provider available');
          logger('No message provider available');
          return null;
        }

        if (llmProviders.length === 0) {
          console.error('No LLM provider available');
          logger('No LLM provider available');
          return null;
        }

        const messageProvider = messageProviders[0];
        const llmProvider = llmProviders[0];
        const providerType =
          botConfig.messageProvider ||
          botConfig.MESSAGE_PROVIDER ||
          botConfig.integration ||
          'generic';
        const platform = providerType.toLowerCase();

        // Delegate platform-specific identity/routing to the integration layer.
        const resolvedAgentContext =
          typeof (messageProvider as any)?.resolveAgentContext === 'function'
            ? (messageProvider as any).resolveAgentContext({
                botConfig,
                agentDisplayName: activeAgentName,
              })
            : null;

        const botId = String(
          resolvedAgentContext?.botId || botConfig?.BOT_ID || messageProvider.getClientId() || ''
        );
        resolvedBotId = botId || resolvedBotId;
        providerSenderKey = String(
          resolvedAgentContext?.senderKey || botConfig?.name || activeAgentName
        );
        const userId = message.getAuthorId();
        let processedMessage = stripBotId(text, botId);
        processedMessage = addUserHint(processedMessage, userId, botId);

        logger(
          `Processing message in channel ${message.getChannelId()} from user ${userId}: "${processedMessage}"`
        );
        logger(`Processed message: "${processedMessage}"`);

        // Command processing
        let commandProcessed = false;
        if (botConfig.MESSAGE_COMMAND_INLINE) {
          await processCommand(message, async (result: string): Promise<void> => {
            const authorisedUsers = botConfig.MESSAGE_COMMAND_AUTHORISED_USERS || '';
            const allowedUsers = authorisedUsers.split(',').map((user: string) => user.trim());
            if (!allowedUsers.includes(userId)) {
              logger('User not authorized:', userId);
              await messageProvider.sendMessageToChannel(
                message.getChannelId(),
                'You are not authorized to use commands.',
                providerSenderKey
              );
              if (resolvedBotId) {
                recordBotActivity(message.getChannelId(), resolvedBotId);
              }
              commandProcessed = true;
              return;
            }
            await messageProvider.sendMessageToChannel(
              message.getChannelId(),
              result,
              providerSenderKey
            );
            if (resolvedBotId) {
              recordBotActivity(message.getChannelId(), resolvedBotId);
            }
            commandProcessed = true;
          });
          if (commandProcessed) {
            return null;
          }
        }

        // Reply eligibility

        // Record interaction for idle response tracking
        const serviceName = botConfig.MESSAGE_PROVIDER || 'generic';
        // Only record non-bot messages as "interactions" to avoid bots (including our own idle replies)
        // continuously rescheduling idle responses.
        if (!message.isFromBot()) {
          idleResponseManager.recordInteraction(
            serviceName,
            message.getChannelId(),
            message.getMessageId()
          );
        }

        const replyNameCandidates: string[] = Array.from(
          new Set(
            (resolvedAgentContext?.nameCandidates || [activeAgentName, botConfig?.name])
              .filter(Boolean)
              .map((v: any) => String(v))
          )
        );

        const defaultChannelId =
          typeof (messageProvider as any).getDefaultChannel === 'function'
            ? (messageProvider as any).getDefaultChannel()
            : undefined;

        const replyDecision = await shouldReplyToMessage(
          message,
          botId,
          platform,
          replyNameCandidates,
          historyMessages,
          defaultChannelId,
          botConfig
        );
        const decisionTimestamp = Date.now();

        // Safely extract human-readable names for logging
        const authorName = (() => {
          try {
            return (
              (typeof message.getAuthorName === 'function' ? message.getAuthorName() : null) ||
              (typeof message.getAuthorId === 'function'
                ? `user:${message.getAuthorId()}`
                : 'someone')
            );
          } catch {
            return 'someone';
          }
        })();
        const channelName = (() => {
          try {
            // Try to get channel name from the original message if Discord
            const orig = (message as any).getOriginalMessage?.();
            if (orig?.channel?.name) {
              return `#${orig.channel.name}`;
            }
            return `ch:${channelId.slice(-6)}`; // Truncated ID fallback
          } catch {
            return `ch:${channelId.slice(-6)}`;
          }
        })();

        if (!replyDecision.shouldReply) {
          logger(`Message not eligible for reply: ${replyDecision.reason}`);
          if (replyDecision.reason !== 'Message from self') {
            // Prose explanation at info level with context
            let prose = replyDecision.meta?.prose || replyDecision.reason;
            prose = await summarizeLogWithLlm(prose);
            console.info(`🚫 ${botConfig.name} skips @${authorName} in ${channelName}: ${prose}`);
          }
          return null;
        }

        // Logic for handling "Leader" bot role in swarm mode
        isLeaderInvocation = !!replyDecision.meta?.isLeader;
        delayKey = `${channelId}:${resolvedBotId}`;

        // If we are responding, attempt to lock this channel for this bot to prevent double-replying.
        if (processingLocks.isLocked(channelId, resolvedBotId)) {
          logger(`Could not acquire lock for channel ${channelId}, skipping.`);
          return null;
        }
        processingLocks.lock(channelId, resolvedBotId);
        didLock = true;

        // Calculate and apply delays
        const density = IncomingMessageDensity.getInstance().getDensity(channelId);
        const isFollowUp =
          historyMessages.length > 0 &&
          historyMessages[historyMessages.length - 1].getAuthorId() === botId;

        const minDelay = Number(botConfig.MESSAGE_MIN_DELAY || 0);
        if (minDelay > 0) {
          logger(`Waiting ${minDelay}ms before processing...`);
          await new Promise((resolve) => setTimeout(resolve, minDelay));
        }

        // Set up typing indicators
        if (botConfig.MESSAGE_TYPING_INDICATOR) {
          typingInterval = setInterval(async () => {
            if (stopTyping) return;
            try {
              await messageProvider.sendTypingIndicator(channelId);
            } catch (err) {
              logger('Failed to send typing indicator:', err);
            }
          }, 4000);

          typingTimeout = setTimeout(() => {
            stopTyping = true;
            if (typingInterval) clearInterval(typingInterval);
          }, 30000);
        }

        // Prepare LLM request
        const systemPrompt = buildSystemPromptWithBotName(
          botConfig.MESSAGE_SYSTEM_PROMPT || '',
          activeAgentName
        );

        // Track and trim history (skip for stateful providers that manage their own)
        const maxHistoryTokens = Number(botConfig.LLM_MAX_HISTORY_TOKENS || 2000);
        const providerWantsHistory = llmProvider.supportsHistory
          ? llmProvider.supportsHistory()
          : true;
        const trimmedHistory = providerWantsHistory
          ? trimHistoryToTokenBudget(historyMessages, {
              inputBudgetTokens: maxHistoryTokens,
              promptText: processedMessage,
            })
          : { trimmed: [] as IMessage[] };

        // Generate response
        const startTime = Date.now();
        let llmResponse: any;

        if (botConfig.MESSAGE_LLM_DIRECT) {
          llmResponse = await generateChatCompletionDirect(
            botConfig as any,
            processedMessage,
            trimmedHistory.trimmed,
            systemPrompt
          );
        } else {
          llmResponse = await llmProvider.generateChatCompletion(
            processedMessage,
            trimmedHistory.trimmed,
            {
              systemPrompt,
              maxTokens: Number(botConfig.LLM_MAX_TOKENS || 150),
              temperature: Number(botConfig.LLM_TEMPERATURE || 0.7),
              channelId: message.getChannelId(),
              userId: message.getAuthorId(),
            }
          );
        }

        stopTyping = true;
        if (typingInterval) clearInterval(typingInterval);
        if (typingTimeout) clearTimeout(typingTimeout);

        if (!llmResponse || !llmResponse.text) {
          logger('LLM returned empty response.');
          return null;
        }

        let responseText = stripSystemPromptLeak(llmResponse.text, systemPrompt);

        // Clean up formatting
        responseText = responseText.replace(/\\n/g, '\n').trim();

        if (responseText) {
          // Split into parts if needed and send
          const parts = splitMessageContent(
            responseText,
            Number(botConfig.MESSAGE_MAX_LENGTH || 2000)
          );

          for (const part of parts) {
            const finalReplyId = botConfig.MESSAGE_REPLY_IN_THREAD
              ? message.getMessageId()
              : undefined;
            const sentTs = await messageProvider.sendMessageToChannel(
              channelId,
              part,
              providerSenderKey,
              undefined,
              finalReplyId
            );

            // Post-send accounting
            duplicateDetector.recordMessage(channelId, part);
            outgoingRateLimiter.recordSend(channelId);
            if (resolvedBotId) recordBotActivity(channelId, resolvedBotId);

            idleResponseManager.recordBotResponse(serviceName, channelId);
          }
        }

        const endTime = Date.now();
        const processingTime = endTime - startTime;
        logger(`Message processed in ${processingTime}ms`);
        return llmResponse.text;
      } catch (error: unknown) {
        ErrorHandler.handle(error, 'messageHandler.handleMessage');
        const modelInfo = botConfig
          ? ` | provider: ${botConfig.llmProvider} | model: ${botConfig.llmModel || 'default'}`
          : '';
        console.info(
          `❌ INFERENCE/PROCESSING FAILED | error: ${error instanceof Error ? error.message : String(error)}${modelInfo}`
        );
        console.error(
          `Error processing message: ${error instanceof Error ? error.message : String(error)}`
        );
        return null;
      } finally {
        stopTyping = true;
        // Stop typing indicator interval if running.
        if (typingInterval) {
          try {
            clearInterval(typingInterval);
          } catch {}
          typingInterval = null;
        }
        if (typingTimeout) {
          try {
            clearTimeout(typingTimeout);
          } catch {}
          typingTimeout = null;
        }
        // Always unlock the channel after processing
        if (didLock) {
          try {
            processingLocks.unlock(channelId, resolvedBotId);
          } catch {}
        }
        if (isLeaderInvocation && delayKey) {
          try {
            channelDelayManager.clear(delayKey);
          } catch {}
        }
      }
    },
    'handleMessage',
    5000
  ); // 5 second threshold for warnings
}

function stripSystemPromptLeak(response: string, ...promptTexts: string[]): string {
  let out = String(response ?? '');
  if (!out) {
    return out;
  }

  const prompts = (promptTexts || [])
    .map((p) => String(p || ''))
    .map((p) => p.trim())
    .filter(Boolean);

  if (prompts.length === 0) {
    return out;
  }

  for (const p of prompts) {
    if (!p) {
      continue;
    }
    if (!out.includes(p)) {
      continue;
    }
    out = out.replaceAll(p, '');
  }

  return out.trim();
}

function buildSystemPromptWithBotName(baseSystemPrompt: unknown, botName: string): string {
  const base = typeof baseSystemPrompt === 'string' ? baseSystemPrompt.trim() : '';
  const name = String(botName || '').trim();
  const hint = name
    ? `You are ${name}. Your display name in chat is "${name}".`
    : 'You are an assistant operating inside a multi-user chat.';

  if (!base) {
    return hint;
  }
  // Put the hint first so models see it early.
  return `${hint}\n\n${base}`;
}

import type { IMessage } from '@message/interfaces/IMessage';

export interface PermissionConfig {
  authorizedUsers?: string[];
  adminOnlyCommands?: string[];
  channelRestrictions?: Record<string, string[]>;
  rateLimits?: Record<string, { count: number; window: number; lastReset: number }>;
}

export function isAuthorizedUser(userId: string, authorizedUsers: string[] = []): boolean {
  if (!userId || !Array.isArray(authorizedUsers) || authorizedUsers.length === 0) {
    return false;
  }
  return authorizedUsers.includes(userId);
}

export function checkCommandPermissions(
  message: IMessage,
  command: string,
  config: PermissionConfig = {}
): boolean {
  if (!config || typeof config !== 'object') {
    return false;
  }

  // Bot messages never allowed
  if (typeof message.isFromBot === 'function' && message.isFromBot()) {
    return false;
  }

  const userId = message.getAuthorId?.() || '';
  const channelId = message.getChannelId?.() || '';
  const authorizedUsers = config.authorizedUsers || [];

  // Must be an authorized user for any command
  if (!isAuthorizedUser(userId, authorizedUsers)) {
    return false;
  }

  // Admin-only commands: treat userId === 'admin' as admin for tests
  if (Array.isArray(config.adminOnlyCommands) && config.adminOnlyCommands.includes(command)) {
    if (userId !== 'admin') {
      return false;
    }
  }

  // Channel-specific restrictions: if channel listed, user must be in that list
  if (config.channelRestrictions && channelId in config.channelRestrictions) {
    const allowed = config.channelRestrictions[channelId] || [];
    if (!allowed.includes(userId)) {
      return false;
    }
  }

  // Rate limits: allow within provided count/window; tests only assert allowed path
  // Keeping permissive behavior unless implementing counters

  return true;
}

import { parseCommand, type ParsedCommand } from './parseCommand';
import { handleStatusCommand } from './statusCommand';

/**
 * Routes parsed commands to their respective handlers.
 *
 * @param {string} commandContent - The raw command message from Slack.
 * @returns {Promise<string | null>} The response message or null if the command is unrecognized.
 */
export async function routeCommand(commandContent: string): Promise<string | null> {
  const parsed: ParsedCommand | null = parseCommand(commandContent);

  if (!parsed) {
    return null;
  }

  try {
    switch (parsed.commandName) {
      case 'status':
        return await handleStatusCommand(parsed.args);
      // Add additional command handlers here as needed
      default:
        return `Unrecognized command: ${parsed.commandName}`;
    }
  } catch (error: any) {
    return `Error: ${error.message}`;
  }
}

import os from 'os';

export interface SystemStatus {
  operational: boolean;
  uptime: number;
  memory: {
    free: number;
    total: number;
    used: number;
  };
  loadAverage: number[];
  timestamp?: Date;
}

/**
 * Retrieves the current system status, including memory usage and uptime.
 * @returns {SystemStatus} An object containing operational status, uptime, memory stats, etc.
 */
export function getSystemStatus(): SystemStatus {
  const memInfo = process.memoryUsage();
  const totalMem = os.totalmem();
  const freeMem = os.freemem();

  return {
    operational: true,
    uptime: process.uptime(),
    memory: {
      free: freeMem,
      total: totalMem,
      used: totalMem - freeMem,
    },
    loadAverage: os.loadavg(),
    timestamp: new Date(),
  };
}

export function formatStatusResponse(status: SystemStatus, args: string[]): string {
  const hasVerbose = args.includes('--verbose');
  const hasJson = args.includes('--json');
  const hasHealth = args.includes('--health');
  const hasMetrics = args.includes('--metrics');
  const serviceIndex = args.indexOf('--service');
  const specificService = serviceIndex >= 0 ? args[serviceIndex + 1] : null;

  if (hasJson && !hasVerbose) {
    return JSON.stringify(
      {
        operational: status.operational,
        status: status.operational ? 'operational' : 'degraded',
        uptime: status.uptime,
        memory: status.memory,
        loadAverage: status.loadAverage,
        timestamp:
          status.timestamp instanceof Date
            ? status.timestamp.toISOString()
            : new Date().toISOString(),
      },
      null,
      2
    );
  }

  let response = status.operational
    ? 'System is operational. All services are running smoothly.'
    : 'System is experiencing issues.';

  if (hasVerbose) {
    const uptimeHours = Math.floor(status.uptime / 3600);
    const uptimeMinutes = Math.floor((status.uptime % 3600) / 60);
    // Heuristic: tests provide MB-scale numbers; runtime uses bytes.
    const total = status.memory.total;
    const divisor = total > 10000 ? 1024 * 1024 * 1024 : 1024;
    const memoryGB = (status.memory.used / divisor).toFixed(1);
    const totalMemoryGB = (total / divisor).toFixed(1);

    response += `\n\nUptime: ${uptimeHours}h ${uptimeMinutes}m`;
    response += `\nMemory: ${memoryGB}GB / ${totalMemoryGB}GB`;
    response += `\nLoad Average: ${status.loadAverage.map((l) => l.toFixed(2)).join(', ')}`;
  }

  if (hasHealth) {
    response += '\n\nHealth Check:';
    response += '\nServices:';
    response += '\n  - Discord: Operational';
    response += '\n  - LLM Provider: Operational';
    response += '\n  - Database: Operational';
  }

  if (hasMetrics) {
    response += '\n\nSystem Metrics:';
    response += `\nCPU Load: ${status.loadAverage[0].toFixed(2)}`;
    response += `\nMemory Usage: ${((status.memory.used / status.memory.total) * 100).toFixed(1)}%`;
    response += `\nUptime: ${Math.floor(status.uptime / 3600)}h ${Math.floor((status.uptime % 3600) / 60)}m`;
  }

  if (specificService) {
    response += `\n\n${specificService.charAt(0).toUpperCase() + specificService.slice(1)} Service:`;
    response += '\nStatus: Operational';
    response += '\nConnections: Active';
    response += '\nLatency: <100ms';
  }

  return response;
}

export async function handleStatusCommand(args: string[] = []): Promise<string> {
  const status = getSystemStatus();
  return formatStatusResponse(status, args);
}

import Debug from 'debug';

const debug = Debug('app:ChannelDelayManager');

interface ChannelDelayState {
  delayUntil: number;
  isLeaderAssigned: boolean;
  leaderMessageId?: string; // Kept for reference
  latestMessageId?: string; // The most recent message in the burst
  pendingMessageIds: Set<string>;
  lastMessageIdFromTrigger?: string;
  triggerUserId?: string;
}

/**
 * Coalesces bursts of incoming messages into a single delayed processing run.
 *
 * - The first message becomes the "leader" and waits until delay expires.
 * - Subsequent messages extend the delay (up to max) and return immediately.
 * - The leader refetches channel history after the delay, so it naturally includes
 *   messages that arrived during the waiting period.
 */
export class ChannelDelayManager {
  private static instance: ChannelDelayManager;
  private states = new Map<string, ChannelDelayState>();

  public static getInstance(): ChannelDelayManager {
    if (!ChannelDelayManager.instance) {
      ChannelDelayManager.instance = new ChannelDelayManager();
    }
    return ChannelDelayManager.instance;
  }

  public getKey(channelId: string, botId: string): string {
    return `${channelId}:${botId}`;
  }

  public registerMessage(
    key: string,
    messageId: string,
    userId: string,
    baseDelayMs: number,
    maxDelayMs: number
  ): { isLeader: boolean } {
    const now = Date.now();
    const existing = this.states.get(key);

    if (!existing) {
      const state: ChannelDelayState = {
        delayUntil: now + baseDelayMs,
        isLeaderAssigned: true,
        leaderMessageId: messageId,
        latestMessageId: messageId,
        pendingMessageIds: new Set([messageId]),
        triggerUserId: userId,
        lastMessageIdFromTrigger: messageId,
      };
      this.states.set(key, state);
      debug(`[${key}] leader=${messageId} delayUntil=${state.delayUntil}`);
      return { isLeader: true };
    }

    existing.pendingMessageIds.add(messageId);
    existing.latestMessageId = messageId; // Update latest
    if (existing.triggerUserId === userId) {
      existing.lastMessageIdFromTrigger = messageId;
    }

    // Extend delay window (but keep bounded)
    if (existing.delayUntil - now < maxDelayMs) {
      const remaining = Math.max(0, existing.delayUntil - now);
      const extended = Math.min(maxDelayMs, remaining + baseDelayMs);
      existing.delayUntil = now + extended;
      debug(
        `[${key}] extended delayUntil=${existing.delayUntil} pending=${existing.pendingMessageIds.size}`
      );
      console.info(
        `⏳ DELAY EXTENDED | key: ${key} | added: ${baseDelayMs}ms | total_pending: ${existing.pendingMessageIds.size}`
      );
    }

    return { isLeader: false };
  }

  public ensureMinimumDelay(key: string, minDelayMs: number, maxDelayMs: number): void {
    const state = this.states.get(key);
    if (!state) {
      return;
    }
    const now = Date.now();
    const desiredUntil = now + minDelayMs;
    const maxUntil = now + maxDelayMs;
    state.delayUntil = Math.min(maxUntil, Math.max(state.delayUntil, desiredUntil));
  }

  public getRemainingDelayMs(key: string): number {
    const state = this.states.get(key);
    if (!state) {
      return 0;
    }
    return Math.max(0, state.delayUntil - Date.now());
  }

  public getReplyToMessageId(key: string): string | undefined {
    const state = this.states.get(key);
    if (!state) {
      return undefined;
    }

    // User requested: only reply-to if delay was extended (i.e. compounding happened).
    // If only 1 message, it implies direct response, so no explicit reply needed.
    if (state.pendingMessageIds.size <= 1) {
      return undefined;
    }

    // User requested: "reply to the most recent message" if more messages came in.
    return state.latestMessageId || state.leaderMessageId;
  }

  public async waitForDelay(key: string): Promise<void> {
    const remaining = this.getRemainingDelayMs(key);
    if (remaining > 0) {
      debug(`[${key}] Enforcing delay: sleeping for ${remaining}ms`);
      await new Promise((resolve) => setTimeout(resolve, remaining));
    }
  }

  public clear(key: string): void {
    this.states.delete(key);
  }
}

export default ChannelDelayManager;

