      return [
        {
          used: 0,
          total: 0,
          free: 0,
          usagePercent: 0,
        },
      ];
    }
  }

  private getDiskUsage(path: string): {
    used: number;
    total: number;
    free: number;
    usagePercent: number;
  } {
    try {
      const stats = fs.statSync(path);
      // This is a simplified implementation
      // In a real scenario, you'd use a library like 'diskusage' or 'systeminformation'
      return {
        used: 0, // Placeholder
        total: 100 * 1024 * 1024 * 1024, // 100GB placeholder
        free: 50 * 1024 * 1024 * 1024, // 50GB placeholder
        usagePercent: 50,
      };
    } catch (error) {
      return {
        used: 0,
        total: 0,
        free: 0,
        usagePercent: 0,
      };
    }
  }

  private getNetworkStats(): { rx: number; tx: number } {
    // This is a simplified implementation
    // In a real scenario, you'd use a library to get actual network statistics
    return {
      rx: Math.floor(Math.random() * 1000000),
      tx: Math.floor(Math.random() * 1000000),
    };
  }

  // Public API methods
  public getSystemMetrics(limit = 100): SystemMetrics[] {
    return this.systemMetrics.slice(-limit);
  }

  public getApplicationMetrics(limit = 100): ApplicationMetrics[] {
    return this.applicationMetrics.slice(-limit);
  }

  public getHealthStatus(): HealthStatus {
    const latestSystemMetrics = this.systemMetrics[this.systemMetrics.length - 1];
    // Adjusted thresholds: >95% memory = unhealthy, 85-95% = degraded
    // High memory usage alone (without errors) should be a warning, not critical failure
    const overall: 'healthy' | 'degraded' | 'unhealthy' =
      latestSystemMetrics &&
      (latestSystemMetrics.memory.usagePercent > 95 || latestSystemMetrics.cpu.usage > 95)
        ? 'unhealthy'
        : latestSystemMetrics &&
            (latestSystemMetrics.memory.usagePercent > 85 || latestSystemMetrics.cpu.usage > 85)
          ? 'degraded'
          : 'healthy';

    return {
      overall,
      services: {
        system: {
          status: overall === 'healthy' ? 'up' : 'degraded',
          lastCheck: Date.now(),
        },
        monitoring: {
          status: 'up',
          lastCheck: Date.now(),
        },
      },
      alerts: this.alerts.filter((a) => !a.resolved),
    };
  }

  public getAlerts(activeOnly = true): Alert[] {
    return activeOnly ? this.alerts.filter((a) => !a.resolved) : this.alerts;
  }

  public resolveAlert(alertId: string): boolean {
    const alert = this.alerts.find((a) => a.id === alertId);
    if (alert && !alert.resolved) {
      alert.resolved = true;
      alert.resolvedAt = Date.now();
      debug(`Alert resolved: ${alertId}`);
      return true;
    }
    return false;
  }

  public getMetricsSummary(): {
    system: Partial<SystemMetrics>;
    application: Partial<ApplicationMetrics>;
    health: HealthStatus;
  } {
    const latestSystem = this.systemMetrics[this.systemMetrics.length - 1];
    const latestApplication = this.applicationMetrics[this.applicationMetrics.length - 1];

    return {
      system: latestSystem
        ? {
            timestamp: latestSystem.timestamp,
            cpu: latestSystem.cpu,
            memory: latestSystem.memory,
          }
        : {},
      application: latestApplication
        ? {
            timestamp: latestApplication.timestamp,
            activeConnections: latestApplication.activeConnections,
            botMetrics: latestApplication.botMetrics,
          }
        : {},
      health: this.getHealthStatus(),
    };
  }

  public cleanup(): void {
    // Clean up old metrics
    const cutoffTime = Date.now() - this.METRICS_RETENTION_PERIOD;

    this.systemMetrics = this.systemMetrics.filter((m) => m.timestamp > cutoffTime);
    this.applicationMetrics = this.applicationMetrics.filter((m) => m.timestamp > cutoffTime);

    // Clean up old resolved alerts
    this.alerts = this.alerts.filter(
      (a) => !a.resolved || (a.resolvedAt && a.resolvedAt > cutoffTime)
    );

    debug('Monitoring data cleanup completed');
  }
}

export default AdvancedMonitor;

import { EventEmitter } from 'events';
import TimerRegistry from '@src/utils/TimerRegistry';
import type { HealthChecker, HealthCheckResult } from './HealthChecker';

export interface AlertConfig {
  memoryThreshold: number; // percentage
  diskThreshold: number; // percentage
  responseTimeThreshold: number; // milliseconds
  errorRateThreshold: number; // percentage
  consecutiveFailures: number;
  cooldownPeriod: number; // milliseconds
}

export interface Alert {
  id: string;
  type: 'memory' | 'disk' | 'response_time' | 'error_rate' | 'service_down' | 'database_error';
  severity: 'info' | 'warning' | 'error' | 'critical';
  title: string;
  message: string;
  timestamp: string;
  value: number;
  threshold: number;
  acknowledged: boolean;
  resolved: boolean;
  resolvedAt?: string;
  metadata?: Record<string, any>;
}

export interface NotificationChannel {
  name: string;
  type: 'email' | 'webhook' | 'slack' | 'console';
  config: Record<string, any>;
  send: (alert: Alert) => Promise<boolean>;
}

export class AlertManager extends EventEmitter {
  private healthChecker: HealthChecker;
  private config: AlertConfig;
  private alerts = new Map<string, Alert>();
  private notificationChannels = new Map<string, NotificationChannel>();
  private failureCounts = new Map<string, number>();
  private lastAlertTimes = new Map<string, number>();
  private alertIdCounter = 0;
  private monitoringIntervalId: string | null = null;

  // Bounded cache configuration
  private readonly MAX_ALERTS = parseInt(process.env.ALERT_MANAGER_MAX_ALERTS || '1000', 10);
  private readonly MAX_FAILURE_COUNTS = parseInt(
    process.env.ALERT_MANAGER_MAX_FAILURE_COUNTS || '100',
    10
  );

  constructor(healthChecker: HealthChecker, config: Partial<AlertConfig> = {}) {
    super();
    this.healthChecker = healthChecker;

    this.config = {
      memoryThreshold: 85,
      diskThreshold: 90,
      responseTimeThreshold: 1000,
      errorRateThreshold: 5,
      consecutiveFailures: 3,
      cooldownPeriod: 300000, // 5 minutes
      ...config,
    };

    // Set up default console notification channel
    this.addNotificationChannel({
      name: 'console',
      type: 'console',
      config: {},
      send: async (alert: Alert) => {
        console.log(`🚨 ALERT [${alert.severity.toUpperCase()}] ${alert.title}`);
        console.log(`   ${alert.message}`);
        console.log(`   Value: ${alert.value} (Threshold: ${alert.threshold})`);
        return true;
      },
    });

    // Start monitoring
    this.startMonitoring();
  }

  public addNotificationChannel(channel: NotificationChannel): void {
    this.notificationChannels.set(channel.name, channel);
    console.log(`📡 Added notification channel: ${channel.name} (${channel.type})`);
  }

  public removeNotificationChannel(name: string): void {
    this.notificationChannels.delete(name);
    console.log(`📡 Removed notification channel: ${name}`);
  }

  public getActiveAlerts(): Alert[] {
    return Array.from(this.alerts.values()).filter((alert) => !alert.resolved);
  }

  public getAllAlerts(): Alert[] {
    return Array.from(this.alerts.values());
  }

  public acknowledgeAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (alert && !alert.acknowledged) {
      alert.acknowledged = true;
      this.emit('alertAcknowledged', alert);
      console.log(`✅ Alert acknowledged: ${alert.title}`);
      return true;
    }
    return false;
  }

  public resolveAlert(alertId: string): boolean {
    const alert = this.alerts.get(alertId);
    if (alert && !alert.resolved) {
      alert.resolved = true;
      alert.resolvedAt = new Date().toISOString();
      this.emit('alertResolved', alert);
      console.log(`✅ Alert resolved: ${alert.title}`);
      return true;
    }
    return false;
  }

  public async createAlert(
    type: Alert['type'],
    severity: Alert['severity'],
    title: string,
    message: string,
    value: number,
    threshold: number,
    metadata?: Record<string, any>
  ): Promise<Alert> {
    const alert: Alert = {
      id: `alert_${++this.alertIdCounter}_${Date.now()}`,
      type,
      severity,
      title,
      message,
      timestamp: new Date().toISOString(),
      value,
      threshold,
      acknowledged: false,
      resolved: false,
      metadata,
    };

    // Enforce max alerts limit before adding new alert
    this.enforceMaxAlerts();

    this.alerts.set(alert.id, alert);
    this.emit('alertCreated', alert);

    // Send notifications
    await this.sendNotifications(alert);

    return alert;
  }

  private async sendNotifications(alert: Alert): Promise<void> {
    const notificationPromises = Array.from(this.notificationChannels.values()).map((channel) =>
      this.sendNotification(channel, alert)
    );

    try {
      await Promise.allSettled(notificationPromises);
    } catch (error) {
      console.error('Failed to send notifications:', error);
    }
  }

  private async sendNotification(channel: NotificationChannel, alert: Alert): Promise<void> {
    try {
      const success = await channel.send(alert);
      if (success) {
        console.log(`📤 Notification sent via ${channel.name}`);
      } else {
        console.error(`❌ Failed to send notification via ${channel.name}`);
      }
    } catch (error) {
      console.error(`❌ Error sending notification via ${channel.name}:`, error);
    }
  }

  private async checkMemoryUsage(healthCheck: HealthCheckResult): Promise<void> {
    const { used, total, percentage } = healthCheck.memory;

    if (percentage > this.config.memoryThreshold) {
      const alertKey = 'memory_high';

      if (this.shouldTriggerAlert(alertKey)) {
        await this.createAlert(
          'memory',
          percentage > 95 ? 'critical' : 'warning',
          'High Memory Usage',
          `Memory usage is at ${percentage}% (${used}MB / ${total}MB)`,
          percentage,
          this.config.memoryThreshold,
          { used, total, process: process.pid }
        );
      }
    } else {
      this.resolveAlertsByType('memory');
    }
  }

  private async checkDiskUsage(healthCheck: HealthCheckResult): Promise<void> {
    const diskUsage = healthCheck.metrics.diskUsage;

    if (diskUsage && diskUsage > this.config.diskThreshold) {
      const alertKey = 'disk_high';

      if (this.shouldTriggerAlert(alertKey)) {
        await this.createAlert(
          'disk',
          diskUsage > 95 ? 'critical' : 'warning',
          'High Disk Usage',
          `Disk usage is at ${diskUsage}%`,
          diskUsage,
          this.config.diskThreshold,
          { diskUsage }
        );
      }
    } else {
      this.resolveAlertsByType('disk');
    }
  }

  private async checkResponseTimes(healthCheck: HealthCheckResult): Promise<void> {
    const slowServices = Object.entries(healthCheck.services).filter(
      ([, service]) =>
        service.responseTime && service.responseTime > this.config.responseTimeThreshold
    );

    for (const [serviceName, service] of slowServices) {
      const alertKey = `response_time_${serviceName}`;

      if (this.shouldTriggerAlert(alertKey)) {
        await this.createAlert(
          'response_time',
          service.responseTime! > 2000 ? 'critical' : 'warning',
          `High Response Time - ${serviceName}`,
          `${serviceName} response time is ${service.responseTime}ms`,
          service.responseTime!,
          this.config.responseTimeThreshold,
          { serviceName, responseTime: service.responseTime }
        );
      }
    }
  }

  private async checkServiceStatus(healthCheck: HealthCheckResult): Promise<void> {
    for (const [serviceName, service] of Object.entries(healthCheck.services)) {
      if (service.status === 'down') {
        const alertKey = `service_down_${serviceName}`;

        if (this.shouldTriggerAlert(alertKey)) {
          await this.createAlert(
            'service_down',
            'critical',
            `Service Down - ${serviceName}`,
            `${serviceName} service is not responding`,
            0,
            0,
            { serviceName, error: service.message }
          );
        }
      } else {
        this.resolveAlertsByType('service_down', serviceName);
      }
    }
  }

  private async checkDatabaseStatus(healthCheck: HealthCheckResult): Promise<void> {
    if (healthCheck.database.status === 'error') {
      const alertKey = 'database_error';

      if (this.shouldTriggerAlert(alertKey)) {
        await this.createAlert(
          'database_error',
          'critical',
          'Database Connection Error',
          'Database connection is experiencing issues',
          0,
          0,
          { status: healthCheck.database.status }
        );
      }
    } else {
      this.resolveAlertsByType('database_error');
    }
  }

  private async checkErrorRate(healthCheck: HealthCheckResult): Promise<void> {
    const errorRate = healthCheck.metrics.errorRate;

    if (errorRate && errorRate > this.config.errorRateThreshold) {
      const alertKey = 'error_rate_high';

      if (this.shouldTriggerAlert(alertKey)) {
        await this.createAlert(
          'error_rate',
          errorRate > 10 ? 'critical' : 'warning',
          'High Error Rate',
          `Error rate is ${errorRate.toFixed(1)}%`,
          errorRate,
          this.config.errorRateThreshold,
          { errorRate }
        );
      }
    } else {
      this.resolveAlertsByType('error_rate');
    }
  }

  private shouldTriggerAlert(alertKey: string): boolean {
    const now = Date.now();
    const lastAlertTime = this.lastAlertTimes.get(alertKey) || 0;

    // Check cooldown period
    if (now - lastAlertTime < this.config.cooldownPeriod) {
      return false;
    }

    // Check consecutive failures
    const failureCount = this.failureCounts.get(alertKey) || 0;
    if (failureCount < this.config.consecutiveFailures) {
      return false;
    }

    return true;
  }

  private updateFailureCount(alertKey: string, failed: boolean): void {
    const currentCount = this.failureCounts.get(alertKey) || 0;

    if (failed) {
      this.failureCounts.set(alertKey, currentCount + 1);
    } else {
      this.failureCounts.set(alertKey, 0);
    }

    // Enforce max failure counts limit
    this.enforceMaxFailureCounts();
  }

  private async startMonitoring(): Promise<void> {
    const timerRegistry = TimerRegistry.getInstance();

    // Check health every 30 seconds
    this.monitoringIntervalId = timerRegistry.registerInterval(
      'alertManager_healthMonitor',
      async () => {
        try {
          const healthCheck = await this.healthChecker.performHealthCheck();
          await this.processHealthCheck(healthCheck);
        } catch (error) {
          console.error('Health monitoring failed:', error);
        }
      },
      30000,
      'AlertManager health monitoring interval'
    );

    console.log('🔍 Health monitoring started');
  }

  private async processHealthCheck(healthCheck: HealthCheckResult): Promise<void> {
    // Update failure counts
    this.updateFailureCount(
      'memory_high',
      healthCheck.memory.percentage > this.config.memoryThreshold
    );
    this.updateFailureCount(
      'disk_high',
      (healthCheck.metrics.diskUsage || 0) > this.config.diskThreshold
    );
    this.updateFailureCount('database_error', healthCheck.database.status === 'error');

    // Check various metrics
    await this.checkMemoryUsage(healthCheck);
    await this.checkDiskUsage(healthCheck);
    await this.checkResponseTimes(healthCheck);
    await this.checkServiceStatus(healthCheck);
    await this.checkDatabaseStatus(healthCheck);
    await this.checkErrorRate(healthCheck);

    // Emit health check event
    this.emit('healthCheck', healthCheck);
  }

  private resolveAlertsByType(type: Alert['type'], serviceName?: string): void {
    const now = Date.now();

    for (const alert of this.alerts.values()) {
      if (!alert.resolved && alert.type === type) {
        if (!serviceName || alert.metadata?.serviceName === serviceName) {
          // Only resolve if the issue has been resolved for a while
          const lastAlertTime = this.lastAlertTimes.get(`${type}_${serviceName || ''}`) || 0;
          if (now - lastAlertTime > this.config.cooldownPeriod / 2) {
            this.resolveAlert(alert.id);
          }
        }
      }
    }
  }

  public async getAlertSummary(): Promise<{
    total: number;
    active: number;
    acknowledged: number;
    resolved: number;
    bySeverity: Record<string, number>;
    byType: Record<string, number>;
  }> {
    const alerts = this.getAllAlerts();

    const bySeverity = alerts.reduce(
      (acc, alert) => {
        acc[alert.severity] = (acc[alert.severity] || 0) + 1;
        return acc;
      },
      {} as Record<string, number>
    );

    const byType = alerts.reduce(
      (acc, alert) => {
        acc[alert.type] = (acc[alert.type] || 0) + 1;
        return acc;
      },
      {} as Record<string, number>
    );

    return {
      total: alerts.length,
      active: alerts.filter((a) => !a.resolved).length,
      acknowledged: alerts.filter((a) => a.acknowledged).length,
      resolved: alerts.filter((a) => a.resolved).length,
      bySeverity,
      byType,
    };
  }

  public async exportAlertData(): Promise<string> {
    const alertSummary = await this.getAlertSummary();

    const alertData = {
      timestamp: new Date().toISOString(),
      config: this.config,
      alerts: this.getAllAlerts(),
      summary: alertSummary,
      channels: Array.from(this.notificationChannels.values()).map((c) => ({
        name: c.name,
        type: c.type,
      })),
    };

    return JSON.stringify(alertData, null, 2);
  }

  /**
   * Enforce max alerts limit by removing oldest resolved alerts first.
   * If still over limit after removing resolved, removes oldest alerts.
   */
  private enforceMaxAlerts(): void {
    if (this.alerts.size < this.MAX_ALERTS) {
      return;
    }

    // First, try to remove resolved alerts (oldest first)
    const resolvedAlerts = Array.from(this.alerts.values())
      .filter((a) => a.resolved)
      .sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

    for (const alert of resolvedAlerts) {
      if (this.alerts.size < this.MAX_ALERTS) {
        break;
      }
      this.alerts.delete(alert.id);
    }

    // If still over limit, remove oldest alerts regardless of status
    if (this.alerts.size >= this.MAX_ALERTS) {
      const allAlerts = Array.from(this.alerts.values()).sort(
        (a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime()
      );

      for (const alert of allAlerts) {
        if (this.alerts.size < this.MAX_ALERTS) {
          break;
        }
        this.alerts.delete(alert.id);
      }
    }
  }

  /**
   * Enforce max failure counts limit by removing oldest entries.
   */
  private enforceMaxFailureCounts(): void {
    if (this.failureCounts.size < this.MAX_FAILURE_COUNTS) {
      return;
    }

    // Remove entries with lowest counts first (less important)
    const entries = Array.from(this.failureCounts.entries()).sort((a, b) => a[1] - b[1]);

    for (const [key] of entries) {
      if (this.failureCounts.size < this.MAX_FAILURE_COUNTS) {
        break;
      }
      this.failureCounts.delete(key);
    }
  }

  /**
   * Get statistics about the AlertManager state.
   */
  public getStats(): {
    alertsCount: number;
    maxAlerts: number;
    failureCountsSize: number;
    maxFailureCounts: number;
    notificationChannelsCount: number;
    isMonitoring: boolean;
  } {
    return {
      alertsCount: this.alerts.size,
      maxAlerts: this.MAX_ALERTS,
      failureCountsSize: this.failureCounts.size,
      maxFailureCounts: this.MAX_FAILURE_COUNTS,
      notificationChannelsCount: this.notificationChannels.size,
      isMonitoring: this.monitoringIntervalId !== null,
    };
  }

  /**
   * Gracefully shutdown the AlertManager.
   * Clears the monitoring interval and releases resources.
   */
  public shutdown(): void {
    const timerRegistry = TimerRegistry.getInstance();

    if (this.monitoringIntervalId) {
      timerRegistry.clear(this.monitoringIntervalId);
      this.monitoringIntervalId = null;
      console.log('🔍 Health monitoring stopped');
    }

    // Clear all alerts
    this.alerts.clear();
    this.failureCounts.clear();
    this.lastAlertTimes.clear();

    // Remove all event listeners
    this.removeAllListeners();

    console.log('✅ AlertManager shutdown complete');
  }
}

