    severity: 'warning',
    messageTemplate: 'CPU usage {{value}}% exceeds threshold',
  },
];

/**
 * EnhancedAlertManager - Alerting system with configurable thresholds
 */
export class EnhancedAlertManager extends EventEmitter {
  private static instance: EnhancedAlertManager;
  private alerts: Map<string, EnhancedAlert> = new Map();
  private thresholds: Map<string, AlertThreshold> = new Map();
  private notificationChannels: Map<string, AlertNotificationChannel> = new Map();
  private providerMetrics: ProviderMetricsCollector;
  private kpiCollector: BusinessKpiCollector;
  private anomalyDetector: IntegrationAnomalyDetector;
  private checkInterval: NodeJS.Timeout | null = null;
  private alertHistory: EnhancedAlert[] = [];
  private maxHistory: number = 10000;
  private idCounter: number = 0;

  private constructor() {
    super();
    this.providerMetrics = ProviderMetricsCollector.getInstance();
    this.kpiCollector = BusinessKpiCollector.getInstance();
    this.anomalyDetector = IntegrationAnomalyDetector.getInstance();
    this.initializeThresholds();
    this.setupEventListeners();
  }

  /**
   * Get singleton instance
   */
  static getInstance(): EnhancedAlertManager {
    if (!EnhancedAlertManager.instance) {
      EnhancedAlertManager.instance = new EnhancedAlertManager();
    }
    return EnhancedAlertManager.instance;
  }

  /**
   * Initialize default thresholds
   */
  private initializeThresholds(): void {
    for (const threshold of DEFAULT_THRESHOLDS) {
      this.thresholds.set(threshold.id, threshold);
    }
  }

  /**
   * Setup event listeners
   */
  private setupEventListeners(): void {
    // Listen for anomalies
    this.anomalyDetector.on('anomalyDetected', (anomaly: IntegrationAnomaly) => {
      this.handleAnomaly(anomaly);
    });
  }

  /**
   * Start alert monitoring
   */
  startMonitoring(intervalMs: number = 30000): void {
    if (this.checkInterval) return;

    this.checkInterval = setInterval(() => {
      this.checkAllThresholds();
    }, intervalMs);

    this.emit('monitoringStarted');
  }

  /**
   * Stop alert monitoring
   */
  stopMonitoring(): void {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = null;
    }
    this.emit('monitoringStopped');
  }

  /**
   * Check all configured thresholds
   */
  private async checkAllThresholds(): Promise<void> {
    // Check provider thresholds
    await this.checkProviderThresholds();

    // Check KPI thresholds
    await this.checkKpiThresholds();

    // Check system thresholds
    this.checkSystemThresholds();
  }

  /**
   * Check provider thresholds
   */
  private async checkProviderThresholds(): Promise<void> {
    const messageProviders = this.providerMetrics.getAllMessageProviderMetrics();
    const llmProviders = this.providerMetrics.getAllLlmProviderMetrics();

    for (const provider of [...messageProviders, ...llmProviders]) {
      for (const [id, threshold] of this.thresholds) {
        if (threshold.source !== 'provider' || !threshold.enabled) continue;

        let value: number | undefined;
        let metricValue: number | undefined;

        if ('messagesReceived' in provider) {
          // Message provider
          switch (threshold.metric) {
            case 'errorRate':
              metricValue = provider.errorRate;
              value = provider.errorRate;
              break;
            case 'responseTime':
              metricValue = provider.averageResponseTime;
              value = provider.averageResponseTime;
              break;
            case 'rateLimitHits':
              metricValue = provider.rateLimitHits;
              value = provider.rateLimitHits;
              break;
            case 'status':
              metricValue =
                provider.status === 'healthy' ? 1 : provider.status === 'degraded' ? 2 : 3;
              value = metricValue;
              break;
          }
        } else {
          // LLM provider
          switch (threshold.metric) {
            case 'errorRate':
              metricValue = provider.errorRate;
              value = provider.errorRate;
              break;
            case 'latency':
              metricValue = provider.averageLatency;
              value = provider.averageLatency;
              break;
            case 'totalCost':
              metricValue = provider.totalCost;
              value = provider.totalCost;
              break;
            case 'llmErrorRate':
              metricValue = provider.errorRate;
              value = provider.errorRate;
              break;
          }
        }

        if (value !== undefined) {
          this.evaluateThreshold(threshold, value, { provider: provider.provider });
        }
      }
    }
  }

  /**
   * Check KPI thresholds
   */
  private async checkKpiThresholds(): Promise<void> {
    const kpis = this.kpiCollector.getAllKpis();

    for (const kpi of kpis) {
      for (const [id, threshold] of this.thresholds) {
        if (threshold.source !== 'kpi' || !threshold.enabled) continue;
        if (threshold.metric !== kpi.id) continue;

        this.evaluateThreshold(threshold, kpi.currentValue, { kpi: kpi.id });
      }
    }
  }

  /**
   * Check system thresholds
   */
  private checkSystemThresholds(): void {
    const memoryUsage = process.memoryUsage();
    const cpuUsage = process.cpuUsage();

    const memPercent = (memoryUsage.heapUsed / memoryUsage.heapTotal) * 100;
    const cpuPercent = ((cpuUsage.user + cpuUsage.system) / 10000000) * 100;

    for (const [id, threshold] of this.thresholds) {
      if (threshold.source !== 'system' || !threshold.enabled) continue;

      if (threshold.metric === 'memoryUsage') {
        this.evaluateThreshold(threshold, memPercent);
      } else if (threshold.metric === 'cpuUsage') {
        this.evaluateThreshold(threshold, cpuPercent);
      }
    }
  }

  /**
   * Evaluate a threshold
   */
  private evaluateThreshold(
    threshold: AlertThreshold,
    value: number,
    context?: Record<string, any>
  ): void {
    let triggered = false;

    switch (threshold.condition) {
      case 'gt':
        triggered = value > threshold.value;
        break;
      case 'lt':
        triggered = value < threshold.value;
        break;
      case 'eq':
        triggered = value === threshold.value;
        break;
      case 'gte':
        triggered = value >= threshold.value;
        break;
      case 'lte':
        triggered = value <= threshold.value;
        break;
      case 'change':
        if (threshold.changePercent) {
          triggered = Math.abs(value) > threshold.changePercent;
        }
        break;
    }

    if (triggered) {
      this.triggerAlert(threshold, value, context);
    }
  }

  /**
   * Trigger an alert
   */
  private triggerAlert(
    threshold: AlertThreshold,
    value: number,
    context?: Record<string, any>
  ): void {
    // Check cooldown
    const recentAlert = Array.from(this.alerts.values())
      .filter((a) => a.source === threshold.source && a.metric === threshold.metric)
      .sort((a, b) => b.timestamp - a.timestamp)[0];

    if (recentAlert && Date.now() - recentAlert.timestamp < threshold.cooldown) {
      return;
    }

    const id = `alert_${++this.idCounter}_${Date.now()}`;
    const message = threshold.messageTemplate
      .replace('{{value}}', value.toString())
      .replace('{{threshold}}', threshold.value.toString());

    const alert: EnhancedAlert = {
      id,
      timestamp: Date.now(),
      level: threshold.severity,
      status: 'active',
      source: threshold.source,
      title: threshold.name,
      message,
      metric: threshold.metric,
      value,
      threshold: threshold.value,
      metadata: context,
    };

    this.alerts.set(id, alert);
    this.alertHistory.push(alert);

    // Trim history
    if (this.alertHistory.length > this.maxHistory) {
      this.alertHistory = this.alertHistory.slice(-this.maxHistory);
    }

    this.sendNotifications(alert);
    this.emit('alertTriggered', alert);
  }

  /**
   * Handle anomaly detected
   */
  private handleAnomaly(anomaly: IntegrationAnomaly): void {
    const level: AlertLevel =
      anomaly.severity === 'critical'
        ? 'emergency'
        : anomaly.severity === 'high'
          ? 'critical'
          : anomaly.severity === 'medium'
            ? 'warning'
            : 'info';

    const id = `alert_anomaly_${++this.idCounter}_${Date.now()}`;
    const alert: EnhancedAlert = {
      id,
      timestamp: Date.now(),
      level,
      status: 'active',
      source: 'anomaly',
      title: `Anomaly: ${anomaly.type}`,
      message: anomaly.message,
      metric: anomaly.type,
      value: anomaly.value,
      threshold: anomaly.expectedValue,
      metadata: { integration: anomaly.integration, deviation: anomaly.deviation },
    };

    this.alerts.set(id, alert);
    this.alertHistory.push(alert);
    this.sendNotifications(alert);
    this.emit('alertTriggered', alert);
  }

  /**
   * Send notifications to all enabled channels
   */
  private sendNotifications(alert: EnhancedAlert): void {
    for (const channel of this.notificationChannels.values()) {
      if (!channel.enabled) continue;
      this.sendToChannel(channel, alert);
    }
  }

  /**
   * Send alert to specific channel
   */
  private sendToChannel(channel: AlertNotificationChannel, alert: EnhancedAlert): void {
    // Implementation depends on channel type
    switch (channel.type) {
      case 'console':
        console.log(`[ALERT ${alert.level.toUpperCase()}] ${alert.title}: ${alert.message}`);
        break;
      case 'slack':
      case 'discord':
      case 'webhook':
        // Would send to webhook
        this.emit('notification', { channel, alert });
        break;
    }
  }

  /**
   * Register a threshold
   */
  registerThreshold(threshold: AlertThreshold): void {
    this.thresholds.set(threshold.id, threshold);
    this.emit('thresholdRegistered', threshold);
  }

  /**
   * Update a threshold
   */
  updateThreshold(id: string, updates: Partial<AlertThreshold>): void {
    const threshold = this.thresholds.get(id);
    if (threshold) {
      Object.assign(threshold, updates);
      this.emit('thresholdUpdated', threshold);
    }
  }

  /**
   * Enable/disable a threshold
   */
  setThresholdEnabled(id: string, enabled: boolean): void {
    const threshold = this.thresholds.get(id);
    if (threshold) {
      threshold.enabled = enabled;
    }
  }

  /**
   * Register a notification channel
   */
  registerNotificationChannel(channel: AlertNotificationChannel): void {
    this.notificationChannels.set(channel.id, channel);
    this.emit('channelRegistered', channel);
  }

  /**
   * Get all alerts
   */
  getAlerts(status?: AlertStatus): EnhancedAlert[] {
    let alerts = Array.from(this.alerts.values());
    if (status) {
      alerts = alerts.filter((a) => a.status === status);
    }
    return alerts.sort((a, b) => b.timestamp - a.timestamp);
  }

  /**
   * Get active alerts
   */
  getActiveAlerts(): EnhancedAlert[] {
    return this.getAlerts('active');
  }

  /**
   * Acknowledge an alert
   */
  acknowledgeAlert(id: string): void {
    const alert = this.alerts.get(id);
    if (alert && alert.status === 'active') {
      alert.status = 'acknowledged';
      alert.acknowledgedAt = Date.now();
      this.emit('alertAcknowledged', alert);
    }
  }

  /**
   * Resolve an alert
   */
  resolveAlert(id: string): void {
    const alert = this.alerts.get(id);
    if (alert && alert.status !== 'resolved') {
      alert.status = 'resolved';
      alert.resolvedAt = Date.now();
      this.emit('alertResolved', alert);
    }
  }

  /**
   * Get alert statistics
   */
  getAlertStats(): AlertStats {
    const alerts = Array.from(this.alerts.values());

    const byLevel: Record<AlertLevel, number> = { info: 0, warning: 0, critical: 0, emergency: 0 };
    const bySource: Record<AlertSource, number> = {
      provider: 0,
      kpi: 0,
      anomaly: 0,
      system: 0,
      custom: 0,
    };

    let active = 0,
      acknowledged = 0,
      resolved = 0;

    for (const alert of alerts) {
      byLevel[alert.level]++;
      bySource[alert.source]++;

      if (alert.status === 'active') active++;
      else if (alert.status === 'acknowledged') acknowledged++;
      else resolved++;
    }

    return {
      total: alerts.length,
      active,
      acknowledged,
      resolved,
      byLevel,
      bySource,
    };
  }

  /**
   * Get all thresholds
   */
  getThresholds(): AlertThreshold[] {
    return Array.from(this.thresholds.values());
  }

  /**
   * Create custom alert
   */
  createCustomAlert(
    level: AlertLevel,
    title: string,
    message: string,
    metadata?: Record<string, any>
  ): void {
    const id = `alert_custom_${++this.idCounter}_${Date.now()}`;
    const alert: EnhancedAlert = {
      id,
      timestamp: Date.now(),
      level,
      status: 'active',
      source: 'custom',
      title,
      message,
      metadata,
    };

    this.alerts.set(id, alert);
    this.alertHistory.push(alert);
    this.sendNotifications(alert);
    this.emit('alertTriggered', alert);
  }
}

export default EnhancedAlertManager;

import { promises as fs } from 'fs';
import { performance } from 'perf_hooks';

export interface HealthCheckResult {
  status: 'healthy' | 'degraded' | 'unhealthy';
  timestamp: string;
  uptime: number;
  memory: {
    used: number;
    total: number;
    percentage: number;
  };
  database: {
    status: 'connected' | 'disconnected' | 'error';
    responseTime?: number;
  };
  services: Record<
    string,
    {
      status: 'up' | 'down' | 'degraded';
      responseTime?: number;
      message?: string;
    }
  >;
  metrics: {
    cpuUsage?: number;
    diskUsage?: number;
    activeConnections?: number;
    errorRate?: number;
  };
}

export class HealthChecker {
  private startTime: number;
  private checkInterval: number;
  private lastCheckTime: number;
  private healthHistory: HealthCheckResult[];
  private maxHistory: number;

  constructor(checkInterval = 30000, maxHistory = 100) {
    this.startTime = performance.now();
    this.checkInterval = checkInterval;
    this.lastCheckTime = 0;
    this.healthHistory = [];
    this.maxHistory = maxHistory;
  }

  public async performHealthCheck(): Promise<HealthCheckResult> {
    const now = performance.now();

    // Throttle health checks
    if (now - this.lastCheckTime < this.checkInterval) {
      const lastResult = this.healthHistory[this.healthHistory.length - 1];
      return lastResult || this.createEmptyHealthCheck();
    }

    this.lastCheckTime = now;

    try {
      const healthCheck: HealthCheckResult = {
        status: 'healthy',
        timestamp: new Date().toISOString(),
        uptime: now - this.startTime,
        memory: this.getMemoryUsage(),
        database: await this.checkDatabase(),
        services: await this.checkServices(),
        metrics: await this.collectMetrics(),
      };

      // Determine overall status
      healthCheck.status = this.determineOverallStatus(healthCheck);

      // Store in history
      this.healthHistory.push(healthCheck);
      if (this.healthHistory.length > this.maxHistory) {
        this.healthHistory.shift();
      }

      return healthCheck;
    } catch (error) {
      console.error('Health check failed:', error);
      return this.createErrorHealthCheck(error);
    }
  }

  private getMemoryUsage() {
    const used = process.memoryUsage().heapUsed;
    const total = process.memoryUsage().heapTotal;
    const percentage = Math.round((used / total) * 100);

    return {
      used: Math.round(used / 1024 / 1024), // MB
      total: Math.round(total / 1024 / 1024), // MB
      percentage,
    };
  }

  private async checkDatabase(): Promise<HealthCheckResult['database']> {
    try {
      const startTime = performance.now();
      // Placeholder for actual database check
      // In real implementation, this would ping the database
      await new Promise((resolve) => setTimeout(resolve, 10));
      const responseTime = performance.now() - startTime;

      return {
        status: 'connected',
        responseTime: Math.round(responseTime),
      };
    } catch (error) {
      return {
        status: 'error',
      };
    }
  }

  private async checkServices(): Promise<HealthCheckResult['services']> {
    const services: HealthCheckResult['services'] = {};

    // Check WebSocket service
    try {
      const startTime = performance.now();
      // Placeholder for WebSocket service check
      await new Promise((resolve) => setTimeout(resolve, 5));
      const responseTime = performance.now() - startTime;

      services.websocket = {
        status: 'up',
        responseTime: Math.round(responseTime),
      };
    } catch (error) {
      services.websocket = {
        status: 'down',
        message: error instanceof Error ? error.message : 'Unknown error',
      };
    }

    // Check LLM service
    try {
      const startTime = performance.now();
      // Placeholder for LLM service check
      await new Promise((resolve) => setTimeout(resolve, 15));
      const responseTime = performance.now() - startTime;

      services.llm = {
        status: 'up',
        responseTime: Math.round(responseTime),
      };
    } catch (error) {
      services.llm = {
        status: 'down',
        message: error instanceof Error ? error.message : 'Unknown error',
      };
    }

    // Check external integrations
    try {
      const startTime = performance.now();
      // Placeholder for external integrations check
      await new Promise((resolve) => setTimeout(resolve, 20));
      const responseTime = performance.now() - startTime;

      services.integrations = {
        status: 'up',
        responseTime: Math.round(responseTime),
      };
    } catch (error) {
      services.integrations = {
        status: 'down',
        message: error instanceof Error ? error.message : 'Unknown error',
      };
    }

    return services;
  }

  private async collectMetrics(): Promise<HealthCheckResult['metrics']> {
    const metrics: HealthCheckResult['metrics'] = {};

    try {
      // CPU Usage (placeholder - would need system-specific implementation)
      metrics.cpuUsage = Math.random() * 100; // Placeholder

      // Disk Usage
      const diskInfo = await this.getDiskUsage();
      metrics.diskUsage = diskInfo.percentage;

      // Active Connections (placeholder)
      metrics.activeConnections = Math.floor(Math.random() * 100);

      // Error Rate (placeholder)
      metrics.errorRate = Math.random() * 5;
    } catch (error) {
      console.error('Failed to collect metrics:', error);
    }

    return metrics;
  }

  private async getDiskUsage() {
    try {
      // Placeholder for disk usage check
      // In real implementation, this would check actual disk usage
      const used = Math.random() * 100;
      const total = 100;

      return {
        used: Math.round(used),
        total: Math.round(total),
        percentage: Math.round((used / total) * 100),
      };
    } catch (error) {
      return {
        used: 0,
        total: 100,
        percentage: 0,
      };
    }
  }

  private determineOverallStatus(
    healthCheck: HealthCheckResult
  ): 'healthy' | 'degraded' | 'unhealthy' {
    // Check for critical failures
    if (healthCheck.database.status === 'error') {
      return 'unhealthy';
    }

    // Check service statuses
    const downServices = Object.values(healthCheck.services).filter((s) => s.status === 'down');
    if (downServices.length >= 1) {
      return 'unhealthy';
    }

    // Check for degraded performance
    if (
      healthCheck.memory.percentage > 90 ||
      (healthCheck.metrics.diskUsage && healthCheck.metrics.diskUsage > 90)
    ) {
      return 'degraded';
    }

    // Check response times
    const slowResponses = Object.values(healthCheck.services).filter(
      (s) => s.responseTime && s.responseTime > 1000
    );
    if (slowResponses.length > 0) {
      return 'degraded';
    }

    return 'healthy';
  }

  private createEmptyHealthCheck(): HealthCheckResult {
    return {
      status: 'healthy',
      timestamp: new Date().toISOString(),
      uptime: 0,
      memory: { used: 0, total: 0, percentage: 0 },
      database: { status: 'disconnected' },
      services: {},
      metrics: {},
    };
  }

  private createErrorHealthCheck(error: any): HealthCheckResult {
    return {
      status: 'unhealthy',
      timestamp: new Date().toISOString(),
      uptime: performance.now() - this.startTime,
      memory: this.getMemoryUsage(),
      database: { status: 'error' },
      services: {
        healthChecker: {
          status: 'down',
          message: error instanceof Error ? error.message : 'Unknown error',
        },
      },
      metrics: {},
    };
  }

  public getHealthHistory(): HealthCheckResult[] {
    return [...this.healthHistory];
  }

  public getHealthTrends(): {
    uptime: number;
    averageResponseTime: number;
    errorRate: number;
    statusDistribution: {
      healthy: number;
      degraded: number;
      unhealthy: number;
    };
  } {
    if (this.healthHistory.length === 0) {
      return {
        uptime: 0,
        averageResponseTime: 0,
        errorRate: 0,
        statusDistribution: { healthy: 0, degraded: 0, unhealthy: 0 },
      };
    }

    const totalChecks = this.healthHistory.length;
    const statusCounts = this.healthHistory.reduce(
      (acc, check) => {
        acc[check.status]++;
        return acc;
      },
      { healthy: 0, degraded: 0, unhealthy: 0 }
    );

    const responseTimes = this.healthHistory.flatMap((check) =>
      Object.values(check.services)
        .map((s) => s.responseTime || 0)
        .filter((t) => t > 0)
    );

    const averageResponseTime =
      responseTimes.length > 0
        ? responseTimes.reduce((sum, time) => sum + time, 0) / responseTimes.length
        : 0;

    return {
      uptime: this.healthHistory[this.healthHistory.length - 1]?.uptime || 0,
      averageResponseTime: Math.round(averageResponseTime),
      errorRate: Math.round((statusCounts.unhealthy / totalChecks) * 100),
      statusDistribution: {
        healthy: Math.round((statusCounts.healthy / totalChecks) * 100),
        degraded: Math.round((statusCounts.degraded / totalChecks) * 100),
        unhealthy: Math.round((statusCounts.unhealthy / totalChecks) * 100),
      },
    };
  }

  public async exportHealthData(): Promise<string> {
    const healthData = {
      timestamp: new Date().toISOString(),
      uptime: performance.now() - this.startTime,
      history: this.healthHistory,
      trends: this.getHealthTrends(),
    };

    return JSON.stringify(healthData, null, 2);
  }

  public async saveHealthReport(filePath: string): Promise<void> {
    const healthData = await this.exportHealthData();
    await fs.writeFile(filePath, healthData, 'utf-8');
  }

  /**
   * Gracefully shutdown the HealthChecker.
   * Clears health history and releases resources.
   */
  public shutdown(): void {
    this.healthHistory = [];
    this.lastCheckTime = 0;
    console.log('💓 HealthChecker shutdown complete');
  }
}

