/**
 * Integration types
 */
export type IntegrationType = 'discord' | 'slack' | 'mattermost' | 'llm' | 'mcp' | 'database';

/**
 * Anomaly severity
 */
export type AnomalySeverity = 'low' | 'medium' | 'high' | 'critical';

/**
 * Anomaly type
 */
export type AnomalyType =
  | 'response_time_spike'
  | 'error_rate_spike'
  | 'rate_limit_exceeded'
  | 'connection_failure'
  | 'message_drop'
  | 'authentication_failure'
  | 'latency_degradation'
  | 'token_usage_anomaly'
  | 'cost_anomaly'
  | 'availability_drop';

/**
 * Integration anomaly
 */
export interface IntegrationAnomaly {
  id: string;
  timestamp: number;
  integration: string;
  integrationType: IntegrationType;
  type: AnomalyType;
  severity: AnomalySeverity;
  message: string;
  value: number;
  expectedValue: number;
  deviation: number;
  metadata?: Record<string, any>;
}

/**
 * Detection threshold configuration
 */
export interface DetectionThreshold {
  type: AnomalyType;
  enabled: boolean;
  warningThreshold: number;
  criticalThreshold: number;
  windowSize: number;
  minDataPoints: number;
}

/**
 * Integration anomaly detection configuration
 */
export interface IntegrationAnomalyConfig {
  enabled: boolean;
  checkInterval: number;
  thresholds: DetectionThreshold[];
}

