      warningThreshold: 5,
      criticalThreshold: 20,
      windowSize: 100,
      minDataPoints: 10,
    },
    {
      type: 'latency_degradation',
      enabled: true,
      warningThreshold: 1000,
      criticalThreshold: 3000,
      windowSize: 50,
      minDataPoints: 10,
    },
    {
      type: 'cost_anomaly',
      enabled: true,
      warningThreshold: 1.5,
      criticalThreshold: 3.0,
      windowSize: 100,
      minDataPoints: 20,
    },
    {
      type: 'availability_drop',
      enabled: true,
      warningThreshold: 95,
      criticalThreshold: 90,
      windowSize: 50,
      minDataPoints: 10,
    },
  ],
};

/**
 * IntegrationAnomalyDetector - Enhanced anomaly detection for Mattermost and other integrations
 */
export class IntegrationAnomalyDetector extends EventEmitter {
  private static instance: IntegrationAnomalyDetector;
  private config: IntegrationAnomalyConfig;
  private anomalies: Map<string, IntegrationAnomaly[]> = new Map();
  private dataWindows: Map<string, Map<string, number[]>> = new Map();
  private checkInterval: NodeJS.Timeout | null = null;
  private providerMetrics: ProviderMetricsCollector;

  private constructor(config: Partial<IntegrationAnomalyConfig> = {}) {
    super();
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.providerMetrics = ProviderMetricsCollector.getInstance();
    this.initializeDataWindows();
  }

  /**
   * Get singleton instance
   */
  static getInstance(config?: Partial<IntegrationAnomalyConfig>): IntegrationAnomalyDetector {
    if (!IntegrationAnomalyDetector.instance) {
      IntegrationAnomalyDetector.instance = new IntegrationAnomalyDetector(config);
    }
    return IntegrationAnomalyDetector.instance;
  }

  /**
   * Initialize data windows for each integration
   */
  private initializeDataWindows(): void {
    const integrations: IntegrationType[] = [
      'discord',
      'slack',
      'mattermost',
      'llm',
      'mcp',
      'database',
    ];
    const metrics = ['response_time', 'error_rate', 'latency', 'messages', 'cost'];

    for (const integration of integrations) {
      const integrationData = new Map<string, number[]>();
      for (const metric of metrics) {
        integrationData.set(metric, []);
      }
      this.dataWindows.set(integration, integrationData);
    }
  }

  /**
   * Start detection
   */
  startDetection(): void {
    if (this.checkInterval) return;

    this.checkInterval = setInterval(() => {
      this.runDetection();
    }, this.config.checkInterval);

    this.emit('detectionStarted');
  }

  /**
   * Stop detection
   */
  stopDetection(): void {
    if (this.checkInterval) {
      clearInterval(this.checkInterval);
      this.checkInterval = null;
    }
    this.emit('detectionStopped');
  }

  /**
   * Add data point for an integration
   */
  addDataPoint(
    integration: string,
    integrationType: IntegrationType,
    metric: string,
    value: number
  ): void {
    const typeData = this.dataWindows.get(integrationType);
    if (!typeData) return;

    const metricData = typeData.get(metric);
    if (!metricData) return;

    metricData.push(value);

    // Trim window
    const threshold = this.config.thresholds.find(
      (t) => t.type === `${metric}_spike` || t.type === `${metric}_degradation`
    );
    const windowSize = threshold?.windowSize || 50;
    if (metricData.length > windowSize) {
      metricData.shift();
    }

    this.emit('dataPoint', { integration, integrationType, metric, value });
  }

  /**
   * Run anomaly detection for all integrations
   */
  runDetection(): void {
    if (!this.config.enabled) return;

    this.detectForMattermost();
    this.detectForDiscord();
    this.detectForSlack();
    this.detectForLlmProviders();
    this.detectForMcp();
    this.detectForDatabase();
  }

  /**
   * Detect anomalies for Mattermost
   */
  private detectForMattermost(): void {
    const metrics = this.providerMetrics.getMessageProviderMetrics('mattermost');
    if (!metrics) return;

    // Response time spike
    if (metrics.averageResponseTime > 0) {
      this.checkThreshold(
        'mattermost',
        'mattermost',
        'response_time_spike',
        metrics.averageResponseTime,
        { response_time: metrics.averageResponseTime }
      );
    }

    // Error rate spike
    if (metrics.errorRate > 0) {
      this.checkThreshold('mattermost', 'mattermost', 'error_rate_spike', metrics.errorRate, {
        error_rate: metrics.errorRate,
      });
    }

    // Rate limit exceeded
    if (metrics.rateLimitHits > 0) {
      this.checkThreshold(
        'mattermost',
        'mattermost',
        'rate_limit_exceeded',
        metrics.rateLimitHits,
        { rate_limit_hits: metrics.rateLimitHits }
      );
    }

    // Availability drop
    if (metrics.status !== 'unknown') {
      const availability =
        metrics.status === 'healthy' ? 100 : metrics.status === 'degraded' ? 75 : 0;
      this.checkThreshold('mattermost', 'mattermost', 'availability_drop', 100 - availability, {
        availability,
      });
    }
  }

  /**
   * Detect anomalies for Discord
   */
  private detectForDiscord(): void {
    const metrics = this.providerMetrics.getMessageProviderMetrics('discord');
    if (!metrics) return;

    if (metrics.averageResponseTime > 0) {
      this.checkThreshold(
        'discord',
        'discord',
        'response_time_spike',
        metrics.averageResponseTime,
        { response_time: metrics.averageResponseTime }
      );
    }

    if (metrics.errorRate > 0) {
      this.checkThreshold('discord', 'discord', 'error_rate_spike', metrics.errorRate, {
        error_rate: metrics.errorRate,
      });
    }

    if (metrics.rateLimitHits > 0) {
      this.checkThreshold('discord', 'discord', 'rate_limit_exceeded', metrics.rateLimitHits, {
        rate_limit_hits: metrics.rateLimitHits,
      });
    }
  }

  /**
   * Detect anomalies for Slack
   */
  private detectForSlack(): void {
    const metrics = this.providerMetrics.getMessageProviderMetrics('slack');
    if (!metrics) return;

    if (metrics.averageResponseTime > 0) {
      this.checkThreshold('slack', 'slack', 'response_time_spike', metrics.averageResponseTime, {
        response_time: metrics.averageResponseTime,
      });
    }

    if (metrics.errorRate > 0) {
      this.checkThreshold('slack', 'slack', 'error_rate_spike', metrics.errorRate, {
        error_rate: metrics.errorRate,
      });
    }

    if (metrics.rateLimitHits > 0) {
      this.checkThreshold('slack', 'slack', 'rate_limit_exceeded', metrics.rateLimitHits, {
        rate_limit_hits: metrics.rateLimitHits,
      });
    }
  }

  /**
   * Detect anomalies for LLM providers
   */
  private detectForLlmProviders(): void {
    const llmProviders = [
      'openai',
      'flowise',
      'openwebui',
      'openswarm',
      'perplexity',
      'replicate',
      'n8n',
    ];

    for (const provider of llmProviders) {
      const metrics = this.providerMetrics.getLlmProviderMetrics(provider as ProviderType);
      if (!metrics) continue;

      // Latency degradation
      if (metrics.averageLatency > 0) {
        this.checkThreshold(provider, 'llm', 'latency_degradation', metrics.averageLatency, {
          latency: metrics.averageLatency,
        });
      }

      // Error rate spike
      if (metrics.errorRate > 0) {
        this.checkThreshold(provider, 'llm', 'error_rate_spike', metrics.errorRate, {
          error_rate: metrics.errorRate,
        });
      }

      // Cost anomaly
      if (metrics.averageCost > 0) {
        // Get historical average
        const costHistory = this.getDataWindow('llm', 'cost');
        if (costHistory.length >= 10) {
          const avgCost = costHistory.reduce((a, b) => a + b, 0) / costHistory.length;
          const deviation = metrics.averageCost / avgCost;
          this.checkThreshold(provider, 'llm', 'cost_anomaly', deviation, {
            cost: metrics.averageCost,
            avgCost,
            deviation,
          });
        }
      }

      // Rate limit exceeded
      if (metrics.rateLimitHits > 0) {
        this.checkThreshold(provider, 'llm', 'rate_limit_exceeded', metrics.rateLimitHits, {
          rate_limit_hits: metrics.rateLimitHits,
        });
      }
    }
  }

  /**
   * Detect anomalies for MCP
   */
  private detectForMcp(): void {
    // MCP metrics would come from MCPService
    // For now, emit event for external data
    this.emit('mcpAnomalyCheck');
  }

  /**
   * Detect anomalies for database
   */
  private detectForDatabase(): void {
    // Database metrics would come from DatabaseManager
    this.emit('databaseAnomalyCheck');
  }

  /**
   * Check threshold for anomaly
   */
  private checkThreshold(
    integration: string,
    integrationType: IntegrationType,
    type: AnomalyType,
    value: number,
    additionalData: Record<string, number>
  ): void {
    const threshold = this.config.thresholds.find((t) => t.type === type);
    if (!threshold || !threshold.enabled) return;

    // Calculate expected value (simple moving average)
    const window = this.getDataWindow(
      integrationType,
      type.replace('_spike', '').replace('_degradation', '')
    );
    const expectedValue = window.length > 0 ? window.reduce((a, b) => a + b, 0) / window.length : 0;

    let severity: AnomalySeverity = 'low';
    let triggered = false;

    if (threshold.criticalThreshold && value >= threshold.criticalThreshold) {
      severity = 'critical';
      triggered = true;
    } else if (threshold.warningThreshold && value >= threshold.warningThreshold) {
      severity = 'medium';
      triggered = true;
    }

    if (triggered) {
      const deviation = expectedValue > 0 ? value / expectedValue : value;

      const anomaly: IntegrationAnomaly = {
        id: `anomaly_${integration}_${type}_${Date.now()}`,
        timestamp: Date.now(),
        integration,
        integrationType,
        type,
        severity,
        message: this.generateAnomalyMessage(type, integration, value, expectedValue),
        value,
        expectedValue,
        deviation,
        metadata: additionalData,
      };

      this.addAnomaly(integration, anomaly);
      this.emit('anomalyDetected', anomaly);
    }

    // Add to data window
    this.addToDataWindow(
      integrationType,
      type.replace('_spike', '').replace('_degradation', ''),
      value
    );
  }

  /**
   * Generate human-readable anomaly message
   */
  private generateAnomalyMessage(
    type: AnomalyType,
    integration: string,
    value: number,
    expected: number
  ): string {
    const formattedValue = value.toFixed(2);
    const formattedExpected = expected.toFixed(2);

    switch (type) {
      case 'response_time_spike':
        return `Response time spike detected for ${integration}: ${formattedValue}ms (expected: ${formattedExpected}ms)`;
      case 'error_rate_spike':
        return `Error rate spike detected for ${integration}: ${formattedValue}%`;
      case 'rate_limit_exceeded':
        return `Rate limit exceeded for ${integration}: ${value} hits`;
      case 'connection_failure':
        return `Connection failures detected for ${integration}: ${value}`;
      case 'message_drop':
        return `Message drops detected for ${integration}: ${value}`;
      case 'latency_degradation':
        return `Latency degradation detected for ${integration}: ${formattedValue}ms`;
      case 'cost_anomaly':
        return `Cost anomaly detected for ${integration}: ${value.toFixed(1)}x normal`;
      case 'availability_drop':
        return `Availability drop detected for ${integration}: ${(100 - value).toFixed(1)}%`;
      default:
        return `Anomaly detected for ${integration}: ${type}`;
    }
  }

  /**
   * Get data window for integration type
   */
  private getDataWindow(integrationType: IntegrationType, metric: string): number[] {
    const typeData = this.dataWindows.get(integrationType);
    if (!typeData) return [];
    return typeData.get(metric) || [];
  }

  /**
   * Add to data window
   */
  private addToDataWindow(integrationType: IntegrationType, metric: string, value: number): void {
    const typeData = this.dataWindows.get(integrationType);
    if (!typeData) return;

    const metricData = typeData.get(metric);
    if (!metricData) {
      typeData.set(metric, [value]);
      return;
    }

    metricData.push(value);
    if (metricData.length > 100) {
      metricData.shift();
    }
  }

  /**
   * Add anomaly
   */
  private addAnomaly(integration: string, anomaly: IntegrationAnomaly): void {
    const existing = this.anomalies.get(integration) || [];
    existing.push(anomaly);

    // Keep only recent anomalies (last 100 per integration)
    if (existing.length > 100) {
      existing.shift();
    }

    this.anomalies.set(integration, existing);
  }

  /**
   * Get active anomalies
   */
  getActiveAnomalies(integration?: string): IntegrationAnomaly[] {
    if (integration) {
      return this.anomalies.get(integration) || [];
    }

    const all: IntegrationAnomaly[] = [];
    for (const anomalies of this.anomalies.values()) {
      all.push(...anomalies);
    }
    return all.sort((a, b) => b.timestamp - a.timestamp);
  }

  /**
   * Get recent anomalies
   */
  getRecentAnomalies(minutes: number = 60, integration?: string): IntegrationAnomaly[] {
    const cutoff = Date.now() - minutes * 60 * 1000;
    return this.getActiveAnomalies(integration).filter((a) => a.timestamp >= cutoff);
  }

  /**
   * Get anomaly summary
   */
  getAnomalySummary(): {
    total: number;
    bySeverity: Record<AnomalySeverity, number>;
    byIntegration: Record<string, number>;
    byType: Partial<Record<AnomalyType, number>>;
    recent: IntegrationAnomaly[];
  } {
    const anomalies = this.getActiveAnomalies();

    const bySeverity: Record<AnomalySeverity, number> = { low: 0, medium: 0, high: 0, critical: 0 };
    const byIntegration: Record<string, number> = {};
    const byType: Partial<Record<AnomalyType, number>> = {};

    for (const anomaly of anomalies) {
      bySeverity[anomaly.severity]++;
      byIntegration[anomaly.integration] = (byIntegration[anomaly.integration] || 0) + 1;
      byType[anomaly.type] = (byType[anomaly.type] || 0) + 1;
    }

    return {
      total: anomalies.length,
      bySeverity,
      byIntegration,
      byType,
      recent: anomalies.slice(0, 10),
    };
  }

  /**
   * Update configuration
   */
  updateConfig(config: Partial<IntegrationAnomalyConfig>): void {
    this.config = { ...this.config, ...config };
    this.emit('configUpdated', this.config);
  }

  /**
   * Set threshold for specific anomaly type
   */
  setThreshold(type: AnomalyType, warning: number, critical: number): void {
    const threshold = this.config.thresholds.find((t) => t.type === type);
    if (threshold) {
      threshold.warningThreshold = warning;
      threshold.criticalThreshold = critical;
    }
  }

  /**
   * Clear anomalies for an integration
   */
  clearAnomalies(integration?: string): void {
    if (integration) {
      this.anomalies.delete(integration);
    } else {
      this.anomalies.clear();
    }
  }
}

export default IntegrationAnomalyDetector;

import { EventEmitter } from 'events';

/**
 * Log levels
 */
export type LogLevel = 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Log source
 */
export type LogSource =
  | 'server'
  | 'discord'
  | 'slack'
  | 'mattermost'
  | 'llm'
  | 'mcp'
  | 'database'
  | 'security'
  | 'custom';

/**
 * Aggregated log entry
 */
export interface LogEntry {
  id: string;
  timestamp: number;
  level: LogLevel;
  source: LogSource;
  message: string;
  metadata?: Record<string, any>;
  traceId?: string;
  spanId?: string;
  botName?: string;
  provider?: string;
  stackTrace?: string;
  userId?: string;
  sessionId?: string;
}

/**
 * Log query filters
 */
export interface LogQuery {
  startTime?: number;
  endTime?: number;
  levels?: LogLevel[];
  sources?: LogSource[];
  search?: string;
  traceId?: string;
  botName?: string;
  provider?: string;
  limit?: number;
  offset?: number;
}

/**
 * Log statistics
 */
export interface LogStats {
  totalLogs: number;
  byLevel: Record<LogLevel, number>;
  bySource: Record<LogSource, number>;
  errorRate: number;
  warningsRate: number;
  recentErrors: LogEntry[];
  timeSeries: { timestamp: number; count: number }[];
}

/**
 * Alert condition for logs
 */
export interface LogAlertCondition {
  id: string;
  name: string;
  enabled: boolean;
  condition: {
    type: 'error_rate' | 'error_count' | 'warning_rate' | 'pattern_match' | 'keyword';
    threshold?: number;
    timeWindow?: number;
    pattern?: string;
    keyword?: string;
  };
  cooldown: number;
  lastTriggered?: number;
}

/**
 * LogAggregator - Log aggregation and analysis capabilities
 */
export class LogAggregator extends EventEmitter {
  private static instance: LogAggregator;
  private logs: LogEntry[] = [];
  private maxLogs: number = 100000;
  private queryIndexes: Map<string, LogEntry[]> = new Map();
  private alertConditions: Map<string, LogAlertCondition> = new Map();
  private idCounter: number = 0;

  private constructor(maxLogs: number = 100000) {
    super();
    this.maxLogs = maxLogs;
    this.initializeDefaultAlertConditions();
  }

  /**
   * Get singleton instance
   */
  static getInstance(maxLogs?: number): LogAggregator {
    if (!LogAggregator.instance) {
      LogAggregator.instance = new LogAggregator(maxLogs);
    }
    return LogAggregator.instance;
  }

  /**
   * Initialize default alert conditions
   */
  private initializeDefaultAlertConditions(): void {
    this.registerAlertCondition({
      id: 'high_error_rate',
      name: 'High Error Rate',
      enabled: true,
      condition: { type: 'error_rate', threshold: 10, timeWindow: 60000 },
      cooldown: 300000,
    });

    this.registerAlertCondition({
      id: 'critical_errors',
      name: 'Critical Errors',
      enabled: true,
      condition: { type: 'error_count', threshold: 5, timeWindow: 60000 },
      cooldown: 60000,
    });

    this.registerAlertCondition({
      id: 'auth_failures',
      name: 'Authentication Failures',
      enabled: true,
      condition: { type: 'keyword', keyword: 'authentication failed', timeWindow: 300000 },
      cooldown: 300000,
    });
  }

  /**
   * Register an alert condition
   */
  registerAlertCondition(condition: LogAlertCondition): void {
    this.alertConditions.set(condition.id, condition);
    this.emit('alertConditionRegistered', condition);
  }

  /**
   * Log an entry
   */
  log(entry: Omit<LogEntry, 'id' | 'timestamp'>): string {
    const id = `log_${++this.idCounter}_${Date.now()}`;
    const logEntry: LogEntry = {
      ...entry,
      id,
      timestamp: Date.now(),
    };

    this.logs.push(logEntry);

    // Trim if exceeds max
    if (this.logs.length > this.maxLogs) {
      this.logs = this.logs.slice(-this.maxLogs);
    }

    // Update indexes
    this.updateIndexes(logEntry);

    // Check alert conditions
    this.checkAlertConditions(logEntry);

    this.emit('log', logEntry);
    return id;
  }

  /**
   * Convenience methods for logging
   */
  debug(message: string, metadata?: Record<string, any>, source: LogSource = 'server'): string {
    return this.log({ level: 'debug', source, message, metadata });
  }

  info(message: string, metadata?: Record<string, any>, source: LogSource = 'server'): string {
    return this.log({ level: 'info', source, message, metadata });
  }

  warn(message: string, metadata?: Record<string, any>, source: LogSource = 'server'): string {
    return this.log({ level: 'warn', source, message, metadata });
  }

  error(message: string, metadata?: Record<string, any>, source: LogSource = 'server'): string {
    return this.log({ level: 'error', source, message, metadata });
  }

  fatal(message: string, metadata?: Record<string, any>, source: LogSource = 'server'): string {
    return this.log({ level: 'fatal', source, message, metadata });
  }

  /**
   * Update query indexes
   */
  private updateIndexes(entry: LogEntry): void {
    // Index by level
    const levelKey = `level_${entry.level}`;
    if (!this.queryIndexes.has(levelKey)) {
      this.queryIndexes.set(levelKey, []);
    }
    this.queryIndexes.get(levelKey)!.push(entry);

    // Index by source
    const sourceKey = `source_${entry.source}`;
    if (!this.queryIndexes.has(sourceKey)) {
      this.queryIndexes.set(sourceKey, []);
    }
    this.queryIndexes.get(sourceKey)!.push(entry);

    // Index by trace
    if (entry.traceId) {
      const traceKey = `trace_${entry.traceId}`;
      if (!this.queryIndexes.has(traceKey)) {
        this.queryIndexes.set(traceKey, []);
      }
      this.queryIndexes.get(traceKey)!.push(entry);
    }
  }

  /**
   * Query logs
   */
  query(query: LogQuery): LogEntry[] {
    let results = this.logs;

    if (query.startTime) {
      results = results.filter((log) => log.timestamp >= query.startTime!);
    }
    if (query.endTime) {
      results = results.filter((log) => log.timestamp <= query.endTime!);
    }
    if (query.levels && query.levels.length > 0) {
      results = results.filter((log) => query.levels!.includes(log.level));
    }
    if (query.sources && query.sources.length > 0) {
      results = results.filter((log) => query.sources!.includes(log.source));
    }
    if (query.search) {
      const search = query.search.toLowerCase();
      results = results.filter(
        (log) =>
          log.message.toLowerCase().includes(search) ||
          (log.metadata && JSON.stringify(log.metadata).toLowerCase().includes(search))
      );
    }
    if (query.traceId) {
      results = results.filter((log) => log.traceId === query.traceId);
    }
    if (query.botName) {
      results = results.filter((log) => log.botName === query.botName);
    }
    if (query.provider) {
      results = results.filter((log) => log.provider === query.provider);
    }

    // Sort by timestamp descending
    results.sort((a, b) => b.timestamp - a.timestamp);

    // Apply pagination
    const offset = query.offset || 0;
    const limit = query.limit || 100;
    results = results.slice(offset, offset + limit);

    return results;
  }

  /**
   * Get log statistics
   */
  getStats(timeWindowMs: number = 3600000): LogStats {
    const cutoff = Date.now() - timeWindowMs;

    const byLevel: Record<LogLevel, number> = {
      debug: 0,
      info: 0,
      warn: 0,
      error: 0,
      fatal: 0,
    };

    const bySource: Record<LogSource, number> = {
      server: 0,
      discord: 0,
      slack: 0,
      mattermost: 0,
      llm: 0,
      mcp: 0,
      database: 0,
      security: 0,
      custom: 0,
    };

    // Time series setup
    const numBuckets = 60;
    const bucketSize = Math.floor(timeWindowMs / numBuckets);
    const timeSeries: { timestamp: number; count: number }[] = Array.from(
      { length: numBuckets },
      (_, i) => ({
        timestamp: cutoff + i * bucketSize,
        count: 0,
      })
    );

    let total = 0;
    const recentErrors: LogEntry[] = [];

    // Reverse iterate to quickly find recent errors and efficiently process logs
    for (let i = this.logs.length - 1; i >= 0; i--) {
      const log = this.logs[i];

      // Collect up to 10 recent errors across all logs (maintaining original behavior)
      if (recentErrors.length < 10 && (log.level === 'error' || log.level === 'fatal')) {
        recentErrors.unshift(log); // unshift to maintain chronological order
      }

      if (log.timestamp >= cutoff) {
        total++;
        byLevel[log.level]++;
        bySource[log.source]++;

        // Calculate bucket index
        const bucketIndex = Math.floor((log.timestamp - cutoff) / bucketSize);
        if (bucketIndex >= 0 && bucketIndex < numBuckets) {
          timeSeries[bucketIndex].count++;
        }
      } else if (recentErrors.length >= 10) {
        // Optimization: since logs are chronological, if we hit a log before the cutoff
        // AND we've already found our 10 recent errors, we can stop entirely
        // This makes the operation O(recent logs) rather than O(all logs)
        break;
      }
    }

    const errorCount = byLevel.error + byLevel.fatal;
    const warningCount = byLevel.warn;

    return {
      totalLogs: total,
      byLevel,
      bySource,
      errorRate: total > 0 ? (errorCount / total) * 100 : 0,
      warningsRate: total > 0 ? (warningCount / total) * 100 : 0,
      recentErrors,
      timeSeries,
    };
  }

  /**
   * Get logs by trace
   */
  getLogsByTrace(traceId: string): LogEntry[] {
    return this.logs
      .filter((log) => log.traceId === traceId)
      .sort((a, b) => a.timestamp - b.timestamp);
  }

  /**
   * Check alert conditions
   */
  private checkAlertConditions(entry: LogEntry): void {
    for (const [id, condition] of this.alertConditions) {
      if (!condition.enabled) continue;

      // Check cooldown
      if (condition.lastTriggered && Date.now() - condition.lastTriggered < condition.cooldown) {
        continue;
      }

      const shouldTrigger = this.evaluateCondition(condition, entry);
      if (shouldTrigger) {
        this.emit('alertTriggered', {
          condition,
          entry,
        });
        condition.lastTriggered = Date.now();
      }
    }
  }

  /**
   * Evaluate an alert condition
   */
  private evaluateCondition(condition: LogAlertCondition, entry: LogEntry): boolean {
    const { type, threshold, timeWindow, pattern, keyword } = condition.condition;
    const windowStart = Date.now() - (timeWindow || 60000);

    switch (type) {
      case 'error_rate': {
        if (entry.level !== 'error' && entry.level !== 'fatal') return false;
        const recentErrors = this.logs.filter(
          (log) => (log.level === 'error' || log.level === 'fatal') && log.timestamp >= windowStart
        ).length;
        return threshold ? recentErrors >= threshold : false;
      }

      case 'error_count': {
        if (entry.level !== 'error' && entry.level !== 'fatal') return false;
        return true;
      }

      case 'warning_rate': {
        if (entry.level !== 'warn') return false;
        const recentWarnings = this.logs.filter(
          (log) => log.level === 'warn' && log.timestamp >= windowStart
        ).length;
        return threshold ? recentWarnings >= threshold : false;
      }

      case 'pattern_match': {
        if (!pattern) return false;
        const regex = new RegExp(pattern, 'i');
        return regex.test(entry.message);
      }

      case 'keyword': {
        if (!keyword) return false;
        return entry.message.toLowerCase().includes(keyword.toLowerCase());
      }

      default:
        return false;
    }
  }

  /**
   * Get all alert conditions
   */
  getAlertConditions(): LogAlertCondition[] {
    return Array.from(this.alertConditions.values());
  }

  /**
   * Enable/disable alert condition
   */
  setAlertConditionEnabled(id: string, enabled: boolean): void {
    const condition = this.alertConditions.get(id);
    if (condition) {
      condition.enabled = enabled;
    }
  }

  /**
   * Get recent logs
   */
  getRecentLogs(limit: number = 100): LogEntry[] {
    return this.logs.slice(-limit).reverse();
  }

  /**
   * Get error logs
   */
  getErrorLogs(limit: number = 100): LogEntry[] {
    return this.logs
      .filter((log) => log.level === 'error' || log.level === 'fatal')
      .slice(-limit)
      .reverse();
  }

  /**
   * Clear all logs
   */
  clear(): void {
    this.logs = [];
    this.queryIndexes.clear();
    this.emit('cleared');
  }

  /**
   * Get total log count
   */
  getLogCount(): number {
    return this.logs.length;
  }

  /**
   * Export logs
   */
  exportLogs(query?: LogQuery): LogEntry[] {
    return query ? this.query(query) : [...this.logs];
  }
}

export default LogAggregator;

import { EventEmitter } from 'events';

export interface Metrics {
  messagesProcessed: number;
  activeConnections: number;
  responseTime: number[];
  errors: number;
  uptime: number;
  llmTokenUsage: number;
}

export interface MetricData {
  name: string;
  value: number;
  timestamp: string;
  tags?: Record<string, string>;
}

export interface MetricDefinition {
  name: string;
  type: 'counter' | 'gauge' | 'histogram';
  description: string;
  unit: string;
}

export interface PerformanceMetrics {
  cpuUsage: number;
  memoryUsage: number;
  diskUsage: number;
  networkIO: number;
  responseTime: number;
  throughput: number;
}

export class MetricsCollector extends EventEmitter {
  private static instance: MetricsCollector;
  private metrics: Metrics = {
    messagesProcessed: 0,
    activeConnections: 0,
    responseTime: [],
    errors: 0,
    uptime: Date.now(),
    llmTokenUsage: 0,
  };
  private history: MetricData[] = [];
  private isCollecting = false;
  private collectionInterval: NodeJS.Timeout | null = null;

  static getInstance(): MetricsCollector {
    if (!MetricsCollector.instance) {
      MetricsCollector.instance = new MetricsCollector();
    }
    return MetricsCollector.instance;
  }

  startCollection(): void {
    if (this.isCollecting) {
      return;
    }

    this.isCollecting = true;
    this.collectionInterval = setInterval(() => {
      this.collectSystemMetrics();
    }, 5000);

    this.emit('metricsCollected', this.getMetricsSummary());
  }

  stopCollection(): void {
    if (!this.isCollecting) {
      return;
    }

    this.isCollecting = false;
    if (this.collectionInterval) {
      clearInterval(this.collectionInterval);
      this.collectionInterval = null;
    }
  }

  private collectSystemMetrics(): void {
    const timestamp = new Date().toISOString();

    // Collect CPU usage (placeholder)
    const cpuUsage = Math.random() * 100;
    this.recordMetric('cpu_usage', cpuUsage, { timestamp });

    // Collect memory usage
    const memoryUsage = process.memoryUsage();
    this.recordMetric('memory_usage', memoryUsage.heapUsed / 1024 / 1024, { timestamp });

    // Emit collected metrics
    this.emit('metricsCollected', this.getMetricsSummary());
  }

  incrementMessages(): void {
    this.metrics.messagesProcessed++;
    this.recordMetric('messages_processed', this.metrics.messagesProcessed);
  }

  incrementRequestCount(): void {
    this.incrementMessages();
  }

  recordResponseTime(time: number): void {
    this.metrics.responseTime.push(time);
    if (this.metrics.responseTime.length > 100) {
      this.metrics.responseTime.shift();
    }
    this.recordMetric('response_time', time);
  }

  incrementErrors(): void {
    this.metrics.errors++;
    this.recordMetric('errors', this.metrics.errors);
  }

  incrementErrorCount(): void {
    this.incrementErrors();
  }

  setActiveConnections(count: number): void {
    this.metrics.activeConnections = count;
    this.recordMetric('active_connections', count);
  }

  recordLlmTokenUsage(tokens: number): void {
    this.metrics.llmTokenUsage += tokens;
    this.recordMetric('llm_token_usage', this.metrics.llmTokenUsage);
  }

  recordMetric(name: string, value: number, tags?: Record<string, string>): void {
    const metricData: MetricData = {
      name,
      value,
      timestamp: new Date().toISOString(),
      tags,
    };

    this.history.push(metricData);

    // Keep only last 1000 metrics
    if (this.history.length > 1000) {
      this.history = this.history.slice(-1000);
    }

    this.emit('metricRecorded', metricData);
  }

  getLatestValue(metricName: string): number | undefined {
    const latestMetric = this.history.filter((m) => m.name === metricName).pop();
    return latestMetric?.value;
  }

  getAllMetrics(): MetricData[] {
    return [...this.history];
  }

  getMetrics(): Metrics {
    return {
      ...this.metrics,
      uptime: Date.now() - this.metrics.uptime,
    };
  }

  getMetricsSummary(): {
    timestamp: string;
    metrics: Metrics;
    performance: PerformanceMetrics;
    historySize: number;
  } {
    const avgResponseTime =
      this.metrics.responseTime.length > 0
        ? this.metrics.responseTime.reduce((a, b) => a + b, 0) / this.metrics.responseTime.length
        : 0;

    const performance: PerformanceMetrics = {
      cpuUsage: this.getLatestValue('cpu_usage') || 0,
      memoryUsage: this.getLatestValue('memory_usage') || 0,
      diskUsage: Math.random() * 100, // placeholder
      networkIO: Math.random() * 1000, // placeholder
      responseTime: avgResponseTime,
      throughput:
        this.metrics.messagesProcessed / (Math.max(1, Date.now() - this.metrics.uptime) / 1000),
    };

    return {
      timestamp: new Date().toISOString(),
      metrics: this.getMetrics(),
      performance,
      historySize: this.history.length,
    };
  }

  getPrometheusFormat(): string {
    const m = this.getMetrics();
    const avgResponseTime =
      m.responseTime.length > 0
        ? m.responseTime.reduce((a, b) => a + b, 0) / m.responseTime.length
        : 0;

    return `# HELP hivemind_messages_total Total messages processed
# TYPE hivemind_messages_total counter
hivemind_messages_total ${m.messagesProcessed}

# HELP hivemind_active_connections Current active connections
# TYPE hivemind_active_connections gauge
hivemind_active_connections ${m.activeConnections}

# HELP hivemind_response_time_ms Average response time in milliseconds
# TYPE hivemind_response_time_ms gauge
hivemind_response_time_ms ${avgResponseTime}

# HELP hivemind_errors_total Total errors encountered
# TYPE hivemind_errors_total counter
hivemind_errors_total ${m.errors}

# HELP hivemind_uptime_seconds Uptime in seconds
# TYPE hivemind_uptime_seconds gauge
hivemind_uptime_seconds ${Math.floor(m.uptime / 1000)}

# HELP hivemind_llm_token_usage_total Total LLM token usage
# TYPE hivemind_llm_token_usage_total counter
hivemind_llm_token_usage_total ${m.llmTokenUsage}`;
  }

  async exportMetricsData(): Promise<string> {
    const metricsData = {
      timestamp: new Date().toISOString(),
      current: this.getMetrics(),
      history: this.history,
      summary: this.getMetricsSummary(),
    };

    return JSON.stringify(metricsData, null, 2);
  }

  reset(): void {
    this.metrics = {
      messagesProcessed: 0,
      activeConnections: 0,
      responseTime: [],
      errors: 0,
      uptime: Date.now(),
      llmTokenUsage: 0,
    };
    this.history = [];
    console.log('📊 Metrics reset');
  }

  /**
   * Gracefully shutdown the MetricsCollector.
   * Stops collection and clears all data.
   */
  shutdown(): void {
    this.stopCollection();
    this.history = [];
    this.removeAllListeners();
    console.log('📊 MetricsCollector shutdown complete');
  }
}

import type { NextFunction, Request, Response } from 'express';
import { AlertManager, type AlertConfig, type NotificationChannel } from './AlertManager';
import { HealthChecker } from './HealthChecker';
import { MetricsCollector } from './MetricsCollector';

export interface MonitoringConfig {
  healthCheck: {
    enabled: boolean;
    interval: number;
    maxHistory: number;
  };
  alerts: {
    enabled: boolean;
    config: AlertConfig;
    channels: NotificationChannel[];
  };
  metrics: {
    enabled: boolean;
    interval: number;
    historySize: number;
  };
  endpoints: {
    health: string;
    metrics: string;
    alerts: string;
  };
}

export class MonitoringService {
  private healthChecker: HealthChecker;
  private alertManager: AlertManager;
  private metricsCollector: MetricsCollector;
  private config: MonitoringConfig;
  private isRunning = false;

  constructor(config: Partial<MonitoringConfig> = {}) {
    this.config = {
      healthCheck: {
        enabled: true,
        interval: 30000,
        maxHistory: 100,
        ...config.healthCheck,
      },
      alerts: {
        enabled: true,
        config: {
          memoryThreshold: 85,
          diskThreshold: 90,
          responseTimeThreshold: 1000,
          errorRateThreshold: 5,
          consecutiveFailures: 3,
          cooldownPeriod: 300000,
          ...config.alerts?.config,
        },
        channels: config.alerts?.channels || [],
      },
      metrics: {
        enabled: true,
        interval: 5000,
        historySize: 1000,
        ...config.metrics,
      },
      endpoints: {
        health: '/health',
        metrics: '/metrics',
        alerts: '/alerts',
        ...config.endpoints,
      },
      ...config,
    };

    // Initialize components
    this.healthChecker = new HealthChecker(
      this.config.healthCheck.interval,
      this.config.healthCheck.maxHistory
    );

    this.alertManager = new AlertManager(this.healthChecker, this.config.alerts.config);

    this.metricsCollector = MetricsCollector.getInstance();

    // Add notification channels
    this.config.alerts.channels.forEach((channel) => {
      this.alertManager.addNotificationChannel(channel);
    });

    // Set up event listeners
    this.setupEventListeners();
  }

  private setupEventListeners(): void {
    // Health check events
    this.alertManager.on('healthCheck', (healthCheck) => {
      console.log(`💓 Health check completed: ${healthCheck.status}`);
    });

    // Alert events
    this.alertManager.on('alertCreated', (alert) => {
      console.log(`🚨 Alert created: ${alert.title} (${alert.severity})`);
    });

    this.alertManager.on('alertAcknowledged', (alert) => {
      console.log(`✅ Alert acknowledged: ${alert.title}`);
    });

    this.alertManager.on('alertResolved', (alert) => {
      console.log(`✅ Alert resolved: ${alert.title}`);
    });

    // Metrics events
    this.metricsCollector.on('metricRecorded', (data) => {
      // Optional: log specific metric events
      if (data.name === 'memory_percentage' && data.value > 80) {
        console.log(`⚠️ High memory usage: ${data.value}%`);
      }
    });

    this.metricsCollector.on('metricsCollected', (metrics) => {
      // Optional: process collected metrics
    });
  }

  public async start(): Promise<void> {
    if (this.isRunning) {
      console.log('Monitoring service already running');
      return;
    }

    console.log('🔧 Starting monitoring service...');

    try {
      // Start metrics collection
      if (this.config.metrics.enabled) {
        this.metricsCollector.startCollection();
        console.log('📊 Metrics collection started');
      }

      // Health checking is started automatically by AlertManager
      if (this.config.healthCheck.enabled) {
        console.log('💓 Health checking started');
      }

      this.isRunning = true;
      console.log('✅ Monitoring service started successfully');

      // Perform initial health check
      const initialHealth = await this.healthChecker.performHealthCheck();
      console.log(`🔍 Initial health status: ${initialHealth.status}`);
    } catch (error) {
      console.error('❌ Failed to start monitoring service:', error);
      throw error;
    }
  }

  public stop(): void {
    if (!this.isRunning) {
      console.log('Monitoring service not running');
      return;
    }

    console.log('🔧 Stopping monitoring service...');

    try {
      // Stop metrics collection
      if (this.config.metrics.enabled) {
        this.metricsCollector.stopCollection();
        console.log('📊 Metrics collection stopped');
      }

      this.isRunning = false;
      console.log('✅ Monitoring service stopped');
    } catch (error) {
      console.error('❌ Error stopping monitoring service:', error);
    }
  }

  /**
   * Gracefully shutdown the MonitoringService and all its components.
   * This is more comprehensive than stop() - it shuts down all sub-components.
   */
  public shutdown(): void {
    console.log('🔧 Shutting down monitoring service...');

    // Stop the service first
    this.stop();

    // Shutdown sub-components
    if (this.alertManager) {
      this.alertManager.shutdown();
      console.log('🚨 AlertManager shutdown complete');
    }

    if (this.healthChecker) {
      this.healthChecker.shutdown();
      console.log('💓 HealthChecker shutdown complete');
    }

    if (this.metricsCollector) {
      this.metricsCollector.shutdown();
      console.log('📊 MetricsCollector shutdown complete');
    }

    console.log('✅ MonitoringService shutdown complete');
  }

  public getHealthMiddleware() {
    return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const healthCheck = await this.healthChecker.performHealthCheck();

        res
          .status(
            healthCheck.status === 'healthy' ? 200 : healthCheck.status === 'degraded' ? 429 : 503
          )
          .json(healthCheck);
      } catch (error) {
        console.error('Health check endpoint error:', error);
        res.status(500).json({
          status: 'error',
          message: 'Health check failed',
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    };
  }

  public getMetricsMiddleware() {
    return (req: Request, res: Response, next: NextFunction): void => {
      try {
        const metrics = this.metricsCollector.getAllMetrics();
        const summary = this.metricsCollector.getMetricsSummary();

        res.json({
          timestamp: new Date().toISOString(),
          summary,
          metrics,
        });
      } catch (error) {
        console.error('Metrics endpoint error:', error);
        res.status(500).json({
          status: 'error',
          message: 'Failed to retrieve metrics',
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    };
  }

  public getAlertsMiddleware() {
    return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const alerts = this.alertManager.getAllAlerts();
        const summary = await this.alertManager.getAlertSummary();

        res.json({
          timestamp: new Date().toISOString(),
          summary,
          alerts,
        });
      } catch (error) {
        console.error('Alerts endpoint error:', error);
        res.status(500).json({
          status: 'error',
          message: 'Failed to retrieve alerts',
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    };
  }

  public getAlertActionMiddleware() {
    return async (req: Request, res: Response, next: NextFunction): Promise<void> => {
      try {
        const { alertId, action } = req.params;

        let result: boolean;
        switch (action) {
          case 'acknowledge':
            result = this.alertManager.acknowledgeAlert(alertId);
            break;
          case 'resolve':
            result = this.alertManager.resolveAlert(alertId);
            break;
          default:
            res.status(400).json({
              status: 'error',
              message: 'Invalid action. Use "acknowledge" or "resolve"',
            });
            return;
        }

        if (result) {
          res.json({
            status: 'success',
            message: `Alert ${action}d successfully`,
            alertId,
          });
        } else {
          res.status(404).json({
            status: 'error',
            message: 'Alert not found or already processed',
          });
        }
      } catch (error) {
        console.error('Alert action endpoint error:', error);
        res.status(500).json({
          status: 'error',
          message: 'Failed to process alert action',
          error: error instanceof Error ? error.message : 'Unknown error',
        });
      }
    };
  }

  public getExpressMiddleware() {
    return [
      // Health check endpoint
      this.config.endpoints.health,
      this.getHealthMiddleware(),

      // Metrics endpoint
      this.config.endpoints.metrics,
      this.getMetricsMiddleware(),

      // Alerts endpoints
      this.config.endpoints.alerts,
      this.getAlertsMiddleware(),

      // Alert action endpoint
      `${this.config.endpoints.alerts}/:alertId/:action`,
      this.getAlertActionMiddleware(),
    ];
  }

  // Utility methods for application integration
  public recordRequest(): void {
    if (this.config.metrics.enabled) {
      this.metricsCollector.incrementRequestCount();
    }
  }

  public recordResponseTime(responseTime: number): void {
    if (this.config.metrics.enabled) {
      this.metricsCollector.recordResponseTime(responseTime);
    }
  }

  public recordError(): void {
    if (this.config.metrics.enabled) {
      this.metricsCollector.incrementErrorCount();
    }
  }

  public incrementActiveConnections(): void {
    if (this.config.metrics.enabled) {
      const current = this.metricsCollector.getLatestValue('app_active_connections') || 0;
      this.metricsCollector.recordMetric('app_active_connections', current + 1);
    }
  }

  public decrementActiveConnections(): void {
    if (this.config.metrics.enabled) {
      const current = this.metricsCollector.getLatestValue('app_active_connections') || 0;
      this.metricsCollector.recordMetric('app_active_connections', Math.max(0, current - 1));
    }
  }

  // Data export methods
  public async exportMonitoringData(): Promise<string> {
    const healthData = await this.healthChecker.exportHealthData();
    const metricsData = await this.metricsCollector.exportMetricsData();
    const alertData = await this.alertManager.exportAlertData();

    return JSON.stringify(
      {
        timestamp: new Date().toISOString(),
        config: this.config,
        health: JSON.parse(healthData),
        metrics: JSON.parse(metricsData),
        alerts: JSON.parse(alertData),
      },
      null,
      2
    );
  }

  public async saveMonitoringReport(filePath: string): Promise<void> {
    const monitoringData = await this.exportMonitoringData();
    const { promises: fs } = await import('fs');
    await fs.writeFile(filePath, monitoringData, 'utf-8');
  }

  // Getters for accessing monitoring components
  public getHealthChecker(): HealthChecker {
    return this.healthChecker;
  }

  public getAlertManager(): AlertManager {
    return this.alertManager;
  }

  public getMetricsCollector(): MetricsCollector {
    return this.metricsCollector;
  }

  public getStatus(): {
    isRunning: boolean;
    config: MonitoringConfig;
    health: any;
    alerts: any;
    metrics: any;
  } {
    return {
      isRunning: this.isRunning,
      config: this.config,
      health: {
        historyLength: this.healthChecker.getHealthHistory().length,
      },
      alerts: {
        activeCount: this.alertManager.getActiveAlerts().length,
        totalCount: this.alertManager.getAllAlerts().length,
      },
      metrics: {
        summary: this.metricsCollector.getMetricsSummary(),
      },
    };
  }
}

