      checkInterval: 60000,
      timeout: 10000,
      retries: 3,
      consecutiveFailuresThreshold: 5,
    },
    {
      provider: 'n8n',
      type: 'llm',
      enabled: true,
      checkInterval: 60000,
      timeout: 10000,
      retries: 3,
      consecutiveFailuresThreshold: 5,
    },
  ],
  historySize: 1000,
  aggregationInterval: 60000,
};

/**
 * ProviderMetricsCollector - Comprehensive metrics collection for all providers
 */
export class ProviderMetricsCollector extends EventEmitter {
  private static instance: ProviderMetricsCollector;
  private messageProviders: Map<ProviderType, MessageProviderMetrics> = new Map();
  private llmProviders: Map<ProviderType, LlmProviderMetrics> = new Map();
  private config: ProviderMonitoringConfig;
  private monitoringIntervals: Map<string, NodeJS.Timeout> = new Map();
  private isMonitoring = false;
  private responseTimes: Map<ProviderType, number[]> = new Map();
  private latencyHistory: Map<ProviderType, number[]> = new Map();
  private costHistory: Map<ProviderType, number[]> = new Map();

  private constructor(config: Partial<ProviderMonitoringConfig> = {}) {
    super();
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.initializeProviders();
  }

  /**
   * Get singleton instance
   */
  static getInstance(config?: Partial<ProviderMonitoringConfig>): ProviderMetricsCollector {
    if (!ProviderMetricsCollector.instance) {
      ProviderMetricsCollector.instance = new ProviderMetricsCollector(config);
    }
    return ProviderMetricsCollector.instance;
  }

  /**
   * Initialize all providers with default metrics
   */
  private initializeProviders(): void {
    // Initialize message providers
    const messageProviderTypes: ProviderType[] = ['discord', 'slack', 'mattermost'];
    for (const provider of messageProviderTypes) {
      this.messageProviders.set(provider, this.createDefaultMessageMetrics(provider));
    }

    // Initialize LLM providers
    const llmProviderTypes: ProviderType[] = [
      'openai',
      'flowise',
      'openwebui',
      'openswarm',
      'perplexity',
      'replicate',
      'n8n',
    ];
    for (const provider of llmProviderTypes) {
      this.llmProviders.set(provider, this.createDefaultLlmMetrics(provider));
    }
  }

  /**
   * Create default message provider metrics
   */
  private createDefaultMessageMetrics(provider: ProviderType): MessageProviderMetrics {
    return {
      provider,
      status: 'unknown',
      messagesReceived: 0,
      messagesSent: 0,
      messagesFailed: 0,
      averageResponseTime: 0,
      lastMessageTime: null,
      lastErrorTime: null,
      errorRate: 0,
      uptime: 0,
      activeConnections: 0,
      rateLimitHits: 0,
      rateLimitRemaining: -1,
    };
  }

  /**
   * Create default LLM provider metrics
   */
  private createDefaultLlmMetrics(provider: ProviderType): LlmProviderMetrics {
    return {
      provider,
      status: 'unknown',
      requestsTotal: 0,
      requestsSuccessful: 0,
      requestsFailed: 0,
      tokensUsed: 0,
      tokensPrompt: 0,
      tokensCompletion: 0,
      averageLatency: 0,
      p50Latency: 0,
      p95Latency: 0,
      p99Latency: 0,
      averageCost: 0,
      totalCost: 0,
      lastRequestTime: null,
      lastErrorTime: null,
      errorRate: 0,
      rateLimitHits: 0,
      rateLimitRemaining: -1,
      contextLength: 0,
      modelName: '',
    };
  }

  /**
   * Record message received
   */
  recordMessageReceived(provider: ProviderType, responseTime?: number): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      metrics.messagesReceived++;
      metrics.lastMessageTime = Date.now();
      if (responseTime !== undefined) {
        this.recordResponseTime(provider, responseTime);
      }
      this.emit('messageReceived', { provider, metrics: { ...metrics } });
    }
  }

  /**
   * Record message sent
   */
  recordMessageSent(provider: ProviderType, responseTime?: number): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      metrics.messagesSent++;
      metrics.lastMessageTime = Date.now();
      if (responseTime !== undefined) {
        this.recordResponseTime(provider, responseTime);
      }
      this.emit('messageSent', { provider, metrics: { ...metrics } });
    }
  }

  /**
   * Record message failure
   */
  recordMessageFailed(provider: ProviderType, error?: string): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      metrics.messagesFailed++;
      metrics.lastErrorTime = Date.now();
      this.updateErrorRate(provider);
      this.emit('messageFailed', { provider, error, metrics: { ...metrics } });
    }
  }

  /**
   * Record LLM request
   */
  recordLlmRequest(
    provider: ProviderType,
    latency: number,
    tokens: { prompt?: number; completion?: number; total?: number },
    cost?: number,
    success: boolean = true,
    modelName?: string
  ): void {
    const metrics = this.llmProviders.get(provider);
    if (metrics) {
      metrics.requestsTotal++;
      if (success) {
        metrics.requestsSuccessful++;
      } else {
        metrics.requestsFailed++;
      }

      if (tokens.prompt) metrics.tokensPrompt += tokens.prompt;
      if (tokens.completion) metrics.tokensCompletion += tokens.completion;
      if (tokens.total) metrics.tokensUsed += tokens.total;
      if (cost !== undefined) {
        metrics.totalCost += cost;
        metrics.averageCost = metrics.totalCost / metrics.requestsTotal;
      }

      metrics.lastRequestTime = Date.now();
      if (!success) {
        metrics.lastErrorTime = Date.now();
      }

      this.recordLatency(provider, latency);
      this.updateErrorRateLLM(provider);

      if (modelName) {
        metrics.modelName = modelName;
      }

      this.emit('llmRequest', {
        provider,
        latency,
        tokens,
        cost,
        success,
        metrics: { ...metrics },
      });
    }
  }

  /**
   * Record response time for message provider
   */
  private recordResponseTime(provider: ProviderType, responseTime: number): void {
    let times = this.responseTimes.get(provider);
    if (!times) {
      times = [];
      this.responseTimes.set(provider, times);
    }
    times.push(responseTime);
    if (times.length > this.config.historySize) {
      times.shift();
    }

    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      metrics.averageResponseTime = times.reduce((a, b) => a + b, 0) / times.length;
    }
  }

  /**
   * Record latency for LLM provider
   */
  private recordLatency(provider: ProviderType, latency: number): void {
    let latencies = this.latencyHistory.get(provider);
    if (!latencies) {
      latencies = [];
      this.latencyHistory.set(provider, latencies);
    }
    latencies.push(latency);
    if (latencies.length > this.config.historySize) {
      latencies.shift();
    }

    const metrics = this.llmProviders.get(provider);
    if (metrics && latencies.length > 0) {
      const sorted = [...latencies].sort((a, b) => a - b);
      metrics.averageLatency = latencies.reduce((a, b) => a + b, 0) / latencies.length;
      metrics.p50Latency = this.percentile(sorted, 50);
      metrics.p95Latency = this.percentile(sorted, 95);
      metrics.p99Latency = this.percentile(sorted, 99);
    }
  }

  /**
   * Calculate percentile
   */
  private percentile(sorted: number[], p: number): number {
    if (sorted.length === 0) return 0;
    const index = Math.ceil((p / 100) * sorted.length) - 1;
    return sorted[Math.max(0, index)];
  }

  /**
   * Update error rate for message provider
   */
  private updateErrorRate(provider: ProviderType): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      const total = metrics.messagesReceived + metrics.messagesSent + metrics.messagesFailed;
      if (total > 0) {
        metrics.errorRate = (metrics.messagesFailed / total) * 100;
      }
      this.updateProviderStatus(provider);
    }
  }

  /**
   * Update error rate for LLM provider
   */
  private updateErrorRateLLM(provider: ProviderType): void {
    const metrics = this.llmProviders.get(provider);
    if (metrics && metrics.requestsTotal > 0) {
      metrics.errorRate = (metrics.requestsFailed / metrics.requestsTotal) * 100;
      this.updateProviderStatusLLM(provider);
    }
  }

  /**
   * Update message provider status based on metrics
   */
  private updateProviderStatus(provider: ProviderType): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      if (metrics.errorRate > 50 || metrics.messagesFailed > 100) {
        metrics.status = 'unhealthy';
      } else if (metrics.errorRate > 10 || metrics.messagesFailed > 10) {
        metrics.status = 'degraded';
      } else if (metrics.messagesReceived > 0 || metrics.messagesSent > 0) {
        metrics.status = 'healthy';
      } else {
        metrics.status = 'unknown';
      }
    }
  }

  /**
   * Update LLM provider status based on metrics
   */
  private updateProviderStatusLLM(provider: ProviderType): void {
    const metrics = this.llmProviders.get(provider);
    if (metrics) {
      if (metrics.errorRate > 50 || metrics.requestsFailed > 100) {
        metrics.status = 'unhealthy';
      } else if (metrics.errorRate > 10 || metrics.requestsFailed > 10) {
        metrics.status = 'degraded';
      } else if (metrics.requestsTotal > 0) {
        metrics.status = 'healthy';
      } else {
        metrics.status = 'unknown';
      }
    }
  }

  /**
   * Record rate limit hit
   */
  recordRateLimitHit(provider: ProviderType, type: 'message' | 'llm'): void {
    if (type === 'message') {
      const metrics = this.messageProviders.get(provider);
      if (metrics) {
        metrics.rateLimitHits++;
        this.emit('rateLimitHit', { provider, type: 'message', metrics: { ...metrics } });
      }
    } else {
      const metrics = this.llmProviders.get(provider);
      if (metrics) {
        metrics.rateLimitHits++;
        this.emit('rateLimitHit', { provider, type: 'llm', metrics: { ...metrics } });
      }
    }
  }

  /**
   * Update rate limit remaining
   */
  updateRateLimitRemaining(
    provider: ProviderType,
    remaining: number,
    type: 'message' | 'llm'
  ): void {
    if (type === 'message') {
      const metrics = this.messageProviders.get(provider);
      if (metrics) {
        metrics.rateLimitRemaining = remaining;
      }
    } else {
      const metrics = this.llmProviders.get(provider);
      if (metrics) {
        metrics.rateLimitRemaining = remaining;
      }
    }
  }

  /**
   * Update active connections
   */
  updateActiveConnections(provider: ProviderType, connections: number): void {
    const metrics = this.messageProviders.get(provider);
    if (metrics) {
      metrics.activeConnections = connections;
    }
  }

  /**
   * Set provider status directly
   */
  setProviderStatus(provider: ProviderType, status: ProviderStatus, type: 'message' | 'llm'): void {
    if (type === 'message') {
      const metrics = this.messageProviders.get(provider);
      if (metrics) {
        metrics.status = status;
      }
    } else {
      const metrics = this.llmProviders.get(provider);
      if (metrics) {
        metrics.status = status;
      }
    }
    this.emit('statusChange', { provider, status, type });
  }

  /**
   * Get message provider metrics
   */
  getMessageProviderMetrics(provider: ProviderType): MessageProviderMetrics | undefined {
    return this.messageProviders.get(provider);
  }

  /**
   * Get LLM provider metrics
   */
  getLlmProviderMetrics(provider: ProviderType): LlmProviderMetrics | undefined {
    return this.llmProviders.get(provider);
  }

  /**
   * Get all message provider metrics
   */
  getAllMessageProviderMetrics(): MessageProviderMetrics[] {
    return Array.from(this.messageProviders.values());
  }

  /**
   * Get all LLM provider metrics
   */
  getAllLlmProviderMetrics(): LlmProviderMetrics[] {
    return Array.from(this.llmProviders.values());
  }

  /**
   * Get all provider metrics
   */
  getAllProviderMetrics(): ProviderMetrics[] {
    const metrics: ProviderMetrics[] = [];
    const timestamp = Date.now();

    for (const [provider, messageMetrics] of this.messageProviders) {
      metrics.push({
        type: 'message',
        messageProvider: { ...messageMetrics },
        timestamp,
      });
    }

    for (const [provider, llmMetrics] of this.llmProviders) {
      metrics.push({
        type: 'llm',
        llmProvider: { ...llmMetrics },
        timestamp,
      });
    }

    return metrics;
  }

  /**
   * Get provider summary for dashboard
   */
  getProviderSummary(): {
    messageProviders: MessageProviderMetrics[];
    llmProviders: LlmProviderMetrics[];
    overallHealth: 'healthy' | 'degraded' | 'unhealthy';
    totalMessagesProcessed: number;
    totalLlmRequests: number;
  } {
    const messageProviders = this.getAllMessageProviderMetrics();
    const llmProviders = this.getAllLlmProviderMetrics();

    const totalMessagesProcessed = messageProviders.reduce(
      (sum, p) => sum + p.messagesReceived + p.messagesSent,
      0
    );
    const totalLlmRequests = llmProviders.reduce((sum, p) => sum + p.requestsTotal, 0);

    // Determine overall health
    let overallHealth: 'healthy' | 'degraded' | 'unhealthy' = 'healthy';
    const allStatuses = [
      ...messageProviders.map((p) => p.status),
      ...llmProviders.map((p) => p.status),
    ];
    if (allStatuses.includes('unhealthy')) {
      overallHealth = 'unhealthy';
    } else if (allStatuses.includes('degraded')) {
      overallHealth = 'degraded';
    }

    return {
      messageProviders,
      llmProviders,
      overallHealth,
      totalMessagesProcessed,
      totalLlmRequests,
    };
  }

  /**
   * Start monitoring all enabled providers
   */
  startMonitoring(): void {
    if (this.isMonitoring) return;
    this.isMonitoring = true;

    for (const providerConfig of this.config.providers) {
      if (providerConfig.enabled) {
        this.startProviderMonitoring(providerConfig);
      }
    }

    this.emit('monitoringStarted');
  }

  /**
   * Start monitoring a specific provider
   */
  private startProviderMonitoring(config: ProviderHealthConfig): void {
    const intervalKey = `${config.provider}_${config.type}`;

    // Clear existing interval if any
    const existing = this.monitoringIntervals.get(intervalKey);
    if (existing) {
      clearInterval(existing);
    }

    const interval = setInterval(() => {
      this.checkProviderHealth(config);
    }, config.checkInterval);

    this.monitoringIntervals.set(intervalKey, interval);
  }

  /**
   * Check provider health
   */
  private checkProviderHealth(config: ProviderHealthConfig): void {
    if (config.type === 'message') {
      const metrics = this.messageProviders.get(config.provider);
      if (metrics) {
        this.updateProviderStatus(config.provider);
        this.emit('providerHealthCheck', {
          provider: config.provider,
          type: 'message',
          status: metrics.status,
          metrics: { ...metrics },
        });
      }
    } else {
      const metrics = this.llmProviders.get(config.provider);
      if (metrics) {
        this.updateProviderStatusLLM(config.provider);
        this.emit('providerHealthCheck', {
          provider: config.provider,
          type: 'llm',
          status: metrics.status,
          metrics: { ...metrics },
        });
      }
    }
  }

  /**
   * Stop monitoring all providers
   */
  stopMonitoring(): void {
    for (const interval of this.monitoringIntervals.values()) {
      clearInterval(interval);
    }
    this.monitoringIntervals.clear();
    this.isMonitoring = false;
    this.emit('monitoringStopped');
  }

  /**
   * Reset metrics for a provider
   */
  resetProviderMetrics(provider: ProviderType, type: 'message' | 'llm'): void {
    if (type === 'message') {
      this.messageProviders.set(provider, this.createDefaultMessageMetrics(provider));
      this.responseTimes.delete(provider);
    } else {
      this.llmProviders.set(provider, this.createDefaultLlmMetrics(provider));
      this.latencyHistory.delete(provider);
      this.costHistory.delete(provider);
    }
    this.emit('metricsReset', { provider, type });
  }

  /**
   * Reset all metrics
   */
  resetAllMetrics(): void {
    this.initializeProviders();
    this.responseTimes.clear();
    this.latencyHistory.clear();
    this.costHistory.clear();
    this.emit('allMetricsReset');
  }

  /**
   * Get Prometheus format metrics
   */
  getPrometheusFormat(): string {
    let output = '';
    const timestamp = Date.now();

    // Message provider metrics
    for (const [provider, metrics] of this.messageProviders) {
      output += `# HELP hivemind_message_provider_status Status of message provider (0=unknown, 1=healthy, 2=degraded, 3=unhealthy)\n`;
      output += `# TYPE hivemind_message_provider_status gauge\n`;
      const statusValue =
        metrics.status === 'healthy'
          ? 1
          : metrics.status === 'degraded'
            ? 2
            : metrics.status === 'unhealthy'
              ? 3
              : 0;
      output += `hivemind_message_provider_status{provider="${provider}"} ${statusValue} ${timestamp}\n`;

      output += `# HELP hivemind_messages_received Total messages received\n`;
      output += `# TYPE hivemind_messages_received counter\n`;
      output += `hivemind_messages_received{provider="${provider}"} ${metrics.messagesReceived} ${timestamp}\n`;

      output += `# HELP hivemind_messages_sent Total messages sent\n`;
      output += `# TYPE hivemind_messages_sent counter\n`;
      output += `hivemind_messages_sent{provider="${provider}"} ${metrics.messagesSent} ${timestamp}\n`;

      output += `# HELP hivemind_messages_failed Total messages failed\n`;
      output += `# TYPE hivemind_messages_failed counter\n`;
      output += `hivemind_messages_failed{provider="${provider}"} ${metrics.messagesFailed} ${timestamp}\n`;

      output += `# HELP hivemind_message_response_time Average response time in ms\n`;
      output += `# TYPE hivemind_message_response_time gauge\n`;
      output += `hivemind_message_response_time{provider="${provider}"} ${metrics.averageResponseTime} ${timestamp}\n`;
    }

    // LLM provider metrics
    for (const [provider, metrics] of this.llmProviders) {
      output += `# HELP hivemind_llm_provider_status Status of LLM provider (0=unknown, 1=healthy, 2=degraded, 3=unhealthy)\n`;
      output += `# TYPE hivemind_llm_provider_status gauge\n`;
      const statusValue =
        metrics.status === 'healthy'
          ? 1
          : metrics.status === 'degraded'
            ? 2
            : metrics.status === 'unhealthy'
              ? 3
              : 0;
      output += `hivemind_llm_provider_status{provider="${provider}"} ${statusValue} ${timestamp}\n`;

      output += `# HELP hivemind_llm_requests_total Total LLM requests\n`;
      output += `# TYPE hivemind_llm_requests_total counter\n`;
      output += `hivemind_llm_requests_total{provider="${provider}"} ${metrics.requestsTotal} ${timestamp}\n`;

      output += `# HELP hivemind_llm_tokens_used Total tokens used\n`;
      output += `# TYPE hivemind_llm_tokens_used counter\n`;
      output += `hemind_llm_tokens_used{provider="${provider}"} ${metrics.tokensUsed} ${timestamp}\n`;

      output += `# HELP hivemind_llm_latency Average latency in ms\n`;
      output += `# TYPE hivemind_llm_latency gauge\n`;
      output += `hivemind_llm_latency{provider="${provider}"} ${metrics.averageLatency} ${timestamp}\n`;

      output += `# HELP hivemind_llm_latency_p95 P95 latency in ms\n`;
      output += `# TYPE hivemind_llm_latency_p95 gauge\n`;
      output += `hivemind_llm_latency_p95{provider="${provider}"} ${metrics.p95Latency} ${timestamp}\n`;

      output += `# HELP hivemind_llm_cost_total Total cost in USD\n`;
      output += `# TYPE hivemind_llm_cost_total gauge\n`;
      output += `hivemind_llm_cost_total{provider="${provider}"} ${metrics.totalCost} ${timestamp}\n`;
    }

    return output;
  }
}

export default ProviderMetricsCollector;

import { randomUUID } from 'crypto';
import { EventEmitter } from 'events';

/**
 * Trace event types
 */
export type TraceEventType =
  | 'request_start'
  | 'request_end'
  | 'message_received'
  | 'message_sent'
  | 'llm_request_start'
  | 'llm_request_end'
  | 'mcp_call_start'
  | 'mcp_call_end'
  | 'db_query_start'
  | 'db_query_end'
  | 'external_api_call_start'
  | 'external_api_call_end'
  | 'processing_step'
  | 'error';

/**
 * Span status
 */
export type SpanStatus = 'ok' | 'error' | 'timeout' | 'cancelled';

/**
 * Trace span
 */
export interface TraceSpan {
  traceId: string;
  spanId: string;
  parentSpanId?: string;
  operationName: string;
  serviceName: string;
  startTime: number;
  endTime?: number;
  duration?: number;
  status: SpanStatus;
  tags: Record<string, string | number | boolean>;
  logs: SpanLog[];
  annotations: SpanAnnotation[];
}

/**
 * Span log entry
 */
export interface SpanLog {
  timestamp: number;
  message: string;
  fields?: Record<string, string | number | boolean>;
}

/**
 * Span annotation
 */
export interface SpanAnnotation {
  timestamp: number;
  value: string;
}

/**
 * Trace context for propagating across services
 */
export interface TraceContext {
  traceId: string;
  spanId: string;
  parentSpanId?: string;
  sampled: boolean;
}

/**
 * Trace configuration
 */
export interface TracingConfig {
  serviceName: string;
  enabled: boolean;
  sampleRate: number;
  maxSpans: number;
  exportInterval: number;
  exporters: TraceExporter[];
}

/**
 * Trace exporter interface
 */
export interface TraceExporter {
  export(spans: TraceSpan[]): Promise<void>;
}

/**
 * Console exporter for development
 */
export class ConsoleTraceExporter implements TraceExporter {
  async export(spans: TraceSpan[]): Promise<void> {
    for (const span of spans) {
      console.log(
        `[TRACE] ${span.operationName} - ${span.duration?.toFixed(2)}ms - ${span.status}`
      );
    }
  }
}

/**
 * Default configuration
 */
const DEFAULT_CONFIG: TracingConfig = {
  serviceName: 'hivemind',
  enabled: true,
  sampleRate: 1.0, // 100% sampling for now
  maxSpans: 10000,
  exportInterval: 5000,
  exporters: [new ConsoleTraceExporter()],
};

/**
 * TracingService - Distributed tracing for request flows
 */
export class TracingService extends EventEmitter {
  private static instance: TracingService;
  private config: TracingConfig;
  private activeSpans: Map<string, TraceSpan> = new Map();
  private completedSpans: TraceSpan[] = [];
  private exportInterval: NodeJS.Timeout | null = null;
  private traceIdStack: Map<string, string[]> = new Map(); // For async context tracking

  private constructor(config: Partial<TracingConfig> = {}) {
    super();
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /**
   * Get singleton instance
   */
  static getInstance(config?: Partial<TracingConfig>): TracingService {
    if (!TracingService.instance) {
      TracingService.instance = new TracingService(config);
    }
    return TracingService.instance;
  }

  /**
   * Start a new trace
   */
  startTrace(
    operationName: string,
    tags?: Record<string, string | number | boolean>
  ): TraceContext {
    const traceId = randomUUID();
    const spanId = this.generateSpanId();

    const span: TraceSpan = {
      traceId,
      spanId,
      operationName,
      serviceName: this.config.serviceName,
      startTime: Date.now(),
      status: 'ok',
      tags: {
        'service.name': this.config.serviceName,
        ...tags,
      },
      logs: [],
      annotations: [],
    };

    this.activeSpans.set(spanId, span);

    const context: TraceContext = {
      traceId,
      spanId,
      sampled: this.shouldSample(),
    };

    this.emit('traceStart', context);
    return context;
  }

  /**
   * Start a child span within an existing trace
   */
  startSpan(
    operationName: string,
    parentContext: TraceContext,
    tags?: Record<string, string | number | boolean>
  ): TraceSpan {
    const spanId = this.generateSpanId();

    const span: TraceSpan = {
      traceId: parentContext.traceId,
      spanId,
      parentSpanId: parentContext.spanId,
      operationName,
      serviceName: this.config.serviceName,
      startTime: Date.now(),
      status: 'ok',
      tags: {
        'service.name': this.config.serviceName,
        ...tags,
      },
      logs: [],
      annotations: [],
    };

    this.activeSpans.set(spanId, span);

    this.emit('spanStart', span);
    return span;
  }

  /**
   * End a span
   */
  endSpan(
    spanId: string,
    status: SpanStatus = 'ok',
    tags?: Record<string, string | number | boolean>
  ): void {
    const span = this.activeSpans.get(spanId);
    if (!span) return;

    span.endTime = Date.now();
    span.duration = span.endTime - span.startTime;
    span.status = status;

    if (tags) {
      Object.assign(span.tags, tags);
    }

    this.activeSpans.delete(spanId);
    this.completedSpans.push(span);

    // Trim if exceeds max
    if (this.completedSpans.length > this.config.maxSpans) {
      this.completedSpans = this.completedSpans.slice(-this.config.maxSpans);
    }

    this.emit('spanEnd', span);
  }

  /**
   * Add log to a span
   */
  logSpan(
    spanId: string,
    message: string,
    fields?: Record<string, string | number | boolean>
  ): void {
    const span = this.activeSpans.get(spanId);
    if (!span) return;

    span.logs.push({
      timestamp: Date.now(),
      message,
      fields,
    });
  }

  /**
   * Add tag to a span
   */
  tagSpan(spanId: string, key: string, value: string | number | boolean): void {
    const span = this.activeSpans.get(spanId);
    if (!span) return;

    span.tags[key] = value;
  }

  /**
   * Add annotation to a span
   */
  annotateSpan(spanId: string, value: string): void {
    const span = this.activeSpans.get(spanId);
    if (!span) return;

    span.annotations.push({
      timestamp: Date.now(),
      value,
    });
  }

  /**
   * Record an error in a span
   */
  recordError(
    spanId: string,
    error: Error,
    tags?: Record<string, string | number | boolean>
  ): void {
    const span = this.activeSpans.get(spanId);
    if (!span) return;

    span.status = 'error';
    span.tags['error'] = true;
    span.tags['error.message'] = error.message;
    span.tags['error.stack'] = error.stack || '';

    if (tags) {
      Object.assign(span.tags, tags);
    }

    span.logs.push({
      timestamp: Date.now(),
      message: error.message,
      fields: { 'error.stack': error.stack },
    });

    this.emit('error', { span, error });
  }

  /**
   * Get trace context from headers (for propagation)
   */
  extractContext(headers: Record<string, string | string[] | undefined>): TraceContext | null {
    const traceId = (headers['x-trace-id'] as string) || (headers['traceparent'] as string);
    const spanId = headers['x-span-id'] as string;
    const parentSpanId = headers['x-parent-span-id'] as string;

    if (!traceId || !spanId) return null;

    return {
      traceId,
      spanId,
      parentSpanId,
      sampled: true,
    };
  }

  /**
   * Inject context into headers (for propagation)
   */
  injectContext(context: TraceContext): Record<string, string> {
    return {
      'x-trace-id': context.traceId,
      'x-span-id': context.spanId,
      'x-parent-span-id': context.parentSpanId || '',
    };
  }

  /**
   * Get all completed spans
   */
  getCompletedSpans(): TraceSpan[] {
    return [...this.completedSpans];
  }

  /**
   * Get spans for a specific trace
   */
  getTraceSpans(traceId: string): TraceSpan[] {
    return this.completedSpans.filter((span) => span.traceId === traceId);
  }

  /**
   * Get active spans
   */
  getActiveSpans(): TraceSpan[] {
    return Array.from(this.activeSpans.values());
  }

  /**
   * Get trace summary
   */
  getTraceSummary(): {
    totalTraces: number;
    activeSpans: number;
    completedSpans: number;
    errorCount: number;
    averageDuration: number;
  } {
    const errorCount = this.completedSpans.filter((s) => s.status === 'error').length;
    const durations = this.completedSpans
      .filter((s) => s.duration !== undefined)
      .map((s) => s.duration!);
    const averageDuration =
      durations.length > 0 ? durations.reduce((a, b) => a + b, 0) / durations.length : 0;

    // Count unique traces
    const traceIds = new Set(this.completedSpans.map((s) => s.traceId));

    return {
      totalTraces: traceIds.size,
      activeSpans: this.activeSpans.size,
      completedSpans: this.completedSpans.length,
      errorCount,
      averageDuration,
    };
  }

  /**
   * Should sample this request
   */
  private shouldSample(): boolean {
    return Math.random() < this.config.sampleRate;
  }

  /**
   * Generate a span ID
   */
  private generateSpanId(): string {
    return randomUUID().substring(0, 16);
  }

  /**
   * Start periodic export
   */
  startExporting(): void {
    if (this.exportInterval) return;

    this.exportInterval = setInterval(async () => {
      await this.exportSpans();
    }, this.config.exportInterval);
  }

  /**
   * Stop periodic export
   */
  stopExporting(): void {
    if (this.exportInterval) {
      clearInterval(this.exportInterval);
      this.exportInterval = null;
    }
  }

  /**
   * Export completed spans
   */
  async exportSpans(): Promise<void> {
    if (this.completedSpans.length === 0) return;

    const spansToExport = [...this.completedSpans];
    this.completedSpans = [];

    for (const exporter of this.config.exporters) {
      try {
        await exporter.export(spansToExport);
      } catch (error) {
        console.error('Failed to export spans:', error);
      }
    }
  }

  /**
   * Clear all spans
   */
  clear(): void {
    this.activeSpans.clear();
    this.completedSpans = [];
    this.emit('cleared');
  }

  /**
   * Get trace tree as JSON for visualization
   */
  getTraceTree(traceId: string): object {
    const spans = this.getTraceSpans(traceId);
    const spanMap = new Map(spans.map((s) => [s.spanId, s]));

    // Build tree structure
    const rootSpans = spans.filter((s) => !s.parentSpanId || !spanMap.has(s.parentSpanId));

    const buildTree = (span: TraceSpan): object => {
      const children = spans.filter((s) => s.parentSpanId === span.spanId);
      return {
        ...span,
        children: children.map(buildTree),
      };
    };

    return {
      traceId,
      spans: rootSpans.map(buildTree),
      totalSpans: spans.length,
    };
  }
}

export default TracingService;

import * as fs from 'fs';
import * as os from 'os';
import * as path from 'path';
import Debug from 'debug';
import type { ILlmProvider, IMessengerService } from '@hivemind/shared-types';
import type { AnyConfig } from '../types/config';

const debug = Debug('app:pluginLoader');

/**
 * Directory where community-installed plugins live.
 * Defaults to ~/.hivemind/plugins — survives app upgrades.
 * Override with HIVEMIND_PLUGINS_DIR env var.
 */
export const PLUGINS_DIR: string =
  process.env.HIVEMIND_PLUGINS_DIR ?? path.join(os.homedir(), '.hivemind', 'plugins');

/**
 * Plugin manifest — every package must export this as `manifest`.
 * The `create(config)` factory is the single entry point for instantiation.
 */
export interface PluginManifest {
  /** Human-readable name shown in the WebUI */
  displayName: string;
  /** Short description shown in the marketplace */
  description: string;
  /** Minimum open-hivemind core version required, e.g. "1.0.0" */
  minVersion?: string;
  /** Provider type — derivable from package name prefix but explicit here for safety */
  type: 'llm' | 'message' | 'memory' | 'tool';
}

export interface PluginModule {
  manifest?: PluginManifest;
  create?: (config?: AnyConfig | any) => any;
  default?: (config?: AnyConfig | any) => any;
  [key: string]: any;
}

/**
 * Load a plugin by its full package name (e.g. 'llm-openai', 'message-discord').
 *
 * Resolution order:
 *   1. @hivemind/<name>  — built-in workspace package
 *   2. PLUGINS_DIR/<name> — community-installed plugin
 *
 * Returns the raw module object. Callers use `mod.create(config)` or
 * fall back to known class names for packages that predate the factory contract.
 */
export function loadPlugin(name: string): PluginModule {
  // 1. Try built-in workspace package
  try {
    const mod = require(`@hivemind/${name}`);
    debug('Loaded built-in plugin: @hivemind/%s', name);
    return mod;
  } catch (e: unknown) {
    if (e instanceof Error && !e.message?.includes('Cannot find module')) throw e;
  }

  // 2. Try community plugins dir
  const pluginPath = path.join(PLUGINS_DIR, name);
  if (fs.existsSync(pluginPath)) {
    try {
      // Bust require cache on reload (e.g. after update)
      const resolved = require.resolve(pluginPath);
      delete require.cache[resolved];
      const mod = require(pluginPath);
      debug('Loaded community plugin: %s', pluginPath);
      return mod;
    } catch (e: unknown) {
      const msg = e instanceof Error ? e.message : String(e);
      throw new Error(`Failed to load community plugin '${name}': ${msg}`);
    }
  }

  throw new Error(
    `Plugin '${name}' not found. ` +
      `Check that @hivemind/${name} is installed or the plugin exists in ${PLUGINS_DIR}.`
  );
}

/**
 * Instantiate an LLM provider from a loaded module.
 *
 * Contract (preferred): module exports `create(config)` → ILlmProvider
 * Fallback: known class name patterns for pre-factory packages.
 */
export function instantiateLlmProvider(mod: PluginModule, config?: AnyConfig | any): ILlmProvider {
  // Preferred: explicit factory
  if (typeof mod.create === 'function') {
    return mod.create(config);
  }
  // Fallback: singleton getInstance
  const name = Object.keys(mod).find(
    (k) => k.endsWith('Provider') && typeof mod[k]?.getInstance === 'function'
  );
  if (name && typeof mod[name].getInstance === 'function') {
    return mod[name].getInstance(config);
  }
  // Fallback: constructor
  const ctor = Object.keys(mod).find((k) => k.endsWith('Provider') && typeof mod[k] === 'function');
  if (ctor && typeof mod[ctor] === 'function') {
    return new mod[ctor](config);
  }
  // Fallback: default export
  if (typeof mod.default === 'function') {
    // Handling cases where default could be a class constructor or a factory
    try {
      return new (mod.default as any)(config);
    } catch (e) {
      return mod.default(config);
    }
  }
  throw new Error('Plugin does not export create(), a Provider class, or a default constructor.');
}

/**
 * Instantiate a message service from a loaded module.
 *
 * Contract (preferred): module exports `create(config)` → IMessengerService
 * Fallback: known Service singleton patterns.
 */
export function instantiateMessageService(
  mod: PluginModule,
  config?: AnyConfig | any
): IMessengerService {
  // Preferred: explicit factory
  if (typeof mod.create === 'function') {
    return mod.create(config);
  }
  if (typeof mod.default === 'function') {
    return mod.default(config);
  }
  // Fallback: *Service.getInstance()
  const svcKey = Object.keys(mod).find(
    (k) => k.endsWith('Service') && typeof mod[k]?.getInstance === 'function'
  );
  if (svcKey && typeof mod[svcKey].getInstance === 'function') {
    return mod[svcKey].getInstance();
  }
  throw new Error(
    'Plugin does not export create(), a default factory, or a Service.getInstance().'
  );
}

/**
 * Instantiate a memory provider from a loaded module.
 *
 * Contract (preferred): module exports `create(config)` → IMemoryProvider
 * Fallback: known Provider class patterns.
 */
export function instantiateMemoryProvider(mod: any, config?: any): any {
  // Preferred: explicit factory
  if (typeof mod.create === 'function') {
    return mod.create(config);
  }
  // Fallback: *Provider constructor
  const ctor = Object.keys(mod).find((k) => k.endsWith('Provider') && typeof mod[k] === 'function');
  if (ctor) {
    return new mod[ctor](config);
  }
  // Fallback: default export
  if (typeof mod.default === 'function') {
    return new mod.default(config);
  }
  throw new Error(
    'Memory plugin does not export create(), a Provider class, or a default constructor.'
  );
}

import { execFileSync } from 'child_process';
import * as fs from 'fs';
import * as path from 'path';
import Debug from 'debug';
import { loadPlugin, PLUGINS_DIR, type PluginManifest } from './PluginLoader';

const debug = Debug('app:pluginManager');

// ---------------------------------------------------------------------------
// Types
// ---------------------------------------------------------------------------

export interface PluginRegistryEntry {
  /** Package name, e.g. 'llm-myprovider' */
  name: string;
  /** Git remote the plugin was cloned from */
  repoUrl: string;
  /** ISO timestamp of installation */
  installedAt: string;
  /** ISO timestamp of last update */
  updatedAt: string;
  /** Version read from package.json at install/update time */
  version: string;
}

export interface PluginInfo extends PluginRegistryEntry {
  manifest: PluginManifest;
  /** Absolute path to the plugin directory */
  pluginPath: string;
}

export class PluginValidationError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'PluginValidationError';
  }
}

// ---------------------------------------------------------------------------
// Registry helpers
// ---------------------------------------------------------------------------

const REGISTRY_FILE = path.join(PLUGINS_DIR, 'registry.json');

function readRegistry(): PluginRegistryEntry[] {
  if (!fs.existsSync(REGISTRY_FILE)) return [];
  try {
    return JSON.parse(fs.readFileSync(REGISTRY_FILE, 'utf-8'));
  } catch {
    debug('Failed to parse registry.json — returning empty');
    return [];
  }
}

function writeRegistry(entries: PluginRegistryEntry[]): void {
  fs.mkdirSync(PLUGINS_DIR, { recursive: true });
  fs.writeFileSync(REGISTRY_FILE, JSON.stringify(entries, null, 2));
}

function updateRegistry(entry: PluginRegistryEntry): void {
  const entries = readRegistry().filter((e) => e.name !== entry.name);
  entries.push(entry);
  writeRegistry(entries);
}

function removeFromRegistry(name: string): void {
  writeRegistry(readRegistry().filter((e) => e.name !== name));
}

// ---------------------------------------------------------------------------
// Require-cache eviction
// ---------------------------------------------------------------------------

function evictFromCache(pluginPath: string): void {
  for (const key of Object.keys(require.cache)) {
    if (key.startsWith(pluginPath)) {
      delete require.cache[key];
      debug('Evicted from require cache: %s', key);
    }
  }
}

// ---------------------------------------------------------------------------
// Manifest validation
// ---------------------------------------------------------------------------

/**
 * Validates that a plugin's exported manifest.type matches the type prefix
 * encoded in its package name.
 *
 * Rule: 'llm-myprovider'.split('-')[0] === manifest.type
 *
 * This prevents a misconfigured community plugin tagged as type 'memory'
 * being loaded as an 'llm' provider silently at runtime.
 */
function validateManifestType(name: string, manifest: PluginManifest): void {
  const namePrefix = name.split('-')[0];
  const validTypes = ['llm', 'message', 'memory', 'tool'] as const;

  if (!validTypes.includes(namePrefix as any)) {
    throw new PluginValidationError(
      `Package name '${name}' must start with a valid type prefix: ${validTypes.join(', ')}. ` +
        `Got prefix '${namePrefix}'.`
    );
  }

  if (manifest.type !== namePrefix) {
    throw new PluginValidationError(
      `Manifest type mismatch for '${name}': ` +
        `package name prefix is '${namePrefix}' but manifest.type is '${manifest.type}'. ` +
        `Rename the package or fix the manifest to match.`
    );
  }
}

/**
 * Validates that a loaded module exports a well-formed manifest.
 */
function validateManifest(name: string, mod: any): PluginManifest {
  const manifest: PluginManifest = mod.manifest;

  if (!manifest) {
    throw new PluginValidationError(
      `Plugin '${name}' does not export a 'manifest'. ` +
        `Add: export const manifest: PluginManifest = { ... } to its index.ts.`
    );
  }
  if (!manifest.displayName || typeof manifest.displayName !== 'string') {
    throw new PluginValidationError(
      `Plugin '${name}' manifest.displayName is missing or not a string.`
    );
  }
  if (!manifest.description || typeof manifest.description !== 'string') {
    throw new PluginValidationError(
      `Plugin '${name}' manifest.description is missing or not a string.`
    );
  }
  if (!manifest.type) {
    throw new PluginValidationError(`Plugin '${name}' manifest.type is missing.`);
  }

  validateManifestType(name, manifest);

  return manifest;
}

// ---------------------------------------------------------------------------
// Package helpers
// ---------------------------------------------------------------------------

function readPackageVersion(pluginPath: string): string {
  try {
    const pkg = JSON.parse(fs.readFileSync(path.join(pluginPath, 'package.json'), 'utf-8'));
    return pkg.version ?? '0.0.0';
  } catch {
    return '0.0.0';
  }
}

function deriveNameFromPath(pluginPath: string): string {
  try {
    const pkg = JSON.parse(fs.readFileSync(path.join(pluginPath, 'package.json'), 'utf-8'));
    // Strip @hivemind/ or @scope/ prefix if present
    return pkg.name?.replace(/^@[^/]+\//, '') ?? path.basename(pluginPath);
  } catch {
    return path.basename(pluginPath);
  }
}

function exec(cmd: string, args: string[], cwd: string): void {
  debug('exec: %s %s (cwd: %s)', cmd, args.join(' '), cwd);
  execFileSync(cmd, args, { cwd, stdio: 'inherit' });
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Install a community plugin from a git repository URL.
 *
 * Steps:
 *   1. git clone <repoUrl> into PLUGINS_DIR/<name>
 *   2. pnpm install --prod in the cloned directory
 *   3. Load the module and validate manifest.type matches name prefix
 *   4. Add to registry
 *
 * @throws PluginValidationError if the manifest is invalid or type mismatches
 */
export async function installPlugin(repoUrl: string): Promise<PluginInfo> {
  fs.mkdirSync(PLUGINS_DIR, { recursive: true });

  // Clone into a temp dir first so we can read the name before committing
  const tempName = `_install_${Date.now()}`;
  const tempPath = path.join(PLUGINS_DIR, tempName);

  try {
    debug('Cloning %s → %s', repoUrl, tempPath);
    exec('git', ['clone', '--depth', '1', repoUrl, tempPath], PLUGINS_DIR);

    const name = deriveNameFromPath(tempPath);
    const pluginPath = path.join(PLUGINS_DIR, name);

    // If already installed, refuse — use updatePlugin instead
    if (fs.existsSync(pluginPath)) {
      fs.rmSync(tempPath, { recursive: true, force: true });
      throw new Error(
        `Plugin '${name}' is already installed at ${pluginPath}. Use updatePlugin('${name}') to upgrade.`
      );
    }

    // Move temp dir to final location
    fs.renameSync(tempPath, pluginPath);

    debug('Running pnpm install --prod in %s', pluginPath);
    exec('pnpm', ['install', '--prod', '--ignore-scripts'], pluginPath);

    // Load and validate — this is the gate
    const mod = loadPlugin(name);
    const manifest = validateManifest(name, mod);

    const version = readPackageVersion(pluginPath);
    const now = new Date().toISOString();
    const entry: PluginRegistryEntry = { name, repoUrl, installedAt: now, updatedAt: now, version };
    updateRegistry(entry);

    debug('Installed plugin %s@%s', name, version);
    return { ...entry, manifest, pluginPath };
  } catch (err) {
    // Clean up temp dir on failure
    if (fs.existsSync(tempPath)) {
      fs.rmSync(tempPath, { recursive: true, force: true });
    }
    throw err;
  }
}

/**
 * Uninstall a community plugin by name.
 *
 * Steps:
 *   1. Evict from require cache
 *   2. Remove plugin directory
 *   3. Remove from registry
 *
 * @throws Error if the plugin is not found in PLUGINS_DIR
 */
export async function uninstallPlugin(name: string): Promise<void> {
  const pluginPath = path.join(PLUGINS_DIR, name);

  if (!fs.existsSync(pluginPath)) {
    throw new Error(`Plugin '${name}' not found at ${pluginPath}. Is it installed?`);
  }

  evictFromCache(pluginPath);
  fs.rmSync(pluginPath, { recursive: true, force: true });
  removeFromRegistry(name);

  debug('Uninstalled plugin %s', name);
}

/**
 * Update a community plugin to its latest commit.
 *
 * Steps:
 *   1. git pull in the plugin directory
 *   2. pnpm install --prod
 *   3. Evict require cache
 *   4. Reload and re-validate manifest (catches type changes post-update)
 *   5. Update registry
 *
 * @throws PluginValidationError if the updated plugin fails manifest validation
 */
export async function updatePlugin(name: string): Promise<PluginInfo> {
  const pluginPath = path.join(PLUGINS_DIR, name);

  if (!fs.existsSync(pluginPath)) {
    throw new Error(`Plugin '${name}' not found at ${pluginPath}. Install it first.`);
  }

  debug('Pulling latest for %s', name);
  exec('git', ['pull', '--ff-only'], pluginPath);
  exec('pnpm', ['install', '--prod', '--ignore-scripts'], pluginPath);

  evictFromCache(pluginPath);

  // Reload and re-validate — type may have changed in an update
  const mod = loadPlugin(name);
  const manifest = validateManifest(name, mod);

  const version = readPackageVersion(pluginPath);
  const existing = readRegistry().find((e) => e.name === name);
  const entry: PluginRegistryEntry = {
    name,
    repoUrl: existing?.repoUrl ?? '',
    installedAt: existing?.installedAt ?? new Date().toISOString(),
    updatedAt: new Date().toISOString(),
    version,
  };
  updateRegistry(entry);

  debug('Updated plugin %s@%s', name, version);
  return { ...entry, manifest, pluginPath };
}

/**
 * List all installed community plugins.
 * Combines registry entries with any manually-dropped directories not in registry.
 */
export function listInstalledPlugins(): PluginInfo[] {
  const results: PluginInfo[] = [];

  if (!fs.existsSync(PLUGINS_DIR)) return results;

  const registry = readRegistry();
  const registryMap = new Map(registry.map((e) => [e.name, e]));

  // Scan directory — includes manually installed plugins not in registry
  const dirs = fs
    .readdirSync(PLUGINS_DIR, { withFileTypes: true })
    .filter((d) => d.isDirectory() && d.name !== '_install_' && !d.name.startsWith('_install_'))
    .map((d) => d.name);

  for (const name of dirs) {
    const pluginPath = path.join(PLUGINS_DIR, name);
    try {
      const mod = loadPlugin(name);
      const manifest = mod.manifest as PluginManifest;
      if (!manifest) continue;

      const registryEntry = registryMap.get(name);
      const version = readPackageVersion(pluginPath);
      const now = new Date().toISOString();

      results.push({
        name,
        repoUrl: registryEntry?.repoUrl ?? '',
        installedAt: registryEntry?.installedAt ?? now,
        updatedAt: registryEntry?.updatedAt ?? now,
        version,
        manifest,
        pluginPath,
      });
    } catch (e) {
      debug('Skipping directory %s — failed to load: %s', name, e);
    }
  }

  return results;
}

import fs from 'fs';
import path from 'path';
import { Discord, type DiscordService } from '@hivemind/message-discord';
import discordConfig, { type DiscordConfig } from '../config/discordConfig';
import type { IBotInfo } from '../types/botInfo';
import { type IMessageProvider } from '../types/IProvider';

export class DiscordProvider implements IMessageProvider<DiscordConfig> {
  id = 'discord';
  label = 'Discord';
  type = 'messenger' as const;
  docsUrl = 'https://discord.com/developers/applications';
  helpText = 'Create a Discord application, add a bot, and copy the bot token from the Bot tab.';
  private discordService: DiscordService;

  constructor(discordService?: DiscordService) {
    this.discordService = discordService || (Discord as any).DiscordService.getInstance();
  }

  getSchema() {
    return discordConfig.getSchema();
  }

  getConfig() {
    return discordConfig;
  }

  getSensitiveKeys() {
    return ['DISCORD_BOT_TOKEN', 'DISCORD_CLIENT_ID'];
  }

  async getStatus() {
    let discordBots: string[] = [];
    let discordInfo: any[] = [];
    try {
      const ds = this.discordService;
      const bots = (ds.getAllBots?.() || []) as IBotInfo[];
      discordBots = bots.map((b) => b?.botUserName || b?.config?.name || 'discord');
      discordInfo = bots.map((b) => ({
        provider: 'discord',
        name: b?.botUserName || b?.config?.name || 'discord',
        connected: true,
      }));
    } catch (e) {
      // Ignore if not initialized
    }
    return {
      ok: true,
      bots: discordInfo,
      count: discordInfo.length,
    };
  }

  getBotNames() {
    // Not strictly used by adminRoutes logic for Discord, but we can implement it
    return [];
  }

  async getBots() {
    const status = await this.getStatus();
    return status.bots;
  }

  async addBot(config: any) {
    const { name, token, llm } = config;
    if (!token) {
      throw new Error('token is required');
    }

    const configDir = process.env.NODE_CONFIG_DIR || path.join(process.cwd(), 'config');
    const messengersPath = path.join(configDir, 'providers', 'messengers.json');

    let cfg: any = { discord: { instances: [] } };
    try {
      const fileContent = await fs.promises.readFile(messengersPath, 'utf8');
      cfg = JSON.parse(fileContent);
    } catch (e: any) {
      // Ignore
    }
    cfg.discord = cfg.discord || {};
    cfg.discord.instances = cfg.discord.instances || [];
    cfg.discord.instances.push({ name: name || '', token, llm });

    try {
      await fs.promises.mkdir(path.dirname(messengersPath), { recursive: true });
      await fs.promises.writeFile(messengersPath, JSON.stringify(cfg, null, 2), 'utf8');
    } catch (e) {
      console.error('Failed writing messengers.json', e);
    }

    // Try runtime add
    const ds = this.discordService;
    const instanceCfg = { name: name || '', token, llm };
    if (ds.addBot) {
      await ds.addBot(instanceCfg);
    }
  }

  async reload() {
    const configDir = process.env.NODE_CONFIG_DIR || path.join(process.cwd(), 'config');
    const messengersPath = path.join(configDir, 'providers', 'messengers.json');
    let cfg: any;
    try {
      const content = await fs.promises.readFile(messengersPath, 'utf8');
      cfg = JSON.parse(content);
    } catch (e: any) {
      return { added: 0 };
    }

    let added = 0;
    const ds = this.discordService;
    const bots = (ds.getAllBots?.() || []) as IBotInfo[];
    const have = new Set(bots.map((b) => b?.config?.discord?.token || b?.config?.token));
    const instances = cfg.discord?.instances || [];
    for (const inst of instances) {
      if (inst.token && !have.has(inst.token)) {
        const instanceCfg = { name: inst.name || '', token: inst.token, llm: inst.llm };
        if (ds.addBot) {
          await ds.addBot(instanceCfg);
          added++;
        }
      }
    }
    return { added };
  }
}

