import { type NextFunction, type Request, type Response } from 'express';
import { Logger } from '@src/common/logger';

export interface AuditLogEntry {
  timestamp: string;
  action: string;
  resource: string;
  resourceId?: string;
  userId?: string;
  ip: string;
  userAgent: string;
  before?: any;
  after?: any;
  status: 'success' | 'failure';
  errorMessage?: string;
}

class AuditLoggerService {
  private logs: AuditLogEntry[] = [];
  private readonly maxLogs: number = 1000;

  log(entry: Omit<AuditLogEntry, 'timestamp'>): void {
    const fullEntry: AuditLogEntry = {
      ...entry,
      timestamp: new Date().toISOString(),
    };

    this.logs.push(fullEntry);

    // Trim logs if exceeding max
    if (this.logs.length > this.maxLogs) {
      this.logs = this.logs.slice(-this.maxLogs);
    }

    // Also log to structured logger
    Logger.info('AUDIT', fullEntry);
  }

  getLogs(limit = 100): AuditLogEntry[] {
    return this.logs.slice(-limit);
  }

  getLogsByUser(userId: string, limit = 100): AuditLogEntry[] {
    return this.logs.filter((log) => log.userId === userId).slice(-limit);
  }

  getLogsByResource(resource: string, limit = 100): AuditLogEntry[] {
    return this.logs.filter((log) => log.resource === resource).slice(-limit);
  }

  getLogsByAction(action: string, limit = 100): AuditLogEntry[] {
    return this.logs.filter((log) => log.action === action).slice(-limit);
  }
}

export const auditLogger = new AuditLoggerService();

/**
 * Middleware factory for route-specific audit logging
 * Wraps response to capture status and log the operation
 */
export const auditMiddleware = (action: string, resource: string) => {
  return (req: Request, res: Response, next: NextFunction) => {
    const originalSend = res.send;
    const startTime = Date.now();

    res.send = function (data: any): Response {
      // Only log once
      if (!(res as any)._auditLogged) {
        (res as any)._auditLogged = true;

        const entry: Omit<AuditLogEntry, 'timestamp'> = {
          action,
          resource,
          resourceId: req.params.id || req.params.name || req.params.key || req.params.userId,
          userId: (req as any).user?.id || (req as any).user?.username || 'anonymous',
          ip:
            req.ip ||
            req.connection?.remoteAddress ||
            (req.headers['x-forwarded-for'] as string) ||
            'unknown',
          userAgent: req.get('user-agent') || 'unknown',
          status: res.statusCode < 400 ? 'success' : 'failure',
          errorMessage: res.statusCode >= 400 ? data?.error || data?.message : undefined,
        };

        auditLogger.log(entry);
      }

      return originalSend.call(this, data);
    };

    next();
  };
};

/**
 * Enhanced audit middleware that captures before/after values
 * Use for update operations where tracking changes is important
 */
export const auditMiddlewareWithChanges = (
  action: string,
  resource: string,
  getBeforeValue?: (req: Request) => Promise<any> | any
) => {
  return async (req: Request, res: Response, next: NextFunction) => {
    const originalSend = res.send;
    let beforeValue: any = undefined;

    // Capture before value if getter provided
    if (getBeforeValue) {
      try {
        beforeValue = await getBeforeValue(req);
      } catch (error) {
        // Ignore errors in before value capture
      }
    }

    res.send = function (data: any): Response {
      if (!(res as any)._auditLogged) {
        (res as any)._auditLogged = true;

        const entry: Omit<AuditLogEntry, 'timestamp'> = {
          action,
          resource,
          resourceId: req.params.id || req.params.name || req.params.key || req.params.userId,
          userId: (req as any).user?.id || (req as any).user?.username || 'anonymous',
          ip:
            req.ip ||
            req.connection?.remoteAddress ||
            (req.headers['x-forwarded-for'] as string) ||
            'unknown',
          userAgent: req.get('user-agent') || 'unknown',
          before: beforeValue,
          after:
            res.statusCode < 400 ? data?.bot || data?.user || data?.profile || data : undefined,
          status: res.statusCode < 400 ? 'success' : 'failure',
          errorMessage: res.statusCode >= 400 ? data?.error || data?.message : undefined,
        };

        auditLogger.log(entry);
      }

      return originalSend.call(this, data);
    };

    next();
  };
};

/**
 * Manual audit logging function for use within route handlers
 * When you need more control over what gets logged
 */
export const logAuditEvent = (
  req: Request,
  action: string,
  resource: string,
  status: 'success' | 'failure',
  options: {
    resourceId?: string;
    before?: any;
    after?: any;
    errorMessage?: string;
  } = {}
): void => {
  const entry: Omit<AuditLogEntry, 'timestamp'> = {
    action,
    resource,
    resourceId: options.resourceId || req.params.id || req.params.name || req.params.key,
    userId: (req as any).user?.id || (req as any).user?.username || 'anonymous',
    ip:
      req.ip ||
      req.connection?.remoteAddress ||
      (req.headers['x-forwarded-for'] as string) ||
      'unknown',
    userAgent: req.get('user-agent') || 'unknown',
    before: options.before,
    after: options.after,
    status,
    errorMessage: options.errorMessage,
  };

  auditLogger.log(entry);
};

export default auditLogger;

import type { NextFunction, Request, Response } from 'express';
import { AuthManager } from '../../auth/AuthManager';

// Extend Express Request interface to include user
declare global {
  namespace Express {
    interface Request {
      user?: any;
    }
  }
}

export const authenticateToken = (req: Request, res: Response, next: NextFunction) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1]; // Bearer TOKEN

  if (!token) {
    res.status(401).json({ error: 'Access token required' });
    return;
  }

  let payload;
  try {
    const authManager = AuthManager.getInstance();
    payload = authManager.verifyAccessToken(token);
  } catch (err) {
    res.status(403).json({ error: 'Invalid or expired token' });
    return;
  }

  if (!payload) {
    res.status(403).json({ error: 'Invalid or expired token' });
    return;
  }

  req.user = payload;
  return next();
};

export const requirePermission = (permission: string) => {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!req.user) {
      res.status(401).json({ error: 'Authentication required' });
      return;
    }

    const authManager = AuthManager.getInstance();
    const user = authManager.getUser(req.user.userId);

    if (!user) {
      res.status(401).json({ error: 'User not found' });
      return;
    }

    if (!authManager.hasPermission(user.role, permission)) {
      res.status(403).json({
        error: 'Insufficient permissions',
        required: permission,
        userRole: user.role,
      });
      return;
    }

    return next();
  };
};

export const requireRole = (role: string) => {
  return (req: Request, res: Response, next: NextFunction) => {
    if (!req.user) {
      res.status(401).json({ error: 'Authentication required' });
      return;
    }

    if (req.user.role !== role) {
      res.status(403).json({
        error: 'Insufficient role',
        required: role,
        userRole: req.user.role,
      });
      return;
    }

    return next();
  };
};

export const optionalAuth = (req: Request, res: Response, next: NextFunction) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (token) {
    try {
      const authManager = AuthManager.getInstance();
      const payload = authManager.verifyAccessToken(token);
      if (payload) {
        req.user = payload;
      }
    } catch (e) {
      // Ignore invalid tokens in optional auth
    }
  }

  return next();
};

import crypto from 'crypto';
import Debug from 'debug';
import type { NextFunction, Request, Response } from 'express';

const debug = Debug('app:csrfMiddleware');

/**
 * CSRF Token Configuration
 */
interface CsrfConfig {
  /** Token length in bytes (default: 32) */
  tokenLength: number;
  /** Cookie name for CSRF token (default: '_csrf') */
  cookieName: string;
  /** Header name for CSRF token (default: 'x-csrf-token') */
  headerName: string;
  /** Token expiration time in milliseconds (default: 24 hours) */
  tokenExpiration: number;
}

const defaultConfig: CsrfConfig = {
  tokenLength: 32,
  cookieName: '_csrf',
  headerName: 'x-csrf-token',
  tokenExpiration: 24 * 60 * 60 * 1000, // 24 hours
};

/**
 * In-memory store for CSRF tokens
 * In production, this should be replaced with Redis or similar
 */
interface CsrfTokenEntry {
  token: string;
  createdAt: number;
  sessionId?: string;
}

// Global token store (use Redis in production)
const tokenStore = new Map<string, CsrfTokenEntry>();

let cleanupInterval: NodeJS.Timeout | null = null;

/**
 * Clean up expired tokens periodically
 */
function startCleanupInterval() {
  if (cleanupInterval) return;
  cleanupInterval = setInterval(
    () => {
      const now = Date.now();
      let expiredCount = 0;
      for (const [key, entry] of tokenStore.entries()) {
        if (now - entry.createdAt > defaultConfig.tokenExpiration) {
          tokenStore.delete(key);
          expiredCount++;
        }
      }
      if (expiredCount > 0) {
        debug('Cleaned up expired CSRF tokens:', expiredCount);
      }
    },
    60 * 60 * 1000
  ); // Clean up every hour
}

startCleanupInterval();

export function stopTokenCleanup() {
  if (cleanupInterval) {
    clearInterval(cleanupInterval);
    cleanupInterval = null;
  }
}

/**
 * Generate a cryptographically secure CSRF token
 */
export function generateCsrfToken(): string {
  return crypto.randomBytes(defaultConfig.tokenLength).toString('base64url');
}

/**
 * Helper to parse cookies from header
 */
function parseCookies(cookieHeader: string | undefined): Record<string, string> {
  const list: Record<string, string> = {};
  if (!cookieHeader) return list;

  cookieHeader.split(';').forEach(function (cookie) {
    let [name, ...rest] = cookie.split('=');
    name = name?.trim();
    if (!name) return;
    const value = rest.join('=').trim();
    if (!value) return;
    list[name] = decodeURIComponent(value);
  });

  return list;
}

/**
 * Get session identifier for token storage
 * Uses a secure random session ID stored in a cookie
 */
export function getSessionId(req: Request, res: Response): string {
  const cookieName = `${defaultConfig.cookieName}_sid`;

  // Try to get from req.cookies (if cookie-parser is used)
  let sid = req.cookies?.[cookieName];

  // If not found, try to parse from header directly
  if (!sid && req.headers.cookie) {
    const cookies = parseCookies(req.headers.cookie);
    sid = cookies[cookieName];
  }

  // If still not found, generate new one and set cookie
  if (!sid) {
    sid = crypto.randomBytes(16).toString('hex');
    res.cookie(cookieName, sid, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: defaultConfig.tokenExpiration,
      path: '/',
    });
    // Also append to req.cookies so subsequent calls in same request can find it (if needed)
    if (!req.cookies) req.cookies = {};
    req.cookies[cookieName] = sid;
  }

  return sid;
}

/**
 * Store CSRF token for session
 */
function storeToken(sessionId: string, token: string): void {
  tokenStore.set(sessionId, {
    token,
    createdAt: Date.now(),
    sessionId,
  });
}

/**
 * Validate CSRF token against stored token
 */
function validateToken(sessionId: string, providedToken: string): boolean {
  const entry = tokenStore.get(sessionId);

  if (!entry) {
    debug('CSRF token not found for session:', sessionId);
    return false;
  }

  // Check expiration
  if (Date.now() - entry.createdAt > defaultConfig.tokenExpiration) {
    debug('CSRF token expired for session:', sessionId);
    tokenStore.delete(sessionId);
    return false;
  }

  // Constant-time comparison to prevent timing attacks
  try {
    return crypto.timingSafeEqual(
      Buffer.from(entry.token, 'base64url'),
      Buffer.from(providedToken, 'base64url')
    );
  } catch {
    debug('CSRF token comparison failed (invalid format)');
    return false;
  }
}

/**
 * CSRF Protection Middleware
 *
 * This middleware provides CSRF protection for state-changing operations.
 *
 * Usage:
 * 1. Client requests CSRF token via GET /api/csrf-token
 * 2. Client includes token in X-CSRF-Token header for POST/PUT/DELETE requests
 * 3. Middleware validates token before allowing the request
 *
 * Security considerations:
 * - Tokens are bound to session (via secure cookie)
 * - Tokens expire after 24 hours
 * - Constant-time comparison prevents timing attacks
 * - Tokens are cryptographically random
 * - CSRF is skipped in test environment (NODE_ENV=test)
 */
export function csrfProtection(req: Request, res: Response, next: NextFunction): void {
  const method = req.method.toUpperCase();

  // Skip CSRF check for safe methods
  if (['GET', 'HEAD', 'OPTIONS'].includes(method)) {
    next();
    return;
  }

  // Optional skip for tests when explicitly enabled
  if (process.env.NODE_ENV === 'test' && process.env.CSRF_SKIP_IN_TEST === 'true') {
    debug('CSRF check skipped in test environment (CSRF_SKIP_IN_TEST=true)');
    next();
    return;
  }

  const sessionId = getSessionId(req, res);
  const providedToken = req.get(defaultConfig.headerName) || req.body?._csrf;

  if (!providedToken) {
    debug('CSRF token missing in request', {
      method,
      path: req.path,
      sessionId: sessionId.substring(0, 8) + '...',
    });

    res.status(403).json({
      error: 'CSRF Token Required',
      message: 'A valid CSRF token is required for this operation',
      code: 'CSRF_TOKEN_MISSING',
    });
    return;
  }

  if (!validateToken(sessionId, providedToken)) {
    debug('CSRF token validation failed', {
      method,
      path: req.path,
      sessionId: sessionId.substring(0, 8) + '...',
    });

    res.status(403).json({
      error: 'Invalid CSRF Token',
      message: 'The provided CSRF token is invalid or expired',
      code: 'CSRF_TOKEN_INVALID',
    });
    return;
  }

  debug('CSRF validation passed', {
    method,
    path: req.path,
    sessionId: sessionId.substring(0, 8) + '...',
  });

  next();
}

/**
 * CSRF Token Endpoint Handler
 *
 * Generates and returns a new CSRF token for the client
 * The token is stored in an httpOnly cookie and returned in the response body
 */
export function csrfTokenHandler(req: Request, res: Response): void {
  const sessionId = getSessionId(req, res);
  const token = generateCsrfToken();

  // Store token for this session
  storeToken(sessionId, token);

  // Set token in httpOnly cookie for additional security
  res.cookie(defaultConfig.cookieName, token, {
    httpOnly: true,
    secure: process.env.NODE_ENV === 'production',
    sameSite: 'strict',
    maxAge: defaultConfig.tokenExpiration,
    path: '/',
  });

  debug('CSRF token generated', {
    sessionId: sessionId.substring(0, 8) + '...',
    tokenPreview: token.substring(0, 8) + '...',
  });

  res.json({
    csrfToken: token,
    expiresIn: defaultConfig.tokenExpiration,
  });
}

/**
 * Optional: Double-submit cookie pattern for stateless CSRF protection
 *
 * This is an alternative approach that doesn't require server-side token storage.
 * Use this for stateless applications or when Redis is not available.
 */
export function csrfDoubleSubmit(req: Request, res: Response, next: NextFunction): void {
  const method = req.method.toUpperCase();

  // Skip CSRF check for safe methods
  if (['GET', 'HEAD', 'OPTIONS'].includes(method)) {
    // Generate and set cookie for GET requests if not present
    if (!req.cookies?.[defaultConfig.cookieName]) {
      const token = generateCsrfToken();
      res.cookie(defaultConfig.cookieName, token, {
        httpOnly: false, // Must be readable by client for double-submit
        secure: process.env.NODE_ENV === 'production',
        sameSite: 'strict',
        maxAge: defaultConfig.tokenExpiration,
        path: '/',
      });
    }
    next();
    return;
  }

  // For state-changing methods, validate double-submit
  const cookieToken = req.cookies?.[defaultConfig.cookieName];
  const headerToken = req.get(defaultConfig.headerName) || req.body?._csrf;

  if (!cookieToken || !headerToken) {
    res.status(403).json({
      error: 'CSRF Token Required',
      message: 'CSRF token must be provided in both cookie and header',
      code: 'CSRF_TOKEN_MISSING',
    });
    return;
  }

  // Constant-time comparison
  try {
    if (
      crypto.timingSafeEqual(
        Buffer.from(cookieToken, 'base64url'),
        Buffer.from(headerToken, 'base64url')
      )
    ) {
      next();
      return;
    }
  } catch {
    // Invalid format - fall through to error
  }

  res.status(403).json({
    error: 'Invalid CSRF Token',
    message: 'CSRF tokens in cookie and header do not match',
    code: 'CSRF_TOKEN_MISMATCH',
  });
}

