  /**
   * Create a new template
   */
  async createTemplate(request: CreateTemplateRequest): Promise<ConfigurationTemplate> {
    try {
      // Validate template configuration
      const validationResult = this.configValidator.validateBotConfig(request.config);
      if (!validationResult.isValid) {
        throw new Error(
          `Template configuration validation failed: ${validationResult.errors.join(', ')}`
        );
      }

      // Check if template name already exists
      const existingTemplate = await this.getTemplateByName(request.name);
      if (existingTemplate) {
        throw new Error(`Template with name '${request.name}' already exists`);
      }

      const template: ConfigurationTemplate = {
        id: this.generateTemplateId(request.name),
        name: request.name,
        description: request.description,
        category: request.category,
        tags: request.tags,
        config: request.config,
        isBuiltIn: false,
        createdBy: request.createdBy,
        createdAt: new Date(),
        updatedAt: new Date(),
        usageCount: 0,
      };

      await this.saveTemplate(template);
      debug('Created template:', template.name);

      return template;
    } catch (error) {
      debug('Error creating template:', error);
      throw new Error(`Failed to create template: ${error}`);
    }
  }

  /**
   * Update an existing template
   */
  async updateTemplate(
    templateId: string,
    request: UpdateTemplateRequest
  ): Promise<ConfigurationTemplate> {
    try {
      const existingTemplate = await this.getTemplateById(templateId);
      if (!existingTemplate) {
        throw new Error(`Template with ID '${templateId}' not found`);
      }

      if (existingTemplate.isBuiltIn) {
        throw new Error('Cannot update built-in templates');
      }

      // Validate new configuration if provided
      if (request.config) {
        const validationResult = this.configValidator.validateBotConfig(request.config);
        if (!validationResult.isValid) {
          throw new Error(
            `Template configuration validation failed: ${validationResult.errors.join(', ')}`
          );
        }
      }

      const updatedTemplate: ConfigurationTemplate = {
        ...existingTemplate,
        name: request.name || existingTemplate.name,
        description: request.description || existingTemplate.description,
        category: request.category || existingTemplate.category,
        tags: request.tags || existingTemplate.tags,
        config: request.config || existingTemplate.config,
        updatedAt: new Date(),
      };

      await this.saveTemplate(updatedTemplate);
      debug('Updated template:', updatedTemplate.name);

      return updatedTemplate;
    } catch (error) {
      debug('Error updating template:', error);
      throw new Error(`Failed to update template: ${error}`);
    }
  }

  /**
   * Delete a template
   */
  async deleteTemplate(templateId: string): Promise<boolean> {
    try {
      const template = await this.getTemplateById(templateId);
      if (!template) {
        throw new Error(`Template with ID '${templateId}' not found`);
      }

      if (template.isBuiltIn) {
        throw new Error('Cannot delete built-in templates');
      }

      const filePath = join(this.templatesDir, `${templateId}.json`);
      await fs.unlink(filePath);

      debug('Deleted template:', template.name);
      return true;
    } catch (error) {
      debug('Error deleting template:', error);
      throw new Error(`Failed to delete template: ${error}`);
    }
  }

  /**
   * Get template by ID
   */
  async getTemplateById(templateId: string): Promise<ConfigurationTemplate | null> {
    try {
      const filePath = join(this.templatesDir, `${templateId}.json`);
      const data = await fs.readFile(filePath, 'utf-8');
      const template = JSON.parse(data);

      // Convert date strings back to Date objects
      template.createdAt = new Date(template.createdAt);
      template.updatedAt = new Date(template.updatedAt);

      return template;
    } catch (error) {
      if ((error as any).code === 'ENOENT') {
        return null;
      }
      debug('Error getting template by ID:', error);
      throw new Error(`Failed to get template: ${error}`);
    }
  }

  /**
   * Get template by name
   */
  async getTemplateByName(name: string): Promise<ConfigurationTemplate | null> {
    try {
      const templates = await this.getAllTemplates();
      return templates.find((template) => template.name === name) || null;
    } catch (error) {
      debug('Error getting template by name:', error);
      throw new Error(`Failed to get template by name: ${error}`);
    }
  }

  /**
   * Get all templates with optional filtering
   */
  async getAllTemplates(filter?: TemplateFilter): Promise<ConfigurationTemplate[]> {
    try {
      const files = await fs.readdir(this.templatesDir);

      const templatePromises = files
        .filter((file) => file.endsWith('.json'))
        .map(async (file) => {
          try {
            const filePath = join(this.templatesDir, file);
            const data = await fs.readFile(filePath, 'utf-8');
            const template = JSON.parse(data);

            // Convert date strings back to Date objects
            template.createdAt = new Date(template.createdAt);
            template.updatedAt = new Date(template.updatedAt);

            return template;
          } catch (error) {
            debug('Error loading template file:', file, error);
            return null;
          }
        });

      const results = await Promise.allSettled(templatePromises);

      const templates = results
        .map((r) => (r.status === 'fulfilled' ? r.value : null))
        .filter((t): t is ConfigurationTemplate => t !== null)
        .filter((t) => this.matchesFilter(t, filter));

      return templates.sort((a, b) => b.updatedAt.getTime() - a.updatedAt.getTime());
    } catch (error) {
      debug('Error getting all templates:', error);
      throw new Error(`Failed to get templates: ${error}`);
    }
  }

  /**
   * Get templates by category
   */
  async getTemplatesByCategory(category: string): Promise<ConfigurationTemplate[]> {
    return this.getAllTemplates({ category: category as any });
  }

  /**
   * Get popular templates (by usage count)
   */
  async getPopularTemplates(limit = 10): Promise<ConfigurationTemplate[]> {
    const templates = await this.getAllTemplates();
    return templates.sort((a, b) => b.usageCount - a.usageCount).slice(0, limit);
  }

  /**
   * Get recently created templates
   */
  async getRecentTemplates(limit = 10): Promise<ConfigurationTemplate[]> {
    const templates = await this.getAllTemplates();
    return templates.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()).slice(0, limit);
  }

  /**
   * Increment template usage count
   */
  async incrementUsageCount(templateId: string): Promise<void> {
    try {
      const template = await this.getTemplateById(templateId);
      if (!template) {
        return;
      }

      template.usageCount += 1;
      template.updatedAt = new Date();

      await this.saveTemplate(template);
      debug('Incremented usage count for template:', template.name);
    } catch (error) {
      debug('Error incrementing template usage count:', error);
    }
  }

  /**
   * Duplicate a template
   */
  async duplicateTemplate(
    templateId: string,
    newName: string,
    createdBy?: string
  ): Promise<ConfigurationTemplate> {
    try {
      const originalTemplate = await this.getTemplateById(templateId);
      if (!originalTemplate) {
        throw new Error(`Template with ID '${templateId}' not found`);
      }

      const duplicateTemplate: ConfigurationTemplate = {
        ...originalTemplate,
        id: this.generateTemplateId(newName),
        name: newName,
        description: `${originalTemplate.description} (Copy)`,
        isBuiltIn: false,
        createdBy,
        createdAt: new Date(),
        updatedAt: new Date(),
        usageCount: 0,
      };

      await this.saveTemplate(duplicateTemplate);
      debug('Duplicated template:', originalTemplate.name, 'as', newName);

      return duplicateTemplate;
    } catch (error) {
      debug('Error duplicating template:', error);
      throw new Error(`Failed to duplicate template: ${error}`);
    }
  }

  /**
   * Export template to JSON
   */
  async exportTemplate(templateId: string): Promise<string> {
    try {
      const template = await this.getTemplateById(templateId);
      if (!template) {
        throw new Error(`Template with ID '${templateId}' not found`);
      }

      return JSON.stringify(template, null, 2);
    } catch (error) {
      debug('Error exporting template:', error);
      throw new Error(`Failed to export template: ${error}`);
    }
  }

  /**
   * Import template from JSON
   */
  async importTemplate(jsonData: string, createdBy?: string): Promise<ConfigurationTemplate> {
    try {
      const templateData = JSON.parse(jsonData);

      // Validate template structure
      if (!templateData.name || !templateData.config) {
        throw new Error('Invalid template format');
      }

      // Remove ID to generate a new one
      delete templateData.id;

      const request: CreateTemplateRequest = {
        name: templateData.name,
        description: templateData.description || '',
        category: templateData.category || 'general',
        tags: templateData.tags || [],
        config: templateData.config,
        createdBy,
      };

      return this.createTemplate(request);
    } catch (error) {
      debug('Error importing template:', error);
      throw new Error(`Failed to import template: ${error}`);
    }
  }

  /**
   * Save template to file
   */
  private async saveTemplate(template: ConfigurationTemplate): Promise<void> {
    const filePath = join(this.templatesDir, `${template.id}.json`);
    const data = JSON.stringify(template, null, 2);
    await fs.writeFile(filePath, data, 'utf-8');
  }

  /**
   * Generate template ID from name
   */
  private generateTemplateId(name: string): string {
    return (
      name
        .toLowerCase()
        .replace(/[^a-z0-9]+/g, '-')
        .replace(/^-|-$/g, '') +
      '-' +
      Date.now().toString(36)
    );
  }

  /**
   * Check if template matches filter
   */
  private matchesFilter(template: ConfigurationTemplate, filter?: TemplateFilter): boolean {
    if (!filter) {
      return true;
    }

    if (filter.category && template.category !== filter.category) {
      return false;
    }

    if (filter.isBuiltIn !== undefined && template.isBuiltIn !== filter.isBuiltIn) {
      return false;
    }

    if (filter.createdBy && template.createdBy !== filter.createdBy) {
      return false;
    }

    if (filter.tags && filter.tags.length > 0) {
      const hasMatchingTag = filter.tags.some((tag) =>
        template.tags.some((templateTag) => templateTag.toLowerCase().includes(tag.toLowerCase()))
      );
      if (!hasMatchingTag) {
        return false;
      }
    }

    if (filter.search) {
      const searchLower = filter.search.toLowerCase();
      const searchableText = [
        template.name,
        template.description,
        ...template.tags,
        template.category,
      ]
        .join(' ')
        .toLowerCase();

      if (!searchableText.includes(searchLower)) {
        return false;
      }
    }

    return true;
  }
}

import convict from 'convict';
import { BotConfigurationManager } from '../../config/BotConfigurationManager';
import { getLlmDefaultStatus } from '../../config/llmDefaultStatus';
import { CONFIG_LIMITS } from '../../types/config';

interface ValidationResult {
  isValid: boolean;
  errors: string[];
  warnings: string[];
  suggestions: string[];
}

interface TestResult {
  success: boolean;
  message: string;
  details?: any;
}

export interface BotConfig {
  name: string;
  messageProvider: string;
  llmProvider: string;
  llmProfile?: string;
  discord?:
    | {
        token: string;
        clientId?: string;
        guildId?: string;
        channelId?: string;
        voiceChannelId?: string;
      }
    | string;
  slack?:
    | {
        botToken: string;
        appToken?: string;
        signingSecret: string;
        joinChannels?: string;
        defaultChannelId?: string;
        mode?: 'socket' | 'rtm';
      }
    | string;
  mattermost?:
    | {
        serverUrl: string;
        token: string;
        teamId?: string;
        channelId?: string;
      }
    | string;
  openai?:
    | {
        apiKey: string;
        model?: string;
        temperature?: number;
        maxTokens?: number;
      }
    | string;
  flowise?:
    | {
        apiKey: string;
        endpoint: string;
        chatflowId?: string;
      }
    | string;
  openwebui?:
    | {
        apiKey: string;
        endpoint: string;
        model?: string;
      }
    | string;
  openswarm?:
    | {
        apiKey: string;
        endpoint: string;
        agentId?: string;
      }
    | string;
  persona?: string;
  mcpGuardProfile?: string;
  responseProfile?: string;
  systemInstruction?: string;
  mcpServers?: string | string[] | { name: string; serverUrl?: string }[];
  mcpGuard?:
    | {
        enabled: boolean;
        type: 'owner' | 'custom';
        allowedUserIds?: string[];
      }
    | string;
  createdAt?: string;
  updatedAt?: string;
  isActive?: boolean;
}

export class ConfigurationValidator {
  private botConfigManager: typeof BotConfigurationManager;
  private botSchema: convict.Schema<any>;

  constructor() {
    this.botConfigManager = BotConfigurationManager;
    this.botSchema = this.createBotSchema();
  }

  /**
   * Create bot configuration schema using convict
   */
  private createBotSchema(): convict.Schema<any> {
    return {
      name: {
        doc: 'Bot name',
        format: String,
        default: '',
      },
      messageProvider: {
        doc: 'Message provider type',
        format: ['discord', 'slack', 'mattermost', 'webhook'],
        default: 'discord',
      },
      llmProvider: {
        doc: 'LLM provider type',
        format: ['openai', 'flowise', 'openwebui', 'openswarm'],
        default: 'openai',
      },
      llmProfile: {
        doc: 'LLM provider profile',
        format: String,
        default: '',
      },
      persona: {
        doc: 'Bot persona',
        format: String,
        default: 'default',
      },
      mcpGuardProfile: {
        doc: 'MCP guardrail profile name',
        format: String,
        default: '',
      },
      responseProfile: {
        doc: 'Response profile name',
        format: String,
        default: '',
      },
      systemInstruction: {
        doc: 'System instruction',
        format: String,
        default: '',
      },
      mcpServers: {
        doc: 'MCP servers',
        format: Array,
        default: [],
      },
      mcpGuard: {
        doc: 'MCP guard configuration',
        format: Object,
        default: { enabled: false, type: 'owner' },
      },
      discord: {
        doc: 'Discord configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      slack: {
        doc: 'Slack configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      mattermost: {
        doc: 'Mattermost configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      openai: {
        doc: 'OpenAI configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      flowise: {
        doc: 'Flowise configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      openwebui: {
        doc: 'OpenWebUI configuration',
        format: Object,
        default: null,
        nullable: true,
      },
      openswarm: {
        doc: 'OpenSwarm configuration',
        format: Object,
        default: null,
        nullable: true,
      },
    };
  }

  /**
   * Validate a bot configuration using convict schema
   */
  validateBotConfigWithSchema(config: BotConfig): ValidationResult {
    try {
      const configSchema = convict(this.botSchema);
      configSchema.load(config);
      configSchema.validate({ allowed: 'strict' });

      return {
        isValid: true,
        errors: [],
        warnings: [],
        suggestions: [],
      };
    } catch (error: any) {
      return {
        isValid: false,
        errors: [error.message],
        warnings: [],
        suggestions: [],
      };
    }
  }

  /**
   * Validate a bot configuration
   */
  validateBotConfig(config: BotConfig): ValidationResult {
    const errors: string[] = [];
    const warnings: string[] = [];
    const suggestions: string[] = [];

    // Basic validation
    if (!config.name || config.name.trim().length === 0) {
      errors.push('Bot name is required');
    } else if (config.name.length < CONFIG_LIMITS.BOT_NAME_MIN_LENGTH) {
      errors.push(`Bot name must be at least ${CONFIG_LIMITS.BOT_NAME_MIN_LENGTH} characters long`);
    } else if (config.name.length > CONFIG_LIMITS.BOT_NAME_MAX_LENGTH) {
      errors.push(
        `Bot name must be less than ${CONFIG_LIMITS.BOT_NAME_MAX_LENGTH} characters long`
      );
    }

    if (!config.messageProvider) {
      errors.push('Message provider is required');
    } else {
      const validProviders = ['discord', 'slack', 'mattermost'];
      if (!validProviders.includes(config.messageProvider)) {
        errors.push(`Invalid message provider. Must be one of: ${validProviders.join(', ')}`);
      }
    }

    const normalizedLlmProvider =
      typeof config.llmProvider === 'string' ? config.llmProvider.trim() : '';
    const llmDefaults = getLlmDefaultStatus();
    const normalizedConfig: BotConfig = { ...config, llmProvider: normalizedLlmProvider };

    if (!normalizedLlmProvider) {
      if (!llmDefaults.configured) {
        errors.push('LLM provider is required when no default LLM provider is configured');
      } else {
        suggestions.push('No LLM provider selected; the default LLM provider will be used');
      }
    } else {
      this.validateLLMProvider(normalizedConfig, errors, warnings, suggestions);
    }

    // Provider-specific validation
    this.validateMessageProvider(config, errors, warnings, suggestions);
    this.validateLLMProvider(config, errors, warnings, suggestions);

    // Advanced configuration validation
    this.validateAdvancedConfig(config, errors, warnings, suggestions);

    return {
      isValid: errors.length === 0,
      errors,
      warnings,
      suggestions,
    };
  }

  /**
   * Validate message provider configuration
   */
  private validateMessageProvider(
    config: BotConfig,
    errors: string[],
    warnings: string[],
    suggestions: string[]
  ): void {
    switch (config.messageProvider) {
      case 'discord': {
        const discord = typeof config.discord === 'string' ? undefined : config.discord;
        if (!discord?.token) {
          errors.push('Discord bot token is required');
        } else if (!discord.token.startsWith('M') && !discord.token.startsWith('Bot ')) {
          warnings.push('Discord token should start with "Bot " prefix or be a valid bot token');
        }
        break;
      }

      case 'slack': {
        const slack = typeof config.slack === 'string' ? undefined : config.slack;
        if (!slack?.botToken) {
          errors.push('Slack bot token is required');
        }
        if (!slack?.signingSecret) {
          errors.push('Slack signing secret is required');
        }
        if (slack?.mode === 'socket' && !slack?.appToken) {
          warnings.push('Slack app token is recommended when using socket mode');
        }
        break;
      }

      case 'mattermost': {
        const mattermost = typeof config.mattermost === 'string' ? undefined : config.mattermost;
        if (!mattermost?.serverUrl) {
          errors.push('Mattermost server URL is required');
        } else {
          try {
            new URL(mattermost.serverUrl);
          } catch {
            errors.push('Mattermost server URL must be a valid URL');
          }
        }
        if (!mattermost?.token) {
          errors.push('Mattermost token is required');
        }
        break;
      }
    }
  }

  /**
   * Validate LLM provider configuration
   */
  private validateLLMProvider(
    config: BotConfig,
    errors: string[],
    warnings: string[],
    suggestions: string[]
  ): void {
    const provider = typeof config.llmProvider === 'string' ? config.llmProvider.trim() : '';
    if (!provider) {
      return;
    }

    switch (provider) {
      case 'openai': {
        const openai = typeof config.openai === 'string' ? undefined : config.openai;
        if (!openai?.apiKey) {
          errors.push('OpenAI API key is required');
        } else if (!openai.apiKey.startsWith('sk-')) {
          warnings.push('OpenAI API key should start with "sk-" prefix');
        }
        if (!openai?.model) {
          suggestions.push('Consider specifying an OpenAI model (e.g., gpt-3.5-turbo, gpt-4)');
        }
        break;
      }

      case 'flowise': {
        const flowise = typeof config.flowise === 'string' ? undefined : config.flowise;
        if (!flowise?.endpoint) {
          errors.push('Flowise endpoint is required');
        } else {
          try {
            new URL(flowise.endpoint);
          } catch {
            errors.push('Flowise endpoint must be a valid URL');
          }
        }
        break;
      }

      case 'openwebui': {
        const openwebui = typeof config.openwebui === 'string' ? undefined : config.openwebui;
        if (!openwebui?.apiKey) {
          errors.push('OpenWebUI API key is required');
        }
        if (!openwebui?.endpoint) {
          errors.push('OpenWebUI endpoint is required');
        } else {
          try {
            new URL(openwebui.endpoint);
          } catch {
            errors.push('OpenWebUI endpoint must be a valid URL');
          }
        }
        break;
      }

      case 'openswarm': {
        const openswarm = typeof config.openswarm === 'string' ? undefined : config.openswarm;
        if (!openswarm?.apiKey) {
          errors.push('OpenSwarm API key is required');
        }
        if (!openswarm?.endpoint) {
          errors.push('OpenSwarm endpoint is required');
        } else {
          try {
            new URL(openswarm.endpoint);
          } catch {
            errors.push('OpenSwarm endpoint must be a valid URL');
          }
        }
        break;
      }
    }
  }

  /**
   * Validate advanced configuration
   */
  private validateAdvancedConfig(
    config: BotConfig,
    errors: string[],
    warnings: string[],
    suggestions: string[]
  ): void {
    // System instruction validation
    if (config.systemInstruction) {
      if (config.systemInstruction.length > CONFIG_LIMITS.SYSTEM_INSTRUCTION_WARNING_LENGTH) {
        warnings.push('System instruction is very long and may affect response times');
      }
      if (config.systemInstruction.length < CONFIG_LIMITS.SYSTEM_INSTRUCTION_MIN_LENGTH) {
        suggestions.push(
          'System instruction is very short. Consider adding more detailed instructions'
        );
      }
    }

    // MCP Server validation
    if (config.mcpServers) {
      const servers = Array.isArray(config.mcpServers) ? config.mcpServers : [config.mcpServers];
      servers.forEach((server, index) => {
        if (typeof server === 'string') {
          try {
            new URL(server);
          } catch {
            errors.push(`MCP server ${index + 1} has invalid URL format`);
          }
        }
      });
    }

    // MCP Guard validation
    const mcpGuard = typeof config.mcpGuard === 'string' ? undefined : config.mcpGuard;
    if (mcpGuard?.enabled) {
      if (mcpGuard.type === 'custom' && !mcpGuard.allowedUserIds?.length) {
        warnings.push('MCP Guard is enabled but no allowed users specified');
        suggestions.push('Add user IDs to the allowed list or consider using owner-only mode');
      }
    }

    // Persona validation
    if (config.persona) {
      const validPersonas = ['dev-assistant', 'friendly-helper', 'teacher', 'custom'];
      if (!validPersonas.includes(config.persona)) {
        warnings.push('Custom persona detected. Ensure it follows expected behavior patterns');
      }
    }
  }

  /**
   * Test bot configuration connectivity
   */
  async testBotConfig(config: BotConfig): Promise<TestResult> {
    try {
      // Test message provider connectivity
      const messageProviderTest = await this.testMessageProvider(config);

      // Test LLM provider connectivity
      const llmProviderTest = await this.testLLMProvider(config);

      const allTestsPassed = messageProviderTest.success && llmProviderTest.success;

      return {
        success: allTestsPassed,
        message: allTestsPassed
          ? 'All configuration tests passed'
          : 'Some configuration tests failed',
        details: {
          messageProvider: messageProviderTest,
          llmProvider: llmProviderTest,
        },
      };
    } catch (error: any) {
      return {
        success: false,
        message: `Configuration test failed: ${error.message}`,
        details: error,
      };
    }
  }

  /**
   * Test message provider connectivity
   */
  private async testMessageProvider(config: BotConfig): Promise<TestResult> {
    // This would implement actual connectivity tests
    // For now, return a mock result
    return {
      success: true,
      message: 'Message provider test completed (mock)',
      details: {
        provider: config.messageProvider,
        status: 'mock_success',
      },
    };
  }

  /**
   * Test LLM provider connectivity
   */
  private async testLLMProvider(config: BotConfig): Promise<TestResult> {
    // This would implement actual connectivity tests
    // For now, return a mock result
    return {
      success: true,
      message: 'LLM provider test completed (mock)',
      details: {
        provider: config.llmProvider,
        status: 'mock_success',
      },
    };
  }

  /**
   * Validate configuration against environment variables
   */
  validateAgainstEnvironment(config: BotConfig): ValidationResult {
    const errors: string[] = [];
    const warnings: string[] = [];
    const suggestions: string[] = [];

    // Check for environment variable overrides
    const envPrefix = `BOTS_${config.name.toUpperCase().replace(/[^A_Z0-9]/g, '_')}_`;

    const envMappings = {
      MESSAGE_PROVIDER: 'messageProvider',
      LLM_PROVIDER: 'llmProvider',
      PERSONA: 'persona',
      SYSTEM_INSTRUCTION: 'systemInstruction',
    };

    Object.entries(envMappings).forEach(([envKey, configKey]) => {
      const envVar = `${envPrefix}${envKey}`;
      if (process.env[envVar]) {
        warnings.push(
          `Configuration field '${configKey}' will be overridden by environment variable ${envVar}`
        );
      }
    });

    // Provider-specific environment checks
    if (config.messageProvider === 'discord') {
      if (process.env.DISCORD_BOT_TOKEN) {
        warnings.push('Discord token will be overridden by DISCORD_BOT_TOKEN environment variable');
      }
    }

    if (config.llmProvider === 'openai') {
      if (process.env.OPENAI_API_KEY) {
        warnings.push('OpenAI API key will be overridden by OPENAI_API_KEY environment variable');
      }
    }

    return {
      isValid: errors.length === 0,
      errors,
      warnings,
      suggestions,
    };
  }
}

import Debug from 'debug';
import {
  DatabaseManager,
  type BotConfiguration,
  type BotConfigurationAudit,
  type BotConfigurationVersion,
} from '../../database/DatabaseManager';
import { ConfigurationValidator } from './ConfigurationValidator';

const debug = Debug('app:ConfigurationVersionService');

interface CreateVersionRequest {
  botConfigurationId: number;
  version: string;
  changeLog?: string;
  createdBy?: string;
}

interface VersionHistoryResponse {
  versions: BotConfigurationVersion[];
  total: number;
  currentVersion?: string;
}

interface VersionComparisonResult {
  version1: BotConfigurationVersion;
  version2: BotConfigurationVersion;
  differences: ConfigurationDifference[];
  summary: {
    added: number;
    modified: number;
    removed: number;
  };
}

interface ConfigurationDifference {
  field: string;
  path: string;
  oldValue: any;
  newValue: any;
  changeType: 'added' | 'modified' | 'removed';
}

export class ConfigurationVersionService {
  private static instance: ConfigurationVersionService;
  private dbManager: DatabaseManager;
  private configValidator: ConfigurationValidator;

  private constructor() {
    this.dbManager = DatabaseManager.getInstance();
    this.configValidator = new ConfigurationValidator();
  }

  public static getInstance(): ConfigurationVersionService {
    if (!ConfigurationVersionService.instance) {
      ConfigurationVersionService.instance = new ConfigurationVersionService();
    }
    return ConfigurationVersionService.instance;
  }

  /**
   * Create a new version of a bot configuration
   */
  async createVersion(request: CreateVersionRequest): Promise<BotConfigurationVersion> {
    try {
      // Get the current configuration
      const currentConfig = await this.dbManager.getBotConfiguration(request.botConfigurationId);
      if (!currentConfig) {
        throw new Error(`Bot configuration with ID ${request.botConfigurationId} not found`);
      }

      // Check if version already exists
      const existingVersions = await this.dbManager.getBotConfigurationVersions(
        request.botConfigurationId
      );
      const existingVersion = existingVersions.find((v) => v.version === request.version);
      if (existingVersion) {
        throw new Error(`Version ${request.version} already exists for this configuration`);
      }

      // Create version data
      const versionData: BotConfigurationVersion = {
        botConfigurationId: request.botConfigurationId,
        version: request.version,
        name: currentConfig.name,
        messageProvider: currentConfig.messageProvider,
        llmProvider: currentConfig.llmProvider,
        persona: currentConfig.persona,
        systemInstruction: currentConfig.systemInstruction,
        mcpServers: currentConfig.mcpServers,
        mcpGuard: currentConfig.mcpGuard,
        discord: currentConfig.discord,
        slack: currentConfig.slack,
        mattermost: currentConfig.mattermost,
        openai: currentConfig.openai,
        flowise: currentConfig.flowise,
        openwebui: currentConfig.openwebui,
        openswarm: currentConfig.openswarm,
        isActive: currentConfig.isActive,
        createdAt: new Date(),
        createdBy: request.createdBy || 'system',
        changeLog: request.changeLog || `Created version ${request.version}`,
      };

      // Save version to database
      const versionId = await this.dbManager.createBotConfigurationVersion(versionData);

      // Get the created version with ID - need to find it in the versions list
      const versions = await this.dbManager.getBotConfigurationVersions(request.botConfigurationId);
      const createdVersion = versions.find((v) => v.version === request.version);

      if (!createdVersion) {
        throw new Error('Failed to create configuration version');
      }

      debug(
        `Created configuration version: ${request.version} for bot configuration ID: ${request.botConfigurationId}`
      );
      return createdVersion;
    } catch (error) {
      debug('Error creating configuration version:', error);
      throw new Error(`Failed to create configuration version: ${error}`);
    }
  }

  /**
   * Get version history for a bot configuration
   */
  async getVersionHistory(botConfigurationId: number): Promise<VersionHistoryResponse> {
    try {
      const versions = await this.dbManager.getBotConfigurationVersions(botConfigurationId);
      const currentConfig = await this.dbManager.getBotConfiguration(botConfigurationId);

      return {
        versions: versions.sort((a, b) => b.createdAt.getTime() - a.createdAt.getTime()),
        total: versions.length,
        currentVersion: currentConfig?.name, // This could be enhanced to track current version
      };
    } catch (error) {
      debug('Error getting version history:', error);
      throw new Error(`Failed to get version history: ${error}`);
    }
  }

  /**
   * Get a specific version of a bot configuration
   */
  async getVersion(
    botConfigurationId: number,
    version: string
  ): Promise<BotConfigurationVersion | null> {
    try {
      const versions = await this.dbManager.getBotConfigurationVersions(botConfigurationId);
      return versions.find((v) => v.version === version) || null;
    } catch (error) {
      debug('Error getting configuration version:', error);
      throw new Error(`Failed to get configuration version: ${error}`);
    }
  }

  /**
   * Compare two versions of a bot configuration
   */
  async compareVersions(
    botConfigurationId: number,
    version1: string,
    version2: string
  ): Promise<VersionComparisonResult> {
    try {
      const versions = await this.dbManager.getBotConfigurationVersions(botConfigurationId);
      const v1 = versions.find((v) => v.version === version1);
      const v2 = versions.find((v) => v.version === version2);

      if (!v1 || !v2) {
        throw new Error('One or both versions not found');
      }

      const differences = this.compareConfigurations(v1, v2);
      const summary = this.generateDifferenceSummary(differences);

      return {
        version1: v1,
        version2: v2,
        differences,
        summary,
      };
    } catch (error) {
      debug('Error comparing configuration versions:', error);
      throw new Error(`Failed to compare configuration versions: ${error}`);
    }
  }

  /**
   * Restore a bot configuration to a specific version
   */
  async restoreVersion(
    botConfigurationId: number,
    version: string,
    restoredBy?: string
  ): Promise<BotConfiguration> {
    try {
      // Get the version to restore
      const versions = await this.dbManager.getBotConfigurationVersions(botConfigurationId);
      const versionData = versions.find((v) => v.version === version);
      if (!versionData) {
        throw new Error(`Version ${version} not found`);
      }

      // Create update data from version
      const updateData: Partial<BotConfiguration> = {
        name: versionData.name,
        messageProvider: versionData.messageProvider,
        llmProvider: versionData.llmProvider,
        persona: versionData.persona,
        systemInstruction: versionData.systemInstruction,
        mcpServers: versionData.mcpServers,
        mcpGuard: versionData.mcpGuard,
        discord: versionData.discord,
        slack: versionData.slack,
        mattermost: versionData.mattermost,
        openai: versionData.openai,
        flowise: versionData.flowise,
        openwebui: versionData.openwebui,
        openswarm: versionData.openswarm,
        isActive: versionData.isActive,
        updatedAt: new Date(),
      };

      // Update the configuration
      await this.dbManager.updateBotConfiguration(botConfigurationId, updateData);

      // Get the updated configuration
      const restoredConfig = await this.dbManager.getBotConfiguration(botConfigurationId);
      if (!restoredConfig) {
        throw new Error('Failed to restore configuration');
      }

      // Create audit log entry
      await this.dbManager.createBotConfigurationAudit({
        botConfigurationId,
        action: 'UPDATE',
        oldValues: JSON.stringify({ restoredFrom: version }),
        newValues: JSON.stringify(restoredConfig),
        performedAt: new Date(),
        performedBy: restoredBy,
      });

      debug(`Restored bot configuration ID: ${botConfigurationId} to version: ${version}`);
      return restoredConfig;
    } catch (error) {
      debug('Error restoring configuration version:', error);
      throw new Error(`Failed to restore configuration version: ${error}`);
    }
  }

  /**
   * Delete a version (if not the only version)
   */
  async deleteVersion(botConfigurationId: number, version: string): Promise<boolean> {
    try {
      // Check if this is the only version
      const versions = await this.dbManager.getBotConfigurationVersions(botConfigurationId);
      if (versions.length <= 1) {
        throw new Error('Cannot delete the only version of a configuration');
      }

      // Check if this is the currently active version
      const currentConfig = await this.dbManager.getBotConfiguration(botConfigurationId);
      if (currentConfig) {
        const versionToDelete = versions.find((v) => v.version === version);
        if (
          versionToDelete &&
          versionToDelete.messageProvider === currentConfig.messageProvider &&
          versionToDelete.llmProvider === currentConfig.llmProvider &&
          versionToDelete.persona === currentConfig.persona
        ) {
          throw new Error('Cannot delete the currently active version');
        }
      }

      const deleted = await this.dbManager.deleteBotConfigurationVersion(
        botConfigurationId,
        version
      );
      if (deleted) {
        debug(
          `Deleted configuration version: ${version} for bot configuration ID: ${botConfigurationId}`
        );
      }
      return deleted;
    } catch (error) {
      debug('Error deleting configuration version:', error);
      throw new Error(`Failed to delete configuration version: ${error}`);
    }
  }

  /**
   * Get audit log for a bot configuration
   */
  async getAuditLog(botConfigurationId: number, limit = 50): Promise<BotConfigurationAudit[]> {
    try {
      const audits = await this.dbManager.getBotConfigurationAudit(botConfigurationId);
      return audits.slice(0, limit);
    } catch (error) {
      debug('Error getting audit log:', error);
      throw new Error(`Failed to get audit log: ${error}`);
    }
  }

  /**
   * Compare two configuration objects and find differences
   */
  private compareConfigurations(
    config1: BotConfigurationVersion,
    config2: BotConfigurationVersion
  ): ConfigurationDifference[] {
    const differences: ConfigurationDifference[] = [];

    // Helper function to compare objects recursively
    const compareObjects = (obj1: any, obj2: any, path = '') => {
      const allKeys = new Set([...Object.keys(obj1 || {}), ...Object.keys(obj2 || {})]);

      for (const key of allKeys) {
        const currentPath = path ? `${path}.${key}` : key;

        if (!(key in obj1)) {
          differences.push({
            field: key,
            path: currentPath,
            oldValue: undefined,
            newValue: obj2[key],
            changeType: 'added',
          });
        } else if (!(key in obj2)) {
          differences.push({
            field: key,
            path: currentPath,
            oldValue: obj1[key],
            newValue: undefined,
            changeType: 'removed',
          });
        } else if (typeof obj1[key] === 'object' && typeof obj2[key] === 'object') {
          compareObjects(obj1[key], obj2[key], currentPath);
        } else if (obj1[key] !== obj2[key]) {
          differences.push({
            field: key,
            path: currentPath,
            oldValue: obj1[key],
            newValue: obj2[key],
            changeType: 'modified',
          });
        }
      }
    };

    // Compare all configuration fields
    const config1Plain = { ...config1 };
    const config2Plain = { ...config2 };

    // Remove fields that shouldn't be compared
    const { id, botConfigurationId, version, createdAt, createdBy, changeLog, ...config1Clean } =
      config1Plain;
    const {
      id: id2,
      botConfigurationId: botConfigurationId2,
      version: version2,
      createdAt: createdAt2,
      createdBy: createdBy2,
      changeLog: changeLog2,
      ...config2Clean
    } = config2Plain;

    compareObjects(config1Plain, config2Plain);

    return differences;
  }

  /**
   * Generate a summary of differences
   */
  private generateDifferenceSummary(differences: ConfigurationDifference[]) {
    return differences.reduce(
      (summary, diff) => {
        summary[diff.changeType]++;
        return summary;
      },
      { added: 0, modified: 0, removed: 0 }
    );
  }
}

import { EventEmitter } from 'events';
import Debug from 'debug';
import { WebSocketService } from './WebSocketService';

const debug = Debug('app:RealTimeNotificationService');

interface NotificationEvent {
  id: string;
  timestamp: string;
  type: 'agent' | 'mcp' | 'system' | 'error' | 'config';
  severity: 'info' | 'warning' | 'error' | 'success';
  title: string;
  message: string;
  source?: string;
  metadata?: Record<string, any>;
}

interface SubscriptionFilter {
  types?: string[];
  severities?: string[];
  sources?: string[];
}

class RealTimeNotificationService extends EventEmitter {
  private static instance: RealTimeNotificationService | null = null;
  private notifications: NotificationEvent[] = [];
  private maxNotifications = 1000;
  private webSocketService: WebSocketService;

  private constructor() {
    super();
    this.webSocketService = WebSocketService.getInstance();
  }

  public static getInstance(): RealTimeNotificationService {
    if (!RealTimeNotificationService.instance) {
      RealTimeNotificationService.instance = new RealTimeNotificationService();
    }
    return RealTimeNotificationService.instance;
  }

  public notify(event: Omit<NotificationEvent, 'id' | 'timestamp'>): string {
    const notification: NotificationEvent = {
      ...event,
      id: this.generateId(),
      timestamp: new Date().toISOString(),
    };

    // Add to internal storage
    this.notifications.unshift(notification);

    // Trim if too many
    if (this.notifications.length > this.maxNotifications) {
      this.notifications = this.notifications.slice(0, this.maxNotifications);
    }

    // Emit to local listeners
    this.emit('notification', notification);

    // Send via WebSocket to connected clients
    (this.webSocketService as any).io?.sockets?.emit('notification', notification);

    debug(
      `Notification sent: ${notification.type}/${notification.severity} - ${notification.title}`
    );

    return notification.id;
  }

  public getNotifications(limit = 50, filter?: SubscriptionFilter): NotificationEvent[] {
    let filtered = [...this.notifications];

    if (filter) {
      filtered = filtered.filter((notification) => {
        if (filter.types && !filter.types.includes(notification.type)) {
          return false;
        }
        if (filter.severities && !filter.severities.includes(notification.severity)) {
          return false;
        }
        if (
          filter.sources &&
          notification.source &&
          !filter.sources.includes(notification.source)
        ) {
          return false;
        }
        return true;
      });
    }

    return filtered.slice(0, limit);
  }

  public markAsRead(notificationId: string): boolean {
    const notification = this.notifications.find((n) => n.id === notificationId);
    if (notification && notification.metadata) {
      notification.metadata.read = true;
      return true;
    }
    return false;
  }

  public clearNotifications(filter?: SubscriptionFilter): number {
    const originalLength = this.notifications.length;

    if (!filter) {
      this.notifications = [];
      return originalLength;
    }

    this.notifications = this.notifications.filter((notification) => {
      // Keep notifications that don't match the filter
      if (filter.types && filter.types.includes(notification.type)) {
        return false;
      }
      if (filter.severities && filter.severities.includes(notification.severity)) {
        return false;
      }
      if (filter.sources && notification.source && filter.sources.includes(notification.source)) {
        return false;
      }
      return true;
    });

    return originalLength - this.notifications.length;
  }

  public subscribe(
    callback: (notification: NotificationEvent) => void,
    filter?: SubscriptionFilter
  ): () => void {
    const listener = (notification: NotificationEvent) => {
      if (!filter) {
        callback(notification);
        return;
      }

      // Apply filter
      if (filter.types && !filter.types.includes(notification.type)) {
        return;
      }
      if (filter.severities && !filter.severities.includes(notification.severity)) {
        return;
      }
      if (filter.sources && notification.source && !filter.sources.includes(notification.source)) {
        return;
      }

      callback(notification);
    };

    this.on('notification', listener);

    // Return unsubscribe function
    return () => {
      this.off('notification', listener);
    };
  }

  // Convenience methods for common notification types
  public notifyAgentEvent(
    agentName: string,
    event: 'started' | 'stopped' | 'error' | 'configured',
    details?: string,
    metadata?: Record<string, any>
  ): string {
    const severityMap = {
      started: 'success' as const,
      stopped: 'info' as const,
      error: 'error' as const,
      configured: 'info' as const,
    };

    return this.notify({
      type: 'agent',
      severity: severityMap[event],
      title: `Agent ${event}`,
      message: `Agent "${agentName}" ${event}${details ? `: ${details}` : ''}`,
      source: agentName,
      metadata: { agentName, event, ...metadata },
    });
  }

  public notifyMCPEvent(
    serverName: string,
    event: 'connected' | 'disconnected' | 'error' | 'tool_executed',
    details?: string,
    metadata?: Record<string, any>
  ): string {
    const severityMap = {
      connected: 'success' as const,
      disconnected: 'warning' as const,
      error: 'error' as const,
      tool_executed: 'info' as const,
    };

    return this.notify({
      type: 'mcp',
      severity: severityMap[event],
      title: `MCP Server ${event}`,
      message: `MCP server "${serverName}" ${event}${details ? `: ${details}` : ''}`,
      source: serverName,
      metadata: { serverName, event, ...metadata },
    });
  }

  public notifySystemEvent(
    event: 'startup' | 'shutdown' | 'config_reload' | 'error',
    details: string,
    metadata?: Record<string, any>
  ): string {
    const severityMap = {
      startup: 'success' as const,
      shutdown: 'info' as const,
      config_reload: 'info' as const,
      error: 'error' as const,
    };

    return this.notify({
      type: 'system',
      severity: severityMap[event],
      title: `System ${event}`,
      message: details,
      source: 'system',
      metadata: { event, ...metadata },
    });
  }

  public getStats(): {
    total: number;
    byType: Record<string, number>;
    bySeverity: Record<string, number>;
    recent: NotificationEvent[];
    unread: number;
  } {
    const byType: Record<string, number> = {};
    const bySeverity: Record<string, number> = {};
    let unread = 0;

    this.notifications.forEach((notification) => {
      byType[notification.type] = (byType[notification.type] || 0) + 1;
      bySeverity[notification.severity] = (bySeverity[notification.severity] || 0) + 1;

      if (!notification.metadata?.read) {
        unread++;
      }
    });

    return {
      total: this.notifications.length,
      byType,
      bySeverity,
      recent: this.notifications.slice(0, 10),
      unread,
    };
  }

  private generateId(): string {
    return `${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
  }
}

import { EventEmitter } from 'events';
import Debug from 'debug';
import { DatabaseManager } from '../../database/DatabaseManager';
import { BotConfigService } from './BotConfigService';
import { ConfigurationTemplateService } from './ConfigurationTemplateService';
import { ConfigurationValidator } from './ConfigurationValidator';

const debug = Debug('app:RealTimeValidationService');

interface ValidationRule {
  id: string;
  name: string;
  description: string;
  category: 'required' | 'format' | 'business' | 'security' | 'performance';
  severity: 'error' | 'warning' | 'info';
  validator: (config: any) => ValidationResult;
}

interface ValidationResult {
  isValid: boolean;
  errors: ValidationError[];
  warnings: ValidationWarning[];
  info: ValidationInfo[];
  score: number; // 0-100, higher is better
}

interface ValidationError {
  id: string;
  ruleId: string;
  message: string;
  field: string;
  value: any;
  expected?: any;
  suggestions?: string[];
  category: 'required' | 'format' | 'business' | 'security' | 'performance';
}

interface ValidationWarning {
  id: string;
  ruleId: string;
  message: string;
  field: string;
  value: any;
  suggestions?: string[];
  category: 'required' | 'format' | 'business' | 'security' | 'performance';
}

interface ValidationInfo {
  id: string;
  ruleId: string;
  message: string;
  field: string;
  value: any;
  suggestions?: string[];
  category: 'required' | 'format' | 'business' | 'security' | 'performance';
}

interface ValidationReport {
  id: string;
  timestamp: Date;
  configId?: number;
  configName?: string;
  configVersion?: string;
  result: ValidationResult;
  executionTime: number;
  rulesExecuted: number;
}

interface ValidationProfile {
  id: string;
  name: string;
  description: string;
  ruleIds: string[];
  isDefault: boolean;
  createdBy?: string;
  createdAt: Date;
  updatedAt: Date;
}

interface ValidationSubscription {
  id: string;
  configId: number;
  clientId: string;
  profileId: string;
  isActive: boolean;
  lastValidated?: Date;
  createdAt: Date;
}

export class RealTimeValidationService extends EventEmitter {
  private static instance: RealTimeValidationService;
  private configValidator: ConfigurationValidator;
  private botConfigService: BotConfigService;
  private templateService: ConfigurationTemplateService;
  private dbManager: DatabaseManager;
  private rules = new Map<string, ValidationRule>();
  private profiles = new Map<string, ValidationProfile>();
  private subscriptions = new Map<string, ValidationSubscription>();
  private validationHistory: ValidationReport[] = [];
  private maxHistorySize = 100;
  private validationInterval: NodeJS.Timeout | null = null;

  private constructor() {
    super();
    this.configValidator = new ConfigurationValidator();
    this.botConfigService = BotConfigService.getInstance();
    this.templateService = ConfigurationTemplateService.getInstance();
    this.dbManager = DatabaseManager.getInstance();
    this.initializeDefaultRules();
    this.initializeDefaultProfiles();
    this.setupEventHandlers();
  }

  public static getInstance(): RealTimeValidationService {
    if (!RealTimeValidationService.instance) {
      RealTimeValidationService.instance = new RealTimeValidationService();
    }
    return RealTimeValidationService.instance;
  }

  /**
   * Initialize default validation rules
   */
  private initializeDefaultRules(): void {
    // Required field validation rules
    this.addRule({
      id: 'required-name',
      name: 'Bot Name Required',
      description: 'Bot configuration must have a name',
      category: 'required',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        if (!config.name || config.name.trim() === '') {
          errors.push({
            id: 'req-name-1',
            ruleId: 'required-name',
            message: 'Bot name is required',
            field: 'name',
            value: config.name,
            suggestions: ['Provide a unique name for your bot configuration'],
            category: 'required',
          });
        }
        return {
          isValid: errors.length === 0,
          errors,
          warnings: [],
          info: [],
          score: errors.length === 0 ? 100 : 0,
        };
      },
    });

    this.addRule({
      id: 'required-message-provider',
      name: 'Message Provider Required',
      description: 'Bot configuration must specify a message provider',
      category: 'required',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        if (!config.messageProvider || config.messageProvider.trim() === '') {
          errors.push({
            id: 'req-msg-1',
            ruleId: 'required-message-provider',
            message: 'Message provider is required',
            field: 'messageProvider',
            value: config.messageProvider,
            suggestions: ['Select a message provider: discord, slack, mattermost, or webhook'],
            category: 'required',
          });
        }
        return {
          isValid: errors.length === 0,
          errors,
          warnings: [],
          info: [],
          score: errors.length === 0 ? 100 : 0,
        };
      },
    });

    this.addRule({
      id: 'required-llm-provider',
      name: 'LLM Provider Required',
      description: 'Bot configuration must specify an LLM provider',
      category: 'required',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        if (!config.llmProvider || config.llmProvider.trim() === '') {
          errors.push({
            id: 'req-llm-1',
            ruleId: 'required-llm-provider',
            message: 'LLM provider is required',
            field: 'llmProvider',
            value: config.llmProvider,
            suggestions: ['Select an LLM provider: openai, flowise, or openwebui'],
            category: 'required',
          });
        }
        return {
          isValid: errors.length === 0,
          errors,
          warnings: [],
          info: [],
          score: errors.length === 0 ? 100 : 0,
        };
      },
    });

    // Format validation rules
    this.addRule({
      id: 'format-bot-name',
      name: 'Bot Name Format',
      description: 'Bot name must follow naming conventions',
      category: 'format',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        if (config.name && !/^[a-zA-Z0-9_-]{1,100}$/.test(config.name)) {
          errors.push({
            id: 'fmt-name-1',
            ruleId: 'format-bot-name',
            message:
              'Bot name must be 1-100 characters and contain only letters, numbers, underscores, and hyphens',
            field: 'name',
            value: config.name,
            expected: '^[a-zA-Z0-9_-]{1,100}$',
            suggestions: ['Use only alphanumeric characters, underscores, and hyphens'],
            category: 'format',
          });
        }
        return {
          isValid: errors.length === 0,
          errors,
          warnings: [],
          info: [],
          score: errors.length === 0 ? 100 : 0,
        };
      },
    });

    // Discord-specific validation rules
    this.addRule({
      id: 'discord-token',
      name: 'Discord Token',
      description: 'Discord bot token must be provided when using Discord as message provider',
      category: 'required',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        const warnings: ValidationWarning[] = [];

        if (config.messageProvider === 'discord') {
          if (!config.discord || !config.discord.token) {
            errors.push({
              id: 'discord-token-1',
              ruleId: 'discord-token',
              message: 'Discord bot token is required when using Discord as message provider',
              field: 'discord.token',
              value: config.discord?.token,
              suggestions: ['Provide your Discord bot token from the Discord Developer Portal'],
              category: 'required',
            });
          } else if (!/^[\w-]+\.[\w-]+\.[\w-]+$/.test(config.discord.token)) {
            warnings.push({
              id: 'discord-token-2',
              ruleId: 'discord-token',
              message: 'Discord token format appears invalid',
              field: 'discord.token',
              value: '***REDACTED***',
              suggestions: [
                'Verify your Discord token format: it should be "BotToken.AppID.Secret"',
              ],
              category: 'required',
            });
          }
        }

        return {
          isValid: errors.length === 0,
          errors,
          warnings,
          info: [],
          score: errors.length === 0 ? (warnings.length === 0 ? 100 : 80) : 0,
        };
      },
    });

    // OpenAI-specific validation rules
    this.addRule({
      id: 'openai-api-key',
      name: 'OpenAI API Key',
      description: 'OpenAI API key must be provided when using OpenAI as LLM provider',
      category: 'required',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];
        const warnings: ValidationWarning[] = [];

        if (config.llmProvider === 'openai') {
          if (!config.openai || !config.openai.apiKey) {
            errors.push({
              id: 'openai-key-1',
              ruleId: 'openai-api-key',
              message: 'OpenAI API key is required when using OpenAI as LLM provider',
              field: 'openai.apiKey',
              value: config.openai?.apiKey,
              suggestions: ['Provide your OpenAI API key from the OpenAI dashboard'],
              category: 'required',
            });
          } else if (!/^sk-[A-Za-z0-9]+$/.test(config.openai.apiKey)) {
            warnings.push({
              id: 'openai-key-2',
              ruleId: 'openai-api-key',
              message: 'OpenAI API key format appears invalid',
              field: 'openai.apiKey',
              value: '***REDACTED***',
              suggestions: ['Verify your OpenAI API key format: it should start with "sk-"'],
              category: 'required',
            });
          }
        }

        return {
          isValid: errors.length === 0,
          errors,
          warnings,
          info: [],
          score: errors.length === 0 ? (warnings.length === 0 ? 100 : 80) : 0,
        };
      },
    });

    // Business logic validation rules
    this.addRule({
      id: 'business-unique-name',
      name: 'Unique Bot Name',
      description: 'Bot name must be unique across all configurations',
      category: 'business',
      severity: 'error',
      validator: (config: any) => {
        const errors: ValidationError[] = [];

        if (config.name) {
          // This is a synchronous validator for simplicity
          // In a real implementation, you would make this async
          errors.push({
            id: 'biz-name-1',
            ruleId: 'business-unique-name',
            message: `Bot name "${config.name}" must be unique`,
            field: 'name',
            value: config.name,
            suggestions: [`Consider using "${config.name}-2" or a different name`],
            category: 'business',
          });
        }

        return {
          isValid: errors.length === 0,
          errors,
          warnings: [],
          info: [],
          score: errors.length === 0 ? 100 : 0,
        };
      },
    });

    // Security validation rules
    this.addRule({
      id: 'security-no-hardcoded-secrets',
      name: 'No Hardcoded Secrets',
      description: 'Configuration should not contain hardcoded secrets or API keys',
      category: 'security',
      severity: 'warning',
      validator: (config: any) => {
        const warnings: ValidationWarning[] = [];
        const configStr = JSON.stringify(config);

        // Check for potential hardcoded secrets
        const secretPatterns = [
          /"apiKey":\s*"[^${]+"/,
          /"token":\s*"[^${]+"/,
          /"secret":\s*"[^${]+"/,
          /"password":\s*"[^${]+"/,
        ];

        for (const pattern of secretPatterns) {
          if (pattern.test(configStr)) {
            warnings.push({
              id: 'sec-secrets-1',
              ruleId: 'security-no-hardcoded-secrets',
              message: 'Potential hardcoded secret detected in configuration',
              field: 'config',
              value: '***REDACTED***',
              suggestions: [
                'Use environment variables with ${VAR_NAME} syntax',
                'Store secrets in a secure configuration management system',
              ],
              category: 'security',
            });
            break;
          }
        }

        return {
          isValid: true,
          errors: [],
          warnings,
          info: [],
          score: warnings.length === 0 ? 100 : 70,
        };
      },
    });

    // Performance validation rules
    this.addRule({
      id: 'performance-model-selection',
      name: 'Model Performance',
      description: 'Check if selected LLM model is appropriate for the use case',
      category: 'performance',
      severity: 'info',
      validator: (config: any) => {
        const info: ValidationInfo[] = [];

        if (config.llmProvider === 'openai' && config.openai?.model) {
          const model = config.openai.model;

          if (model === 'gpt-4') {
            info.push({
              id: 'perf-model-1',
              ruleId: 'performance-model-selection',
              message: 'Using GPT-4 model - consider performance implications',
              field: 'openai.model',
              value: model,
              suggestions: [
                'GPT-4 is powerful but slower and more expensive',
                'Consider GPT-3.5-turbo for faster responses and lower cost',
              ],
              category: 'performance',
            });
          } else if (model === 'gpt-3.5-turbo') {
            info.push({
              id: 'perf-model-2',
              ruleId: 'performance-model-selection',
              message: 'Using GPT-3.5-turbo - good balance of performance and cost',
              field: 'openai.model',
              value: model,
              suggestions: [
                'GPT-3.5-turbo offers fast responses at a lower cost',
                'Consider GPT-4 for complex reasoning tasks',
              ],
              category: 'performance',
            });
          }
        }

        return {
          isValid: true,
          errors: [],
          warnings: [],
          info,
          score: 100,
        };
      },
    });

    debug(`Initialized ${this.rules.size} validation rules`);
  }

  /**
   * Initialize default validation profiles
   */
  private initializeDefaultProfiles(): void {
    // Strict profile - all rules enabled
    this.addProfile({
      id: 'strict',
      name: 'Strict Validation',
      description: 'All validation rules enabled, maximum security and compliance',
      ruleIds: Array.from(this.rules.keys()),
      isDefault: false,
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    // Standard profile - most rules enabled
    const standardRuleIds = Array.from(this.rules.keys()).filter(
      (id) => !id.startsWith('performance-') // Exclude performance rules
    );

    this.addProfile({
      id: 'standard',
      name: 'Standard Validation',
      description: 'Standard validation with essential security and business rules',
      ruleIds: standardRuleIds,
      isDefault: true,
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    // Quick profile - only required fields
    const quickRuleIds = Array.from(this.rules.keys()).filter(
      (id) => id.startsWith('required-') // Only required field rules
    );

    this.addProfile({
      id: 'quick',
      name: 'Quick Validation',
      description: 'Basic validation of required fields only',
      ruleIds: quickRuleIds,
      isDefault: false,
      createdAt: new Date(),
      updatedAt: new Date(),
    });

    debug(`Initialized ${this.profiles.size} validation profiles`);
  }

  /**
   * Setup event handlers
   */
  private setupEventHandlers(): void {
    // Periodic validation for subscribed configurations
    this.validationInterval = setInterval(() => {
      this.validateSubscribedConfigurations().catch((error: any) => {
        debug('Error in periodic validation:', error);
      });
    }, 60000); // Validate every minute
  }

  /**
   * Clean up resources, particularly stopping the validation interval.
   */
  public shutdown(): void {
    if (this.validationInterval) {
      clearInterval(this.validationInterval);
      this.validationInterval = null;
    }
    this.removeAllListeners();
    debug('RealTimeValidationService shutdown completed');
  }

  /**
   * Add a validation rule
   */
  public addRule(rule: ValidationRule): void {
    this.rules.set(rule.id, rule);
    debug(`Added validation rule: ${rule.name}`);
  }

  /**
   * Remove a validation rule
   */
  public removeRule(ruleId: string): boolean {
    const removed = this.rules.delete(ruleId);
    if (removed) {
      debug(`Removed validation rule: ${ruleId}`);

      // Remove from all profiles
      for (const profile of this.profiles.values()) {
        profile.ruleIds = profile.ruleIds.filter((id) => id !== ruleId);
      }
    }
    return removed;
  }

  /**
   * Get a validation rule
   */
  public getRule(ruleId: string): ValidationRule | undefined {
    return this.rules.get(ruleId);
  }

  /**
   * Get all validation rules
   */
  public getAllRules(): ValidationRule[] {
    return Array.from(this.rules.values());
  }

  /**
   * Add a validation profile
   */
  public addProfile(profile: ValidationProfile): void {
    this.profiles.set(profile.id, profile);
    debug(`Added validation profile: ${profile.name}`);
  }

  /**
   * Remove a validation profile
   */
  public removeProfile(profileId: string): boolean {
    const removed = this.profiles.delete(profileId);
    if (removed) {
      debug(`Removed validation profile: ${profileId}`);

      // Remove related subscriptions
      for (const [subId, sub] of this.subscriptions) {
        if (sub.profileId === profileId) {
          this.subscriptions.delete(subId);
        }
      }
    }
    return removed;
  }

  /**
   * Get a validation profile
   */
  public getProfile(profileId: string): ValidationProfile | undefined {
    return this.profiles.get(profileId);
  }

  /**
   * Get all validation profiles
   */
  public getAllProfiles(): ValidationProfile[] {
    return Array.from(this.profiles.values());
  }

  /**
   * Validate a configuration
   */
  public async validateConfiguration(
    configId: number,
    profileId = 'standard',
    clientId?: string
  ): Promise<ValidationReport> {
    const startTime = Date.now();

    try {
      // Get configuration
      const config = await this.botConfigService.getBotConfig(configId);
      if (!config) {
        throw new Error(`Configuration with ID ${configId} not found`);
      }

      // Get validation profile
      const profile = this.profiles.get(profileId);
      if (!profile) {
        throw new Error(`Validation profile with ID ${profileId} not found`);
      }

      // Execute validation rules
      const allErrors: ValidationError[] = [];
      const allWarnings: ValidationWarning[] = [];
      const allInfo: ValidationInfo[] = [];
      let rulesExecuted = 0;

      for (const ruleId of profile.ruleIds) {
        const rule = this.rules.get(ruleId);
        if (rule) {
          try {
            const result = rule.validator(config);
            allErrors.push(...result.errors);
            allWarnings.push(...result.warnings);
            allInfo.push(...result.info);
            rulesExecuted++;
          } catch (error) {
            debug(`Error executing rule ${ruleId}:`, error);

            // Add error for failed rule execution
            allErrors.push({
              id: `rule-error-${ruleId}`,
              ruleId,
              message: `Validation rule execution failed: ${(error as any).message}`,
              field: 'system',
              value: null,
              category: 'required',
            });
          }
        }
      }

      // Calculate overall score
      const errorWeight = 10;
      const warningWeight = 3;
      const infoWeight = 1;
      const totalDeductions =
        allErrors.length * errorWeight +
        allWarnings.length * warningWeight +
        allInfo.length * infoWeight;
      const maxPossibleDeductions = rulesExecuted * errorWeight;
      const score =
        maxPossibleDeductions > 0
          ? Math.max(0, 100 - (totalDeductions / maxPossibleDeductions) * 100)
          : 100;

      // Create validation result
      const result: ValidationResult = {
        isValid: allErrors.length === 0,
        errors: allErrors,
        warnings: allWarnings,
        info: allInfo,
        score: Math.round(score),
      };

      // Create validation report
      const report: ValidationReport = {
        id: this.generateReportId(),
        timestamp: new Date(),
        configId,
        configName: config.name,
        result,
        executionTime: Date.now() - startTime,
        rulesExecuted,
      };

      // Store in history
      this.addToHistory(report);

      // Update subscription if provided
      if (clientId) {
        const subId = this.getSubscriptionId(configId, clientId);
        const sub = this.subscriptions.get(subId);
        if (sub) {
          sub.lastValidated = new Date();
        }
      }

      // Emit events
      this.emit('validationCompleted', report);
      if (!result.isValid) {
        this.emit('validationFailed', report);
      }

      debug(
        `Validated configuration ${config.name} (${configId}): ${result.isValid ? 'VALID' : 'INVALID'} (${result.score}/100)`
      );

      return report;
    } catch (error) {
      debug('Error validating configuration:', error);

      // Create error report
      const report: ValidationReport = {
        id: this.generateReportId(),
        timestamp: new Date(),
        configId,
        result: {
          isValid: false,
          errors: [
            {
              id: 'validation-error',
              ruleId: 'system',
              message: `Validation failed: ${(error as any).message}`,
              field: 'system',
              value: null,
              category: 'required',
            },
          ],
          warnings: [],
          info: [],
          score: 0,
        },
        executionTime: Date.now() - startTime,
        rulesExecuted: 0,
      };

      this.addToHistory(report);
      this.emit('validationError', report);

      return report;
    }
  }

  /**
   * Validate configuration data directly
   */
  public validateConfigurationData(configData: any, profileId = 'standard'): ValidationResult {
    try {
      // Get validation profile
      const profile = this.profiles.get(profileId);
      if (!profile) {
        throw new Error(`Validation profile with ID ${profileId} not found`);
      }

      // Execute validation rules
      const allErrors: ValidationError[] = [];
      const allWarnings: ValidationWarning[] = [];
      const allInfo: ValidationInfo[] = [];
      let rulesExecuted = 0;

      for (const ruleId of profile.ruleIds) {
        const rule = this.rules.get(ruleId);
        if (rule) {
          try {
            const result = rule.validator(configData);
            allErrors.push(...result.errors);
            allWarnings.push(...result.warnings);
            allInfo.push(...result.info);
            rulesExecuted++;
          } catch (error) {
            debug(`Error executing rule ${ruleId}:`, error);

            // Add error for failed rule execution
            allErrors.push({
              id: `rule-error-${ruleId}`,
              ruleId,
              message: `Validation rule execution failed: ${(error as any).message}`,
              field: 'system',
              value: null,
              category: 'required',
            });
          }
        }
      }

      // Calculate overall score
      const errorWeight = 10;
      const warningWeight = 3;
      const infoWeight = 1;
      const totalDeductions =
        allErrors.length * errorWeight +
        allWarnings.length * warningWeight +
        allInfo.length * infoWeight;
      const maxPossibleDeductions = rulesExecuted * errorWeight;
      const score =
        maxPossibleDeductions > 0
          ? Math.max(0, 100 - (totalDeductions / maxPossibleDeductions) * 100)
          : 100;

      return {
        isValid: allErrors.length === 0,
        errors: allErrors,
        warnings: allWarnings,
        info: allInfo,
        score: Math.round(score),
      };
    } catch (error) {
      debug('Error validating configuration data:', error);

      return {
        isValid: false,
        errors: [
          {
            id: 'validation-error',
            ruleId: 'system',
            message: `Validation failed: ${(error as any).message}`,
            field: 'system',
            value: null,
            category: 'required',
          },
        ],
        warnings: [],
        info: [],
        score: 0,
      };
    }
  }

  /**
   * Subscribe to real-time validation for a configuration
   */
  public subscribe(
    configId: number,
    clientId: string,
    profileId = 'standard'
  ): ValidationSubscription {
    const subId = this.getSubscriptionId(configId, clientId);

    let subscription = this.subscriptions.get(subId);
    if (subscription) {
      // Update existing subscription
      subscription.profileId = profileId;
      subscription.isActive = true;
    } else {
      // Create new subscription
      subscription = {
        id: subId,
        configId,
        clientId,
        profileId,
        isActive: true,
        createdAt: new Date(),
      };
      this.subscriptions.set(subId, subscription);
    }

    debug(`Subscribed client ${clientId} to validation for config ${configId}`);

    // Perform initial validation
    this.validateConfiguration(configId, profileId, clientId).catch((error: any) => {
      debug('Error in initial validation for subscription:', error);
    });

    return subscription;
  }

  /**
   * Unsubscribe from real-time validation
   */
  public unsubscribe(configId: number, clientId: string): boolean {
    const subId = this.getSubscriptionId(configId, clientId);
    const removed = this.subscriptions.delete(subId);

    if (removed) {
      debug(`Unsubscribed client ${clientId} from validation for config ${configId}`);
    }

    return removed;
  }

  /**
   * Get validation history
   */
  public getValidationHistory(configId?: number, limit = 50): ValidationReport[] {
    let history = this.validationHistory;

    if (configId) {
      history = history.filter((report) => report.configId === configId);
    }

    return history.slice(0, limit);
  }

  /**
   * Get validation statistics
   */
  public getValidationStatistics(): {
    totalReports: number;
    validReports: number;
    invalidReports: number;
    averageScore: number;
    averageExecutionTime: number;
    rulesCount: number;
    profilesCount: number;
    activeSubscriptions: number;
  } {
    const totalReports = this.validationHistory.length;
    const validReports = this.validationHistory.filter((r) => r.result.isValid).length;
    const invalidReports = totalReports - validReports;

    const averageScore =
      totalReports > 0
        ? this.validationHistory.reduce((sum, r) => sum + r.result.score, 0) / totalReports
        : 0;

    const averageExecutionTime =
      totalReports > 0
        ? this.validationHistory.reduce((sum, r) => sum + r.executionTime, 0) / totalReports
        : 0;

    const activeSubscriptions = Array.from(this.subscriptions.values()).filter(
      (sub) => sub.isActive
    ).length;

    return {
      totalReports,
      validReports,
      invalidReports,
      averageScore: Math.round(averageScore),
      averageExecutionTime: Math.round(averageExecutionTime),
      rulesCount: this.rules.size,
      profilesCount: this.profiles.size,
      activeSubscriptions,
    };
  }

  /**
   * Validate all subscribed configurations
   */
  private async validateSubscribedConfigurations(): Promise<void> {
    const activeSubs = Array.from(this.subscriptions.values()).filter((sub) => sub.isActive);

    for (const sub of activeSubs) {
      try {
        await this.validateConfiguration(sub.configId, sub.profileId, sub.clientId);
      } catch (error) {
        debug(`Error validating subscribed config ${sub.configId}:`, error);
      }
    }
  }

  /**
   * Add report to history
   */
  private addToHistory(report: ValidationReport): void {
    this.validationHistory.unshift(report);

    // Limit history size
    if (this.validationHistory.length > this.maxHistorySize) {
      this.validationHistory = this.validationHistory.slice(0, this.maxHistorySize);
    }
  }

  /**
   * Generate report ID
   */
  private generateReportId(): string {
    return 'val-' + Date.now().toString(36) + '-' + Math.random().toString(36).substr(2, 9);
  }

  /**
   * Get subscription ID
   */
  private getSubscriptionId(configId: number, clientId: string): string {
    return `sub-${configId}-${clientId}`;
  }
}

import type { Server as HttpServer } from 'http';
import os from 'os';
import Debug from 'debug';
import { Server as SocketIOServer } from 'socket.io';
import { BotConfigurationManager } from '../../config/BotConfigurationManager';
import ApiMonitorService, { type EndpointStatus } from '../../services/ApiMonitorService';
import { ActivityLogger } from './ActivityLogger';
import { BotMetricsService } from './BotMetricsService';
import 'reflect-metadata';
import { injectable, singleton } from 'tsyringe';

const debug = Debug('app:WebSocketService');

export interface MessageFlowEvent {
  id: string;
  timestamp: string;
  botName: string;
  provider: string;
  channelId: string;
  userId: string;
  messageType: 'incoming' | 'outgoing';
  contentLength: number;
  processingTime?: number;
  status: 'success' | 'error' | 'timeout';
  errorMessage?: string;
}

interface PerformanceMetric {
  timestamp: string;
  responseTime: number;
  memoryUsage: number;
  cpuUsage: number;
  activeConnections: number;
  messageRate: number;
  errorRate: number;
}

export interface AlertEvent {
  id: string;
  timestamp: string;
  level: 'info' | 'warning' | 'error' | 'critical';
  status: 'active' | 'acknowledged' | 'resolved';
  title: string;
  message: string;
  botName?: string;
  channelId?: string;
  metadata?: Record<string, any>;
  acknowledgedAt?: string;
  resolvedAt?: string;
}

@singleton()
@injectable()
export class WebSocketService {
  private static instance: WebSocketService;
  private io: SocketIOServer | null = null;
  private metricsInterval: NodeJS.Timeout | null = null;
  private connectedClients = 0;

  // Real-time monitoring data
  private messageFlow: MessageFlowEvent[] = [];
  private performanceMetrics: PerformanceMetric[] = [];
  private alerts: AlertEvent[] = [];
  private messageRateHistory: number[] = [];
  private errorRateHistory: number[] = [];
  // internal sampling state
  private lastCpuUsage = process.cpuUsage();
  private lastHrTime = process.hrtime.bigint();
  // per-bot stats
  private botErrors = new Map<string, string[]>();
  // API monitoring
  private apiMonitorService: ApiMonitorService;

  constructor() {
    this.initializeMonitoringData();
    this.apiMonitorService = ApiMonitorService.getInstance();
    this.setupApiMonitoring();
  }

  private initializeMonitoringData(): void {
    // Initialize with empty arrays and default metrics
    this.messageFlow = [];
    this.performanceMetrics = [];
    this.alerts = [];
    this.messageRateHistory = new Array(60).fill(0); // 60 data points for 5-minute history
    this.errorRateHistory = new Array(60).fill(0);
  }

  private setupApiMonitoring(): void {
    // Listen for API monitoring events
    this.apiMonitorService.on('statusUpdate', (status: EndpointStatus) => {
      this.handleApiStatusUpdate(status);
    });

    this.apiMonitorService.on('healthCheckResult', (result) => {
      this.handleApiHealthCheckResult(result);
    });

    // Sync LLM endpoints on startup before starting monitoring
    this.apiMonitorService.syncLlmEndpoints();

    // Start monitoring all configured endpoints
    this.apiMonitorService.startAllMonitoring();
  }

  private handleApiStatusUpdate(status: EndpointStatus): void {
    debug(`API endpoint status update: ${status.name} - ${status.status}`);

    // Broadcast to connected clients
    if (this.io && this.connectedClients > 0) {
      this.io.emit('api_status_update', {
        endpoint: status,
        timestamp: new Date().toISOString(),
      });
    }

    // Create alert for status changes
    if (status.status === 'error' || status.status === 'offline') {
      this.recordAlert({
        level: status.status === 'error' ? 'error' : 'warning',
        title: `API Endpoint ${status.status.toUpperCase()}`,
        message: `${status.name} is ${status.status}: ${status.errorMessage || 'No response'}`,
        metadata: {
          endpointId: status.id,
          url: status.url,
          responseTime: status.responseTime,
          consecutiveFailures: status.consecutiveFailures,
        },
      });
    }
  }

  private handleApiHealthCheckResult(result: any): void {
    debug(
      `API health check result: ${result.endpointId} - ${result.success ? 'success' : 'failed'}`
    );

    // Broadcast health check results to connected clients
    if (this.io && this.connectedClients > 0) {
      this.io.emit('api_health_check_result', {
        result,
        timestamp: new Date().toISOString(),
      });
    }
  }

  public static getInstance(): WebSocketService {
    if (!WebSocketService.instance) {
      WebSocketService.instance = new WebSocketService();
    }
    return WebSocketService.instance;
  }

  // Public methods for external components to report events
  public recordMessageFlow(event: Omit<MessageFlowEvent, 'id' | 'timestamp'>): void {
    const messageEvent: MessageFlowEvent = {
      ...event,
      id: `msg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date().toISOString(),
    };

    this.messageFlow.push(messageEvent);

    // Log to persistent storage
    ActivityLogger.getInstance().log(messageEvent);

    // Per-bot message count
    const key = event.botName || 'unknown';
    BotMetricsService.getInstance().incrementMessageCount(key);

    // Keep only last 1000 messages
    if (this.messageFlow.length > 1000) {
      this.messageFlow = this.messageFlow.slice(-1000);
    }

    // Update message rate
    this.updateMessageRate();

    // Broadcast to connected clients
    if (this.io && this.connectedClients > 0) {
      this.io.emit('message_flow_update', messageEvent);
    }
  }

  public recordAlert(
    alert: Omit<AlertEvent, 'id' | 'timestamp' | 'status' | 'acknowledgedAt' | 'resolvedAt'>
  ): void {
    const alertEvent: AlertEvent = {
      ...alert,
      id: `alert_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date().toISOString(),
      status: 'active',
    };

    this.alerts.push(alertEvent);

    // Per-bot error tracking (cap at 20 per bot)
    const key = alertEvent.botName || 'unknown';
    const list = this.botErrors.get(key) || [];
    list.push(`${alertEvent.level}: ${alertEvent.title}`);
    if (list.length > 20) {
      list.shift();
    }
    this.botErrors.set(key, list);

    // Keep only last 500 alerts
    if (this.alerts.length > 500) {
      this.alerts = this.alerts.slice(-500);
    }

    // Update error rate if this is an error
    if (alert.level === 'error' || alert.level === 'critical') {
      this.updateErrorRate();
      const key = alertEvent.botName || 'unknown';
      BotMetricsService.getInstance().incrementErrorCount(key);
    }

    // Broadcast to connected clients
    if (this.io && this.connectedClients > 0) {
      this.io.emit('alert_update', alertEvent);
    }
  }

  public getMessageFlow(limit = 100): MessageFlowEvent[] {
    return this.messageFlow.slice(-limit);
  }

  public getAlerts(limit = 50): AlertEvent[] {
    return this.alerts.slice(-limit);
  }

  public acknowledgeAlert(id: string): boolean {
    const alert = this.alerts.find((a) => a.id === id);
    if (alert) {
      alert.status = 'acknowledged';
      alert.acknowledgedAt = new Date().toISOString();

      // Broadcast to connected clients
      if (this.io && this.connectedClients > 0) {
        this.io.emit('alert_update', alert);
      }
      return true;
    }
    return false;
  }

  public resolveAlert(id: string): boolean {
    const alert = this.alerts.find((a) => a.id === id);
    if (alert) {
      alert.status = 'resolved';
      alert.resolvedAt = new Date().toISOString();

      // Broadcast to connected clients
      if (this.io && this.connectedClients > 0) {
        this.io.emit('alert_update', alert);
      }
      return true;
    }
    return false;
  }

  public getPerformanceMetrics(limit = 60): PerformanceMetric[] {
    return this.performanceMetrics.slice(-limit);
  }

  public getMessageRateHistory(): number[] {
    return [...this.messageRateHistory];
  }

  public getErrorRateHistory(): number[] {
    return [...this.errorRateHistory];
  }

  public getBotStats(botName: string): {
    messageCount: number;
    errors: string[];
    errorCount: number;
  } {
    const metrics = BotMetricsService.getInstance().getMetrics(botName);
    return {
      messageCount: metrics.messageCount,
      errors: [...(this.botErrors.get(botName) || [])],
      errorCount: metrics.errorCount,
    };
  }

  // prettier-ignore
  public getAllBotStats(): Record<string, { messageCount: number; errors: string[]; errorCount: number }> {
    const metricsService = BotMetricsService.getInstance();
    const allMetrics = metricsService.getAllMetrics();
    const out: Record<string, { messageCount: number; errors: string[]; errorCount: number }> = {};

    // Merge in-memory errors with persistent metrics
    const botNames = new Set([...this.botErrors.keys(), ...Object.keys(allMetrics)]);

    for (const name of botNames) {
      const metrics = metricsService.getMetrics(name);
      out[name] = {
        messageCount: metrics.messageCount,
        errors: [...(this.botErrors.get(name) || [])],
        errorCount: metrics.errorCount,
      };
    }
    return out;
  }

  private updateMessageRate(): void {
    const now = new Date();
    const oneMinuteAgo = new Date(now.getTime() - 60000);

    const recentMessages = this.messageFlow.filter(
      (event) => new Date(event.timestamp) > oneMinuteAgo
    );

    const currentRate = recentMessages.length;
    this.messageRateHistory.push(currentRate);
    this.messageRateHistory.shift(); // Remove oldest
  }

  private updateErrorRate(): void {
    const now = new Date();
    const oneMinuteAgo = new Date(now.getTime() - 60000);

    const recentErrors = this.alerts.filter(
      (alert) =>
        (alert.level === 'error' || alert.level === 'critical') &&
        new Date(alert.timestamp) > oneMinuteAgo
    );

    const currentRate = recentErrors.length;
    this.errorRateHistory.push(currentRate);
    this.errorRateHistory.shift(); // Remove oldest
  }

  public initialize(server: HttpServer): void {
    try {
      debug('Initializing WebSocket service...');
      if (!server) {
        debug('ERROR: HTTP server is required for WebSocket initialization');
        throw new Error('HTTP server is required for WebSocket initialization');
      }

      this.io = new SocketIOServer(server, {
        path: '/webui/socket.io',
        cors: {
          origin: [
            /^https?:\/\/localhost(:\d+)?/,
            /^https?:\/\/127\.0\.0\.1(:\d+)?/,
            /^https:\/\/.*\.netlify\.app$/,
            /^https:\/\/.*\.netlify\.com$/,
            /^https:\/\/.*\.fly\.dev$/,
          ],
          methods: ['GET', 'POST'],
          credentials: true,
          allowedHeaders: [
            'Origin',
            'X-Requested-With',
            'Content-Type',
            'Accept',
            'Authorization',
            'Cache-Control',
            'X-CSRF-Token',
          ],
        },
      });

      this.setupEventHandlers();
      this.startMetricsCollection();
      debug('WebSocket service initialized successfully with CORS enabled');
    } catch (error: any) {
      debug('CRITICAL: Failed to initialize WebSocket service:', {
        error: error.message,
        stack: error.stack,
        serverProvided: !!server,
      });
      throw new Error(`WebSocket service initialization failed: ${error.message}`);
    }
  }

  /**
   * Sets up WebSocket event handlers for client connections
   * Handles connection, disconnection, and various client requests
   */
  private setupEventHandlers(): void {
    if (!this.io) {
      return;
    }

    this.io.on('connection', (socket) => {
      this.connectedClients++;
      debug(`Client connected. Total clients: ${this.connectedClients}`);

      // Send initial data
      this.sendBotStatus(socket);
      this.sendSystemMetrics(socket);

      socket.on('request_bot_status', () => {
        this.sendBotStatus(socket);
      });

      socket.on('request_system_metrics', () => {
        this.sendSystemMetrics(socket);
      });

      socket.on('request_config_validation', () => {
        this.sendConfigValidation(socket);
      });

      socket.on('request_message_flow', () => {
        this.sendMessageFlow(socket);
      });

      socket.on('request_alerts', () => {
        this.sendAlerts(socket);
      });

      socket.on('request_performance_metrics', () => {
        this.sendPerformanceMetrics(socket);
      });

      socket.on('request_monitoring_dashboard', () => {
        this.sendMonitoringDashboard(socket);
      });

      socket.on('request_api_status', () => {
        this.sendApiStatus(socket);
      });

      socket.on('request_api_endpoints', () => {
        this.sendApiEndpoints(socket);
      });

      socket.on('disconnect', () => {
        this.connectedClients--;
        debug(`Client disconnected. Total clients: ${this.connectedClients}`);
        // Clean up event listeners to prevent memory leaks
        socket.removeAllListeners();
      });
    });
  }

  /**
   * Starts periodic metrics collection and broadcasting
   * Sends bot status and system metrics updates every 5 seconds to connected clients
   */
  private startMetricsCollection(): void {
    // Send updates every 5 seconds to connected clients
    this.metricsInterval = setInterval(() => {
      if (this.connectedClients > 0) {
        this.broadcastBotStatus();
        this.broadcastSystemMetrics();
        this.broadcastMonitoringData();
      }
    }, 5000);
  }

  private broadcastMonitoringData(): void {
    if (!this.io) {
      return;
    }

    // Broadcast message flow updates
    if (this.messageFlow.length > 0) {
      this.io.emit('message_flow_broadcast', {
        latest: this.messageFlow.slice(-5), // Last 5 messages
        total: this.messageFlow.length,
        timestamp: new Date().toISOString(),
      });
    }

    // Broadcast alert updates
    if (this.alerts.length > 0) {
      const recentAlerts = this.alerts.filter(
        (alert) => new Date(alert.timestamp) > new Date(Date.now() - 30000) // Last 30 seconds
      );
      if (recentAlerts.length > 0) {
        this.io.emit('alerts_broadcast', {
          alerts: recentAlerts,
          timestamp: new Date().toISOString(),
        });
      }
    }

    // Broadcast performance metrics
    this.io.emit('performance_metrics_broadcast', {
      current: {
        memoryUsage: Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
        messageRate: this.messageRateHistory[this.messageRateHistory.length - 1] || 0,
        errorRate: this.errorRateHistory[this.errorRateHistory.length - 1] || 0,
        activeConnections: this.connectedClients,
      },
      timestamp: new Date().toISOString(),
    });

    // Broadcast compact per-bot stats (message counts and error counts)
    try {
      const statsObj = this.getAllBotStats();
      const stats = Object.entries(statsObj).map(([name, s]) => ({
        name,
        messageCount: s.messageCount,
        errorCount: s.errorCount,
      }));
      this.io.emit('bot_stats_broadcast', {
        stats,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error broadcasting bot stats:', error);
    }
  }

  private sendBotStatus(socket: any): void {
    try {
      const manager = BotConfigurationManager.getInstance();
      const bots = manager.getAllBots();

      const status = bots.map((bot) => {
        const hasProviderSecret = !!(
          bot.discord?.token ||
          bot.slack?.botToken ||
          bot.mattermost?.token
        );
        const botStatus = hasProviderSecret ? 'active' : 'inactive';
        return {
          name: bot.name,
          provider: bot.messageProvider,
          llmProvider: bot.llmProvider,
          status: botStatus,
          lastSeen: new Date().toISOString(),
          capabilities: {
            voiceSupport: !!bot.discord?.voiceChannelId,
            multiChannel: bot.messageProvider === 'slack' && !!bot.slack?.joinChannels,
            hasSecrets: !!(bot.discord?.token || bot.slack?.botToken || bot.openai?.apiKey),
          },
        };
      });

      socket.emit('bot_status_update', {
        bots: status,
        timestamp: new Date().toISOString(),
        total: bots.length,
        active: status.filter((s) => s.status === 'active').length,
      });
    } catch (error) {
      debug('Error sending bot status:', error);
      socket.emit('error', { message: 'Failed to get bot status' });
    }
  }

  private sendSystemMetrics(socket: any): void {
    try {
      const memUsage = process.memoryUsage();
      const metrics = {
        uptime: process.uptime(),
        memory: {
          used: Math.round(memUsage.heapUsed / 1024 / 1024), // MB
          total: Math.round(memUsage.heapTotal / 1024 / 1024), // MB
          external: Math.round(memUsage.external / 1024 / 1024), // MB
          rss: Math.round(memUsage.rss / 1024 / 1024), // MB
        },
        cpu: {
          usage: process.cpuUsage(),
        },
        connectedClients: this.connectedClients,
        timestamp: new Date().toISOString(),
      };

      socket.emit('system_metrics_update', metrics);
    } catch (error) {
      debug('Error sending system metrics:', error);
      socket.emit('error', { message: 'Failed to get system metrics' });
    }
  }

  private sendConfigValidation(socket: any): void {
    try {
      const manager = BotConfigurationManager.getInstance();
      const bots = manager.getAllBots();
      const warnings = manager.getWarnings();

      const validation = {
        isValid: warnings.length === 0,
        warnings,
        botCount: bots.length,
        missingConfigs: this.findMissingConfigurations(bots),
        recommendations: this.generateRecommendations(bots),
        timestamp: new Date().toISOString(),
      };

      socket.emit('config_validation_update', validation);
    } catch (error) {
      debug('Error sending config validation:', error);
      socket.emit('error', { message: 'Failed to validate configuration' });
    }
  }

  private findMissingConfigurations(bots: any[]): string[] {
    const missing: string[] = [];

    bots.forEach((bot) => {
      if (bot.messageProvider === 'discord' && !bot.discord?.token) {
        missing.push(`${bot.name}: Missing Discord bot token`);
      }
      if (bot.messageProvider === 'slack' && !bot.slack?.botToken) {
        missing.push(`${bot.name}: Missing Slack bot token`);
      }
      if (bot.llmProvider === 'openai' && !bot.openai?.apiKey) {
        missing.push(`${bot.name}: Missing OpenAI API key`);
      }
      if (bot.llmProvider === 'flowise' && !bot.flowise?.apiKey) {
        missing.push(`${bot.name}: Missing Flowise API key`);
      }
    });

    return missing;
  }

  private generateRecommendations(bots: any[]): string[] {
    const recommendations: string[] = [];

    if (bots.length === 0) {
      recommendations.push('No bots configured. Add at least one bot to get started.');
    }

    const providers = new Set(bots.map((b) => b.messageProvider));
    if (providers.size === 1 && providers.has('discord')) {
      recommendations.push('Consider adding Slack integration for broader platform support.');
    }

    const llmProviders = new Set(bots.map((b) => b.llmProvider));
    if (llmProviders.size === 1) {
      recommendations.push('Consider configuring multiple LLM providers for redundancy.');
    }

    return recommendations;
  }

  private broadcastBotStatus(): void {
    if (!this.io) {
      return;
    }
    this.io.emit('bot_status_broadcast', { timestamp: new Date().toISOString() });
  }

  private broadcastSystemMetrics(): void {
    if (!this.io) {
      return;
    }
    this.io.sockets.sockets.forEach((socket) => {
      this.sendSystemMetrics(socket);
    });
  }

  public broadcastConfigChange(): void {
    if (!this.io) {
      return;
    }
    debug('Broadcasting configuration change');
    this.io.emit('config_changed', { timestamp: new Date().toISOString() });

    // Send updated data to all clients
    this.io.sockets.sockets.forEach((socket) => {
      this.sendBotStatus(socket);
      this.sendConfigValidation(socket);
    });
  }

  private sendMessageFlow(socket: any): void {
    try {
      const messageFlow = this.getMessageFlow(50); // Last 50 messages
      socket.emit('message_flow_update', {
        messages: messageFlow,
        total: this.messageFlow.length,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error sending message flow:', error);
      socket.emit('error', { message: 'Failed to get message flow' });
    }
  }

  private sendAlerts(socket: any): void {
    try {
      const alerts = this.getAlerts(20); // Last 20 alerts
      socket.emit('alerts_update', {
        alerts,
        total: this.alerts.length,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error sending alerts:', error);
      socket.emit('error', { message: 'Failed to get alerts' });
    }
  }

  private sendPerformanceMetrics(socket: any): void {
    try {
      const metrics = this.getPerformanceMetrics(30); // Last 30 data points

      // Compute CPU usage percentage since last sample
      const nowHr = process.hrtime.bigint();
      const elapsedNs = Number(nowHr - this.lastHrTime);
      const elapsedMs = elapsedNs / 1_000_000;
      const currentCpu = process.cpuUsage(this.lastCpuUsage);
      const totalCpuMicros = currentCpu.user + currentCpu.system;
      const cpuCores = Math.max(1, os.cpus()?.length || 1);
      // percent of a single core, normalized by core count
      const cpuPercent =
        elapsedMs > 0
          ? Math.min(100, Math.max(0, (totalCpuMicros / (elapsedMs * 1000)) * (100 / cpuCores)))
          : 0;
      this.lastCpuUsage = process.cpuUsage();
      this.lastHrTime = nowHr;

      // Approximate response time as average processingTime of last 10 message events (if present)
      const recentWithTimes = this.messageFlow
        .slice(-20)
        .map((m) => m.processingTime)
        .filter((t): t is number => typeof t === 'number' && isFinite(t));
      const avgResponse = recentWithTimes.length
        ? Math.round(recentWithTimes.reduce((a, b) => a + b, 0) / recentWithTimes.length)
        : 0;

      const currentMetric: PerformanceMetric = {
        timestamp: new Date().toISOString(),
        responseTime: avgResponse,
        memoryUsage: Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
        cpuUsage: Math.round(cpuPercent),
        activeConnections: this.connectedClients,
        messageRate: this.messageRateHistory[this.messageRateHistory.length - 1] || 0,
        errorRate: this.errorRateHistory[this.errorRateHistory.length - 1] || 0,
      };

      this.performanceMetrics.push(currentMetric);
      if (this.performanceMetrics.length > 100) {
        this.performanceMetrics = this.performanceMetrics.slice(-100);
      }

      socket.emit('performance_metrics_update', {
        metrics: [...metrics, currentMetric],
        current: currentMetric,
        history: {
          messageRate: this.getMessageRateHistory(),
          errorRate: this.getErrorRateHistory(),
        },
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error sending performance metrics:', error);
      socket.emit('error', { message: 'Failed to get performance metrics' });
    }
  }

  private sendMonitoringDashboard(socket: any): void {
    try {
      const manager = BotConfigurationManager.getInstance();
      const bots = manager.getAllBots();
      const totalBots = bots.length;
      const activeBots = totalBots; // without runtime signals, assume all configured are active
      const dashboard = {
        summary: {
          totalBots,
          activeBots,
          totalMessages: this.messageFlow.length,
          totalAlerts: this.alerts.length,
          uptime: process.uptime(),
          connectedClients: this.connectedClients,
        },
        recentActivity: {
          messages: this.getMessageFlow(10),
          alerts: this.getAlerts(5),
        },
        performance: {
          current: {
            memoryUsage: Math.round(process.memoryUsage().heapUsed / 1024 / 1024),
            messageRate: this.messageRateHistory[this.messageRateHistory.length - 1] || 0,
            errorRate: this.errorRateHistory[this.errorRateHistory.length - 1] || 0,
          },
          history: {
            messageRate: this.getMessageRateHistory(),
            errorRate: this.getErrorRateHistory(),
          },
        },
        timestamp: new Date().toISOString(),
      };

      socket.emit('monitoring_dashboard_update', dashboard);
    } catch (error) {
      debug('Error sending monitoring dashboard:', error);
      socket.emit('error', { message: 'Failed to get monitoring dashboard' });
    }
  }

  private sendApiStatus(socket: any): void {
    try {
      const statuses = this.apiMonitorService.getAllStatuses();
      const overallHealth = this.apiMonitorService.getOverallHealth();

      socket.emit('api_status_update', {
        endpoints: statuses,
        overall: overallHealth,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error sending API status:', error);
      socket.emit('error', { message: 'Failed to get API status' });
    }
  }

  private sendApiEndpoints(socket: any): void {
    try {
      const endpoints = this.apiMonitorService.getAllEndpoints();

      socket.emit('api_endpoints_update', {
        endpoints,
        timestamp: new Date().toISOString(),
      });
    } catch (error) {
      debug('Error sending API endpoints:', error);
      socket.emit('error', { message: 'Failed to get API endpoints' });
    }
  }

  public shutdown(): void {
    if (this.metricsInterval) {
      clearInterval(this.metricsInterval);
      this.metricsInterval = null;
    }

    if (this.io) {
      try {
        // Proactively disconnect sockets without touching the underlying HTTP server
        try {
          this.io.sockets.sockets.forEach((socket) => {
            try {
              socket.disconnect(true);
            } catch {
              /* ignore */
            }
          });
        } catch {
          /* ignore */
        }
        // Remove listeners to avoid emitting errors on the shared HTTP server
        this.io.removeAllListeners();
        // Avoid calling close() to prevent 'Server is not running' errors in certain environments
      } catch (error) {
        debug('Error during WebSocket shutdown:', error);
      }
      this.io = null;
    }

    // Clean up per-bot statistics to prevent memory leaks
    this.botErrors.clear();

    debug('WebSocket service shut down');
  }
}

export default WebSocketService;

import { promises as fs } from 'fs';
import { join } from 'path';
import Debug from 'debug';
import { ErrorUtils } from '../../types/errors';

const debug = Debug('app:fileConfigUtils');

// Ensure data directory exists
export const ensureDataDir = async () => {
  const dataDir = join(process.cwd(), 'data');
  try {
    await fs.mkdir(dataDir, { recursive: true });
  } catch (error: unknown) {
    const hivemindError = ErrorUtils.toHivemindError(error) as any;
    debug('Error creating data directory:', hivemindError.message);
  }
};

// Load configurations
export const loadJsonConfig = async <T>(
  filePath: string,
  defaultValue: T,
  debugInstance = debug
): Promise<T> => {
  try {
    const data = await fs.readFile(filePath, 'utf8');
    return JSON.parse(data);
  } catch (error: unknown) {
    const hivemindError = ErrorUtils.toHivemindError(error) as any;
    debugInstance(`Config file ${filePath} not found, using defaults:`, hivemindError.message);
    return defaultValue;
  }
};

// Save configurations
export const saveJsonConfig = async <T>(filePath: string, data: T): Promise<void> => {
  await ensureDataDir();
  await fs.writeFile(filePath, JSON.stringify(data, null, 2));
};

import { type Response } from 'express';
import { ErrorUtils } from '../../types/errors';

export const handleRouteError = (
  error: unknown,
  res: Response,
  debugInstance: any,
  debugMessage: string,
  defaultErrorCode: string,
  includeSuccess = false
) => {
  const hivemindError = ErrorUtils.toHivemindError(error) as any;
  const errorInfo = ErrorUtils.classifyError(hivemindError);

  debugInstance(debugMessage, {
    message: hivemindError.message,
    code: hivemindError.code,
    type: errorInfo.type,
    severity: errorInfo.severity,
  });

  const responseBody: any = {
    error: hivemindError.message,
    code: hivemindError.code || defaultErrorCode,
    timestamp: new Date().toISOString(),
  };

  if (includeSuccess) {
    responseBody.success = false;
  }

  return res.status(hivemindError.statusCode || 500).json(responseBody);
};

import { EventEmitter } from 'events';
import Debug from 'debug';
import type { Response } from 'node-fetch';
import { webUIStorage } from '../storage/webUIStorage';
import 'reflect-metadata';
import { injectable, singleton } from 'tsyringe';

const debug = Debug('app:ApiMonitorService');

type FetchImplementation = (input: any, init?: any) => Promise<Response>;

const resolveFetch = async (): Promise<FetchImplementation> => {
  if (typeof fetch === 'function') {
    return fetch as unknown as FetchImplementation;
  }

  const { default: nodeFetch } = await import('node-fetch');
  return nodeFetch as unknown as FetchImplementation;
};

export interface EndpointConfig {
  id: string;
  name: string;
  url: string;
  method: 'GET' | 'POST' | 'PUT' | 'DELETE' | 'HEAD';
  headers?: Record<string, string>;
  body?: any;
  expectedStatusCodes?: number[];
  timeout?: number;
  interval?: number;
  enabled: boolean;
  retries?: number;
  retryDelay?: number;
}

export interface EndpointStatus {
  id: string;
  name: string;
  url: string;
  status: 'online' | 'offline' | 'slow' | 'error';
  responseTime: number;
  lastChecked: Date;
  lastSuccessfulCheck?: Date;
  consecutiveFailures: number;
  totalChecks: number;
  successfulChecks: number;
  averageResponseTime: number;
  errorMessage?: string;
  statusCode?: number;
  sslExpiry?: Date;
  sslValid?: boolean;
}

export interface HealthCheckResult {
  endpointId: string;
  timestamp: Date;
  success: boolean;
  responseTime: number;
  statusCode?: number;
  errorMessage?: string;
}

@singleton()
@injectable()
export class ApiMonitorService extends EventEmitter {
  private static instance: ApiMonitorService;
  private endpoints = new Map<string, EndpointConfig>();
  private statuses = new Map<string, EndpointStatus>();
  private monitoringIntervals = new Map<string, NodeJS.Timeout>();
  private isMonitoring = false;

  constructor() {
    super();
    // Increase max listeners for monitoring service
    this.setMaxListeners(20);
  }

  public static getInstance(): ApiMonitorService {
    if (!ApiMonitorService.instance) {
      ApiMonitorService.instance = new ApiMonitorService();
    }
    return ApiMonitorService.instance;
  }

  public addEndpoint(config: EndpointConfig): void {
    this.endpoints.set(config.id, config);
    this.initializeEndpointStatus(config);
    debug(`Added endpoint: ${config.name} (${config.url})`);

    if (config.enabled && config.interval) {
      this.startMonitoring(config.id);
    }
  }

  public removeEndpoint(id: string): void {
    this.stopMonitoring(id);
    this.endpoints.delete(id);
    this.statuses.delete(id);
    debug(`Removed endpoint: ${id}`);
  }

  public updateEndpoint(id: string, config: Partial<EndpointConfig>): void {
    const existing = this.endpoints.get(id);
    if (!existing) {
      throw new Error(`Endpoint ${id} not found`);
    }

    const updatedConfig = { ...existing, ...config };
    this.endpoints.set(id, updatedConfig);

    // Restart monitoring if needed
    this.stopMonitoring(id);
    if (updatedConfig.enabled && updatedConfig.interval) {
      this.startMonitoring(id);
    }

    debug(`Updated endpoint: ${id}`);
  }

  public getEndpoint(id: string): EndpointConfig | undefined {
    return this.endpoints.get(id);
  }

  public getAllEndpoints(): EndpointConfig[] {
    return Array.from(this.endpoints.values());
  }

  public getEndpointStatus(id: string): EndpointStatus | undefined {
    return this.statuses.get(id);
  }

  public getAllStatuses(): EndpointStatus[] {
    return Array.from(this.statuses.values());
  }

  public syncLlmEndpoints(): void {
    try {
      const providers = webUIStorage.getLlmProviders();
      const currentLlmIds = new Set<string>();

      if (Array.isArray(providers)) {
        providers.forEach((provider: any) => {
          if (!provider.isActive) return;

          let url = '';
          if (provider.config && provider.config.baseUrl) {
            url = provider.config.baseUrl.replace(/\/$/, '') + '/v1/models';
          } else if (provider.type === 'openai') {
            url = 'https://api.openai.com/v1/models';
          } else {
            return; // Skip if no URL can be constructed safely
          }

          if (url && !url.startsWith('http')) {
            return;
          }

          const endpointId = `llm-${provider.id || provider.type}`;
          currentLlmIds.add(endpointId);

          const config: EndpointConfig = {
            id: endpointId,
            name: `${provider.name || provider.type} (LLM)`,
            url: url,
            method: 'GET',
            enabled: true,
            interval: 60000,
            timeout: 10000,
            retries: 3,
            retryDelay: 1000,
          };

          // Note: API keys are used for health check requests but are never exposed
          // in the `/health/api-endpoints` response, as `getAllStatuses()` returns
          // `EndpointStatus`, not `EndpointConfig`.
          if (provider.config && provider.config.apiKey) {
            config.headers = {
              Authorization: `Bearer ${provider.config.apiKey}`,
            };
          }

          if (!this.endpoints.has(endpointId)) {
            this.addEndpoint(config);
          } else {
            const existing = this.endpoints.get(endpointId);
            // Only update if url or key changes to avoid resetting intervals unnecessarily
            if (
              existing &&
              (existing.url !== config.url ||
                existing.headers?.Authorization !== config.headers?.Authorization)
            ) {
              this.updateEndpoint(endpointId, config);
            }
          }
        });
      }

      // Clean up deleted or deactivated providers
      Array.from(this.endpoints.keys()).forEach((key) => {
        if (key.startsWith('llm-') && !currentLlmIds.has(key)) {
          this.removeEndpoint(key);
        }
      });
    } catch (e) {
      debug('Error syncing LLM endpoints:', e);
    }
  }

  public startMonitoring(id: string): void {
    const config = this.endpoints.get(id);
    if (!config || !config.enabled || !config.interval) {
      return;
    }

    this.stopMonitoring(id);

    const interval = setInterval(() => {
      this.checkEndpoint(id);
    }, config.interval);

    this.monitoringIntervals.set(id, interval);
    debug(`Started monitoring: ${config.name}`);
  }

  public stopMonitoring(id: string): void {
    const interval = this.monitoringIntervals.get(id);
    if (interval) {
      clearInterval(interval);
      this.monitoringIntervals.delete(id);
      debug(`Stopped monitoring: ${id}`);
    }
  }

  public startAllMonitoring(): void {
    if (this.isMonitoring) {
      return;
    }

    this.endpoints.forEach((config, id) => {
      if (config.enabled && config.interval) {
        this.startMonitoring(id);
      }
    });

    this.isMonitoring = true;
    debug('Started monitoring all endpoints');
  }

  public stopAllMonitoring(): void {
    this.monitoringIntervals.forEach((interval, id) => {
      clearInterval(interval);
    });
    this.monitoringIntervals.clear();
    this.isMonitoring = false;
    debug('Stopped monitoring all endpoints');
  }

  /**
   * Clean up resources, particularly stopping all intervals.
   */
  public shutdown(): void {
    this.stopAllMonitoring();
    this.removeAllListeners();
    debug('ApiMonitorService shutdown completed');
  }

  private initializeEndpointStatus(config: EndpointConfig): void {
    const status: EndpointStatus = {
      id: config.id,
      name: config.name,
      url: config.url,
      status: 'offline',
      responseTime: 0,
      lastChecked: new Date(),
      consecutiveFailures: 0,
      totalChecks: 0,
      successfulChecks: 0,
      averageResponseTime: 0,
    };

    this.statuses.set(config.id, status);
  }

  private async checkEndpoint(id: string): Promise<void> {
    const config = this.endpoints.get(id);
    const status = this.statuses.get(id);

    if (!config || !status) {
      return;
    }

    const startTime = Date.now();
    status.lastChecked = new Date();

    try {
      const response = await this.performRequest(config);
      const responseTime = Date.now() - startTime;

      status.responseTime = responseTime;
      status.statusCode = response.status;
      status.totalChecks++;

      if (this.isSuccessfulResponse(config, response)) {
        status.status = this.getStatusFromResponseTime(responseTime);
        status.consecutiveFailures = 0;
        status.successfulChecks++;
        status.lastSuccessfulCheck = new Date();
        status.errorMessage = undefined;

        // Update average response time
        status.averageResponseTime =
          (status.averageResponseTime * (status.successfulChecks - 1) + responseTime) /
          status.successfulChecks;
      } else {
        throw new Error(`HTTP ${response.status}: ${response.statusText}`);
      }
    } catch (error) {
      const responseTime = Date.now() - startTime;
      status.responseTime = responseTime;
      status.status = 'error';
      status.consecutiveFailures++;
      status.totalChecks++;
      status.errorMessage = error instanceof Error ? error.message : 'Unknown error';

      debug(`Endpoint check failed: ${config.name} - ${status.errorMessage}`);
    }

    // Emit status update
    this.emit('statusUpdate', status);

    // Emit health check result for logging
    const result: HealthCheckResult = {
      endpointId: id,
      timestamp: status.lastChecked,
      success: status.status === 'online' || status.status === 'slow',
      responseTime: status.responseTime,
      statusCode: status.statusCode,
      errorMessage: status.errorMessage,
    };

    this.emit('healthCheckResult', result);
  }

  private async performRequest(config: EndpointConfig): Promise<any> {
    const controller = new AbortController();
    const timeoutId = setTimeout(() => controller.abort(), config.timeout || 10000);

    try {
      const fetchImpl = await resolveFetch();
      const response = await fetchImpl(config.url, {
        method: config.method,
        headers: {
          'User-Agent': 'Open-Hivemind API Monitor',
          ...config.headers,
        },
        body: config.body ? JSON.stringify(config.body) : undefined,
        signal: controller.signal,
      });

      clearTimeout(timeoutId);
      return response;
    } catch (error) {
      clearTimeout(timeoutId);
      throw error;
    }
  }

  private isSuccessfulResponse(config: EndpointConfig, response: Response): boolean {
    const expectedCodes = config.expectedStatusCodes || [200, 201, 202, 204];
    return expectedCodes.includes(response.status);
  }

  private getStatusFromResponseTime(responseTime: number): 'online' | 'slow' {
    return responseTime > 5000 ? 'slow' : 'online'; // 5 seconds threshold
  }

  public getOverallHealth(): {
    status: 'healthy' | 'warning' | 'error';
    message: string;
    stats: {
      total: number;
      online: number;
      slow: number;
      offline: number;
      error: number;
    };
  } {
    const statuses = Array.from(this.statuses.values());
    const stats = {
      total: statuses.length,
      online: 0,
      slow: 0,
      offline: 0,
      error: 0,
    };

    statuses.forEach((status) => {
      switch (status.status) {
        case 'online':
          stats.online++;
          break;
        case 'slow':
          stats.slow++;
          break;
        case 'offline':
          stats.offline++;
          break;
        case 'error':
          stats.error++;
          break;
      }
    });

    let overallStatus: 'healthy' | 'warning' | 'error' = 'healthy';
    let message = 'All monitored APIs are operational';

    if (stats.error > 0) {
      overallStatus = 'error';
      message = `${stats.error} API endpoint(s) are experiencing errors`;
    } else if (stats.offline > 0) {
      overallStatus = 'error';
      message = `${stats.offline} API endpoint(s) are offline`;
    } else if (stats.slow > 0) {
      overallStatus = 'warning';
      message = `${stats.slow} API endpoint(s) are responding slowly`;
    }

    return { status: overallStatus, message, stats };
  }
}

