/**
 * DemoModeService - Manages demo/simulation mode when no configuration is provided
 *
 * This service detects when the application is running without proper configuration
 * and provides a simulated environment for demonstration purposes.
 */

import Debug from 'debug';
import { BotConfigurationManager } from '../config/BotConfigurationManager';
import { UserConfigStore } from '../config/UserConfigStore';

const debug = Debug('app:DemoModeService');

export interface DemoBot {
  id: string;
  name: string;
  messageProvider: 'discord' | 'slack' | 'mattermost';
  llmProvider: 'openai' | 'flowise' | 'openwebui';
  persona: string;
  systemInstruction: string;
  status: 'active' | 'idle' | 'demo';
  connected: boolean;
  isDemo: true;
  discord?: {
    channelId: string;
    guildId: string;
  };
  slack?: {
    channelId: string;
    teamId: string;
  };
}

export interface DemoMessage {
  id: string;
  timestamp: string;
  botName: string;
  channelId: string;
  userId: string;
  userName: string;
  content: string;
  type: 'incoming' | 'outgoing';
  isDemo: true;
}

export interface DemoConversation {
  id: string;
  channelId: string;
  botName: string;
  messages: DemoMessage[];
  createdAt: string;
  updatedAt: string;
}

/**
 * DemoModeService Singleton
 *
 * Detects and manages demo mode operation
 */
export class DemoModeService {
  private static instance: DemoModeService | null = null;
  private isDemoMode = false;
  private demoBots: DemoBot[] = [];
  private conversations = new Map<string, DemoConversation>();
  private userConfigStore = UserConfigStore.getInstance();

  private constructor() {
    debug('DemoModeService constructed');
  }

  /**
   * Get singleton instance
   */
  public static getInstance(): DemoModeService {
    if (!DemoModeService.instance) {
      DemoModeService.instance = new DemoModeService();
    }
    return DemoModeService.instance;
  }

  /**
   * Check if demo mode should be activated
   * Demo mode is activated when:
   * - No bots are configured via environment or config files
   * - No API keys are provided for LLM providers
   * - No messenger tokens are provided
   */
  public detectDemoMode(): boolean {
    // Check if explicitly enabled via environment
    if (process.env.DEMO_MODE === 'true') {
      debug('Demo mode explicitly enabled via DEMO_MODE=true');
      return true;
    }

    // Check if explicitly disabled
    if (process.env.DEMO_MODE === 'false') {
      debug('Demo mode explicitly disabled via DEMO_MODE=false');
      return false;
    }

    // Check for existing bot configuration
    const botManager = BotConfigurationManager.getInstance();
    const bots = botManager.getAllBots();
    const warnings = botManager.getWarnings();

    // If there are bots configured, not in demo mode
    if (bots.length > 0) {
      // But check if any have actual credentials
      const hasRealCredentials = bots.some((bot) => {
        // Check for Discord token
        if (bot.discord?.token && bot.discord.token.length > 10) {
          return true;
        }
        // Check for Slack token
        if (bot.slack?.botToken && bot.slack.botToken.length > 10) {
          return true;
        }
        // Check for Mattermost token
        if ((bot as any).mattermost?.token && (bot as any).mattermost.token.length > 10) {
          return true;
        }
        // Check for OpenAI key
        if (bot.openai?.apiKey && bot.openai.apiKey.length > 10) {
          return true;
        }
        // Check for Flowise key
        if (bot.flowise?.apiKey && bot.flowise.apiKey.length > 10) {
          return true;
        }
        return false;
      });

      if (hasRealCredentials) {
        debug('Real credentials found, demo mode disabled');
        return false;
      }
    }

    // Check for warning about no configuration
    const hasNoConfigWarning = warnings.some(
      (w) =>
        w.toLowerCase().includes('no bot configuration') ||
        w.toLowerCase().includes('no configuration')
    );

    // Check for critical environment variables
    const hasDiscordToken =
      process.env.DISCORD_BOT_TOKEN && process.env.DISCORD_BOT_TOKEN.length > 10;
    const hasSlackToken = process.env.SLACK_BOT_TOKEN && process.env.SLACK_BOT_TOKEN.length > 10;
    const hasOpenAIKey = process.env.OPENAI_API_KEY && process.env.OPENAI_API_KEY.length > 10;
    const hasFlowiseKey = process.env.FLOWISE_API_KEY && process.env.FLOWISE_API_KEY.length > 10;

    // If no critical credentials are found and no bots configured, enable demo mode
    if (!hasDiscordToken && !hasSlackToken && !hasOpenAIKey && !hasFlowiseKey) {
      if (bots.length === 0 || hasNoConfigWarning) {
        debug('No credentials or configuration found, enabling demo mode');
        return true;
      }
    }

    return false;
  }

  /**
   * Initialize demo mode
   */
  public initialize(): void {
    this.isDemoMode = this.detectDemoMode();

    if (this.isDemoMode) {
      this.createDemoBots();
      debug('Demo mode initialized with %d demo bots', this.demoBots.length);
    }
  }

  /**
   * Check if currently in demo mode
   */
  public isInDemoMode(): boolean {
    return this.isDemoMode;
  }

  /**
   * Get demo bots
   */
  public getDemoBots(): DemoBot[] {
    return [...this.demoBots];
  }

  /**
   * Create demo bot configurations
   */
  private createDemoBots(): void {
    this.demoBots = [
      {
        id: 'demo-discord-bot',
        name: 'Demo Discord Bot',
        messageProvider: 'discord',
        llmProvider: 'openai',
        persona: 'helpful-assistant',
        systemInstruction:
          'You are a helpful AI assistant demonstrating the Open-Hivemind platform. Be friendly and informative.',
        status: 'demo',
        connected: true,
        isDemo: true,
        discord: {
          channelId: 'demo-channel-123',
          guildId: 'demo-guild-456',
        },
      },
      {
        id: 'demo-slack-bot',
        name: 'Demo Slack Bot',
        messageProvider: 'slack',
        llmProvider: 'flowise',
        persona: 'friendly-helper',
        systemInstruction:
          'You are a friendly assistant helping users understand Open-Hivemind capabilities.',
        status: 'demo',
        connected: true,
        isDemo: true,
        slack: {
          channelId: 'C12345678',
          teamId: 'T12345678',
        },
      },
    ];
  }

  /**
   * Generate a simulated AI response
   */
  public generateDemoResponse(message: string, botName: string): string {
    const responses = this.getContextualResponses(message, botName);
    const randomIndex = Math.floor(Math.random() * responses.length);
    return responses[randomIndex];
  }

  /**
   * Get contextual responses based on message content
   */
  private getContextualResponses(message: string, _botName: string): string[] {
    const lowerMessage = message.toLowerCase();

    // Greeting responses
    if (lowerMessage.match(/^(hi|hello|hey|greetings)/)) {
      return [
        "Hello! 👋 Welcome to Open-Hivemind! I'm a demo bot showing you what's possible. How can I help you today?",
        "Hey there! Great to meet you! I'm running in demo mode to show off the platform's capabilities.",
        "Hi! I'm a demonstration bot. In production, I'd be connected to real AI services to help you!",
      ];
    }

    // Help responses
    if (lowerMessage.includes('help') || lowerMessage.includes('what can you do')) {
      return [
        "I can help you explore Open-Hivemind! Here's what the platform offers:\n\n" +
          '🤖 **Multi-Platform Bots** - Discord, Slack, Mattermost\n' +
          '🧠 **Multiple LLM Providers** - OpenAI, Flowise, OpenWebUI, and more\n' +
          '🔌 **MCP Integration** - Connect to external tools and services\n' +
          '👥 **Personas** - Customize bot personalities\n\n' +
          'Configure your API keys to unlock full functionality!',
        'Open-Hivemind is a powerful multi-agent orchestration framework! Key features:\n\n' +
          '• Unified bot management across platforms\n' +
          '• Flexible LLM provider switching\n' +
          '• Real-time WebUI dashboard\n' +
          '• MCP tool integration\n\n' +
          'Add your credentials to start using real AI services!',
      ];
    }

    // Configuration questions
    if (
      lowerMessage.includes('config') ||
      lowerMessage.includes('setup') ||
      lowerMessage.includes('start')
    ) {
      return [
        'To configure Open-Hivemind, you can:\n\n' +
          '1. **Environment Variables** - Set `DISCORD_BOT_TOKEN`, `OPENAI_API_KEY`, etc.\n' +
          '2. **Config Files** - Create files in `config/bots/` directory\n' +
          '3. **WebUI** - Use the dashboard at `/` to manage bots\n\n' +
          'Check the `.env.example` file for all available options!',
        'Getting started is easy! You can configure bots via:\n\n' +
          '• Environment variables (BOTS_botname_* pattern)\n' +
          '• JSON config files in config/bots/\n' +
          '• The WebUI configuration panel\n\n' +
          'Would you like me to explain any specific configuration option?',
      ];
    }

    // Feature questions
    if (lowerMessage.includes('feature') || lowerMessage.includes('capabil')) {
      return [
        "Open-Hivemind's key capabilities:\n\n" +
          '🌐 **Multi-Messenger Support** - Discord, Slack, Mattermost\n' +
          '🤖 **Multi-Bot Management** - Run multiple bots from one instance\n' +
          '🔄 **Hot Reload** - Update configs without restart\n' +
          '📊 **Activity Dashboard** - Monitor bot performance\n' +
          '🔐 **Secure Config** - Encrypted credential storage\n' +
          '🛠️ **MCP Tools** - Extend with external tools\n\n' +
          'Explore the WebUI to see more!',
      ];
    }

    // Default conversational responses
    return [
      "That's an interesting point! In production mode, I'd connect to a real LLM to give you a thoughtful response. For now, I'm demonstrating the platform's messaging capabilities.",
      "Great question! When you configure an LLM provider (like OpenAI or Flowise), I'll be able to provide intelligent responses. This demo shows the message flow works perfectly!",
      "I'm running in demo mode with simulated responses. Add your API keys to unlock real AI-powered conversations!",
      "The Open-Hivemind platform is designed to handle messages just like this. With proper configuration, you'd get AI-generated responses tailored to your use case.",
      'Thanks for testing the demo! This shows how messages flow through the system. Configure your credentials to enable real AI responses.',
    ];
  }

  /**
   * Create or get a conversation
   */
  public getOrCreateConversation(channelId: string, botName: string): DemoConversation {
    const key = `${botName}:${channelId}`;

    if (!this.conversations.has(key)) {
      this.conversations.set(key, {
        id: `conv-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
        channelId,
        botName,
        messages: [],
        createdAt: new Date().toISOString(),
        updatedAt: new Date().toISOString(),
      });
    }

    return this.conversations.get(key)!;
  }

  /**
   * Add a message to a conversation
   */
  public addMessage(
    channelId: string,
    botName: string,
    content: string,
    type: 'incoming' | 'outgoing',
    userId = 'demo-user',
    userName = 'Demo User'
  ): DemoMessage {
    const conversation = this.getOrCreateConversation(channelId, botName);

    const message: DemoMessage = {
      id: `msg-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      timestamp: new Date().toISOString(),
      botName,
      channelId,
      userId,
      userName,
      content,
      type,
      isDemo: true,
    };

    conversation.messages.push(message);
    conversation.updatedAt = new Date().toISOString();

    return message;
  }

  /**
   * Get conversation history
   */
  public getConversationHistory(channelId: string, botName: string): DemoMessage[] {
    const key = `${botName}:${channelId}`;
    const conversation = this.conversations.get(key);
    return conversation ? [...conversation.messages] : [];
  }

  /**
   * Get all conversations
   */
  public getAllConversations(): DemoConversation[] {
    return Array.from(this.conversations.values());
  }

  /**
   * Get demo mode status info
   */
  public getDemoStatus(): {
    isDemoMode: boolean;
    botCount: number;
    conversationCount: number;
    messageCount: number;
  } {
    let messageCount = 0;
    this.conversations.forEach((conv) => {
      messageCount += conv.messages.length;
    });

    return {
      isDemoMode: this.isDemoMode,
      botCount: this.demoBots.length,
      conversationCount: this.conversations.size,
      messageCount,
    };
  }

  /**
   * Reset demo mode (clear conversations)
   */
  public reset(): void {
    this.conversations.clear();
    debug('Demo mode reset - conversations cleared');
  }
}

export default DemoModeService;

import fs from 'fs/promises';
import path from 'path';
import Logger from '@common/logger';

const appLogger = Logger.withContext('GreetingStateManager');

type GreetingState = Record<
  string,
  {
    timestamp: number;
    channelId: string;
  }
>;

export class GreetingStateManager {
  private static instance: GreetingStateManager;
  private stateFilePath: string;
  private state: GreetingState = {};
  private initialized = false;

  public constructor() {
    this.stateFilePath = path.join(process.cwd(), 'data', 'greeting-state.json');
  }

  public static getInstance(): GreetingStateManager {
    if (!GreetingStateManager.instance) {
      GreetingStateManager.instance = new GreetingStateManager();
    }
    return GreetingStateManager.instance;
  }

  /**
   * Initialize the state manager by loading existing state from file
   */
  public async initialize(): Promise<void> {
    if (this.initialized) {
      return;
    }

    try {
      // Ensure data directory exists
      const dataDir = path.dirname(this.stateFilePath);
      try {
        await fs.access(dataDir);
      } catch {
        await fs.mkdir(dataDir, { recursive: true });
        appLogger.info('Created data directory for greeting state', { path: dataDir });
      }

      // Load existing state
      try {
        const data = await fs.readFile(this.stateFilePath, 'utf-8');
        this.state = JSON.parse(data);
        appLogger.info('Loaded greeting state from file', { path: this.stateFilePath });
      } catch (error: any) {
        if (error.code === 'ENOENT') {
          // File doesn't exist yet, start with empty state
          this.state = {};
          appLogger.info('No existing greeting state file found, starting fresh');
        } else {
          throw error;
        }
      }

      // Clean up expired entries
      this.cleanupExpiredEntries();

      this.initialized = true;
      appLogger.info('GreetingStateManager initialized successfully');
    } catch (error) {
      appLogger.error('Failed to initialize GreetingStateManager', { error });
      // Don't throw, just start with empty state
      this.state = {};
      this.initialized = true;
    }
  }

  /**
   * Check if a greeting has already been sent for a service
   * @param serviceId Unique identifier for the service (e.g., 'slack-#general')
   * @returns boolean indicating if greeting was sent
   */
  public hasGreetingBeenSent(serviceId: string): boolean {
    this.ensureInitialized();

    const entry = this.state[serviceId];
    if (!entry) {
      return false;
    }

    // Check if entry is expired (24 hours)
    const now = Date.now();
    const twentyFourHours = 24 * 60 * 60 * 1000;

    if (now - entry.timestamp > twentyFourHours) {
      // Entry is expired, remove it and return false
      delete this.state[serviceId];
      this.saveState().catch((error) => {
        appLogger.error('Failed to save state after expiration', { error, serviceId });
      });
      return false;
    }

    return true;
  }

  /**
   * Mark a greeting as sent for a service
   * @param serviceId Unique identifier for the service
   * @param channelId The channel ID where the greeting was sent
   */
  public async markGreetingAsSent(serviceId: string, channelId: string): Promise<void> {
    this.ensureInitialized();

    this.state[serviceId] = {
      timestamp: Date.now(),
      channelId,
    };

    await this.saveState();
    appLogger.info('Marked greeting as sent', { serviceId, channelId });
  }

  /**
   * Get the state for a specific service
   * @param serviceId Unique identifier for the service
   */
  public getServiceState(serviceId: string): { timestamp: number; channelId: string } | null {
    this.ensureInitialized();
    return this.state[serviceId] || null;
  }

  /**
   * Clean up expired entries from the state
   */
  private cleanupExpiredEntries(): void {
    const now = Date.now();
    const twentyFourHours = 24 * 60 * 60 * 1000;
    let cleanedCount = 0;

    for (const [serviceId, entry] of Object.entries(this.state)) {
      if (now - entry.timestamp > twentyFourHours) {
        delete this.state[serviceId];
        cleanedCount++;
      }
    }

    if (cleanedCount > 0) {
      appLogger.info('Cleaned up expired greeting state entries', { count: cleanedCount });
      this.saveState().catch((error) => {
        appLogger.error('Failed to save state after cleanup', { error });
      });
    }
  }

  /**
   * Save the current state to file
   */
  private async saveState(): Promise<void> {
    try {
      const data = JSON.stringify(this.state, null, 2);
      await fs.writeFile(this.stateFilePath, data, 'utf-8');
    } catch (error) {
      appLogger.error('Failed to save greeting state', { error, path: this.stateFilePath });
      throw error;
    }
  }

  /**
   * Clear all greeting state (useful for testing)
   */
  public async clearAllState(): Promise<void> {
    this.ensureInitialized();
    this.state = {};
    await this.saveState();
    appLogger.info('Cleared all greeting state');
  }

  /**
   * Get all current state (useful for debugging)
   */
  public getAllState(): GreetingState {
    this.ensureInitialized();
    return { ...this.state };
  }

  /**
   * Ensure the manager is initialized before operations
   */
  private ensureInitialized(): void {
    if (!this.initialized) {
      throw new Error('GreetingStateManager must be initialized before use');
    }
  }
}

import { EventEmitter } from 'events';
import { inject, singleton } from 'tsyringe';
import messageConfig from '@config/messageConfig';
import { getLlmProvider } from '@llm/getLlmProvider';
import type { IMessengerService } from '@message/interfaces/IMessengerService';
import Logger from '@common/logger';
import { GreetingStateManager } from './GreetingStateManager';

const appLogger = Logger.withContext('StartupGreetingService');

interface GreetingConfig {
  disabled: boolean;
  message: string;
  use_llm?: boolean;
}

@singleton()
export class StartupGreetingService extends EventEmitter {
  public constructor(
    @inject(GreetingStateManager) private greetingStateManager: GreetingStateManager
  ) {
    super();
    appLogger.info('StartupGreetingService initialized');
    this.on('service-ready', this.handleServiceReady.bind(this));
  }

  public async initialize() {
    await this.greetingStateManager.initialize();
    appLogger.info('StartupGreetingService initialized');
  }

  /**
   * Strip surrounding quotes from a string if both leading and trailing quotes exist
   */
  private stripSurroundingQuotes(text: string): string {
    // Check if text starts and ends with the same quote character
    if (text.length >= 2) {
      const first = text[0];
      const last = text[text.length - 1];
      if ((first === '"' && last === '"') || (first === "'" && last === "'")) {
        return text.slice(1, -1);
      }
    }
    return text;
  }

  /**
   * Generate a fun welcome message using LLM
   */
  private async generateLlmGreeting(): Promise<string> {
    try {
      const providers = await getLlmProvider();
      if (providers.length === 0) {
        appLogger.warn('No LLM providers available for greeting generation');
        return 'Hello! I am online and ready to assist.';
      }

      const provider = providers[0];
      const prompt = `Generate a short, friendly, and fun welcome message for a Discord channel. 
The message should be welcoming, slightly playful, and indicate that the bot is now online and ready to help. 
Keep it under 200 characters. You may use action words or emotes. 
IMPORTANT: Do not wrap any part of your response in quotation marks. Just output the plain message text directly.`;

      appLogger.info('Generating LLM greeting message...');

      if (provider.supportsChatCompletion()) {
        const response = await provider.generateChatCompletion(prompt, []);
        if (response) {
          appLogger.info('LLM greeting generated successfully');
          return this.stripSurroundingQuotes(response.trim());
        }
      } else if (provider.supportsCompletion()) {
        const response = await provider.generateCompletion(prompt);
        if (response) {
          appLogger.info('LLM greeting generated successfully');
          return this.stripSurroundingQuotes(response.trim());
        }
      }

      return 'Hello! I am online and ready to assist.';
    } catch (error) {
      appLogger.error('Failed to generate LLM greeting', { error });
      return 'Hello! I am online and ready to assist.';
    }
  }

  private async handleServiceReady(service: IMessengerService) {
    try {
      const serviceName = service.constructor.name || 'UnknownService';
      appLogger.info('Service ready event received', { provider: serviceName });

      const greetingConfig = messageConfig.get('greeting') as GreetingConfig;

      if (greetingConfig.disabled) {
        appLogger.info('Greeting message is disabled by configuration.');
        return;
      }

      const defaultChannel = service.getDefaultChannel();
      if (!defaultChannel) {
        appLogger.warn('No default channel configured for greeting message', {
          provider: serviceName,
        });
        return;
      }

      const serviceId = `${serviceName}-${defaultChannel}`;
      if (this.greetingStateManager.hasGreetingBeenSent(serviceId)) {
        appLogger.info('Greeting already sent for this service and channel', { serviceId });
        return;
      }

      // Determine the greeting message
      let greetingMessage: string;
      if (greetingConfig.use_llm) {
        appLogger.info('Using LLM to generate greeting message');
        greetingMessage = await this.generateLlmGreeting();
      } else {
        greetingMessage = greetingConfig.message || 'Hello! I am online.';
      }

      // Send the greeting
      appLogger.info('Sending greeting message', {
        provider: serviceName,
        channel: defaultChannel,
        message: greetingMessage,
      });
      await service.sendMessageToChannel(defaultChannel, greetingMessage);
      await this.greetingStateManager.markGreetingAsSent(serviceId, defaultChannel);
      appLogger.info('✅ Greeting message sent successfully', {
        provider: serviceName,
        channel: defaultChannel,
      });
    } catch (error) {
      const serviceName = service.constructor.name || 'UnknownService';
      const defaultChannel = service.getDefaultChannel() || 'unknown';
      appLogger.error('Failed to send greeting message', {
        provider: serviceName,
        channel: defaultChannel,
        error,
      });
    }
  }
}

