// Type Guards for Runtime Type Checking
export function isDiscordMessage(obj: any): obj is DiscordMessage {
  return (
    obj &&
    typeof obj.id === 'string' &&
    typeof obj.channel_id === 'string' &&
    typeof obj.content === 'string' &&
    obj.author &&
    typeof obj.author.id === 'string'
  );
}

export function isDiscordUser(obj: any): obj is DiscordUser {
  return obj && typeof obj.id === 'string' && typeof obj.username === 'string';
}

export function isDiscordChannel(obj: any): obj is DiscordChannel {
  return obj && typeof obj.id === 'string' && typeof obj.type === 'number';
}

export function isDiscordGuild(obj: any): obj is DiscordGuild {
  return obj && typeof obj.id === 'string' && typeof obj.name === 'string';
}

export function isDiscordAPIResponse(obj: any): obj is DiscordAPIResponse {
  return obj && typeof obj.ok === 'boolean';
}

export function isDiscordAPIError(obj: any): obj is DiscordAPIError {
  return obj && typeof obj.code === 'number' && typeof obj.message === 'string';
}

/**
 * Enhanced error classes for Open Hivemind with recovery strategies
 *
 * This file extends the base error types with concrete error classes
 * that include recovery mechanisms and correlation IDs for tracking.
 */

import { v4 as uuidv4 } from 'uuid';
import { ErrorUtils, type AppError, type ErrorType } from './errors';

/**
 * Base error class with correlation ID and recovery capabilities
 */
export abstract class BaseHivemindError extends Error implements AppError {
  public readonly code: string;
  public readonly type: ErrorType;
  public readonly statusCode?: number;
  public readonly details?: Record<string, unknown>;
  public readonly retryable: boolean;
  public readonly severity: string;
  public readonly timestamp: Date;
  public readonly correlationId: string;
  public readonly context?: Record<string, unknown>;

  constructor(
    message: string,
    type: ErrorType,
    code?: string,
    statusCode?: number,
    details?: Record<string, unknown>,
    context?: Record<string, unknown>
  ) {
    super(message);
    this.name = this.constructor.name;
    this.type = type;
    this.code = code || type.toUpperCase();
    this.statusCode = statusCode;
    this.details = details;
    this.context = context;
    this.timestamp = new Date();
    this.correlationId = uuidv4();

    const classification = ErrorUtils.classifyError(this);
    this.retryable = classification.retryable;
    this.severity = classification.severity;

    // Maintains proper stack trace for where our error was thrown (only available on V8)
    if (Error.captureStackTrace) {
      Error.captureStackTrace(this, this.constructor);
    }
  }

  /**
   * Get the HTTP status code (alias for statusCode)
   */
  get status(): number | undefined {
    return this.statusCode;
  }

  /**
   * Get a recovery strategy for this error
   */
  abstract getRecoveryStrategy(): ErrorRecoveryStrategy;

  /**
   * Convert to JSON for logging/serialization
   */
  toJSON(): Record<string, unknown> {
    return {
      name: this.name,
      message: this.message,
      code: this.code,
      type: this.type,
      statusCode: this.statusCode,
      details: this.details,
      context: this.context,
      retryable: this.retryable,
      timestamp: this.timestamp.toISOString(),
      correlationId: this.correlationId,
      stack: this.stack,
    };
  }
}

/**
 * Recovery strategy interface
 */
export interface ErrorRecoveryStrategy {
  canRecover: boolean;
  retryDelay?: number;
  maxRetries?: number;
  fallbackAction?: () => Promise<unknown>;
  recoverySteps?: string[];
}

/**
 * Network error with retry capabilities
 */
export class NetworkError extends BaseHivemindError {
  public override readonly severity: string = 'medium';
  public readonly response?: {
    data?: unknown;
    headers?: Record<string, string>;
    status?: number;
  };
  public readonly request?: {
    url?: string;
    method?: string;
    headers?: Record<string, string>;
  };

  constructor(
    message: string,
    response?: {
      data?: unknown;
      headers?: Record<string, string>;
      status?: number;
    },
    request?: {
      url?: string;
      method?: string;
      headers?: Record<string, string>;
    },
    context?: Record<string, unknown>
  ) {
    super(
      message,
      'network',
      'NETWORK_ERROR',
      response?.status || 503,
      { response, request },
      context
    );
    this.response = response;
    this.request = request;
  }

  getRecoveryStrategy(): ErrorRecoveryStrategy {
    const statusCode = this.response?.status;

    // Retry on server errors and rate limits
    if (!statusCode || statusCode >= 500 || statusCode === 429) {
      return {
        canRecover: true,
        maxRetries: 3,
        retryDelay: this.calculateRetryDelay(),
        recoverySteps: [
          'Check network connectivity',
          'Verify endpoint availability',
          'Retry with exponential backoff',
        ],
      };
    }

    // Don't retry client errors (4xx except 429)
    return {
      canRecover: false,
      recoverySteps: [
        'Check request parameters',
        'Verify authentication credentials',
        'Contact support if issue persists',
      ],
    };
  }

  private calculateRetryDelay(): number {
    // Exponential backoff with jitter
    const baseDelay = 1000; // 1 second
    const jitter = Math.random() * 1000; // Random jitter up to 1 second
    return baseDelay + jitter;
  }
}

/**
 * Validation error with field-specific information
 */
export class ValidationError extends BaseHivemindError {
  public readonly field?: string;
  public readonly value?: unknown;
  public readonly expected?: unknown;
  public readonly suggestions?: string[];

  constructor(
    message: string,
    details?: Record<string, unknown> | string,
    value?: unknown,
    expected?: unknown,
    suggestions?: string[],
    context?: Record<string, unknown>
  ) {
    // Handle both old signature (message, details object) and new signature
    let field: string | undefined;
    let actualDetails: Record<string, unknown> | undefined;

    if (typeof details === 'object' && details !== null) {
      field = details.field as string;
      actualDetails = details;
    } else if (typeof details === 'string') {
      field = details;
    }

    super(
      message,
      'validation',
      'VALIDATION_ERROR',
      400,
      { field, value, expected, suggestions, ...actualDetails },
      context
    );
    this.field = field;
    this.value = value;
    this.expected = expected;
    this.suggestions = suggestions;
  }

  getRecoveryStrategy(): ErrorRecoveryStrategy {
    return {
      canRecover: false,
      recoverySteps: [
        'Check input data format',
        'Validate required fields',
        ...(this.suggestions || []),
      ],
    };
  }
}

