/**
 * Database error with connection retry capabilities
 */
export class DatabaseError extends BaseHivemindError {
  public readonly operation?: string;
  public readonly table?: string;
  public readonly query?: string;

  constructor(
    message: string,
    operation?: string,
    table?: string,
    query?: string,
    context?: Record<string, unknown>
  ) {
    super(message, 'database', 'DATABASE_ERROR', 500, { operation, table, query }, context);
    this.operation = operation;
    this.table = table;
    this.query = query;
  }

  getRecoveryStrategy(): ErrorRecoveryStrategy {
    // Retry on connection errors
    if (
      this.message.toLowerCase().includes('connection') ||
      this.message.toLowerCase().includes('timeout')
    ) {
      return {
        canRecover: true,
        maxRetries: 3,
        retryDelay: 2000,
        recoverySteps: [
          'Check database server status',
          'Verify connection string',
          'Retry connection with backoff',
        ],
      };
    }

    return {
      canRecover: false,
      recoverySteps: [
        'Check database permissions',
        'Verify query syntax',
        'Contact database administrator',
      ],
    };
  }
}

/**
 * Authentication error with token refresh capabilities
 */
export class AuthenticationError extends BaseHivemindError {
  public readonly provider?: string;
  public readonly reason?:
    | 'invalid_credentials'
    | 'expired_token'
    | 'missing_token'
    | 'invalid_format';

  constructor(
    message: string,
    provider?: string,
    reason?: 'invalid_credentials' | 'expired_token' | 'missing_token' | 'invalid_format',
    context?: Record<string, unknown>
  ) {
    super(message, 'authentication', 'AUTH_ERROR', 401, { provider, reason }, context);
    this.provider = provider;
    this.reason = reason;
  }

  getRecoveryStrategy(): ErrorRecoveryStrategy {
    // Allow token refresh for expired tokens
    if (this.reason === 'expired_token') {
      return {
        canRecover: true,
        maxRetries: 1,
        retryDelay: 0,
        fallbackAction: async () => {
          // This would be implemented by the calling code
          throw new Error('Token refresh not implemented');
        },
        recoverySteps: ['Attempt to refresh authentication token', 'Re-authenticate with provider'],
      };
    }

    return {
      canRecover: false,
      recoverySteps: [
        'Check authentication credentials',
        'Verify token format',
        'Re-authenticate with provider',
      ],
    };
  }
}

