/**
 * Input sanitization utilities for the Open Hivemind bot
 *
 * Provides security-focused input validation and sanitization
 * to prevent injection attacks and ensure data integrity.
 */
export class InputSanitizer {
  /**
   * Sanitize user messages to prevent injection attacks
   *
   * @param content - Raw message content
   * @returns Sanitized message content
   */
  static sanitizeMessage(content: string): string {
    if (!content || typeof content !== 'string') {
      return '';
    }

    return (
      content
        // Remove script tags and javascript: protocols
        .replace(/<script[^>]*>.*?<\/script>/gi, '')
        .replace(/javascript:/gi, '')
        // Remove potentially harmful HTML
        .replace(/<[^>]*>/g, '')
        // Remove null bytes and control characters
        .replace(/[\x00-\x1F\x7F]/g, '')
        // Trim whitespace
        .trim()
        // Limit length to prevent abuse
        .substring(0, 10000)
    );
  }

  /**
   * Validate and sanitize user IDs
   *
   * @param userId - Raw user ID
   * @returns Sanitized user ID or null if invalid
   */
  static sanitizeUserId(userId: string): string | null {
    if (!userId || typeof userId !== 'string') {
      return null;
    }

    // Allow alphanumeric, underscores, hyphens, and dots
    const sanitized = userId.replace(/[^a-zA-Z0-9_.-]/g, '');

    // Must be between 1 and 100 characters
    if (sanitized.length < 1 || sanitized.length > 100) {
      return null;
    }

    return sanitized;
  }

  /**
   * Validate and sanitize channel IDs
   *
   * @param channelId - Raw channel ID
   * @returns Sanitized channel ID or null if invalid
   */
  static sanitizeChannelId(channelId: string): string | null {
    if (!channelId || typeof channelId !== 'string') {
      return null;
    }

    // Allow alphanumeric, underscores, hyphens, and dots
    const sanitized = channelId.replace(/[^a-zA-Z0-9_.-]/g, '');

    // Must be between 1 and 100 characters
    if (sanitized.length < 1 || sanitized.length > 100) {
      return null;
    }

    return sanitized;
  }

  /**
   * Validate message content for basic requirements
   *
   * @param content - Message content to validate
   * @returns Validation result
   */
  static validateMessage(content: string): { isValid: boolean; reason?: string } {
    if (!content || typeof content !== 'string') {
      return { isValid: false, reason: 'Content is required' };
    }

    if (content.trim().length === 0) {
      return { isValid: false, reason: 'Content cannot be empty' };
    }

    if (content.length > 10000) {
      return { isValid: false, reason: 'Content is too long' };
    }

    // Check for excessive special characters (potential spam)
    const specialCharCount = (content.match(/[^a-zA-Z0-9\s]/g) || []).length;
    if (specialCharCount > content.length * 0.5) {
      return { isValid: false, reason: 'Too many special characters' };
    }

    return { isValid: true };
  }

  /**
   * Strips surrounding quotes if and only if the text starts and ends with matching quotes.
   * Handles standard quotes, smart quotes, guillemets, and backticks.
   * Operates recursively to remove multiple layers of matching wrapping.
   * Finally, applies a greedy pass to strip any remaining unmatched quotes at the start or end.
   *
   * @param text - The text to sanitize
   * @returns The text with all layers of surrounding quotes removed.
   */
  static stripSurroundingQuotes(text: string): string {
    if (!text) {
      return '';
    }

    let current = text.trim();
    let stripped = true;

    const pairs = [
      ['"', '"'],
      ["'", "'"],
      ['“', '”'],
      ['‘', '’'],
      ['«', '»'],
      ['`', '`'],
    ];

    // Phase 1: Recursive Matching Pairs
    while (stripped && current.length >= 2) {
      stripped = false;
      const first = current[0];
      const last = current[current.length - 1];

      for (const [start, end] of pairs) {
        if (first === start && last === end) {
          current = current.substring(1, current.length - 1).trim();
          stripped = true;
          break;
        }
      }
    }

    // Phase 2: Greedy Unmatched Stripping
    // Handles cases like '"Text' or 'Text"' or multi-line splits
    const allQuotes = ['"', "'", '“', '”', '‘', '’', '«', '»', '`'];

    let greedyStripped = true;
    while (greedyStripped && current.length > 0) {
      greedyStripped = false;

      if (allQuotes.includes(current[0])) {
        current = current.substring(1).trim();
        greedyStripped = true;
      }

      if (current.length > 0 && allQuotes.includes(current[current.length - 1])) {
        current = current.substring(0, current.length - 1).trim();
        greedyStripped = true;
      }
    }

    return current;
  }

  /**
   * Sanitize configuration values
   *
   * @param value - Raw configuration value
   * @param type - Expected type ('string', 'number', 'boolean')
   * @returns Sanitized value or null if invalid
   */
  static sanitizeConfigValue(value: any, type: 'string' | 'number' | 'boolean'): any {
    switch (type) {
      case 'string':
        if (typeof value === 'string') {
          return value.trim().substring(0, 1000);
        }
        return null;

      case 'number':
        const num = Number(value);
        return isNaN(num) ? null : num;

      case 'boolean':
        if (typeof value === 'boolean') {
          return value;
        }
        if (typeof value === 'string') {
          return value.toLowerCase() === 'true';
        }
        return null;

      default:
        return null;
    }
  }
}

/**
 * Rate limiting utilities
 */
export class RateLimiter {
  private static attempts = new Map<string, number[]>();

  // Bounded cache configuration
  private static readonly MAX_IDENTIFIERS = parseInt(
    process.env.RATE_LIMITER_MAX_IDENTIFIERS || '10000',
    10
  );
  private static readonly MAX_ATTEMPTS_PER_IDENTIFIER = parseInt(
    process.env.RATE_LIMITER_MAX_ATTEMPTS_PER_ID || '100',
    10
  );

  /**
   * Enforce max identifiers limit by removing oldest entries.
   * Called when the Map size exceeds the limit.
   */
  private static enforceMaxIdentifiers(): void {
    if (this.attempts.size < this.MAX_IDENTIFIERS) {
      return;
    }

    // Find entries with oldest last attempt time
    const entries = Array.from(this.attempts.entries())
      .map(([key, timestamps]) => ({
        key,
        lastAttempt: timestamps.length > 0 ? Math.max(...timestamps) : 0,
      }))
      .sort((a, b) => a.lastAttempt - b.lastAttempt);

    // Remove oldest 10% of entries
    const toRemove = Math.ceil(this.MAX_IDENTIFIERS * 0.1);
    for (let i = 0; i < toRemove && i < entries.length; i++) {
      this.attempts.delete(entries[i].key);
    }
  }

  /**
   * Prune old attempts for a specific identifier and enforce max attempts limit.
   */
  private static pruneAttempts(identifier: string, windowMs: number): void {
    const attempts = this.attempts.get(identifier);
    if (!attempts) {
      return;
    }

    const now = Date.now();
    // Remove old attempts outside the window
    const validAttempts = attempts.filter((time) => now - time < windowMs);
    // Also enforce max attempts per identifier to prevent unbounded array growth
    const limitedAttempts = validAttempts.slice(-this.MAX_ATTEMPTS_PER_IDENTIFIER);
    this.attempts.set(identifier, limitedAttempts);
  }

  /**
   * Check if an action should be rate limited
   *
   * @param identifier - Unique identifier (user ID, IP, etc.)
   * @param maxAttempts - Maximum attempts allowed
   * @param windowMs - Time window in milliseconds
   * @returns Whether the action is allowed
   */
  static checkLimit(identifier: string, maxAttempts = 10, windowMs = 60000): boolean {
    const now = Date.now();
    const attempts = this.attempts.get(identifier) || [];

    // Remove old attempts outside the window
    const validAttempts = attempts.filter((time) => now - time < windowMs);

    if (validAttempts.length >= maxAttempts) {
      return false; // Rate limited
    }

    // Add current attempt
    validAttempts.push(now);
    // Limit the array size to prevent unbounded growth
    const limitedAttempts = validAttempts.slice(-this.MAX_ATTEMPTS_PER_IDENTIFIER);
    this.attempts.set(identifier, limitedAttempts);

    // Enforce max identifiers limit
    this.enforceMaxIdentifiers();

    return true; // Allowed
  }

  /**
   * Get remaining attempts for an identifier
   *
   * @param identifier - Unique identifier
   * @param maxAttempts - Maximum attempts allowed
   * @returns Number of remaining attempts
   */
  static getRemainingAttempts(identifier: string, maxAttempts = 10): number {
    const attempts = this.attempts.get(identifier) || [];
    return Math.max(0, maxAttempts - attempts.length);
  }

  /**
   * Clear rate limit data for an identifier
   *
   * @param identifier - Unique identifier
   */
  static clearLimit(identifier: string): void {
    this.attempts.delete(identifier);
  }

  /**
   * Get statistics about the rate limiter state.
   */
  static getStats(): {
    identifiersCount: number;
    maxIdentifiers: number;
    totalAttempts: number;
  } {
    let totalAttempts = 0;
    for (const attempts of this.attempts.values()) {
      totalAttempts += attempts.length;
    }
    return {
      identifiersCount: this.attempts.size,
      maxIdentifiers: this.MAX_IDENTIFIERS,
      totalAttempts,
    };
  }

  /**
   * Clear all rate limit data.
   */
  static clearAll(): void {
    this.attempts.clear();
  }
}

import * as fs from 'fs';
import * as path from 'path';
import * as v8 from 'v8';
import Debug from 'debug';

const debug = Debug('app:PerformanceProfiler');

interface PerformanceSnapshot {
  timestamp: number;
  memoryUsage: NodeJS.MemoryUsage;
  heapStatistics: v8.HeapInfo;
  cpuUsage?: NodeJS.CpuUsage;
}

interface MethodProfile {
  methodName: string;
  className?: string;
  executionCount: number;
  totalExecutionTime: number;
  averageExecutionTime: number;
  minExecutionTime: number;
  maxExecutionTime: number;
  lastExecutionTime: number;
  errorCount: number;
}

interface PerformanceReport {
  timestamp: number;
  duration: number;
  memory: {
    initial: PerformanceSnapshot;
    final: PerformanceSnapshot;
    delta: {
      rss: number;
      heapTotal: number;
      heapUsed: number;
      external: number;
      arrayBuffers: number;
    };
  };
  methods: MethodProfile[];
  alerts: string[];
}

export class PerformanceProfiler {
  private static instance: PerformanceProfiler;
  private isProfiling = false;
  private snapshots: PerformanceSnapshot[] = [];
  private methodProfiles = new Map<string, MethodProfile>();
  private startTime = 0;
  private profileName = 'default';
  private maxSnapshots = 50;
  private cleanupInterval: NodeJS.Timeout | null = null;
  private maxProfileAge: number = 24 * 60 * 60 * 1000; // 24 hours

  private constructor() {
    // Start automatic cleanup
    this.startAutomaticCleanup();
  }

  public static getInstance(): PerformanceProfiler {
    if (!PerformanceProfiler.instance) {
      PerformanceProfiler.instance = new PerformanceProfiler();
    }
    return PerformanceProfiler.instance;
  }

  /**
   * Start performance profiling
   */
  public startProfiling(profileName = 'default'): void {
    if (this.isProfiling) {
      debug('Profiling already in progress');
      return;
    }

    this.isProfiling = true;
    this.profileName = profileName;
    this.startTime = Date.now();
    this.snapshots = [];
    this.methodProfiles.clear();

    // Take initial snapshot
    this.takeSnapshot();

    debug(`Performance profiling started: ${profileName}`);
  }

  /**
   * Stop performance profiling and generate report
   */
  public stopProfiling(): PerformanceReport | null {
    if (!this.isProfiling) {
      debug('No profiling in progress');
      return null;
    }

    this.isProfiling = false;

    // Take final snapshot
    this.takeSnapshot();

    const report = this.generateReport();
    debug(`Performance profiling stopped: ${this.profileName}`);

    return report;
  }

  /**
   * Profile a method execution
   */
  public profileMethod<T>(methodName: string, fn: () => T, className?: string): T {
    if (!this.isProfiling) {
      return fn();
    }

    const startTime = process.hrtime.bigint();
    let result: T;
    let error: Error | null = null;

    try {
      result = fn();
    } catch (err) {
      error = err as Error;
      throw err;
    } finally {
      const endTime = process.hrtime.bigint();
      const executionTime = Number(endTime - startTime) / 1_000_000; // Convert to milliseconds

      this.recordMethodExecution(methodName, className, executionTime, !!error);
    }

    return result;
  }

  /**
   * Profile an async method execution
   */
  public async profileMethodAsync<T>(
    methodName: string,
    fn: () => Promise<T>,
    className?: string
  ): Promise<T> {
    if (!this.isProfiling) {
      return fn();
    }

    const startTime = process.hrtime.bigint();
    let result: T;
    let error: Error | null = null;

    try {
      result = await fn();
    } catch (err) {
      error = err as Error;
      throw err;
    } finally {
      const endTime = process.hrtime.bigint();
      const executionTime = Number(endTime - startTime) / 1_000_000; // Convert to milliseconds

      this.recordMethodExecution(methodName, className, executionTime, !!error);
    }

    return result;
  }

  /**
   * Take a performance snapshot
   */
  public takeSnapshot(): void {
    const timestamp = Date.now();
    const memoryUsage = process.memoryUsage();

    // Get heap statistics if available
    let heapStatistics: v8.HeapInfo;
    try {
      heapStatistics = v8.getHeapStatistics();
    } catch (error) {
      // Fallback for environments where v8.getHeapStatistics is not available
      heapStatistics = {
        total_heap_size: memoryUsage.heapTotal,
        used_heap_size: memoryUsage.heapUsed,
        external_memory: memoryUsage.external,
        heap_size_limit: 0,
        malloced_memory: 0,
        peak_malloced_memory: 0,
        does_zap_garbage: false,
        number_of_native_contexts: 0,
        number_of_detached_contexts: 0,
      } as any;
    }

    const snapshot: PerformanceSnapshot = {
      timestamp,
      memoryUsage,
      heapStatistics,
      cpuUsage: process.cpuUsage(),
    };

    this.snapshots.push(snapshot);

    // Keep only recent snapshots
    if (this.snapshots.length > this.maxSnapshots) {
      this.snapshots.shift();
    }

    debug(`Performance snapshot taken at ${new Date(timestamp).toISOString()}`);
  }

  /**
   * Get current performance metrics
   */
  public getCurrentMetrics(): {
    memoryUsage: NodeJS.MemoryUsage;
    heapStatistics: v8.HeapInfo;
    methodProfiles: MethodProfile[];
  } {
    const memoryUsage = process.memoryUsage();
    let heapStatistics: v8.HeapInfo;

    try {
      heapStatistics = v8.getHeapStatistics();
    } catch (error) {
      heapStatistics = {
        total_heap_size: memoryUsage.heapTotal,
        used_heap_size: memoryUsage.heapUsed,
        external_memory: memoryUsage.external,
        heap_size_limit: 0,
        malloced_memory: 0,
        peak_malloced_memory: 0,
        does_zap_garbage: false,
        number_of_native_contexts: 0,
        number_of_detached_contexts: 0,
      } as any;
    }

    return {
      memoryUsage,
      heapStatistics,
      methodProfiles: Array.from(this.methodProfiles.values()),
    };
  }

  /**
   * Export performance data to file
   */
  public exportToFile(filename?: string): string {
    const exportData = {
      profileName: this.profileName,
      startTime: this.startTime,
      snapshots: this.snapshots,
      methodProfiles: Array.from(this.methodProfiles.entries()),
      currentMetrics: this.getCurrentMetrics(),
    };

    const fileName = filename || `performance-profile-${this.profileName}-${Date.now()}.json`;
    const filePath = path.join(process.cwd(), 'logs', fileName);

    // Ensure logs directory exists
    const logsDir = path.dirname(filePath);
    if (!fs.existsSync(logsDir)) {
      fs.mkdirSync(logsDir, { recursive: true });
    }

    fs.writeFileSync(filePath, JSON.stringify(exportData, null, 2));
    debug(`Performance data exported to: ${filePath}`);

    return filePath;
  }

  private recordMethodExecution(
    methodName: string,
    className: string | undefined,
    executionTime: number,
    hadError: boolean
  ): void {
    const key = className ? `${className}.${methodName}` : methodName;

    if (!this.methodProfiles.has(key)) {
      this.methodProfiles.set(key, {
        methodName,
        className,
        executionCount: 0,
        totalExecutionTime: 0,
        averageExecutionTime: 0,
        minExecutionTime: Number.MAX_VALUE,
        maxExecutionTime: 0,
        lastExecutionTime: 0,
        errorCount: 0,
      });
    }

    const profile = this.methodProfiles.get(key)!;
    profile.executionCount++;
    profile.totalExecutionTime += executionTime;
    profile.averageExecutionTime = profile.totalExecutionTime / profile.executionCount;
    profile.minExecutionTime = Math.min(profile.minExecutionTime, executionTime);
    profile.maxExecutionTime = Math.max(profile.maxExecutionTime, executionTime);
    profile.lastExecutionTime = executionTime;

    if (hadError) {
      profile.errorCount++;
    }
  }

  private generateReport(): PerformanceReport {
    const endTime = Date.now();
    const duration = endTime - this.startTime;

    const initialSnapshot = this.snapshots[0];
    const finalSnapshot = this.snapshots[this.snapshots.length - 1];

    const memoryDelta = {
      rss: finalSnapshot.memoryUsage.rss - initialSnapshot.memoryUsage.rss,
      heapTotal: finalSnapshot.memoryUsage.heapTotal - initialSnapshot.memoryUsage.heapTotal,
      heapUsed: finalSnapshot.memoryUsage.heapUsed - initialSnapshot.memoryUsage.heapUsed,
      external: finalSnapshot.memoryUsage.external - initialSnapshot.memoryUsage.external,
      arrayBuffers:
        finalSnapshot.memoryUsage.arrayBuffers - initialSnapshot.memoryUsage.arrayBuffers,
    };

    const alerts: string[] = [];

    // Generate alerts for performance issues
    if (memoryDelta.heapUsed > 50 * 1024 * 1024) {
      // 50MB increase
      alerts.push(
        `High memory usage increase: +${(memoryDelta.heapUsed / 1024 / 1024).toFixed(2)}MB`
      );
    }

    // Check for slow methods
    const slowMethods = Array.from(this.methodProfiles.values())
      .filter((profile) => profile.averageExecutionTime > 1000) // Methods taking > 1 second on average
      .sort((a, b) => b.averageExecutionTime - a.averageExecutionTime);

    if (slowMethods.length > 0) {
      alerts.push(
        `Slow methods detected: ${slowMethods
          .slice(0, 3)
          .map((m) => `${m.methodName} (${m.averageExecutionTime.toFixed(2)}ms)`)
          .join(', ')}`
      );
    }

    // Check for methods with high error rates
    const errorProneMethods = Array.from(this.methodProfiles.values())
      .filter(
        (profile) =>
          profile.executionCount > 10 && profile.errorCount / profile.executionCount > 0.1
      ) // > 10% error rate
      .sort((a, b) => b.errorCount / b.executionCount - a.errorCount / a.executionCount);

    if (errorProneMethods.length > 0) {
      alerts.push(
        `Error-prone methods: ${errorProneMethods
          .slice(0, 3)
          .map(
            (m) =>
              `${m.methodName} (${((m.errorCount / m.executionCount) * 100).toFixed(1)}% errors)`
          )
          .join(', ')}`
      );
    }

    return {
      timestamp: endTime,
      duration,
      memory: {
        initial: initialSnapshot,
        final: finalSnapshot,
        delta: memoryDelta,
      },
      methods: Array.from(this.methodProfiles.values()),
      alerts,
    };
  }
  /**
   * Start automatic cleanup interval
   */
  private startAutomaticCleanup(): void {
    // Run cleanup every hour
    this.cleanupInterval = setInterval(
      () => {
        this.cleanupOldData();
      },
      60 * 60 * 1000
    ); // 1 hour

    debug('Automatic cleanup started');
  }

  /**
   * Stop automatic cleanup interval
   */
  private stopAutomaticCleanup(): void {
    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
      debug('Automatic cleanup stopped');
    }
  }

  /**
   * Clean up old performance data
   */
  private cleanupOldData(): void {
    const now = Date.now();
    const cutoffTime = now - this.maxProfileAge;
    let cleanedSnapshots = 0;
    let cleanedProfiles = 0;

    // Clean old snapshots
    const originalSnapshotLength = this.snapshots.length;
    this.snapshots = this.snapshots.filter((snapshot) => snapshot.timestamp > cutoffTime);
    cleanedSnapshots = originalSnapshotLength - this.snapshots.length;

    // Clean old method profiles
    const originalProfileCount = this.methodProfiles.size;
    for (const [key, profile] of this.methodProfiles.entries()) {
      if (profile.lastExecutionTime < cutoffTime) {
        this.methodProfiles.delete(key);
        cleanedProfiles++;
      }
    }

    if (cleanedSnapshots > 0 || cleanedProfiles > 0) {
      debug(
        `Cleanup completed: ${cleanedSnapshots} snapshots, ${cleanedProfiles} profiles removed`
      );
    }
  }

  /**
   * Force cleanup of old data
   */
  public forceCleanup(): void {
    this.cleanupOldData();
  }

  /**
   * Set cleanup configuration
   */
  public setCleanupConfig(config: {
    maxSnapshots?: number;
    maxProfileAge?: number;
    cleanupIntervalMinutes?: number;
  }): void {
    if (config.maxSnapshots !== undefined) {
      this.maxSnapshots = config.maxSnapshots;
    }

    if (config.maxProfileAge !== undefined) {
      this.maxProfileAge = config.maxProfileAge;
    }

    if (config.cleanupIntervalMinutes !== undefined) {
      this.stopAutomaticCleanup();
      if (config.cleanupIntervalMinutes > 0) {
        this.cleanupInterval = setInterval(
          () => {
            this.cleanupOldData();
          },
          config.cleanupIntervalMinutes * 60 * 1000
        );
      }
    }

    debug(
      `Cleanup config updated: maxSnapshots=${this.maxSnapshots}, maxAge=${this.maxProfileAge}ms`
    );
  }

  /**
   * Get memory usage statistics
   */
  public getMemoryUsage(): {
    snapshotsCount: number;
    profilesCount: number;
    estimatedMemoryUsage: number;
  } {
    const snapshotSize = JSON.stringify(this.snapshots).length * 2; // Rough estimate
    const profilesSize = Array.from(this.methodProfiles.entries()).reduce(
      (size, [key, profile]) => size + key.length + JSON.stringify(profile).length * 2,
      0
    );

    return {
      snapshotsCount: this.snapshots.length,
      profilesCount: this.methodProfiles.size,
      estimatedMemoryUsage: snapshotSize + profilesSize,
    };
  }

  /**
   * Cleanup method for graceful shutdown
   */
  public destroy(): void {
    this.stopAutomaticCleanup();
    this.clear();
    debug('PerformanceProfiler destroyed');
  }

  /**
   * Enhanced clear method with better cleanup
   */
  public clear(): void {
    this.snapshots = [];
    this.methodProfiles.clear();
    this.startTime = 0;
    debug('Performance profiling data cleared');
  }
}

/**
 * Decorator for profiling method execution
 */
export function Profile(target: any, propertyName: string, descriptor: PropertyDescriptor) {
  const method = descriptor.value;
  const className = target.constructor.name;

  descriptor.value = function (...args: any[]) {
    const profiler = PerformanceProfiler.getInstance();
    return profiler.profileMethod(propertyName, () => method.apply(this, args), className);
  };
}

/**
 * Decorator for profiling async method execution
 */
export function ProfileAsync(target: any, propertyName: string, descriptor: PropertyDescriptor) {
  const method = descriptor.value;
  const className = target.constructor.name;

  descriptor.value = async function (...args: any[]) {
    const profiler = PerformanceProfiler.getInstance();
    return profiler.profileMethodAsync(propertyName, () => method.apply(this, args), className);
  };
}

export default PerformanceProfiler;

import Debug from 'debug';

const debug = Debug('app:TimerRegistry');

/**
 * TimerRecord stores information about a registered timer.
 */
interface TimerRecord {
  id: string;
  handle: NodeJS.Timeout;
  type: 'timeout' | 'interval';
  callback: () => void;
  delay: number;
  createdAt: number;
  description?: string;
}

/**
 * TimerRegistry provides centralized management of all timers and intervals.
 * This ensures proper cleanup during shutdown and prevents resource leaks.
 *
 * @example
 * // Register a timeout
 * const timerId = TimerRegistry.getInstance().registerTimeout('my-timeout', () => {
 *   console.log('Timer fired');
 * }, 5000);
 *
 * // Register an interval
 * const intervalId = TimerRegistry.getInstance().registerInterval('my-interval', () => {
 *   console.log('Interval fired');
 * }, 60000);
 *
 * // Clear a specific timer
 * TimerRegistry.getInstance().clear(timerId);
 *
 * // Clear all timers on shutdown
 * TimerRegistry.getInstance().clearAll();
 */
export class TimerRegistry {
  private static instance: TimerRegistry;
  private timers = new Map<string, TimerRecord>();
  private cleanupInterval: NodeJS.Timeout | null = null;

  // Configuration
  private readonly MAX_TIMERS = 1000;
  private readonly CLEANUP_INTERVAL_MS = 60000; // 1 minute
  private readonly MAX_TIMER_AGE_MS = 24 * 60 * 60 * 1000; // 24 hours

  private constructor() {
    debug('TimerRegistry initialized');
    this.startCleanupInterval();
  }

  /**
   * Get the singleton instance of TimerRegistry.
   */
  public static getInstance(): TimerRegistry {
    if (!TimerRegistry.instance) {
      TimerRegistry.instance = new TimerRegistry();
    }
    return TimerRegistry.instance;
  }

  /**
   * Register a timeout (one-shot timer).
   * @param id Unique identifier for this timer
   * @param callback Function to call when timer fires
   * @param delayMs Delay in milliseconds
   * @param description Optional description for debugging
   * @returns The timer ID
   */
  public registerTimeout(
    id: string,
    callback: () => void,
    delayMs: number,
    description?: string
  ): string {
    this.enforceMaxTimers();

    const handle = setTimeout(() => {
      this.executeAndRemove(id, callback);
    }, delayMs);

    const record: TimerRecord = {
      id,
      handle,
      type: 'timeout',
      callback,
      delay: delayMs,
      createdAt: Date.now(),
      description,
    };

    this.timers.set(id, record);
    debug(`Registered timeout: ${id} (${delayMs}ms)${description ? ` - ${description}` : ''}`);

    return id;
  }

  /**
   * Register an interval (repeating timer).
   * @param id Unique identifier for this interval
   * @param callback Function to call on each interval
   * @param intervalMs Interval in milliseconds
   * @param description Optional description for debugging
   * @returns The interval ID
   */
  public registerInterval(
    id: string,
    callback: () => void,
    intervalMs: number,
    description?: string
  ): string {
    this.enforceMaxTimers();

    const handle = setInterval(callback, intervalMs);

    const record: TimerRecord = {
      id,
      handle,
      type: 'interval',
      callback,
      delay: intervalMs,
      createdAt: Date.now(),
      description,
    };

    this.timers.set(id, record);
    debug(`Registered interval: ${id} (${intervalMs}ms)${description ? ` - ${description}` : ''}`);

    return id;
  }

  /**
   * Clear a specific timer by ID.
   * @param id The timer ID to clear
   * @returns true if the timer was found and cleared
   */
  public clear(id: string): boolean {
    const record = this.timers.get(id);
    if (!record) {
      debug(`Timer not found: ${id}`);
      return false;
    }

    if (record.type === 'timeout') {
      clearTimeout(record.handle);
    } else {
      clearInterval(record.handle);
    }

    this.timers.delete(id);
    debug(`Cleared ${record.type}: ${id}`);
    return true;
  }

  /**
   * Clear all registered timers and intervals.
   * This should be called during graceful shutdown.
   */
  public clearAll(): void {
    debug(`Clearing all timers (${this.timers.size} total)`);

    for (const [id, record] of this.timers) {
      if (record.type === 'timeout') {
        clearTimeout(record.handle);
      } else {
        clearInterval(record.handle);
      }
      debug(`Cleared ${record.type}: ${id}`);
    }

    this.timers.clear();

    if (this.cleanupInterval) {
      clearInterval(this.cleanupInterval);
      this.cleanupInterval = null;
    }
  }

  /**
   * Get statistics about registered timers.
   */
  public getStats(): {
    total: number;
    timeouts: number;
    intervals: number;
    oldestAge: number;
  } {
    const now = Date.now();
    let timeouts = 0;
    let intervals = 0;
    let oldestAge = 0;

    for (const record of this.timers.values()) {
      if (record.type === 'timeout') {
        timeouts++;
      } else {
        intervals++;
      }
      const age = now - record.createdAt;
      if (age > oldestAge) {
        oldestAge = age;
      }
    }

    return {
      total: this.timers.size,
      timeouts,
      intervals,
      oldestAge,
    };
  }

  /**
   * Check if a timer exists.
   */
  public has(id: string): boolean {
    return this.timers.has(id);
  }

  /**
   * Get a list of all timer IDs.
   */
  public getTimerIds(): string[] {
    return Array.from(this.timers.keys());
  }

  /**
   * Execute a callback and remove the timer (for timeouts).
   */
  private executeAndRemove(id: string, callback: () => void): void {
    try {
      callback();
    } catch (error) {
      debug(`Error executing timer ${id}: ${error}`);
    } finally {
      this.timers.delete(id);
    }
  }

  /**
   * Enforce maximum timer limit to prevent memory leaks.
   */
  private enforceMaxTimers(): void {
    if (this.timers.size >= this.MAX_TIMERS) {
      // Remove oldest timers first
      const entries = [...this.timers.entries()];
      entries.sort((a, b) => a[1].createdAt - b[1].createdAt);

      const toRemove = entries.slice(0, Math.floor(this.MAX_TIMERS * 0.1)); // Remove 10%
      for (const [id, record] of toRemove) {
        if (record.type === 'timeout') {
          clearTimeout(record.handle);
        } else {
          clearInterval(record.handle);
        }
        this.timers.delete(id);
        debug(`Removed old timer due to limit: ${id}`);
      }
    }
  }

  /**
   * Start periodic cleanup of old timers.
   */
  private startCleanupInterval(): void {
    this.cleanupInterval = setInterval(() => {
      this.cleanupOldTimers();
    }, this.CLEANUP_INTERVAL_MS);
  }

  /**
   * Clean up timers that have been running too long.
   */
  private cleanupOldTimers(): void {
    const now = Date.now();
    const toRemove: string[] = [];

    for (const [id, record] of this.timers) {
      // Only clean up intervals that have been running too long
      if (record.type === 'interval' && now - record.createdAt > this.MAX_TIMER_AGE_MS) {
        toRemove.push(id);
      }
    }

    if (toRemove.length > 0) {
      debug(`Cleaning up ${toRemove.length} old intervals`);
      for (const id of toRemove) {
        this.clear(id);
      }
    }
  }

  /**
   * Reset the singleton instance (useful for testing).
   */
  public static resetInstance(): void {
    if (TimerRegistry.instance) {
      TimerRegistry.instance.clearAll();
      TimerRegistry.instance = null as any;
    }
  }
}

export default TimerRegistry;

