    return process.env[key] || fallback;
  },

  /**
   * Check if running in development mode
   */
  isDevelopment: (): boolean => {
    return process.env.NODE_ENV === 'development';
  },

  /**
   * Check if running in production mode
   */
  isProduction: (): boolean => {
    return process.env.NODE_ENV === 'production';
  },
};

/**
 * String utilities
 */
export const strings = {
  /**
   * Capitalize first letter of a string
   */
  capitalize: (str: string): string => {
    return str.charAt(0).toUpperCase() + str.slice(1);
  },

  /**
   * Truncate string to specified length
   */
  truncate: (str: string, length: number): string => {
    return str.length > length ? str.substring(0, length) + '...' : str;
  },
};

/**
 * Array utilities
 */
export const arrays = {
  /**
   * Get random element from array
   */
  random: <T>(arr: T[]): T | undefined => {
    return arr[Math.floor(Math.random() * arr.length)];
  },

  /**
   * Remove duplicates from array
   */
  unique: <T>(arr: T[]): T[] => {
    return [...new Set(arr)];
  },
};

/**
 * Validation utilities
 */
export const validation = {
  /**
   * Check if string is empty or whitespace
   */
  isEmpty: (str: string): boolean => {
    return !str || str.trim().length === 0;
  },

  /**
   * Check if value is defined and not null
   */
  isDefined: <T>(value: T | null | undefined): value is T => {
    return value !== null && value !== undefined;
  },
};

/**
 * Error Logging System for Open Hivemind
 *
 * Integrates with the existing logging system to provide structured error logging
 * with context, severity levels, and correlation IDs.
 */

import Debug from 'debug';
import { MetricsCollector } from '../monitoring/MetricsCollector';
import { BaseHivemindError } from '../types/errorClasses';
import { ErrorUtils, type HivemindError } from '../types/errors';

/**
 * Error log entry structure
 */
export interface ErrorLogEntry {
  timestamp: string;
  correlationId: string;
  level: LogLevel;
  error: {
    name: string;
    message: string;
    code: string;
    type: string;
    stack?: string;
    details?: Record<string, unknown>;
    context?: Record<string, unknown>;
  };
  request?: {
    path: string;
    method: string;
    userAgent?: string;
    ip?: string;
    userId?: string;
    requestId?: string;
    duration?: number;
    body?: any;
    params?: any;
    query?: any;
  };
  system: {
    hostname: string;
    pid: number;
    nodeVersion: string;
    platform: string;
    arch: string;
    memory: {
      used: number;
      total: number;
      external: number;
    };
  };
  recovery?: {
    canRecover: boolean;
    retryDelay?: number;
    maxRetries?: number;
    steps?: string[];
  };
}

/**
 * Log levels
 */
export type LogLevel = 'debug' | 'info' | 'warn' | 'error' | 'fatal';

/**
 * Error context interface
 */
export interface ErrorContext {
  correlationId: string;
  requestId?: string;
  userId?: string;
  path: string;
  method: string;
  userAgent?: string;
  ip?: string;
  duration?: number;
  body?: any;
  params?: any;
  query?: any;
}

/**
 * Logger configuration
 */
export interface LoggerConfig {
  level: LogLevel;
  enableConsole: boolean;
  enableFile: boolean;
  enableStructured: boolean;
  filePath?: string;
  maxFileSize?: number;
  maxFiles?: number;
  enableMetrics: boolean;
  enableTracing: boolean;
}

/**
 * Error logger class
 */
export class ErrorLogger {
  private static instance: ErrorLogger;
  private config: LoggerConfig;
  private debug: Debug.Debugger;
  private errorCounts = new Map<string, number>();
  private lastErrors = new Map<string, number>(); // correlationId -> timestamp

  constructor(config: Partial<LoggerConfig> = {}) {
    this.config = {
      level: (process.env.LOG_LEVEL as LogLevel) || 'info',
      enableConsole: process.env.NODE_ENV !== 'test',
      enableFile: process.env.NODE_ENV === 'production',
      enableStructured: true,
      filePath: process.env.ERROR_LOG_PATH || './logs/error.log',
      maxFileSize: 10 * 1024 * 1024, // 10MB
      maxFiles: 5,
      enableMetrics: true,
      enableTracing: process.env.NODE_ENV === 'development',
      ...config,
    };

    this.debug = Debug('app:error:logger');
    this.debug('Error logger initialized with config:', this.config);
  }

  static getInstance(config?: Partial<LoggerConfig>): ErrorLogger {
    if (!ErrorLogger.instance) {
      ErrorLogger.instance = new ErrorLogger(config);
    }
    return ErrorLogger.instance;
  }

  /**
   * Log an error with context
   */
  logError(error: HivemindError, context: ErrorContext): void {
    const logEntry = this.createLogEntry(error, context);
    const logLevel = this.determineLogLevel(error, context);

    // Update error counts
    this.updateErrorCounts(error);

    // Log to appropriate outputs
    this.logToConsole(logEntry, logLevel);
    this.logToFile(logEntry, logLevel);
    this.logToStructured(logEntry, logLevel);

    // Update metrics
    if (this.config.enableMetrics) {
      this.updateMetrics(error, context);
    }

    // Check for error patterns
    this.checkErrorPatterns(error, context);

    this.debug(
      `Error logged: ${(error as any).name || 'Unknown'} - ${ErrorUtils.getMessage(error)}`,
      {
        correlationId: context.correlationId,
        level: logLevel,
      }
    );
  }

  /**
   * Create a structured log entry
   */
  private createLogEntry(error: HivemindError, context: ErrorContext): ErrorLogEntry {
    const memoryUsage = process.memoryUsage();

    return {
      timestamp: new Date().toISOString(),
      correlationId: context.correlationId,
      level: this.determineLogLevel(error, context),
      error: {
        name: error instanceof Error ? error.name : 'UnknownError',
        message: ErrorUtils.getMessage(error),
        code: ErrorUtils.getCode(error) || 'UNKNOWN',
        type: this.getErrorType(error),
        stack: error instanceof Error ? error.stack : undefined,
        details: error && typeof error === 'object' ? (error as any).details : undefined,
        context: error instanceof BaseHivemindError ? error.context : undefined,
      },
      request: {
        path: context.path,
        method: context.method,
        userAgent: context.userAgent,
        ip: context.ip,
        userId: context.userId,
        requestId: context.requestId,
        duration: context.duration,
        body: context.body,
        params: context.params,
        query: context.query,
      },
      system: {
        hostname: require('os').hostname(),
        pid: process.pid,
        nodeVersion: process.version,
        platform: process.platform,
        arch: process.arch,
        memory: {
          used: memoryUsage.heapUsed,
          total: memoryUsage.heapTotal,
          external: memoryUsage.external,
        },
      },
      recovery:
        error instanceof BaseHivemindError
          ? {
              canRecover: error.getRecoveryStrategy().canRecover,
              retryDelay: error.getRecoveryStrategy().retryDelay,
              maxRetries: error.getRecoveryStrategy().maxRetries,
              steps: error.getRecoveryStrategy().recoverySteps,
            }
          : undefined,
    };
  }

  /**
   * Determine log level based on error type and context
   */
  private determineLogLevel(error: HivemindError, context: ErrorContext): LogLevel {
    void context;
    const statusCode = ErrorUtils.getStatusCode(error);
    const errorType = this.getErrorType(error);

    // Fatal errors
    if (errorType === 'configuration' || errorType === 'database') {
      return 'fatal';
    }

    // Server errors
    if (statusCode && statusCode >= 500) {
      return 'error';
    }

    // Client errors
    if (statusCode && statusCode >= 400) {
      return 'warn';
    }

    // Network and timeout errors
    if (errorType === 'network' || errorType === 'timeout') {
      return 'warn';
    }

    // Authentication and authorization errors
    if (errorType === 'authentication' || errorType === 'authorization') {
      return 'warn';
    }

    // Rate limit errors
    if (errorType === 'rate-limit') {
      return 'info';
    }

    // Validation errors
    if (errorType === 'validation') {
      return 'info';
    }

    return 'error';
  }

  /**
   * Extract error type from error object
   */
  private getErrorType(error: HivemindError): string {
    if (error && typeof error === 'object') {
      // Check for source property first (for frontend errors)
      if ('source' in error && error.source === 'frontend') {
        return 'frontend';
      }
      // Check for type property
      if ('type' in error && error.type) {
        return String(error.type);
      }
      // Check for other properties that might indicate type
      if ('name' in error && error.name) {
        return String(error.name).toLowerCase();
      }
    }
    return 'unknown';
  }

  /**
   * Log to console
   */
  private logToConsole(logEntry: ErrorLogEntry, level: LogLevel): void {
    if (!this.config.enableConsole) {
      return;
    }

    const message = `[${logEntry.level.toUpperCase()}] ${logEntry.error.message}`;
    const meta = {
      correlationId: logEntry.correlationId,
      code: logEntry.error.code,
      type: logEntry.error.type,
      path: logEntry.request?.path,
      method: logEntry.request?.method,
      userId: logEntry.request?.userId,
    };

    switch (level) {
      case 'debug':
        console.debug(message, meta);
        break;
      case 'info':
        console.info(message, meta);
        break;
      case 'warn':
        console.warn(message, meta);
        break;
      case 'error':
      case 'fatal':
        console.error(message, meta);
        if (logEntry.error.stack) {
          console.error(logEntry.error.stack);
        }
        break;
    }
  }

  /**
   * Log to file (simplified implementation)
   */
  private logToFile(logEntry: ErrorLogEntry, level: LogLevel): void {
    if (!this.config.enableFile) {
      return;
    }

    // In a real implementation, this would write to a file
    // For now, we'll use console.log with a file-like format
    const logLine = JSON.stringify(logEntry) + '\n';
    console.log(`[FILE:${level.toUpperCase()}]`, logLine);
  }

  /**
   * Log to structured output (for monitoring systems)
   */
  private logToStructured(logEntry: ErrorLogEntry, level: LogLevel): void {
    if (!this.config.enableStructured) {
      return;
    }

    // Emit structured log for monitoring systems
    if ((process as any).emit) {
      (process as any).emit('hivemind:log', {
        type: 'error',
        level,
        entry: logEntry,
      });
    }
  }

  /**
   * Update error metrics
   */
  private updateMetrics(error: HivemindError, context: ErrorContext): void {
    // Update global error count
    MetricsCollector.getInstance().incrementErrors();

    // Track error types
    const errorType = this.getErrorType(error);
    this.errorCounts.set(errorType, (this.errorCounts.get(errorType) || 0) + 1);

    // Track recent errors for pattern detection
    this.lastErrors.set(context.correlationId, Date.now());

    // Clean up old entries (keep last 1000)
    if (this.lastErrors.size > 1000) {
      const oldest = Array.from(this.lastErrors.entries()).sort((a, b) => a[1] - b[1])[0];
      if (oldest) {
        this.lastErrors.delete(oldest[0]);
      }
    }
  }

  /**
   * Update error counts
   */
  private updateErrorCounts(error: HivemindError): void {
    const errorType = this.getErrorType(error);
    this.errorCounts.set(errorType, (this.errorCounts.get(errorType) || 0) + 1);
  }

  /**
   * Check for error patterns and anomalies
   */
  private checkErrorPatterns(error: HivemindError, context: ErrorContext): void {
    void context;
    const errorType = this.getErrorType(error);
    const count = this.errorCounts.get(errorType) || 0;

    // Check for error spikes
    if (count > 10 && count % 10 === 0) {
      this.debug(`Error spike detected for type ${errorType}: ${count} occurrences`);

      // Emit alert for monitoring
      if ((process as any).emit) {
        (process as any).emit('hivemind:alert', {
          type: 'error_spike',
          errorType,
          count,
          timestamp: new Date().toISOString(),
        });
      }
    }

    // Check for repeated errors from same correlation ID
    const recentErrors = Array.from(this.lastErrors.entries()).filter(
      ([, timestamp]) => Date.now() - timestamp < 60000
    ).length; // Last minute

    if (recentErrors > 5) {
      this.debug(`High error rate detected: ${recentErrors} errors in last minute`);

      if ((process as any).emit) {
        (process as any).emit('hivemind:alert', {
          type: 'high_error_rate',
          count: recentErrors,
          timeframe: '1 minute',
          timestamp: new Date().toISOString(),
        });
      }
    }
  }

  /**
   * Get error statistics
   */
  getErrorStats(): any {
    // Calculate total errors
    const totalErrors = Array.from(this.errorCounts.values()).reduce(
      (sum, count) => sum + count,
      0
    );

    // Get error types with counts
    const errorTypes = Object.fromEntries(this.errorCounts);

    // Generate mock data for bySeverity and byDate
    const bySeverity = {
      high: Math.floor(totalErrors * 0.3),
      medium: Math.floor(totalErrors * 0.5),
      low: Math.floor(totalErrors * 0.2),
    };

    const byDate: Record<string, number> = {};
    const today = new Date();
    for (let i = 0; i < 7; i++) {
      const date = new Date(today);
      date.setDate(today.getDate() - i);
      const dateStr = date.toISOString().split('T')[0];
      byDate[dateStr] = Math.floor(totalErrors * 0.1 * (i + 1));
    }

    return {
      totalErrors,
      errorTypes,
      bySeverity,
      byDate,
    };
  }

  /**
   * Get recent error count
   */
  getRecentErrorCount(timeframeMs = 60000): number {
    const cutoff = Date.now() - timeframeMs;
    return Array.from(this.lastErrors.values()).filter((timestamp) => timestamp > cutoff).length;
  }

  /**
   * Get recent errors
   */
  getRecentErrors(
    limit = 10
  ): { error: HivemindError; context: ErrorContext; timestamp: number }[] {
    return Array.from(this.lastErrors.entries())
      .sort((a, b) => b[1] - a[1]) // Sort by timestamp descending
      .slice(0, limit)
      .map(([correlationId, timestamp]) => ({
        error: {
          name: 'RecentError',
          message: 'Recent error',
          code: 'RECENT_ERROR',
          type: 'recent',
        } as HivemindError,
        context: {
          correlationId,
          path: '',
          method: '',
        } as ErrorContext,
        timestamp,
      }));
  }

  /**
   * Clear error statistics
   */
  clearStats(): void {
    this.errorCounts.clear();
    this.lastErrors.clear();
    this.debug('Error statistics cleared');
  }

  /**
   * Set log level
   */
  setLevel(level: LogLevel): void {
    this.config.level = level;
    this.debug(`Log level set to: ${level}`);
  }

  /**
   * Get current configuration
   */
  getConfig(): LoggerConfig {
    return { ...this.config };
  }

  /**
   * Update configuration
   */
  updateConfig(config: Partial<LoggerConfig>): void {
    this.config = { ...this.config, ...config };
    this.debug('Logger configuration updated:', config);
  }
}

/**
 * Default error logger instance
 */
export const errorLogger = ErrorLogger.getInstance();

/**
 * Convenience function to log errors
 */
export function logError(error: HivemindError, context: ErrorContext): void {
  errorLogger.logError(error, context);
}

/**
 * Create error context from Express request
 */
export function createErrorContext(req: any): ErrorContext {
  return {
    correlationId: req.correlationId || req.headers['x-correlation-id'] || 'unknown',
    requestId: req.headers['x-request-id'] as string,
    userId: req.user?.id || req.user?.sub,
    path: req.path,
    method: req.method,
    userAgent: req.headers['user-agent'],
    ip: req.ip || req.connection.remoteAddress,
    duration: req.startTime ? Date.now() - req.startTime : undefined,
    body: req.body,
    params: req.params,
    query: req.query,
  };
}

/**
 * Error logging middleware
 */
export function errorLoggingMiddleware(req: any, res: any, next: any): void {
  // Add error logger to request object
  req.errorLogger = errorLogger;
  next();
}

export default {
  ErrorLogger,
  errorLogger,
  logError,
  createErrorContext,
  errorLoggingMiddleware,
};

/**
 * Error Recovery System for Open Hivemind
 *
 * Implements retry logic and fallback mechanisms for recoverable errors
 * with exponential backoff, circuit breakers, and adaptive strategies.
 */

import Debug from 'debug';
import { BaseHivemindError, TimeoutError } from '../types/errorClasses';

const debug = Debug('app:error:recovery');

/**
 * Retry configuration
 */
export interface RetryConfig {
  maxRetries: number;
  baseDelay: number;
  maxDelay: number;
  backoffMultiplier: number;
  jitter: boolean;
  retryableErrors: string[];
  retryableStatusCodes: number[];
}

/**
 * Circuit breaker configuration
 */
export interface CircuitBreakerConfig {
  failureThreshold: number;
  resetTimeout: number;
  monitoringPeriod: number;
  expectedRecoveryTime: number;
}

/**
 * Recovery strategy result
 */
export interface RecoveryResult<T = any> {
  success: boolean;
  result?: T;
  error?: Error;
  attempts: number;
  totalDuration: number;
  strategy: string;
}

/**
 * Circuit breaker states
 */
export type CircuitState = 'closed' | 'open' | 'half_open';

/**
 * Circuit breaker implementation
 */
export class CircuitBreaker {
  private state: CircuitState = 'closed';
  private failureCount = 0;
  private lastFailureTime = 0;
  private successCount = 0;

  constructor(private config: CircuitBreakerConfig) {}

  /**
   * Execute operation with circuit breaker protection
   */
  async execute<T>(operation: () => Promise<T>): Promise<T> {
    if (this.state === 'open') {
      if (this.shouldAttemptReset()) {
        this.state = 'half_open';
        debug('Circuit breaker transitioning to HALF_OPEN');
      } else {
        throw new Error('Circuit breaker is OPEN');
      }
    }

    try {
      const result = await operation();
      this.onSuccess();
      return result;
    } catch (error) {
      this.onFailure();
      throw error;
    }
  }

  /**
   * Handle successful operation
   */
  private onSuccess(): void {
    this.failureCount = 0;
    this.successCount++;

    if (this.state === 'half_open') {
      this.state = 'closed';
      debug('Circuit breaker transitioning to CLOSED');
    }
  }

  /**
   * Handle failed operation
   */
  private onFailure(): void {
    this.failureCount++;
    this.lastFailureTime = Date.now();
    this.successCount = 0;

    if (this.failureCount >= this.config.failureThreshold) {
      this.state = 'open';
      debug(`Circuit breaker transitioning to OPEN after ${this.failureCount} failures`);
    }
  }

  /**
   * Check if circuit breaker should attempt reset
   */
  private shouldAttemptReset(): boolean {
    return Date.now() - this.lastFailureTime >= this.config.resetTimeout;
  }

  /**
   * Get circuit breaker state
   */
  getState(): CircuitState {
    return this.state;
  }

  /**
   * Get circuit breaker stats
   */
  getStats() {
    return {
      state: this.state,
      failureCount: this.failureCount,
      successCount: this.successCount,
      lastFailureTime: this.lastFailureTime,
    };
  }

  /**
   * Reset circuit breaker
   */
  reset(): void {
    this.state = 'closed';
    this.failureCount = 0;
    this.successCount = 0;
    this.lastFailureTime = 0;
    debug('Circuit breaker reset to CLOSED');
  }
}

/**
 * Retry mechanism with exponential backoff
 */
export class RetryHandler {
  constructor(private config: RetryConfig) {}

  /**
   * Execute operation with retry logic
   */
  async executeWithRetry<T>(
    operation: () => Promise<T>,
    context?: Record<string, unknown>
  ): Promise<RecoveryResult<T>> {
    void context;
    const startTime = Date.now();
    let lastError: Error | undefined;

    for (let attempt = 0; attempt <= this.config.maxRetries; attempt++) {
      try {
        debug(`Executing operation, attempt ${attempt + 1}/${this.config.maxRetries + 1}`);

        const result = await operation();

        if (attempt > 0) {
          debug(`Operation succeeded on attempt ${attempt + 1}`);
        }

        return {
          success: true,
          result,
          attempts: attempt + 1,
          totalDuration: Date.now() - startTime,
          strategy: 'retry',
        };
      } catch (error) {
        lastError = error instanceof Error ? error : new Error(String(error));

        debug(`Operation failed on attempt ${attempt + 1}:`, lastError.message);

        // Check if error is retryable
        if (!this.isRetryableError(lastError) && attempt < this.config.maxRetries) {
          debug(`Error is not retryable: ${lastError.message}`);
          break;
        }

        // Don't wait on the last attempt
        if (attempt < this.config.maxRetries) {
          const delay = this.calculateDelay(attempt);
          debug(`Waiting ${delay}ms before retry...`);
          await this.sleep(delay);
        }
      }
    }

    return {
      success: false,
      error: lastError,
      attempts: this.config.maxRetries + 1,
      totalDuration: Date.now() - startTime,
      strategy: 'retry',
    };
  }

  /**
   * Check if error is retryable
   */
  private isRetryableError(error: Error): boolean {
    // Check by error code
    if (this.config.retryableErrors.includes(error.name)) {
      return true;
    }

    // Check by status code (for HTTP errors)
    const statusCode = this.extractStatusCode(error);
    if (statusCode && this.config.retryableStatusCodes.includes(statusCode)) {
      return true;
    }

    // Check BaseHivemindError retryable flag
    if (error instanceof BaseHivemindError && error.retryable) {
      return true;
    }

    // Check error message patterns
    const message = error.message.toLowerCase();
    const retryablePatterns = [
      'timeout',
      'connection',
      'network',
      'temporary',
      'service unavailable',
      'rate limit',
    ];

    return retryablePatterns.some((pattern) => message.includes(pattern));
  }

  /**
   * Extract status code from error
   */
  private extractStatusCode(error: Error): number | undefined {
    if (error instanceof BaseHivemindError) {
      return error.statusCode;
    }

    // Try to extract from error message or properties
    const statusCodeMatch = error.message.match(/status\s*:\s*(\d+)/i);
    if (statusCodeMatch) {
      return parseInt(statusCodeMatch[1]);
    }

    return undefined;
  }

  /**
   * Calculate delay with exponential backoff and jitter
   */
  private calculateDelay(attempt: number): number {
    let delay = this.config.baseDelay * Math.pow(this.config.backoffMultiplier, attempt);

    // Apply maximum delay limit
    delay = Math.min(delay, this.config.maxDelay);

    // Add jitter if enabled
    if (this.config.jitter) {
      const jitterRange = delay * 0.1;
      delay += Math.random() * jitterRange - jitterRange / 2;
    }

    return Math.max(0, Math.floor(delay));
  }

  /**
   * Sleep for specified milliseconds
   */
  private sleep(ms: number): Promise<void> {
    return new Promise((resolve) => setTimeout(resolve, ms));
  }
}

/**
 * Fallback mechanism manager
 */
export class FallbackManager {
  private fallbacks = new Map<string, (() => Promise<any>)[]>();

  /**
   * Register fallback for an operation
   */
  registerFallback(operationKey: string, fallback: () => Promise<any>): void {
    if (!this.fallbacks.has(operationKey)) {
      this.fallbacks.set(operationKey, []);
    }
    this.fallbacks.get(operationKey)!.push(fallback);
  }

  /**
   * Execute operation with fallbacks
   */
  async executeWithFallback<T>(
    operationKey: string,
    primaryOperation: () => Promise<T>,
    context?: Record<string, unknown>
  ): Promise<RecoveryResult<T>> {
    void context;
    const startTime = Date.now();
    const fallbacks = this.fallbacks.get(operationKey) || [];

    // Try primary operation first
    try {
      const result = await primaryOperation();
      return {
        success: true,
        result,
        attempts: 1,
        totalDuration: Date.now() - startTime,
        strategy: 'primary',
      };
    } catch (primaryError) {
      const error = primaryError instanceof Error ? primaryError : new Error(String(primaryError));
      debug(`Primary operation failed: ${error.message}`);

      // Try fallbacks in order
      for (let i = 0; i < fallbacks.length; i++) {
        try {
          debug(`Attempting fallback ${i + 1}/${fallbacks.length}`);
          const result = await fallbacks[i]();

          debug(`Fallback ${i + 1} succeeded`);
          return {
            success: true,
            result,
            attempts: i + 2, // primary + this fallback
            totalDuration: Date.now() - startTime,
            strategy: `fallback_${i + 1}`,
          };
        } catch (fallbackError) {
          const fallbackErr =
            fallbackError instanceof Error ? fallbackError : new Error(String(fallbackError));
          debug(`Fallback ${i + 1} failed: ${fallbackErr.message}`);
        }
      }

      // All fallbacks failed
      return {
        success: false,
        error,
        attempts: 1 + fallbacks.length,
        totalDuration: Date.now() - startTime,
        strategy: 'failed',
      };
    }
  }

  /**
   * Get registered fallbacks for an operation
   */
  getFallbacks(operationKey: string): (() => Promise<any>)[] {
    return this.fallbacks.get(operationKey) || [];
  }

  /**
   * Clear fallbacks for an operation
   */
  clearFallbacks(operationKey: string): void {
    this.fallbacks.delete(operationKey);
  }

  /**
   * Clear all fallbacks
   */
  clearAllFallbacks(): void {
    this.fallbacks.clear();
  }
}

/**
 * Adaptive recovery manager that combines retry, circuit breaker, and fallback strategies
 */
export class AdaptiveRecoveryManager {
  private circuitBreakers = new Map<string, CircuitBreaker>();
  private retryHandlers = new Map<string, RetryHandler>();
  private fallbackManagers = new Map<string, FallbackManager>();

  constructor(
    private defaultRetryConfig: RetryConfig,
    private defaultCircuitBreakerConfig: CircuitBreakerConfig
  ) {}

  /**
   * Execute operation with adaptive recovery
   */
  async execute<T>(
    operationKey: string,
    operation: () => Promise<T>,
    options: {
      enableRetry?: boolean;
      enableCircuitBreaker?: boolean;
      enableFallback?: boolean;
      retryConfig?: Partial<RetryConfig>;
      circuitBreakerConfig?: Partial<CircuitBreakerConfig>;
      context?: Record<string, unknown>;
    } = {}
  ): Promise<RecoveryResult<T>> {
    const {
      enableRetry = true,
      enableCircuitBreaker = true,
      enableFallback = true,
      retryConfig = {},
      circuitBreakerConfig = {},
      context = {},
    } = options;

    debug(`Executing operation ${operationKey} with adaptive recovery`);

    // Get or create handlers
    const retryHandler = this.getRetryHandler(operationKey, retryConfig);
    const circuitBreaker = this.getCircuitBreaker(operationKey, circuitBreakerConfig);
    const fallbackManager = this.getFallbackManager(operationKey);

    // Wrap operation with circuit breaker if enabled
    const protectedOperation = enableCircuitBreaker
      ? () => circuitBreaker.execute(operation)
      : operation;

    // Try with retry first
    if (enableRetry) {
      const retryResult = await retryHandler.executeWithRetry(protectedOperation, context);
      if (retryResult.success) {
        return retryResult;
      }
      debug(`Retry strategy failed for ${operationKey}`);
    } else {
      try {
        const result = await protectedOperation();
        return {
          success: true,
          result,
          attempts: 1,
          totalDuration: 0,
          strategy: 'direct',
        };
      } catch (error) {
        debug(`Direct execution failed for ${operationKey}: ${error}`);
      }
    }

    // Try fallbacks if enabled
    if (enableFallback) {
      debug(`Attempting fallbacks for ${operationKey}`);
      const fallbackResult = await fallbackManager.executeWithFallback(
        operationKey,
        operation,
        context
      );

      if (fallbackResult.success) {
        return fallbackResult;
      }
    }

    // All strategies failed
    return {
      success: false,
      error: new Error(`All recovery strategies failed for ${operationKey}`),
      attempts: 1,
      totalDuration: 0,
      strategy: 'failed',
    };
  }

  /**
   * Get or create retry handler
   */
  public getRetryHandler(operationKey: string, config: Partial<RetryConfig> = {}): RetryHandler {
    if (!this.retryHandlers.has(operationKey)) {
      const mergedConfig = { ...this.defaultRetryConfig, ...config };
      this.retryHandlers.set(operationKey, new RetryHandler(mergedConfig));
    }
    return this.retryHandlers.get(operationKey)!;
  }

  /**
   * Get or create circuit breaker
   */
  public getCircuitBreaker(
    operationKey: string,
    config: Partial<CircuitBreakerConfig> = {}
  ): CircuitBreaker {
    if (!this.circuitBreakers.has(operationKey)) {
      const mergedConfig = { ...this.defaultCircuitBreakerConfig, ...config };
      this.circuitBreakers.set(operationKey, new CircuitBreaker(mergedConfig));
    }
    return this.circuitBreakers.get(operationKey)!;
  }

  /**
   * Get or create fallback manager
   */
  public getFallbackManager(operationKey: string): FallbackManager {
    if (!this.fallbackManagers.has(operationKey)) {
      this.fallbackManagers.set(operationKey, new FallbackManager());
    }
    return this.fallbackManagers.get(operationKey)!;
  }

  /**
   * Register fallback for an operation
   */
  registerFallback(operationKey: string, fallback: () => Promise<any>): void {
    this.getFallbackManager(operationKey).registerFallback(operationKey, fallback);
  }

  /**
   * Get circuit breaker stats
   */
  getCircuitBreakerStats(operationKey: string) {
    const circuitBreaker = this.circuitBreakers.get(operationKey);
    return circuitBreaker ? circuitBreaker.getStats() : null;
  }

  /**
   * Reset circuit breaker
   */
  resetCircuitBreaker(operationKey: string): void {
    const circuitBreaker = this.circuitBreakers.get(operationKey);
    if (circuitBreaker) {
      circuitBreaker.reset();
    }
  }

  /**
   * Get all recovery stats
   */
  getAllStats() {
    const stats: Record<string, any> = {};

    for (const [key, circuitBreaker] of this.circuitBreakers.entries()) {
      stats[key] = {
        circuitBreaker: circuitBreaker.getStats(),
        fallbacks: this.fallbackManagers.get(key)?.getFallbacks(key).length || 0,
      };
    }

    return stats;
  }
}

/**
 * Default configurations
 */
export const DEFAULT_RETRY_CONFIG: RetryConfig = {
  maxRetries: 3,
  baseDelay: 1000,
  maxDelay: 30000,
  backoffMultiplier: 2,
  jitter: true,
  retryableErrors: ['NetworkError', 'TimeoutError', 'ApiError'],
  retryableStatusCodes: [408, 429, 500, 502, 503, 504],
};

export const DEFAULT_CIRCUIT_BREAKER_CONFIG: CircuitBreakerConfig = {
  failureThreshold: 5,
  resetTimeout: 60000, // 1 minute
  monitoringPeriod: 10000, // 10 seconds
  expectedRecoveryTime: 30000, // 30 seconds
};

/**
 * Global recovery manager instance
 */
export const globalRecoveryManager = new AdaptiveRecoveryManager(
  DEFAULT_RETRY_CONFIG,
  DEFAULT_CIRCUIT_BREAKER_CONFIG
);

/**
 * Convenience instance for direct access to recovery methods
 */
export const errorRecovery = {
  withRetry: (fn: () => Promise<any>, config?: Partial<RetryConfig>) =>
    globalRecoveryManager.getRetryHandler('default', config).executeWithRetry(fn),
  withFallback: async (primary: () => Promise<any>, fallback: () => Promise<any>) => {
    const fallbackManager = globalRecoveryManager.getFallbackManager('default');
    fallbackManager.registerFallback('default', fallback);
    return fallbackManager.executeWithFallback('default', primary, {});
  },
  withCircuitBreaker: (fn: () => Promise<any>, config?: Partial<CircuitBreakerConfig>) =>
    globalRecoveryManager.getCircuitBreaker('default', config).execute(fn),
  withTimeout: async (fn: () => Promise<any>, timeoutMs: number) => {
    const startTime = Date.now();
    try {
      const result = await Promise.race([
        fn(),
        new Promise((_, reject) =>
          setTimeout(() => reject(new TimeoutError('Operation timed out', timeoutMs)), timeoutMs)
        ),
      ]);
      return {
        success: true,
        result,
        attempts: 1,
        totalDuration: Date.now() - startTime,
        strategy: 'timeout',
      };
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error : new Error(String(error)),
        attempts: 1,
        totalDuration: Date.now() - startTime,
        strategy: 'timeout',
      };
    }
  },
};

/**
 * Convenience function to execute with recovery
 */
export async function executeWithRecovery<T>(
  operationKey: string,
  operation: () => Promise<T>,
  options?: {
    enableRetry?: boolean;
    enableCircuitBreaker?: boolean;
    enableFallback?: boolean;
    retryConfig?: Partial<RetryConfig>;
    circuitBreakerConfig?: Partial<CircuitBreakerConfig>;
    context?: Record<string, unknown>;
  }
): Promise<RecoveryResult<T>> {
  return globalRecoveryManager.execute(operationKey, operation, options);
}

/**
 * Register a fallback for an operation
 */
export function registerFallback(operationKey: string, fallback: () => Promise<any>): void {
  globalRecoveryManager.registerFallback(operationKey, fallback);
}

export default {
  RetryHandler,
  CircuitBreaker,
  FallbackManager,
  AdaptiveRecoveryManager,
  globalRecoveryManager,
  executeWithRecovery,
  registerFallback,
  DEFAULT_RETRY_CONFIG,
  DEFAULT_CIRCUIT_BREAKER_CONFIG,
};

/**
 * Error Response Utilities for Open Hivemind
 *
 * Utility functions for creating standardized error responses with proper
 * HTTP status codes, error codes, and structured data.
 */

import type { Response } from 'express';
import { BaseHivemindError } from '../types/errorClasses';
import { ErrorUtils, type HivemindError } from '../types/errors';

/**
 * Standard error response structure
 */
export interface StandardErrorResponse {
  success: false;
  error: {
    code: string;
    message: string;
    type: string;
    correlationId?: string;
    timestamp: string;
    details?: Record<string, unknown>;
    recovery?: {
      canRecover: boolean;
      retryDelay?: number;
      maxRetries?: number;
      steps?: string[];
    };
  };
  request?: {
    path?: string;
    method?: string;
    correlationId?: string;
  };
  stack?: string; // Only in development
}

/**
 * Success response structure for consistency
 */
export interface StandardSuccessResponse<T = any> {
  success: true;
  data: T;
  meta?: {
    timestamp: string;
    correlationId?: string;
    version?: string;
  };
}

/**
 * HTTP Status Code mappings for error types
 */
export const HTTP_STATUS_CODES = {
  // Success
  OK: 200,
  CREATED: 201,
  ACCEPTED: 202,
  NO_CONTENT: 204,

  // Redirection
  MOVED_PERMANENTLY: 301,
  FOUND: 302,
  NOT_MODIFIED: 304,

  // Client Errors
  BAD_REQUEST: 400,
  UNAUTHORIZED: 401,
  FORBIDDEN: 403,
  NOT_FOUND: 404,
  METHOD_NOT_ALLOWED: 405,
  NOT_ACCEPTABLE: 406,
  REQUEST_TIMEOUT: 408,
  CONFLICT: 409,
  GONE: 410,
  PAYLOAD_TOO_LARGE: 413,
  UNSUPPORTED_MEDIA_TYPE: 415,
  TOO_MANY_REQUESTS: 429,

  // Server Errors
  INTERNAL_SERVER_ERROR: 500,
  NOT_IMPLEMENTED: 501,
  BAD_GATEWAY: 502,
  SERVICE_UNAVAILABLE: 503,
  GATEWAY_TIMEOUT: 504,
  NETWORK_AUTHENTICATION_REQUIRED: 511,
} as const;

/**
 * Error response builder class
 */
export class ErrorResponseBuilder {
  private response: StandardErrorResponse;

  constructor(error: HivemindError, correlationId?: string) {
    this.response = {
      success: false,
      error: {
        code: ErrorUtils.getCode(error) || 'UNKNOWN_ERROR',
        message: ErrorUtils.getMessage(error),
        type: this.getErrorType(error),
        correlationId,
        timestamp: new Date().toISOString(),
      },
    };

    // Add error details if available
    if (error && typeof error === 'object' && 'details' in error) {
      this.response.error.details = error.details as Record<string, unknown>;
    }

    // Add recovery information if it's a BaseHivemindError
    if (error instanceof BaseHivemindError) {
      const recovery = error.getRecoveryStrategy();
      this.response.error.recovery = {
        canRecover: recovery.canRecover,
        retryDelay: recovery.retryDelay,
        maxRetries: recovery.maxRetries,
        steps: recovery.recoverySteps,
      };
    }
  }

  /**
   * Add request information to the error response
   */
  withRequest(path?: string, method?: string, correlationId?: string): ErrorResponseBuilder {
    this.response.request = {
      path,
      method,
      correlationId,
    };
    return this;
  }

  /**
   * Add additional details to the error response
   */
  withDetails(details: Record<string, unknown>): ErrorResponseBuilder {
    this.response.error.details = {
      ...this.response.error.details,
      ...details,
    };
    return this;
  }

  /**
   * Override the error message (useful for security in production)
   */
  withMessage(message: string): ErrorResponseBuilder {
    this.response.error.message = message;
    return this;
  }

  /**
   * Build the final error response
   */
  build(): StandardErrorResponse {
    return { ...this.response };
  }

  /**
   * Get the appropriate HTTP status code for this error
   */
  getStatusCode(): number {
    const error = this.response.error;

    // Check for specific status codes
    switch (error.code) {
      case 'VALIDATION_ERROR':
        return HTTP_STATUS_CODES.BAD_REQUEST;
      case 'AUTH_ERROR':
        return HTTP_STATUS_CODES.UNAUTHORIZED;
      case 'AUTHZ_ERROR':
        return HTTP_STATUS_CODES.FORBIDDEN;
      case 'NOT_FOUND':
        return HTTP_STATUS_CODES.NOT_FOUND;
      case 'RATE_LIMIT_ERROR':
        return HTTP_STATUS_CODES.TOO_MANY_REQUESTS;
      case 'TIMEOUT_ERROR':
        return HTTP_STATUS_CODES.REQUEST_TIMEOUT;
      case 'CONFIG_ERROR':
        return HTTP_STATUS_CODES.INTERNAL_SERVER_ERROR;
      case 'DATABASE_ERROR':
        return HTTP_STATUS_CODES.INTERNAL_SERVER_ERROR;
      case 'NETWORK_ERROR':
        // Check if it's a client or server error
        if (error.details && typeof error.details === 'object' && 'response' in error.details) {
          const response = (error.details as any).response;
          if (response && typeof response === 'object' && 'status' in response) {
            const status = Number(response.status);
            if (status >= 400 && status < 600) {
              return status;
            }
          }
        }
        return HTTP_STATUS_CODES.INTERNAL_SERVER_ERROR;
      default:
        return HTTP_STATUS_CODES.INTERNAL_SERVER_ERROR;
    }
  }

  /**
   * Extract error type from error object
   */
  private getErrorType(error: HivemindError): string {
    if (error && typeof error === 'object' && 'type' in error) {
      return String(error.type);
    }
    return 'unknown';
  }
}

/**
 * Success response builder class
 */
export class SuccessResponseBuilder<T = any> {
  private response: StandardSuccessResponse<T>;

  constructor(data: T, correlationId?: string) {
    this.response = {
      success: true,
      data,
      meta: {
        timestamp: new Date().toISOString(),
        correlationId,
      },
    };
  }

  /**
   * Add metadata to the success response
   */
  withMeta(meta: Partial<StandardSuccessResponse<T>['meta']>): SuccessResponseBuilder<T> {
    this.response.meta = {
      ...this.response.meta,
      ...meta,
    } as StandardSuccessResponse<T>['meta'];
    return this;
  }

  /**
   * Build the final success response
   */
  build(): StandardSuccessResponse<T> {
    return { ...this.response };
  }
}

/**
 * Create a standardized error response
 */
export function createErrorResponse(
  error: HivemindError,
  correlationId?: string
): ErrorResponseBuilder {
  return new ErrorResponseBuilder(error, correlationId);
}

/**
 * Create a standardized success response
 */
export function createSuccessResponse<T>(
  data: T,
  correlationId?: string
): SuccessResponseBuilder<T> {
  return new SuccessResponseBuilder(data, correlationId);
}

/**
 * Send error response with Express
 */
export function sendErrorResponse(
  res: Response,
  error: HivemindError,
  correlationId?: string,
  requestInfo?: { path?: string; method?: string }
): Response {
  const builder = createErrorResponse(error, correlationId);

  if (requestInfo) {
    builder.withRequest(requestInfo.path, requestInfo.method, correlationId);
  }

  const errorResponse = builder.build();
  const statusCode = builder.getStatusCode();

  // Set correlation ID header if not already set
  if (correlationId && !res.getHeader('X-Correlation-ID')) {
    res.setHeader('X-Correlation-ID', correlationId);
  }

  return res.status(statusCode).json(errorResponse);
}

/**
 * Send success response with Express
 */
export function sendSuccessResponse<T>(
  res: Response,
  data: T,
  correlationId?: string,
  meta?: Partial<StandardSuccessResponse<T>['meta']>
): Response {
  const builder = createSuccessResponse(data, correlationId);

  if (meta) {
    builder.withMeta(meta);
  }

  const successResponse = builder.build();

  // Set correlation ID header if not already set
  if (correlationId && !res.getHeader('X-Correlation-ID')) {
    res.setHeader('X-Correlation-ID', correlationId);
  }

  return res.status(HTTP_STATUS_CODES.OK).json(successResponse);
}

/**
 * Common error response creators
 */
export const ErrorResponses = {
  /**
   * Bad request error (400)
   */
  badRequest(message: string, details?: Record<string, unknown>): ErrorResponseBuilder {
    const error = {
      code: 'BAD_REQUEST',
      message,
      type: 'validation' as const,
      details,
    };
    return createErrorResponse(error);
  },

  /**
   * Unauthorized error (401)
   */
  unauthorized(message = 'Authentication required'): ErrorResponseBuilder {
    const error = {
      code: 'UNAUTHORIZED',
      message,
      type: 'authentication' as const,
    };
    return createErrorResponse(error);
  },

  /**
   * Forbidden error (403)
   */
  forbidden(message = 'Access denied'): ErrorResponseBuilder {
    const error = {
      code: 'FORBIDDEN',
      message,
      type: 'authorization' as const,
    };
    return createErrorResponse(error);
  },

  /**
   * Not found error (404)
   */
  notFound(resource = 'Resource'): ErrorResponseBuilder {
    const error = {
      code: 'NOT_FOUND',
      message: `${resource} not found`,
      type: 'api' as const,
    };
    return createErrorResponse(error);
  },

  /**
   * Method not allowed error (405)
   */
  methodNotAllowed(method: string, allowedMethods: string[] = []): ErrorResponseBuilder {
    const error = {
      code: 'METHOD_NOT_ALLOWED',
      message: `Method ${method} not allowed`,
      type: 'api' as const,
      details: { allowedMethods },
    };
    return createErrorResponse(error);
  },

  /**
   * Conflict error (409)
   */
  conflict(message: string, details?: Record<string, unknown>): ErrorResponseBuilder {
    const error = {
      code: 'CONFLICT',
      message,
      type: 'api' as const,
      details,
    };
    return createErrorResponse(error);
  },

  /**
   * Too many requests error (429)
   */
  tooManyRequests(retryAfter?: number, limit?: number): ErrorResponseBuilder {
    const error = {
      code: 'TOO_MANY_REQUESTS',
      message: 'Rate limit exceeded',
      type: 'rate-limit' as const,
      details: { retryAfter, limit },
    };
    return createErrorResponse(error);
  },

  /**
   * Internal server error (500)
   */
  internalServerError(message = 'Internal server error'): ErrorResponseBuilder {
    const error = {
      code: 'INTERNAL_SERVER_ERROR',
      message,
      type: 'unknown' as const,
    };
    return createErrorResponse(error);
  },

  /**
   * Service unavailable error (503)
   */
  serviceUnavailable(message = 'Service temporarily unavailable'): ErrorResponseBuilder {
    const error = {
      code: 'SERVICE_UNAVAILABLE',
      message,
      type: 'api' as const,
    };
    return createErrorResponse(error);
  },

  /**
   * Validation error (400)
   */
  validation(
    field: string,
    value: any,
    expected: any,
    suggestions?: string[]
  ): ErrorResponseBuilder {
    const error = {
      code: 'VALIDATION_ERROR',
      message: `Validation failed for field: ${field}`,
      type: 'validation' as const,
      details: { field, value, expected, suggestions },
    };
    return createErrorResponse(error);
  },

  /**
   * Configuration error (500)
   */
  configuration(
    configKey: string,
    expectedType: string,
    providedType: string
  ): ErrorResponseBuilder {
    const error = {
      code: 'CONFIG_ERROR',
      message: `Configuration error for ${configKey}`,
      type: 'configuration' as const,
      details: { configKey, expectedType, providedType },
    };
    return createErrorResponse(error);
  },

  /**
   * Database error (500)
   */
  database(operation: string, table?: string, query?: string): ErrorResponseBuilder {
    const error = {
      code: 'DATABASE_ERROR',
      message: `Database error during ${operation}`,
      type: 'database' as const,
      details: { operation, table, query },
    };
    return createErrorResponse(error);
  },

  /**
   * Network error (500/4xx)
   */
  network(message: string, statusCode?: number, response?: any): ErrorResponseBuilder {
    const error = {
      code: 'NETWORK_ERROR',
      message,
      type: 'network' as const,
      details: { response },
    };
    return createErrorResponse(error);
  },

  /**
   * Timeout error (408)
   */
  timeout(operation: string, timeoutMs: number): ErrorResponseBuilder {
    const error = {
      code: 'TIMEOUT_ERROR',
      message: `Operation ${operation} timed out after ${timeoutMs}ms`,
      type: 'timeout' as const,
      details: { operation, timeoutMs },
    };
    return createErrorResponse(error);
  },
};

/**
 * Response utility functions for common patterns
 */
export const ResponseUtils = {
  /**
   * Send a paginated response
   */
  paginated<T>(
    res: Response,
    data: T[],
    page: number,
    limit: number,
    total: number,
    correlationId?: string
  ): Response {
    const totalPages = Math.ceil(total / limit);

    return sendSuccessResponse(
      res,
      {
        items: data,
        pagination: {
          page,
          limit,
          total,
          totalPages,
          hasNext: page < totalPages,
          hasPrev: page > 1,
        },
      },
      correlationId
    );
  },

  /**
   * Send a created response (201)
   */
  created<T>(res: Response, data: T, correlationId?: string, location?: string): Response {
    const response = createSuccessResponse(data, correlationId).build();

    if (location) {
      res.setHeader('Location', location);
    }

    if (correlationId && !res.getHeader('X-Correlation-ID')) {
      res.setHeader('X-Correlation-ID', correlationId);
    }

    return res.status(HTTP_STATUS_CODES.CREATED).json(response);
  },

  /**
   * Send an accepted response (202)
   */
  accepted<T>(res: Response, data: T, correlationId?: string): Response {
    const response = createSuccessResponse(data, correlationId).build();

    if (correlationId && !res.getHeader('X-Correlation-ID')) {
      res.setHeader('X-Correlation-ID', correlationId);
    }

    return res.status(HTTP_STATUS_CODES.ACCEPTED).json(response);
  },

  /**
   * Send a no content response (204)
   */
  noContent(res: Response, correlationId?: string): Response {
    if (correlationId && !res.getHeader('X-Correlation-ID')) {
      res.setHeader('X-Correlation-ID', correlationId);
    }

    return res.status(HTTP_STATUS_CODES.NO_CONTENT).send();
  },
};

export default {
  createErrorResponse,
  createSuccessResponse,
  sendErrorResponse,
  sendSuccessResponse,
  ErrorResponses,
  ResponseUtils,
  HTTP_STATUS_CODES,
};

/**
 * Parser utilities for various data formats
 */

/**
 * Command parser utilities
 */
export const commandParser = {
  /**
   * Parse a command string into command and arguments
   */
  parse: (input: string): { command?: string; args: string[] } => {
    if (!input || typeof input !== 'string') {
      return { args: [] };
    }

    const trimmed = input.trim();
    if (!trimmed) {
      return { args: [] };
    }

    // Check if it's a command (starts with ! or /)
    if (!trimmed.startsWith('!') && !trimmed.startsWith('/')) {
      return { args: [] };
    }

    const parts = trimmed.slice(1).split(/\s+/);
    const command = parts[0];
    const args = parts.slice(1);

    return { command, args };
  },
};

/**
 * Message parsing utilities
 */
export const messageParser = {
  /**
   * Extract mentions from message text
   */
  extractMentions: (text: string): string[] => {
    const mentionRegex = /<@([^>]+)>/g;
    const mentions: string[] = [];
    let match;

    while ((match = mentionRegex.exec(text)) !== null) {
      mentions.push(match[1]);
    }

    return mentions;
  },

  /**
   * Extract channel mentions from message text
   */
  extractChannelMentions: (text: string): string[] => {
    const channelRegex = /<#([^>]+)>/g;
    const mentions: string[] = [];
    let match;

    while ((match = channelRegex.exec(text)) !== null) {
      mentions.push(match[1]);
    }

    return mentions;
  },

  /**
   * Remove formatting from message text
   */
  stripFormatting: (text: string): string => {
    return text
      .replace(/```[\s\S]*?```/g, '') // Remove code blocks
      .replace(/<[^>]+>/g, '') // Remove Slack mentions
      .replace(/\*([^*]+)\*/g, '$1') // Remove bold
      .replace(/_([^_]+)_/g, '$1') // Remove italic
      .replace(/`([^`]+)`/g, '$1') // Remove inline code
      .trim();
  },
};

/**
 * JSON parsing utilities with error handling
 */
export const jsonParser = {
  /**
   * Safely parse JSON with fallback
   */
  safeParse: <T = any>(jsonString: string, fallback: T): T => {
    try {
      return JSON.parse(jsonString);
    } catch {
      return fallback;
    }
  },

  /**
   * Safely stringify JSON with error handling
   */
  safeStringify: (obj: any, fallback = '{}'): string => {
    try {
      return JSON.stringify(obj);
    } catch {
      return fallback;
    }
  },
};

/**
 * Number parsing utilities
 */
export const numberParser = {
  /**
   * Parse number with fallback
   */
  parseNumber: (value: string | number, fallback = 0): number => {
    if (typeof value === 'number') {
      return isNaN(value) ? fallback : value;
    }

    const parsed = parseFloat(value);
    return isNaN(parsed) ? fallback : parsed;
  },

  /**
   * Parse integer with fallback
   */
  parseInt: (value: string | number, fallback = 0): number => {
    if (typeof value === 'number') {
      if (isNaN(value)) return fallback;
      return Math.floor(value);
    }

    const parsed = global.parseInt(value, 10);
    return isNaN(parsed) ? fallback : parsed;
  },
};

/**
 * Serializes a convict configuration schema into a JSON-friendly format.
 * Primarily handles converting constructor functions (String, Number, etc.) in 'format' field to strings.
 */
export function serializeSchema(schema: any): any {
  if (schema === null || typeof schema !== 'object') {
    return schema;
  }

  if (Array.isArray(schema)) {
    return schema.map((item) => serializeSchema(item));
  }

  // If this object looks like a schema leaf node with a function format
  if ('format' in schema && typeof schema.format === 'function') {
    const copy = { ...schema };
    const fnName = schema.format.name;
    copy.format = fnName || 'custom';

    // Recursively process other properties (e.g. default value might be an object)
    for (const key in copy) {
      if (key !== 'format') {
        copy[key] = serializeSchema(copy[key]);
      }
    }
    return copy;
  }

  const result: any = {};
  for (const key in schema) {
    if (Object.prototype.hasOwnProperty.call(schema, key)) {
      result[key] = serializeSchema(schema[key]);
    }
  }
  return result;
}

import dns from 'dns';
import net from 'net';

/**
 * Checks if a URL is safe to connect to (SSRF protection).
 *
 * Validates:
 * 1. Protocol is http, https, ws, or wss.
 * 2. Hostname resolves to a public IP address.
 * 3. IP address is not in private/reserved ranges.
 *
 * Can be bypassed by setting ALLOW_LOCAL_NETWORK_ACCESS=true environment variable.
 *
 * @param url The URL to check
 * @returns Promise resolving to true if safe, false otherwise
 */
export async function isSafeUrl(url: string): Promise<boolean> {
  // 1. Protocol Check
  try {
    const parsedUrl = new URL(url);
    const protocol = parsedUrl.protocol.toLowerCase();

    // Only allow HTTP/S and WS/S protocols
    if (!['http:', 'https:', 'ws:', 'wss:'].includes(protocol)) {
      return false;
    }

    // Allow loopback/private IPs if explicitly configured
    if (process.env.ALLOW_LOCAL_NETWORK_ACCESS === 'true') {
      return true;
    }

    const hostname = parsedUrl.hostname;

    // Check if hostname is an IP literal
    if (net.isIP(hostname)) {
      return !isPrivateIP(hostname);
    }

    // Resolve hostname to IP
    try {
      const { address } = await dns.promises.lookup(hostname);
      return !isPrivateIP(address);
    } catch (error) {
      // DNS resolution failed - treat as unsafe
      return false;
    }
  } catch (error) {
    // Invalid URL format
    return false;
  }
}

/**
 * Checks if an IP address is private or reserved.
 * @param ip The IP address to check
 * @returns true if private/reserved, false if public
 */
export function isPrivateIP(ip: string): boolean {
  if (net.isIPv4(ip)) {
    return isPrivateIPv4(ip);
  } else if (net.isIPv6(ip)) {
    return isPrivateIPv6(ip);
  }
  return false; // Invalid IP
}

function isPrivateIPv4(ip: string): boolean {
  const parts = ip.split('.').map(Number);
  if (parts.length !== 4) return false;

  const [a, b, c, d] = parts;

  // 10.0.0.0/8
  if (a === 10) return true;

  // 172.16.0.0/12
  if (a === 172 && b >= 16 && b <= 31) return true;

  // 192.168.0.0/16
  if (a === 192 && b === 168) return true;

  // 127.0.0.0/8 (Loopback)
  if (a === 127) return true;

  // 169.254.0.0/16 (Link-local)
  if (a === 169 && b === 254) return true;

  // 0.0.0.0/8 (Current network)
  if (a === 0) return true;

  return false;
}

function isPrivateIPv6(ip: string): boolean {
  // Normalize IPv6 address (handle :: compression)
  // Simple check for common private ranges

  // ::1 (Loopback)
  if (ip === '::1' || ip === '0:0:0:0:0:0:0:1') return true;

  // :: (Unspecified)
  if (ip === '::' || ip === '0:0:0:0:0:0:0:0') return true;

  // fc00::/7 (Unique Local)
  // standard format usually starts with fc or fd
  const firstBlock = ip.split(':')[0].toLowerCase();
  if (firstBlock.startsWith('fc') || firstBlock.startsWith('fd')) return true;

  // fe80::/10 (Link Local)
  if (
    firstBlock.startsWith('fe8') ||
    firstBlock.startsWith('fe9') ||
    firstBlock.startsWith('fea') ||
    firstBlock.startsWith('feb')
  )
    return true;

  // IPv4 Mapped Address (::ffff:127.0.0.1)
  if (ip.toLowerCase().startsWith('::ffff:')) {
    const ipv4Part = ip.split(':').pop();
    if (ipv4Part && net.isIPv4(ipv4Part)) {
      return isPrivateIPv4(ipv4Part);
    }
  }

  return false;
}

/**
 * @fileoverview Enhanced startup diagnostics and visibility module
 * @module utils/startupDiagnostics
 * @description Provides comprehensive startup visibility with credential redaction
 */

import * as fs from 'fs';
import * as path from 'path';
import { Logger } from '../common/logger';
import { redactSensitiveInfo } from '../common/redactSensitiveInfo';

const startupLog = Logger.withContext('startup:diagnostics');

interface EnvironmentSummary {
  critical: { key: string; value: string; status: 'present' | 'missing' | 'invalid' }[];
  optional: { key: string; value: string; status: 'present' | 'missing' }[];
  featureFlags: { key: string; value: string; description: string }[];
}

interface ProviderStatus {
  type: string;
  configured: boolean;
  connected: boolean;
  details?: any;
}

interface SystemResources {
  memoryUsage: NodeJS.MemoryUsage;
  freeDiskSpace: number;
  nodeVersion: string;
  platform: string;
}

export class StartupDiagnostics {
  private static instance: StartupDiagnostics;

  public static getInstance(): StartupDiagnostics {
    if (!StartupDiagnostics.instance) {
      StartupDiagnostics.instance = new StartupDiagnostics();
    }
    return StartupDiagnostics.instance;
  }

  /**
   * Log comprehensive startup diagnostics with credential redaction
   */
  public async logStartupDiagnostics(): Promise<void> {
    startupLog.info('🔍 Starting comprehensive startup diagnostics...');

    try {
      await this.logEnvironmentSummary();
      await this.logConfigurationStatus();
      await this.logProviderConnectivity();
      await this.logApiWebUiStatus();
      await this.logSystemResources();
      await this.logFeatureFlags();

      startupLog.info('✅ Startup diagnostics complete');
    } catch (error) {
      startupLog.error('❌ Error during startup diagnostics', { error });
    }
  }

  /**
   * Log environment variable summary with credential redaction
   */
  private async logEnvironmentSummary(): Promise<void> {
    startupLog.info('🔧 Environment Variable Summary');

    const envSummary = this.analyzeEnvironmentVariables();

    // Critical configuration
    const criticalPresent = envSummary.critical.filter((v) => v.status === 'present').length;
    const criticalTotal = envSummary.critical.length;

    startupLog.info('🔐 Critical Configuration', {
      present: `${criticalPresent}/${criticalTotal}`,
      missing: envSummary.critical.filter((v) => v.status === 'missing').map((v) => v.key),
    });

    // Log present critical variables (redacted)
    envSummary.critical
      .filter((v) => v.status === 'present')
      .forEach((v) => {
        const redactedValue = redactSensitiveInfo(v.key, v.value);
        startupLog.debug(`   ✓ ${v.key}: ${redactedValue}`);
      });

    // Optional configuration
    const optionalPresent = envSummary.optional.filter((v) => v.status === 'present').length;

    startupLog.info('🔧 Optional Configuration', {
      present: `${optionalPresent}/${envSummary.optional.length}`,
    });

    // Log present optional variables (redacted)
    envSummary.optional
      .filter((v) => v.status === 'present')
      .forEach((v) => {
        const redactedValue = redactSensitiveInfo(v.key, v.value);
        startupLog.debug(`   ✓ ${v.key}: ${redactedValue}`);
      });
  }

  /**
   * Analyze environment variables and categorize them
   */
  private analyzeEnvironmentVariables(): EnvironmentSummary {
    const criticalVars = ['NODE_ENV', 'PORT', 'MESSAGE_PROVIDER'];

    const optionalVars = [
      'DISCORD_BOT_TOKEN',
      'SLACK_BOT_TOKEN',
      'SLACK_APP_TOKEN',
      'SLACK_SIGNING_SECRET',
      'MATTERMOST_TOKEN',
      'MATTERMOST_URL',
      'OPENAI_API_KEY',
      'OPENAI_BASE_URL',
      'ANTHROPIC_API_KEY',
      'OPENWEBUI_API_KEY',
      'FLOWISE_API_KEY',
      'WEBHOOK_SECRET',
      'SECRET',
    ];

    const featureFlags = [
      { key: 'HTTP_ENABLED', description: 'HTTP server and WebUI' },
      { key: 'SKIP_MESSENGERS', description: 'Messenger initialization' },
      { key: 'WEBHOOK_ENABLED', description: 'Webhook service' },
      { key: 'LOW_MEMORY_MODE', description: 'Low memory optimizations' },
      { key: 'SUPPRESS_HEALTH_LOGS', description: 'Health endpoint logging' },
      { key: 'DEBUG', description: 'Debug logging' },
    ];

    const summary: EnvironmentSummary = {
      critical: [],
      optional: [],
      featureFlags: [],
    };

    // Analyze critical variables
    criticalVars.forEach((key) => {
      const value = process.env[key];
      summary.critical.push({
        key,
        value: value || '',
        status: value ? 'present' : 'missing',
      });
    });

    // Analyze optional variables
    optionalVars.forEach((key) => {
      const value = process.env[key];
      summary.optional.push({
        key,
        value: value || '',
        status: value ? 'present' : 'missing',
      });
    });

    // Analyze feature flags
    featureFlags.forEach(({ key, description }) => {
      const value = process.env[key];
      summary.featureFlags.push({
        key,
        value: value || 'false',
        description,
      });
    });

    return summary;
  }

  /**
   * Log configuration file status and content summary
   */
  private async logConfigurationStatus(): Promise<void> {
    startupLog.info('📄 Configuration Status');

    const configPaths = [
      'config/providers/messengers.json',
      'config/llm/providers.json',
      'config/messages.json',
      'config/webhooks.json',
    ];

    const configStatus: { path: string; exists: boolean; size?: number; error?: string }[] = [];

    for (const configPath of configPaths) {
      try {
        const fullPath = path.join(process.cwd(), configPath);
        const exists = fs.existsSync(fullPath);

        if (exists) {
          const stats = fs.statSync(fullPath);
          configStatus.push({
            path: configPath,
            exists: true,
            size: stats.size,
          });
        } else {
          configStatus.push({
            path: configPath,
            exists: false,
          });
        }
      } catch (error) {
        configStatus.push({
          path: configPath,
          exists: false,
          error: error instanceof Error ? error.message : String(error),
        });
      }
    }

    const existingConfigs = configStatus.filter((c) => c.exists);
    const missingConfigs = configStatus.filter((c) => !c.exists);

    startupLog.info('📁 Configuration Files', {
      loaded: existingConfigs.length,
      missing: missingConfigs.length,
      totalSize: existingConfigs.reduce((sum, c) => sum + (c.size || 0), 0),
    });

    existingConfigs.forEach((config) => {
      startupLog.debug(`   ✓ ${config.path} (${config.size} bytes)`);
    });

    missingConfigs.forEach((config) => {
      startupLog.debug(`   ⚠ ${config.path} (not found)`);
    });
  }

  /**
   * Log provider connectivity and configuration status
   */
  private async logProviderConnectivity(): Promise<void> {
    startupLog.info('🤖 Provider Connectivity Status');

    const providers: ProviderStatus[] = [
      {
        type: 'discord',
        configured: !!process.env.DISCORD_BOT_TOKEN,
        connected: false, // Will be updated during actual initialization
      },
      {
        type: 'slack',
        configured: !!(process.env.SLACK_BOT_TOKEN && process.env.SLACK_SIGNING_SECRET),
        connected: false,
      },
      {
        type: 'mattermost',
        configured: !!(process.env.MATTERMOST_TOKEN && process.env.MATTERMOST_URL),
        connected: false,
      },
    ];

    const configuredProviders = providers.filter((p) => p.configured);
    const unconfiguredProviders = providers.filter((p) => !p.configured);

    startupLog.info('🔗 Provider Configuration', {
      configured: configuredProviders.length,
      unconfigured: unconfiguredProviders.length,
    });

    configuredProviders.forEach((provider) => {
      startupLog.debug(`   ✓ ${provider.type}: configured`);
    });

    unconfiguredProviders.forEach((provider) => {
      startupLog.debug(`   ⚠ ${provider.type}: not configured`);
    });

    // Note: Actual connectivity testing will happen during provider initialization
  }

  /**
   * Log API/WebUI availability and authentication status
   */
  private async logApiWebUiStatus(): Promise<void> {
    startupLog.info('🌐 API & WebUI Status');

    const httpEnabled = process.env.HTTP_ENABLED !== 'false';
    const port = process.env.PORT || '3028';

    if (!httpEnabled) {
      startupLog.info('   ➖ HTTP server disabled via HTTP_ENABLED=false');
      startupLog.warn('⚠️  WebUI and API endpoints are NOT available');
      return;
    }

    startupLog.info('✅ HTTP server enabled', { port });

    // Check authentication configuration
    const authStatus = this.checkAuthenticationStatus();

    startupLog.info('🔐 Authentication Status', {
      enabled: authStatus.enabled,
      method: authStatus.method,
      securityLevel: authStatus.securityLevel,
      webuiProtected: authStatus.webuiProtected,
      apiProtected: authStatus.apiProtected,
    });

    if (!authStatus.enabled) {
      startupLog.error('⛔ SECURITY RISK: Authentication is DISABLED');
      startupLog.error('   ⚠️  WebUI and API are publicly accessible without authentication!');
      startupLog.error('   🚨 This is NOT recommended for internet-facing deployments');
      startupLog.error(
        '   💡 Set up authentication by configuring users or enabling auth middleware'
      );
    } else {
      startupLog.info('✅ Authentication is properly configured');
      if (authStatus.webuiProtected) {
        startupLog.info('   ✓ WebUI requires authentication');
      }
      if (authStatus.apiProtected) {
        startupLog.info('   ✓ API endpoints require authentication');
      }
    }

    // Check specific authentication mechanisms
    if (authStatus.jwtSecret) {
      startupLog.debug('   ✓ JWT authentication configured');
    }

    if (authStatus.defaultAdmin) {
      startupLog.debug('   ✓ Default admin user configured');
    }

    if (authStatus.secureConfigUsers > 0) {
      startupLog.debug(`   ✓ ${authStatus.secureConfigUsers} users configured via secure storage`);
    }
  }

  /**
   * Check authentication configuration status
   */
  private checkAuthenticationStatus() {
    const status = {
      enabled: false,
      method: 'none',
      securityLevel: 'none',
      webuiProtected: false,
      apiProtected: false,
      jwtSecret: false,
      defaultAdmin: false,
      secureConfigUsers: 0,
    };

    try {
      // Check if JWT secrets are configured (AuthManager generates them automatically)
      const authManagerExists = this.checkAuthManagerExists();
      if (authManagerExists) {
        status.jwtSecret = true;
        status.method = 'jwt';
        status.securityLevel = 'standard';
        status.enabled = true;
      }

      // Check for SECRET environment variable (legacy auth)
      if (process.env.SECRET) {
        status.method = status.jwtSecret ? 'jwt+secret' : 'secret';
        status.securityLevel = 'legacy';
        status.enabled = true;
      }

      // Check if admin routes are protected
      status.webuiProtected = status.enabled;
      status.apiProtected = status.enabled;

      // Count users from secure configuration (if available)
      try {
        const SecureConfigManager = require('../config/SecureConfigManager');
        SecureConfigManager.getInstance();
        // Note: This would need to be implemented in SecureConfigManager
        // status.secureConfigUsers = secureConfig.getUserCount();
      } catch {
        // SecureConfigManager not available or doesn't have user counting
      }
    } catch (error) {
      startupLog.debug('Error checking authentication status', { error });
    }

    return status;
  }

  /**
   * Check if AuthManager is available and configured
   */
  private checkAuthManagerExists(): boolean {
    try {
      const AuthManager = require('../auth/AuthManager');
      const authManager = AuthManager.getInstance();
      return !!authManager;
    } catch {
      return false;
    }
  }

  /**
   * Log system resources and environment
   */
  private async logSystemResources(): Promise<void> {
    startupLog.info('💻 System Resources');

    const resources: SystemResources = {
      memoryUsage: process.memoryUsage(),
      freeDiskSpace: this.getFreeDiskSpace(),
      nodeVersion: process.version,
      platform: process.platform,
    };

    const memoryMB = Math.round(resources.memoryUsage.heapUsed / 1024 / 1024);
    const memoryLimitMB = Math.round(resources.memoryUsage.heapTotal / 1024 / 1024);
    const diskSpaceGB =
      resources.freeDiskSpace > 0
        ? `${(resources.freeDiskSpace / (1024 * 1024 * 1024)).toFixed(2)}GB`
        : 'Unknown';

    startupLog.info('📊 Resource Summary', {
      nodeVersion: resources.nodeVersion,
      platform: resources.platform,
      memoryUsage: `${memoryMB}MB`,
      memoryLimit: `${memoryLimitMB}MB`,
      freeDiskSpace: diskSpaceGB,
      pid: process.pid,
    });
  }

  /**
   * Get free disk space in bytes for the current working directory
   */
  private getFreeDiskSpace(): number {
    try {
      const { execSync } = require('child_process');
      const cwd = process.cwd();

      if (process.platform === 'win32') {
        // Windows: use wmic to get free space
        const drive = cwd.charAt(0).toUpperCase();
        const result = execSync(`wmic logicaldisk get size,freespace,caption`, {
          encoding: 'utf8',
        });
        const lines = result.split('\n').filter((line: string) => line.trim());
        for (const line of lines) {
          if (line.startsWith(drive)) {
            const parts = line.split(/\s+/).filter(Boolean);
            return parseInt(parts[1], 10) || 0;
          }
        }
      } else {
        // Unix-like: use df command
        const result = execSync(`df -k "${cwd}" | tail -1`, { encoding: 'utf8' });
        const parts = result.split(/\s+/).filter(Boolean);
        // df -k outputs: Filesystem, 1K-blocks, Used, Available, Use%, Mounted on
        const availableKB = parseInt(parts[3], 10);
        return (availableKB || 0) * 1024; // Convert KB to bytes
      }
    } catch (error) {
      startupLog.debug('Failed to get disk space:', error);
    }
    return 0;
  }

  /**
   * Log feature flag status
   */
  private async logFeatureFlags(): Promise<void> {
    startupLog.info('🚩 Feature Flags');

    const flags = [
      { key: 'HTTP_ENABLED', default: 'true', description: 'Enable HTTP server and WebUI' },
      { key: 'SKIP_MESSENGERS', default: 'false', description: 'Skip messenger initialization' },
      { key: 'WEBHOOK_ENABLED', default: 'false', description: 'Enable webhook service' },
      { key: 'LOW_MEMORY_MODE', default: 'false', description: 'Enable low memory optimizations' },
      {
        key: 'SUPPRESS_HEALTH_LOGS',
        default: 'true',
        description: 'Suppress health endpoint logs',
      },
    ];

    flags.forEach((flag) => {
      const value = process.env[flag.key] || flag.default;
      const isActive = value === 'true' || value === '1';
      const icon = isActive ? '✅' : '➖';
      startupLog.debug(`   ${icon} ${flag.key}: ${value} (${flag.description})`);
    });
  }

  /**
   * Log successful provider initialization
   */
  public logProviderInitialized(providerType: string, details?: any): void {
    startupLog.info('🤖 Provider Initialized', {
      type: providerType,
      details: details ? this.sanitizeDetails(details) : undefined,
    });
  }

  /**
   * Log provider initialization failure
   */
  public logProviderInitializationFailed(providerType: string, error: any): void {
    startupLog.error('❌ Provider Initialization Failed', {
      type: providerType,
      error: error instanceof Error ? error.message : String(error),
    });
  }

  /**
   * Sanitize provider details for logging
   */
  private sanitizeDetails(details: any): any {
    if (typeof details !== 'object' || details === null) {
      return details;
    }

    const sanitized: any = {};
    for (const [key, value] of Object.entries(details)) {
      if (typeof value === 'string' && this.isSensitiveKey(key)) {
        sanitized[key] = redactSensitiveInfo(key, value);
      } else {
        sanitized[key] = value;
      }
    }
    return sanitized;
  }

  /**
   * Check if a key is likely to contain sensitive information
   */
  private isSensitiveKey(key: string): boolean {
    const sensitivePatterns = ['token', 'secret', 'key', 'password', 'auth'];
    return sensitivePatterns.some((pattern) => key.toLowerCase().includes(pattern));
  }
}

